-- Poems batch 240
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fc9c7c78-e835-4d26-b13d-5e34ba9a8531','北山遇雪','衛宗武','宋','宋诗','song-poetry','','[]','天公衒天巧，三見臘之時。',168,'全唐诗/poet.song.218000.json','["天公衒天巧，三見臘之時。", "似花還非花，衮衮縱橫飛。", "瀉竹振清香，壓梅迷真蕤。", "烏兔耿無光，遁跡不敢馳。", "雕鎪各成形，磊塊或作堆。", "蔽空來若塵，著物明於璣。", "武騎當此際，縱獵方打圍。", "森森紛甲刃，爛爛光相輝。", "豈若灞橋馿，領此一段奇。", "今朝積數寸，回眎覺昨非。", "比屋占農祥，津津喜上眉。", "對書明徹眼，煮茗清入脾。", "肯爲袁安卧，宜賦劉叉詩。", "呼童掃松逕，迎客扶桃枝。"]'),
('532925ae-d2d0-42b1-8d16-d5cff1b53a4d','再遇雪','衛宗武','宋','宋诗','song-poetry','','[]','窮冬滯空山，風雨何凄迷。',204,'全唐诗/poet.song.218000.json','["窮冬滯空山，風雨何凄迷。", "馮夷工剪水，有技不肯施。", "俄於夜未分，六出紛葳蕤。", "但見草壤間，疊疊生玉枝。", "須臾遂彌滿，匼匝生四圍。", "突兀千丈高，浩無膚寸遺。", "寒林遠映带，一色相參差。", "天工呈大巧，幻出此段奇。", "遂令翳薈間，瑣碎玉作姿。", "安得借化冶，烹鍊如銀爲。", "勿使見睍消，有若朝露晞。", "巨靈與夸娥，負挾從我歸。", "以此幾嵯峨，森列置八維。", "爲民除熱惱，盛夏袪炎威。", "金石可流爍，天瑞無變移。", "良宵著明蟾，遶以波琉璃。", "四時照吟筆，千古凝清輝。"]'),
('21f00c45-ae45-401f-9629-07fed09a46fb','所居遇雪','衛宗武','宋','宋诗','song-poetry','','[]','去年雪於臘，見睍跡已滅。',180,'全唐诗/poet.song.218000.json','["去年雪於臘，見睍跡已滅。", "今年天作花，再白遂凝結。", "鱗鱗甍相接，爛爛銀互疊。", "平尺雖未盈，皓若布層㲲。", "洪纖歸一覆，高下同至潔。", "入夜更飄揚，未久復匼匝。", "打窗明映書，堆垣厚成堞。", "披衣起推戶，勇不待明發。", "庭間數十挺，葉葉如楮刻。", "牆角南北枝，艷艷疑花壓。", "遥想幾青山，幻成玉崨嶪。", "郊原瑞色浮，穹壤和氣浹。", "豈但疵癘消，可卜豐穰協。", "書生喜無寐，但覺吻囁囁。", "掬之滋吟觴，石鐺煮團月。"]'),
('db91e0fb-9d99-4a50-a7b6-26158ad2eeb1','北山值雪偶成','衛宗武','宋','宋诗','song-poetry','','[]','艮象涵萬有，佳趣備四時。',156,'全唐诗/poet.song.218000.json','["艮象涵萬有，佳趣備四時。", "此行屬寒沍，喜遇臘雪飛。", "琤琤初集霰，粲粲紛葳蕤。", "奔騰漸成陣，勢作龍鳳馳。", "森森千碧林，緣飾如珠璣。", "旋觀壓層嶺，爛若銀成圍。", "一天散和氣，萬境凝清輝。", "飛揚到朽壤，臭腐爲神奇。", "問山何幻怪，頃刻顔面非。", "蒼蒼改正色，皓皓浮鬚眉。", "我來逢此瑞，爽塏流肝脾。", "對之豈徒酒，而可不以詩。", "因詩探山意，春信橫南枝。"]'),
('b2157360-8ad3-44b5-bfa8-59620b81180c','次歲雪後作','衛宗武','宋','宋诗','song-poetry','','[]','伊耆令將行，玄冥車載轄。',288,'全唐诗/poet.song.218000.json','["伊耆令將行，玄冥車載轄。", "玉律歲肇新，一白至再白。", "三冬望上瑞，猶喜在窮臘。", "霅然沖氣布，潛可弭凶札。", "積之近盈尺，豈但宜黍麥。", "化工尤善幻，散集總奇特。", "飛颺漫天來，龍鳳相擺擲。", "萬殊無兩色，大地總明潔。", "初疑散花女，空中碎裂帛。", "俄成古佛居，移下爛銀闕。", "玲瓏千萬林，一一如玉刻。", "梁園曾未春，紛紛徧遊蝶。", "飛鳥迷所栖，狡兔失其穴。", "乾坤凈無塵，川原互清發。", "我輩當此時，意氣倍軒豁。", "顧慚海上夫，餒欲和旃齧。", "濱死氣不衰，挺挺抱奇節。", "且非邁古才，閉門眠自若。", "藏器以待用，內藴經濟業。", "祇有健吟哦，舍此無他說。", "雅欲訪古梅，一笑邀皓月。", "開樽約勝踐，共對此三絕。", "夫何見睍消，非久即變滅。", "是固雪負予，抑亦予負雪。"]'),
('5479b571-040f-41db-ae57-68cba09c1fe8','冬留紫芝庵即事','衛宗武','宋','宋诗','song-poetry','','[]','玄冬適莽蒼，霜宇更闃寂。',180,'全唐诗/poet.song.218000.json','["玄冬適莽蒼，霜宇更闃寂。", "繫舟山下路，窈窕松關入。", "一榻寄僧居，幽雲生卧室。", "明朝過東山，千尋更矹硉。", "丙舍尤杳深，寒林互盤屈。", "孤楓綴餘丹，萬竹錯叢碧。", "天寒鳥聲靜，木落山骨出。", "飲無客獻酬，坐有僧分席。", "一盃復一盃，不覺日之夕。", "林鳥欲歸栖，翩翩競翔集。", "萬點布平田，有似坡仙弈。", "此行爲訪梅，東尋復西覓。", "俄見影橫斜，蕭然倚山壁。", "中有第一春，緘藏何太密。", "數日我重來，要見南枝白。"]'),
('898f79e6-51ea-4b6b-a86b-1d9ea45f72a9','天寒留滯山中即事','衛宗武','宋','宋诗','song-poetry','','[]','逾月留窮源，不覺歲云暮。',204,'全唐诗/poet.song.218000.json','["逾月留窮源，不覺歲云暮。", "緒景寖凄凉，重陰方固沍。", "芳叢菊殫殘，丹楓葉飛舞。", "蒙茸豐草萎，剝落喬木古。", "茲來遂幽尋，所恨乏勝侶。", "釋友間往還，農父相爾汝。", "索句課唐吟，繙經勘佛語。", "肅肅繁霜零，輝輝寒月吐。", "夜氣消檠燈，凜威薄衣絮。", "榾柮煨爐紅，輪囷擁衾素。", "噓呵冷欲冰，拳攣宿如露。", "老瓦補茅柴，破釜煮栗芋。", "烹鮮遠莫致，擷蔬美可茹。", "氓廛絕紛囂，僧席割清苦。", "頹然撫孤蹤，樂哉忘萬慮。", "亡何歸興動，適爲物怪忤。", "舉手謝白雲，扁舟鳴去艣。"]'),
('280b03e8-7623-4974-9cbd-dd617e05bcb5','留墓松','衛宗武','宋','宋诗','song-poetry','','[]','青青冢上木，夭矯摩太虛。',180,'全唐诗/poet.song.218000.json','["青青冢上木，夭矯摩太虛。", "日夜之所息，雨露之所濡。", "其來至高曾，奚啻五世儲。", "偉哉廊廟材，而受斤斧屠。", "其間鍾異質，形氣與衆殊。", "小者近十圍，大者百尺軀。", "九苞鳳可巢，千載苓可耡。", "難以刀鋸加，俾與玉石俱。", "留爲龍鸞種，要産駒與雛。", "咨汝二十二，結交猶朋徒。", "共期松喬壽，以衛龍虎區。", "子孫其保之，慎勿使剪除。", "毋傚發冢儒，假辭取珠襦。", "羣柏既就殲，所存能幾餘。", "時哉能得已，涕泣而長吁。"]'),
('a84ed2bf-8e08-4bca-bd44-2ee9096c835e','伐墓松','衛宗武','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鬰鬰乎佳哉，古松茂而秀。',168,'全唐诗/poet.song.218000.json','["鬰鬰乎佳哉，古松茂而秀。", "封植難計年，龍鸞相錯糾。", "天風動清籟，洞庭喧雅奏。", "護之珠玉如，期以金石久。", "夫何從斧戕，山木豈自寇。", "衆咻謂宜然，一諤固所否。", "梯航方勤遠，斬刈或恐復。", "衆巔已成童，懷璧豈吾有。", "欲爲狂瀾障，無奈鑠金口。", "幾世培梁棟，一朝等薪槱。", "壤樹其可芟，不覺眥飛溜。", "惟思植萬本，易新以補舊。", "初如牛羊散，漸見蛟虬走。", "庶保墓域安，盤錯至不朽。"]'),
('89a25dd5-5d73-4789-b14c-bb5b44c8ffc4','歲冬至唐村墳山掃松','衛宗武','宋','宋诗','song-poetry','','[]','憶昔入此山，首夏接春季。',240,'全唐诗/poet.song.218000.json','["憶昔入此山，首夏接春季。", "谷鳥正嚘嚶，芬芳尤嫵媚。", "青青交道杉，森鬰互參倚。", "誰乎一叱咤，斬艾如草薙。", "遂令墟墓間，常抱斧斤恥。", "僅存盤澗松，綽有虬龍勢。", "矯矯千歲姿，昂霄猶舞翠。", "我來省松檟，適當谷之昧。", "石齒咽殘流，鳴族息羣喙。", "木石縮羽鱗，風霜翦菑翳。", "豁然眼界清，如至人境外。", "意行步崎嶇，白雲生屐履。", "林光漬欲流，冉冉濕衣袂。", "僧來入畫圖，人行絕氈毳。", "風塵不可到，心跡兩無穢。", "追尋得良儔，清吟可相配。", "不效互唱酬，日與青山對。", "茲游擬暢情，俄值風雨晦。", "漸喜迫新陽，天地寧久閉。", "屋角數點明，冰花送春意。"]'),
('b10ded5b-e216-4bb2-96d9-8972c15e79f7','獨鶴','衛宗武','宋','宋诗','song-poetry','','[]','獨鶴來有年，置彼三徑曲。',120,'全唐诗/poet.song.218000.json','["獨鶴來有年，置彼三徑曲。", "挈至此靖廬，幽絕山林屋。", "戛然發長唳，清亮振虛谷。", "炳炳千歲丹，不受烏兔促。", "乘之雖有軒，頗窘筋骸束。", "寥廓萬里心，夫豈在食粟。", "一舉窮紫清，真境可洞矚。", "奈何剪其翅，殆類驥縶足。", "然雖啄菢恩，變化乃迅速。", "昂昂禽中仙，未數昆明鵠。"]'),
('6c53a74d-eb86-4d46-91d4-7b711f729eef','過茶塢子舍新塋','衛宗武','宋','宋诗','song-poetry','','[]','自閲管郭書，風水好成癖。',288,'全唐诗/poet.song.218000.json','["自閲管郭書，風水好成癖。", "維舟走霅嶠，川谷幾徧歷。", "晚年乃得此，於焉擬藏骨。", "身謀適不偶，命子爲冢宅。", "癡兒好侈大，治庵如考室。", "豁然天地寬，有若混沌闢。", "層巒猶連城，一一互拱揖。", "案後三奇峰，參倚而特立。", "端然顧其穴，宛類鳳展翼。", "又似老泉翁，二季侍其側。", "啟戶儼若臨，朝夕在几席。", "回頭看新月，對面賓出日。", "鬰乎氣佳哉，秀異鍾一窟。", "神刲與鬼劃，天授非人力。", "一丘有如此，萬金買難覓。", "羊眠協夢祥，牛卧兆墓域。", "地將發秘藏，人已産英特。", "吾家顧未然，貞符在種德。", "爲善斯有慶，積衰由作慝。", "素履或未純，青囊惡可必。", "要須法睿武，粹如圭與璧。", "戒之而謹之，箴儆毋我忽。", "庶或生賢貴，簪紱可世及。", "不然負此山，山亦有慚色。"]'),
('d463873b-01bb-41f9-a03a-be6933061dcd','和趙蓮奧琴','衛宗武','宋','宋诗','song-poetry','','[]','豈無五尺桐，所貯徒百囊。',72,'全唐诗/poet.song.218000.json','["豈無五尺桐，所貯徒百囊。", "惟君匣中材，古韻涵混茫。", "高山與流水，雅趣深可長。", "古人寶清英，今君豈殊揚。", "鏘然出金石，振厲如歌商。", "毋惜一運軫，冰雪置我腸。"]'),
('ebc91159-bed2-4146-843f-790dc24ca6de','和趙蓮奧劍','衛宗武','宋','宋诗','song-poetry','','[]','豈無三尺鐵，巧事犀玉粧。',72,'全唐诗/poet.song.218000.json','["豈無三尺鐵，巧事犀玉粧。", "惟君匣中藏，百鍊侔步光。", "小試鋒莫當，崖石中開張。", "會須斬姦邪，曄曄神光揚。", "未遜古佩刀，公輔誇王祥。", "斯物由天成，匪但工之良。"]'),
('9f996b73-4fd2-4acf-940f-67c85de6e4c2','次韻酬李黄山','衛宗武','宋','宋诗','song-poetry','','[]','吾儒何所事，讀書而挾策。',156,'全唐诗/poet.song.218000.json','["吾儒何所事，讀書而挾策。", "君才郄林枝，靈根芳正發。", "筆下富詞藻，雲錦自天落。", "英英光嶽氣，灑灑冰雪魄。", "中秋璧月圓，宜赴廣寒約。", "桂籍那未香，天公無皂白。", "學如禾與稻，既藝宜必穫。", "于時誤儒冠，孰不嗟鑄錯。", "篇章來聯翩，有主此有客。", "隋珠既璀璨，和璞無踳駁。", "有文可與評，有酒可與酌。", "長吟不淹宿，捷若蛇赴壑。", "喜得羅庾儔，吾鄉宜卜宅。"]'),
('6e5c786e-081f-441e-8475-671d2772c50d','酬鄉友惠詩','衛宗武','宋','宋诗','song-poetry','','[]','乃翁不遐遺，招邀至宅里。',132,'全唐诗/poet.song.218000.json','["乃翁不遐遺，招邀至宅里。", "芳馨秩俎豆，聲歌列紈綺。", "壽色竇庭椿，天芬郄枝桂。", "皤皤七十叟，義方嚴教子。", "大兒書滿架，心惟醉經史。", "金朱非所樂，飲食能知味。", "篇章落咳唾，葩藻振奇麗。", "月眼老增明，三讀使予起。", "小兒暨若孫，未遑試以藝。", "具謂善吟哦，抑亦工誦記。", "庭蘭其在茲，芬芳殊未既。"]'),
('85255085-8554-49b8-9c06-29671a3409f4','懷南塘朱省閲','衛宗武','宋','宋诗','song-poetry','','[]','我如蟄戶居，跬步不可移。',240,'全唐诗/poet.song.218000.json','["我如蟄戶居，跬步不可移。", "君有遠行役，暑途方驅馳。", "覘知所如往，謂已杭雙溪。", "人苟懷忠信，蠻貊其行之。", "平生玉雪襟，節行所素持。", "督運奉省檄，迨今已數期。", "故牘出袖間，數不差毫釐。", "皓皓其可汙，皎若明鑑垂。", "堂堂大司存，肯計銖與錙。", "往事等塵埃，意者窮奸欺。", "奸欺固莫逃，賞識必見奇。", "豈惟憂責無，可以歌嘯歸。", "獨念行路難，藴隆丁斯時。", "野有暍死夫，何以當炎曦。", "越山未易登，其上號狐狸。", "越水不可厲，其下多蛟螭。", "鬼魅常瞰人，往者來者稀。", "毋爲巖壑娛，返旆因遲遲。", "粵從軫既東，一日腸九迴。", "桂秋俄已近，數日盼歸期。"]'),
('8ff9c748-9b4d-4c8c-ba06-7cf0fd5624d8','謝朱南塘借己田爲易陸宅山建玉宸道宇','衛宗武','宋','宋诗','song-poetry','','[]','好山未易得，况此不多山。',252,'全唐诗/poet.song.218000.json','["好山未易得，况此不多山。", "靡迤八九丘，遠眎猶彈丸。", "幾載謀一區，經營何其艱。", "尺求而寸予，往往人所慳。", "丙舍西復西，一岑頗巑岏。", "其坡委蛇垂，宛若縈带鞶。", "又類立大纛，轉幟風飛翻。", "其中似掌平，可爲宮與壇。", "荷君割膏腴，易置爲我懽。", "斯舉昔罕聞，豈但今所難。", "得以奉帝尊，峻閣而危欄。", "顧惟匪陶頓，奚以役倕般。", "蓋由心願欲，寧恤家殫殘。", "于茲延真侶，亦足化世頑。", "報乏千鎰金，感著方寸丹。", "每嗟隸黔首，孰若儕黄冠。", "惟弗叛宣尼，何妨師老聃。", "斯宇儻落成，屈致居其間。", "玄玄五千言，言言推其端。", "看生白室光，相對清晝閒。", "學道能造極，何必三神巒。"]'),
('96705951-c0d9-4b43-ad1f-a9b7686eb7f6','和葉野渡易古銅瓶韻','衛宗武','宋','宋诗','song-poetry','','[]','此方而彼圓，何異冰與炭。',288,'全唐诗/poet.song.218000.json','["此方而彼圓，何異冰與炭。", "彼工而此樸，土簋眎玉瓚。", "達人以道觀，萬殊等一貫。", "我有四耳尊，自謂今之冠。", "刻畫盡精微，光澤加璀璨。", "流傳知幾年，器不減周漢。", "肯使居水湄，敬用如始盥。", "殆類古罍洗，盆盎不可亂。", "以好易所好，在昔有公案。", "張硯晉卿石，坡老詩可按。", "于以篤心盟，豈但榮目觀。", "緬思古之人，未嘗不三歎。", "君家螭文壺，相去未能半。", "癡兒厭家雞，咄咄求互換。", "四美欲其并，片言爲之贊。", "慨然湖海襟，弗以錙銖算。", "捷于響斯答，不寶己所玩。", "折簡墨未乾，訂金言靡叛。", "信云義易利，殆類耕遜畔。", "將以舂容篇，溢目珠璣粲。", "捧持簪春花，恨無雙玉腕。", "凡物各有匹，以時而合散。", "干將與莫邪，蛟龍可水斷。", "方其埋豐城，雌雄元未判。"]'),
('5dc6f16a-a191-4ed5-81e0-e8f5b8af080c','爲雲侶天游賦','衛宗武','宋','宋诗','song-poetry','','[]','汗漫可以期，列缺可以至。',132,'全唐诗/poet.song.218000.json','["汗漫可以期，列缺可以至。", "豈不高且遠，未足語超詣。", "至人悟重玄，妙境此融會。", "無聲亦無臭，萬象於我備。", "不必八柱承，不必二極繫。", "曾城九重居，儼若具乎內。", "於焉以泮渙，其樂浩無際。", "氣凝而神化，舉步六合外。", "乘輪閬風行，稅駕丹丘憩。", "逍遥兮周流，斯特跡之寄。", "混然吾太虛，遊是息於是。"]'),
('7aade251-3da8-4824-a200-f9390528a585','贈潘天游','衛宗武','宋','宋诗','song-poetry','','[]','乾以健而運，如轂不停息。',108,'全唐诗/poet.song.218000.json','["乾以健而運，如轂不停息。", "周流徧六虛，升降靡差忒。", "故能權四序，而以轉萬物。", "茲其氣之遊，造化由是出。", "一元亙終古，塵劫浩難詰。", "人有貌以生，於中具太極。", "苟知法天行，折旋而闔闢。", "浮游潛深淵，外想不內入。", "亦解長不死，壽與之爲一。"]'),
('940ce4d3-0149-4395-85d3-2e4139e623d8','寄徐清溪','衛宗武','宋','宋诗','song-poetry','','[]','清溪溪上山，九山山下水。',120,'全唐诗/poet.song.218000.json','["清溪溪上山，九山山下水。", "山水遥相望，美人隔千里。", "飛鴻來遠音，老鶴喜得類。", "望履杳無從，豈或尼而止。", "採蘭以爲贈，折梅以爲寄。", "芳馨匪常存，懷想惡能已。", "吾衰年幾何，歲月猶川逝。", "理奧欠析微，書囊未窮底。", "古杭可葦航，溪流迅如駛。", "雖爽菊秋期，花時更清美。"]'),
('6de11118-d24a-49e5-a025-d51848eaf361','次青溪後二章爲別  其一','衛宗武','宋','宋诗','song-poetry','','[]','季世思良士，如抱渴與饑。',72,'全唐诗/poet.song.218000.json','["季世思良士，如抱渴與饑。", "峩峩章甫冠，瑞氣浮芝眉。", "粹然君子儒，赴我同襟期。", "凡林非鸞棲，丹穴仍歸飛。", "恨無健羽翰，所至相追隨。", "懷歸宜莫留，荆州那足依。"]'),
('43ddd8d1-e69c-4da5-85ae-410c90a1a551','次青溪後二章爲別  其二','衛宗武','宋','宋诗','song-poetry','','[]','今古多紛攘，宇宙彌氛埃。',96,'全唐诗/poet.song.218000.json','["今古多紛攘，宇宙彌氛埃。", "故友晨星然，往往淪劫灰。", "幸得莫逆交，子輿從子來。", "道義本契合，心跡無疑猜。", "不徒千斛舟，置此坳堂杯。", "動靜必與俱，書林日徘徊。", "一聞驪駒駕，黯然腸九迴。", "從今子陵臺，目睫常嵬嵬。"]'),
('3155cde9-5803-4d5e-914d-c5a852d37b22','劉錦山自衡州歸復書仍貽之詩','衛宗武','宋','宋诗','song-poetry','','["\u8861\u5c71"]','渺渺湘水波，浩浩衡山雲。',192,'全唐诗/poet.song.218000.json','["渺渺湘水波，浩浩衡山雲。", "悠悠我之思，皎皎兮美人。", "美人不可見，陵谷日遷變。", "風塵方紛攘，意者生死判。", "鴈來信可通，豈若重會逢。", "恨無健羽翮，萬里飛相從。", "腰下黄金佩，人間紫馬貴。", "還疑衮繡身，易奪丘園志。", "鶴髮幾七旬，年與君爲鄰。", "交至老彌篤，恨弗時相親。", "急流中勇退，一舸歸私第。", "俄傳尺素書，讀之喜不寐。", "願堅如蘭心，共締松菊盟。", "毋貽林澗愧，復動軒冕情。", "皓首金石契，何異園與綺。", "昔日良友朋，今爲老兄弟。"]'),
('03f8d796-1e70-404c-a292-3f9eafbf5fb1','過秀城','衛宗武','宋','宋诗','song-poetry','','[]','舟行過鄉城，憶昨又三載。',72,'全唐诗/poet.song.218000.json','["舟行過鄉城，憶昨又三載。", "鶴表人或非，雉堞址仍在。", "郊郭幸苟完，室廬俱可慨。", "十年遠親友，一見如有礙。", "胡爲窮紀次，際此遠行邁。", "歸來椒柏新，德人年未艾。"]'),
('20a7e147-d9f1-40c5-97c6-d82b97541403','贈趙月麓之霅','衛宗武','宋','宋诗','song-poetry','','[]','乍合成乍離，歲月何飄忽。',204,'全唐诗/poet.song.218000.json','["乍合成乍離，歲月何飄忽。", "重來吾愈老，喜復遂良覿。", "月麓號新改，簪裳亦殊昔。", "議論羲皇前，咳唾煙霞出。", "囊中詩一編，語到不可及。", "清圓粲珠璣，雅正諧呂律。", "新吟多感慨，能使鬼神泣。", "洗耳聽談玄，有言皆造極。", "豁然啟其蒙，不覺膝欲屈。", "一碧涵千峰，吳興山水窟。", "來辦結構資，丹砂鑄僊骨。", "魯公千載祠，已仆誰復植。", "新宇儻落成，端莊厲忠直。", "滔滔姦佞夫，見使心怵惕。", "雖爲老氏徒，未廢儒者術。", "我有招隠廬，亦足以棲白。", "安能挽之留，共勘先天易。"]'),
('8a206713-fd96-4d60-9880-deb89e9a6c1b','送人','衛宗武','宋','宋诗','song-poetry','','[]','荆璞雖未琢，須成圭璧珍。',72,'全唐诗/poet.song.218000.json','["荆璞雖未琢，須成圭璧珍。", "嶧桐雖未弦，須奏雲和音。", "抱此材質良，識真豈無人。", "薦進居禁嚴，持美以效君。", "永爲廊廟器，陋彼瑚璉陳。", "胡然久賢勞，展驥滄海濱。"]'),
('cdfffbbd-b0eb-48a7-90d1-50f9b277ab98','送林松壑','衛宗武','宋','宋诗','song-poetry','','[]','彈鋏歸來乎，暫作蘇臺客。',48,'全唐诗/poet.song.218000.json','["彈鋏歸來乎，暫作蘇臺客。", "昂昂歲寒姿，依然返故壑。", "詩卷浩千萬，斗大室難著。", "往哉掣巨鰲，肯戀華亭鶴。"]'),
('60f4ca1d-12ca-448a-8df9-0de201cf2438','答野渡墊賓并其子和篇','衛宗武','宋','宋诗','song-poetry','','[]','唐人尚五言，秀句推柳塘。',240,'全唐诗/poet.song.218000.json','["唐人尚五言，秀句推柳塘。", "復有善鳴者，鷄鳴傳遠商。", "氏名幾百載，郁若蘭芷香。", "詩來破餘暑，如挹風露凉。", "芬敷富辭藻，鮮碧逾叢篁。", "鋪張几案間，蔚爲前修光。", "讀之律呂諧，擊拊鳥聲鏘。", "可踵翰林白，未遜太史黄。", "東屏斯文主，書傳撐滿腸。", "固宜蘇門客，而有晁與張。", "豈但如昔人，風雅能補亡。", "胸中千萬篇，浩若五穀穰。", "况復有小坡，氣習遺膏粱。", "書林惟日涉，藝圃無時荒。", "內有芳潤融，外蔑聲色戕。", "篇章雖後至，巖菊擅晚芳。", "又類秋芙蕖，水鏡臨夕陽。", "顧惟糠粃揚，凜負荆棘芒。", "嘆予以詩隠，貨藥猶韓康。", "何時天朗清，共泛蘭亭觴。"]'),
('d00ddee5-922d-448c-939c-68d0aab49a0c','贈白湛囦','衛宗武','宋','宋诗','song-poetry','','[]','老窮蟄一室，獨與聖賢對。',168,'全唐诗/poet.song.218000.json','["老窮蟄一室，獨與聖賢對。", "禰刺倏在前，喜有佳士至。", "此客可曾有，良覿今乃遂。", "夫豈燥濕同，未易折柬致。", "鄉鄰道不謀，咫尺楚越異。", "張范志苟合，千里盟弗背。", "蟠木何假容，猗蘭蓋仝味。", "吟詠浩篇章，口誦卷壓几。", "湛然珠在淵，晨夜光明媚。", "譜接唐人傳，句與唐人儷。", "滿貯風月襟，迥絕煙火氣。", "筆下戲羣鴻，尤跨虞薛輩。", "樂哉得新交，風期從此契。", "張鼓於越門，聊爲歲月記。"]'),
('5f740b13-075f-48f5-8506-ab027144bfb5','即席贈太陽山極圓上人','衛宗武','宋','宋诗','song-poetry','','[]','招提幾百載，其來自唐室。',156,'全唐诗/poet.song.218000.json','["招提幾百載，其來自唐室。", "屢此繫扁舟，過門不暇入。", "豈圖今之行，招携敘舊室。", "遂停欲歸櫂，重整倦遊屐。", "粵昔有高僧，斯地曾卓錫。", "湛然一方泉，千歲停寒碧。", "古殿倚太陽，佛光含慧日。", "巍巍屋上峰，森森庭下杓。", "禪房窈且深，竹樹尤靜密。", "開尊具濁饌，領客日至夕。", "久要亦所難，此意豈易得。", "探囊出詩章，往往名勝筆。", "誦詩所以名，極圓而圓極。"]'),
('744b6d28-436c-4160-b6e6-e36764dcd493','錦山自杭來詩呈鄉曲共舉月集','衛宗武','宋','宋诗','song-poetry','','[]','歲月易以邁，羲娥不停旋。',276,'全唐诗/poet.song.218000.json','["歲月易以邁，羲娥不停旋。", "憶昔聚嬉戲，縞髮今盈顛。", "日往而月來，壯逝老至焉。", "交情貴浹洽，良辰忍棄捐。", "簪舄要時集，尊俎宜相先。", "聞風益所無，議論攻其偏。", "急難援心勇，友助勞斯宣。", "里閭皆吾與，疾苦毋吝言。", "惠利苟可及，念勿遺顛連。", "杜門惟獨善，此見恐未然。", "良朋去七載，歸錦榮山川。", "盟鷗思海上，訪鶴來雲邊。", "胸中五千卷，筆下琳琅篇。", "尤當會以文，雅好庶不愆。", "真率月有集，舊典猶可沿。", "洛社多尚齒，尚齒則未便。", "何如倣修禊，少長無拘攣。", "光風獵獵長，萬象皆暄妍。", "四時有佳致，陵谷縱變遷。", "山巔或水際，竹下并花前。", "高吟吐風月，逸氣噓雲烟。", "煩襟可洗除，芳景宜留連。", "毋徒嗟百罹，一笑觴互傳。"]'),
('b111ade1-0701-4748-836d-b2a646658362','贈龍虎山甘道士','衛宗武','宋','宋诗','song-poetry','','[]','袖携尺素書，遠從上清至。',48,'全唐诗/poet.song.218000.json','["袖携尺素書，遠從上清至。", "胸涵龍虎象，語带煙霞氣。", "千古夔牙音，指下發其秘。", "爲鼓桃源行，桃源何處是。"]'),
('92bc4cc8-771f-4ae9-bb2f-cb7df694062a','和南塘貽林丹巖古風時丹巖館郊外','衛宗武','宋','宋诗','song-poetry','','[]','丹巖今良士，南塘古當時。',156,'全唐诗/poet.song.218000.json','["丹巖今良士，南塘古當時。", "館餐未有適，義圖以助之。", "渠渠推轂心，終莫副所思。", "遇合各有緣，天只非人爲。", "裴回明月枝，乃在海一涯。", "一字以拔人，我慚蔡子尼。", "遂使文字交，遠邁爲人師。", "騷壇不可即，比興安所施。", "唱酬懷舊章，絢若辭藻摛。", "細玩二君詠，形神坐欲馳。", "蹤跡有聚散，情意無盈虧。", "非晚即簪盍，寧久成訣離。", "停雲思親友，且和淵明詩。"]'),
('f64f9338-c29a-466a-8bc0-3359c660441b','夜坐待月次日補吟','衛宗武','宋','宋诗','song-poetry','','[]','瑶壇禮碧虛，返次羽人坐。',144,'全唐诗/poet.song.218000.json','["瑶壇禮碧虛，返次羽人坐。", "引脰延月華，吞吐隔翠嶞。", "衆吻盼流芳，冉冉忽透過。", "大規雖微虧，猶喜鏡未破。", "浮翳從何來，掩蔽仍不果。", "連巒一色浄，清輝千里播。", "爽塏入襟裾，光明生咳唾。", "詩翁於此時，枯腸正無奈。", "愧乏雲錦章，翻然乃高卧。", "斯辰悵有懷，無語坐偷墮。", "今夕冰輪升，不吟則不可。", "預解素娥嘲，免謂翁負我。"]'),
('cb58cf6e-a054-481c-a124-4e6945ed57c2','再用韻答和者','衛宗武','宋','宋诗','song-poetry','','[]','依山構靖廬，雖陋亦可坐。',144,'全唐诗/poet.song.218000.json','["依山構靖廬，雖陋亦可坐。", "幽林隔塵囂，邐迤八九嶞。", "時來友高士，一歲知幾過。", "野花薰醉醒，山鳥啼夢破。", "何莫匪真詮，豈爲崇小果。", "頗喜仙侶稠，可使玄風播。", "道腴足雋永，世味等涕唾。", "谷神儻不死，造物何能奈。", "多君從我游，白雲肯分卧。", "第嗟屋宅壞，殆類甑已墮。", "內煉悵莫成，服食其或可。", "伯陽丹鼎餘，刀圭分贈我。"]'),
('af417b95-8efe-410c-aeca-a20d0a93130c','慰張石山幼子亡','衛宗武','宋','宋诗','song-poetry','','[]','無子雖可悲，有子未爲喜。',144,'全唐诗/poet.song.218000.json','["無子雖可悲，有子未爲喜。", "斷以釋子言，莫非假合耳。", "杜陵詠爲麟，瑞物能有幾。", "昌黎謂之梟，惡德乃類是。", "無之恐無後，有之亦爲累。", "苟非弗克肖，曷若聽其逝。", "顔路之亡回，宣尼之喪鯉。", "此皆長而賢，痛甚于幼死。", "夷甫雖嘗云，情鍾在我輩。", "過哀亦奚爲，安有復生理。", "子夏空失明，季札號知禮。", "吾友方盛年，何憂乏良嗣。"]'),
('43f1f8c9-6f53-41c8-8470-17e2dc3e0706','和友人新陽韻','衛宗武','宋','宋诗','song-poetry','','[]','生機天地寧終藏，剝極復反開新陽。',128,'全唐诗/poet.song.218000.json','["生機天地寧終藏，剝極復反開新陽。", "陽明漸進陰濁散，輝光萬象熏佳祥。", "不必晷驗度合表，不必風問來何方。", "朝廷有道雨暘若，滿家五穀歌穰穰。", "占年梅映臘雪瑞，回暖柳拂春晝長。", "願君多送錦繡句，爲我一洗冰炭腸。", "陽春一曲和蓋寡，媿我蕪陋匪報章。", "獨思愁嘆接田里，安得擊壤衢遊康。"]'),
('b23923ec-867f-4d8b-9a79-bb533c24257d','爲徐進士天隠賦辟穀長吟','衛宗武','宋','宋诗','song-poetry','','[]','物盈宇宙皆有窮，一氣先天常浩浩。',368,'全唐诗/poet.song.218000.json','["物盈宇宙皆有窮，一氣先天常浩浩。", "榮華富貴能幾何，百歲光陰如電掃。", "開闢由來莫幾年，聖哲英雄骨俱槁。", "勳名蓋世文瑞時，豈若玄玄窮徼妙。", "古仙率多山澤癯，方平通經後從老。", "伯陽隠士著參同，援述宣尼辭可考。", "人身口腹乃大患，舉世凡夫爲此惱。", "厚味腊毒尤傷生，甘旨肥醴偏害道。", "學仙萬慮要屏除，有累俱爲方寸擾。", "希夷辟穀功始成，抱朴休糧法宜效。", "所以丹丘諸羽人，莫不餐松茹靈草。", "誰云不食胃徒空，入道門衢此爲要。", "天隠良士工詞章，經傳百家仍探討。", "孰知抗志乃松喬，濁利浮榮非所好。", "年當强仕舍壯圖，勇辭館餐棲窈窱。", "欲仁仁至天所資，道藏仙方過鴻寶。", "衛生有藥可忘饑，不愁煮字那能飽。", "一從易置冰玉腸，不假青精顔色好。", "會驅乾馬及坤牛，捕虎擒龍歸鼎竈。", "易骨洗髓由此基，三島十洲輕可到。", "縱未能嘗方朔桃，亦須先致安期棗。", "世儒悉被客塵迷，志在衣錦而食稻。", "惟君高蹈出凡流，見謂秋陽同皜皜。"]'),
('558ed8bf-93c8-4fe4-915d-5ea2efba45e9','和野渡賦雙竹松梅古風','衛宗武','宋','宋诗','song-poetry','','[]','挺然昂霄蟠澗阿，彼美松者非凡槎。',292,'全唐诗/poet.song.218000.json','["挺然昂霄蟠澗阿，彼美松者非凡槎。", "千林摇落乃孤秀，舞春楊柳徒傞傞。", "翛然照水溪一涯，彼美梅者非凡葩。", "冰姿皎潔抱清獨，漫山桃李徒繁華。", "昔人品題信不苟，每以此木配此花。", "伊誰挈置小盆盎，高標盤曲良可嗟。", "然雖矯揉失真性，幽香貞色仍堪誇。", "况分瑞竹與鼎立，歲寒之侶何以加。", "竹尤挺特過二者，逸鞭吐秀如蘭芽。", "兩枝撐出露頭角，一類襁褓髻未丫。", "於中此更拔其萃，似覺小異如孟嘉。", "會從尺寸達尋丈，摩拂穹漢生雲霞。", "可親雅與書帙稱，相對慎勿肉食奢。", "君之取友莫此尚，此友寧久留君家。", "須知調鼎待佳實，豈但水影誇橫斜。", "須知大才作隆棟，豈但古幹森虬蛇。", "虛心勁節豈無用，寧在楚楚儀容佳。", "爲龍致雨行矣神，變化轟雷掣電與世驅姦邪。"]'),
('3b95c610-3364-4a01-ad1a-6539ad38ca22','與卿寓登多景樓口占立成','衛宗武','宋','宋诗','song-poetry','','[]','世稱斯樓天下奇，雨餘振履此遊適。',128,'全唐诗/poet.song.218000.json','["世稱斯樓天下奇，雨餘振履此遊適。", "埋頭旅舍氣弗蘇，一見端能洗湮鬰。", "連岡三面作襟袖，洪流千里在履舄。", "俯窺萬井若棋布，前閲千帆似梭擲。", "銀濤湧出丹碧居，金焦兩山相對立。", "羣陰解駮宿靄收，放出脩眉數峰碧。", "景名多景名不虛，似此江山何處覓。", "凭欄一笑問波神，欲舉歸帆在何日。"]'),
('de7684b8-45eb-49ff-97c4-4f27824cc52f','和張石山古風約郊行','衛宗武','宋','宋诗','song-poetry','','[]','乾坤空闊幾由旬，仁氣坱圠熏爲春。',224,'全唐诗/poet.song.218000.json','["乾坤空闊幾由旬，仁氣坱圠熏爲春。", "郊原萬象列綺繡，華哉規令方施行。", "舊年與花嘗有約，肯倦携筇并躡屩。", "近來時事與花違，一任自開還自落。", "此時何地可維舟，難效山陰禊事修。", "醉吟有樣猶可法，隨處可留無不留。", "欲縱清遊先蠟屐，剩擬一造芝蘭室。", "料應紅紫尚餘芳，但媿平章無健筆。", "折簡支郎盟在前，期弔野王今幾年。", "或行或止若有制，人不自由殊可憐。", "轉頭點點飛紅雨，美景良辰那忍負。", "大篇短牘重招邀，起往從之其敢後。", "但嗟戴笠與乘車，昔騎紫馬今無馿。", "榮華消歇與春盡，寵辱不動心如如。"]'),
('482e3321-163f-4d91-a2ec-5429e5875f8f','和野渡爲青溪賦','衛宗武','宋','宋诗','song-poetry','','[]','好士不論親與疎，絕甘分少寧求餘。',256,'全唐诗/poet.song.218000.json','["好士不論親與疎，絕甘分少寧求餘。", "孔程一見便傾盖，懽如故舊其非歟。", "世多奇俊無南北，平昔可曾致佳客。", "吾鄉良友無出君，二仲之交猶欠一。", "青溪人瑞名聞揚，劍氣上射牛斗光。", "淋漓筆下走風雨，其勢浩浩聲浪浪。", "雙鵠俱堪儕野鶴，宜與翺翔天地廓。", "一爲羈羽一仝巢，羈者飛來慰寥寞。", "人生遇合天實爲，遠方朋來從爾思。", "但親益友非損友，何間新知與舊知。", "吾儕氣臭在投合，有來館粲須延納。", "不妨北海常開樽，豈但休源乃施榻。", "我家有竹門可款，植此不徒悅俗眼。", "批風抹月待嘉賓，絕勝肉食供朝晚。", "嵇呂交情雖似漆，千里相遇難再得。", "何如耆俊里社仝，時得親薰才學識。"]'),
('694765d7-3797-4a54-9f16-ca3b27502207','鶑花吟爲良友作','衛宗武','宋','宋诗','song-poetry','','[]','羽族競繁聲，倉庚尤善鳴。',192,'全唐诗/poet.song.218000.json','["羽族競繁聲，倉庚尤善鳴。", "喧啾百喙忽奏雅，盡洗盈耳箏竽音。", "芬菲芳事畢，木芍藥晚出。", "於中姚魏更傾城，掃退目前頳紫色。", "轉眼韶華便欲休，恨無長繩繫春留。", "一春嫵媚在花鳥，常恐易逐光陰流。", "浮蕩誰家挾彈子，飛丸巧中俄摧翅。", "封姨底事苦禁持，飄摇欲使無完蔕。", "可嗟凡卉與凡禽，遂情快意何紛紛。", "不思物惡傷其類，爾形爾氣非同羣。", "歲購名葩不常遇，日聽好音能幾度。", "寄與東君力遮護，勿使凋零同臭腐，不然辜負鶑花主。"]'),
('1940014a-49c1-46d5-b238-c87e187b1003','爲徐太初友人陳府判賦梅居餞行','衛宗武','宋','宋诗','song-poetry','','[]','青鞋不踏孤山路，辜負逋花今幾度。',128,'全唐诗/poet.song.218000.json','["青鞋不踏孤山路，辜負逋花今幾度。", "那知別有姑射居，衆謂孤山未必如。", "夙昔名傳尤願見，渴想此仙難覿面。", "朋來滿口譽風神，儼若眼底逢佳人。", "枝間獨具先天易，惟有太初心默識。", "雅遊擬問古航船，索笑相親須有緣。", "閒中積歲玩風月，虐甚祁寒飽霜雪。", "此往春浮雨露香，歸來萬玉爭輝光。"]'),
('1ef60f7c-2930-450a-a35e-1fdc4564bcab','墓松既夷所餘無幾方植松秧自賦','衛宗武','宋','宋诗','song-poetry','','[]','重來丙舍歲三易，翠巘插空仍兀突。',176,'全唐诗/poet.song.218000.json','["重來丙舍歲三易，翠巘插空仍兀突。", "喬林鬰蓊殲斧斨，一二僅存於百億。", "參差歷落更孤秀，不假依憑而挺立。", "宛如九老瑞唐朝，又類耆英隆宋室。", "合茲異代衆君子，仙去一朝於此集。", "千夫束手何敢向，萬牛回首難容力。", "已芟嘉植勿復論，壽此佺期不朽骨。", "稚松匝地散新秧，頭角森森紛羽翼。", "他年雨露飽沾濡，滿鼻珠璣香習習。", "會須百尺長龍身，仍復層林森鳳翼。", "作詩聊記角弓章，子子孫孫永培植。"]'),
('89b035cb-320b-4ed6-8467-7fbdea82e433','和南塘詠梅','衛宗武','宋','宋诗','song-poetry','','[]','剝極大冶如死灰，潛陽初動生意回。',160,'全唐诗/poet.song.218000.json','["剝極大冶如死灰，潛陽初動生意回。", "沖融一脉貫萬彙，物有清氣拂斗魁。", "嘉植幾世培其栽，孤芳欲折猶裴回。", "此花消得酒百杯，料君恥與紅紫偎。", "祇應兩屐磨蒼苔，豪飲豈惜玉山頹。", "醉中兩手敲復推，句成不假擊鉢催。", "青皇襟量何恢恢，任教殘臘偷春來。", "暗香明艷無纖埃，俯視衆植爲陪臺。", "紛紛盆盎見古罍，千花錦繡徒成堆。", "天然不假冰玉裁，歲歲爲渠青眼開。"]'),
('704ca3b3-17bb-49af-9910-1a8937d0a484','過瓜洲','衛宗武','宋','宋诗','song-poetry','','[]','偉哉千里萬里流，衮衮其來自巴蜀。',256,'全唐诗/poet.song.218000.json','["偉哉千里萬里流，衮衮其來自巴蜀。", "奔騰澎湃入尾閭，勢雄何啻吞百谷。", "金焦對峙兩鰲浮，千頃玻瓈浸其足。", "光生金碧殿閣湧，氣蒸紫翠林叢沃。", "附庸更有小陂陀，東晉詩仙卧其麓。", "穹龜長蛇簸風雨，鬼怪神奇不可觸。", "地靈設險莫此如，此天所以限南北。", "江山終古無變遷，世運如輸幾翻覆。", "英雄滅沒去不反，人事紛輪轉相續。", "嗟予蟄處幾二紀，殆類龜藏蝸局縮。", "茲來雲夢氣可吞，浩蕩乾坤在吾目。", "靴紋獵獵日流輝，鬟黛葱葱雨初沐。", "沙禽雲鳥自往來，浪舶風帆互征逐。", "野芳零落舞殘紅，汀草蒙茸漲平綠。", "爛然宇宙一丹青，絕勝鵝溪千畫幅。", "歸舟那得大如川，載取江頭春萬斛。"]'),
('3a095f9b-009a-4c2e-ae02-c08fb3e8c8c7','和陸象翁以梅配竹','衛宗武','宋','宋诗','song-poetry','','[]','駢頭始生爲籜龍，森然而立列羣玉。',288,'全唐诗/poet.song.218000.json','["駢頭始生爲籜龍，森然而立列羣玉。", "琮琤有韻天籟鳴，蓊鬰成陰雲氣簇。", "楚楚少年來自河，猗猗君子瞻彼澳。", "其實曾致雛鵷來，其枝可留棲鳳宿。", "月香水影猶更奇，彈壓春花千萬屬。", "羞爲西子事塗抹，喜作道韞淡粧束。", "不居驛路即溪橋，好傍巖腰與山腹。", "謂宜作妃以相從，雅韵幽姿俱不俗。", "此君何以待美人，翠帷重重富羅縠。", "美人何以奉此君，碎玉明珠不論斛。", "於中更有無價香，迥勝龍涎與麝馥。", "此君挺特氣不凡，美人窈窕姿尤淑。", "執柯者友秦大夫，不煩月老繩紆足。", "且善爲醪以合歡，味過蒲萄及醽醁。", "梅之所見乃不然，謂恐爲人所指目。", "從來潔白不可溷，每鄙仙人華萼綠。", "彼固無慊爲丈夫，予寧屈體而雌伏。", "不如仍作歲寒交，永爲貞女甘幽獨。"]'),
('c6fc15ae-c6a9-4c50-a47f-a2a17d98aa17','自王園歸約諸友山行','衛宗武','宋','宋诗','song-poetry','','[]','天不憐我老且貧，荒逕不可酬華春。',176,'全唐诗/poet.song.218000.json','["天不憐我老且貧，荒逕不可酬華春。", "遂令東里互邀致，借之雙圃娛芳辰。", "癡雲釀雨雨旋止，霽日含輝更清美。", "花間盡晷得盤桓，但費東君爲料理。", "歸來未久簷溜傾，乃信造物真有情。", "十分淑景一分在，但願從此天開明。", "一方一曲春有限，芳菲未足舒老眼。", "扁舟遠欲逐清華，錦繡山川窮勝賞。", "維此林巒地雖窄，聳秀流芳亦不惡。", "安得良友相追隨，步屧生香徧行樂。", "只恐囊無賀老詩，不愁屐費阮生蠟。"]'),
('24a73187-4700-47d3-859d-fedea7f8dfa0','五雲詩','衛宗武','宋','宋诗','song-poetry','','[]','千巖萬壑東南美，中有一山尤秀偉。',160,'全唐诗/poet.song.218000.json','["千巖萬壑東南美，中有一山尤秀偉。", "伊誰衣被以佳名，非霧非烟騰瑞氣。", "有人於此曾課書，出山能士爲寫圖。", "風林泉石振清響，佔畢吟誦聲難模。", "聚爲胸中綫五色，不補衣裳華衮黻。", "迺作江湖漫浪遊，奮藻揚葩肆吟筆。", "文爲人瑞要瑞時，時不與我文奚爲。", "何如抱書還舊隠，姑頌楚橘歌商芝。", "吾衰一字不解作，平生學殖嘆荒落。", "爲儒無用擬修玄，徒想仙人五雲宅。"]'),
('07c16af6-a2da-4fd6-989b-ac07e9315c10','春歸','衛宗武','宋','宋诗','song-poetry','','[]','紅飛綠膩晴晝遲，木香滿架柔條披。',96,'全唐诗/poet.song.218000.json','["紅飛綠膩晴晝遲，木香滿架柔條披。", "芳菲過眼能幾日，娛樂常少多憂悲。", "東君歸計何太早，四序光陰如電掃。", "今年花謝復明年，祇使看花人易老。", "蕭然白髮朱顔蒼，競春肯學兒童狂。", "不如坐對歲寒木，清談與客窮書囊。"]'),
('498e9237-5ea5-4937-8b78-b0951285989e','送龍孝梅過上海及見郊外巨室','衛宗武','宋','宋诗','song-poetry','','[]','宇宙清淑物絜齊，春工告成青帝歸。',176,'全唐诗/poet.song.218000.json','["宇宙清淑物絜齊，春工告成青帝歸。", "雲縫霧織翠萬幄，尤勝紅紫芳菲菲。", "高人出郊窮遠目，一童兩屐隨所之。", "五茸三泖在指顧，收攬萬象歸詩脾。", "袖中三尺貫牛斗，劍光到處神魂悲。", "肘間更有不傳妙，禍福隠奧能前知。", "高門懸薄奚待往，候迎紫氣爭先馳。", "此行直須訪海若，揮斥物怪搜珍奇。", "連鰲自可赤手取，何用釣犗五十爲。", "十洲三島不難到，御風騎氣從安期。", "願君斯遊姑少遲，爲我六月開南枝。"]'),
('d1409c88-9b28-4021-9e21-3f40e9bc80da','和唐人惜花韵','衛宗武','宋','宋诗','song-poetry','','[]','一年最是花時好，花開莫待鶑呼老。',64,'全唐诗/poet.song.218000.json','["一年最是花時好，花開莫待鶑呼老。", "有酒對花勿草草，清唱美人眉淡掃。", "一觴一詠要相當，櫂船喚取黄頭郎。", "川原紅紫相低昂，載取十里春風香。"]'),
('f0ae8628-29e9-43cf-9976-3346fab9f74f','新暑賦西軒竹','衛宗武','宋','宋诗','song-poetry','','[]','此君與我同襟期，延致屋宅西南維。',288,'全唐诗/poet.song.218000.json','["此君與我同襟期，延致屋宅西南維。", "涵濡雨露歲未半，柯葉深茂華而滋。", "恍疑神士萃庭宇，旌𣄛羽蓋紛交馳。", "非箏非竽發天籟，不湍不瀨含風漪。", "綠光到眼冰雪潑，頓令六月無炎威。", "何須挹爽置象簟，不假去熱施龍皮。", "挺然直節異凡植，四時不改琳瑯姿。", "翛然雅致滌萬慮，一塵不染珊瑚枝。", "明蟾寫真銀散彩，騰烏弄影金流輝。", "千林剝落氣愈勁，更好雪壓并霜欹。", "無山無水自幽勝，雨天霽景俱相宜。", "方嗟此地翳草莽，幻出臭腐爲神奇。", "恨無與可圖作幛，消得坡老模成詩。", "中虛而靜有隠德，妙氣獨有予心知。", "年今七十諸妄屏，久壓花本芳菲菲。", "締交惟汝與松杓，嘯風吟月相追隨。", "願言棲鳳同作伴，慎勿化龍隨所之。", "武公勳業我所媿，猶覬老壽幾耆頤。"]'),
('febbb5dd-5609-4673-b530-c836a96a77ba','次韻憫雨','衛宗武','宋','宋诗','song-poetry','','[]','百穀仰雨而蕃滋，乃穎乃苞乃成實。',224,'全唐诗/poet.song.218000.json','["百穀仰雨而蕃滋，乃穎乃苞乃成實。", "鍤雲方喜高下齊，大田俄報東南坼。", "民窮至此噫亦甚，無年餓死其無日。", "佛靈猶未致涓流，人力焉能施寸尺。", "况當十室九室空，可堪百里千里赤。", "仰天無路扣彼蒼，望雲自旦尋至黑。", "一歲不稔百沴生，所憂豈止人艱食。", "聲嗟氣歎方載途，屈莫求伸枉莫直。", "繇來有感則有應，影響一機端可必。", "時遷事改理不移，今日天工豈殊昔。", "烹羊乃雨古語云，何假雷師起河伯。", "調元贊化更有人，怪魃螟蝝俱蟄跡。", "人心既悅天意從，利澤須能致甘澤。", "油然沛然苗勃興，奚用象龍施五色。"]'),
('a918ebb3-8043-4d35-9221-0d338a51b943','賦竹深處','衛宗武','宋','宋诗','song-poetry','','[]','淇園既往不足論，渭川徒多未足貴。',176,'全唐诗/poet.song.218000.json','["淇園既往不足論，渭川徒多未足貴。", "森然玉立闢幽深，彌望恢恢有餘地。", "何異東亭手親植，遂使南陽日清閟。", "綠雲障日間弗容，翠濤翻空杳無涘。", "冥冥韓林靜而秀，窈窈蔣逕深且邃。", "洗清袢暑迥莫留，截斷俗塵飛不至。", "何須層冰置几案，自然凉氣生衣袂。", "吟弄風月騷人徒，伯季松梅歲寒味。", "於斯二仲可論交，誰爲六逸宜邀致。", "何時徒步許直造，著我其間同一醉。", "祇恐君疑庾亮來，角巾豈免還私第。"]'),
('1fabfaa2-d174-4fbc-a1b1-8bdad54c65c5','宣妙墳院古柏','衛宗武','宋','宋诗','song-poetry','','[]','古來喬木産墓宅，新甫之儔匪凡質。',192,'全唐诗/poet.song.218000.json','["古來喬木産墓宅，新甫之儔匪凡質。", "風梳雨沐三百年，聳壑昂霄過千尺。", "孤標屹立獨擎天，繁柯偏重常傾日。", "蒼皮剝落節理堅，挺挺長虬初蛻骨。", "我來屢見此崛奇，摩挲老眼增雙碧。", "吁嗟松檟幾遷易，拱者芟夷新者茁。", "青青惟此貫四時，物換人非飽更歷。", "栽培意有天地根，不然守護資神物。", "須知碩果不徒存，天佑吾宗當默識。", "公侯復始此其符，衮衮人英須輩出。", "偉才未許萬牛挽，香葉擬留孤鳳集。", "千秋要與此山存，世世宗盟共封植。"]'),
('482fb365-656f-409a-9663-2cdcf90a7bb2','和新篁韻','衛宗武','宋','宋诗','song-poetry','','[]','竹君清絕潤於玉，譜牒出自淇之澳。',172,'全唐诗/poet.song.218000.json','["竹君清絕潤於玉，譜牒出自淇之澳。", "移根分種置吾廬，纔隔樊牆即家塾。", "塾之所有無非書，師友摛文剪其蕪。", "此君兒郎趣亦雅，駢頭相過紛鋪舒。", "鮮鮮綠色照鄴架，駸駸宗祖可方駕。", "鈎章題品得騷翁，倍使新篁長光價。", "矛甲鏦鏦看擊雲，未遜六千君子軍。", "琅玕一一如椽大，此中更有風月存。", "巨細何異公領孫，低昂尤若主承賓。", "有賓如君誠可人，西窗六月暑如焚。", "會見爲君滌除熱惱來凉薰。"]'),
('1d44b479-eba1-40d0-9dc1-21818d3babfc','墳院新篁  其一','衛宗武','宋','宋诗','song-poetry','','[]','琅玕挺秀徑尺盈，森森直上摩蒼冥。',160,'全唐诗/poet.song.218000.json','["琅玕挺秀徑尺盈，森森直上摩蒼冥。", "封培保護猶重器，歲餘二十林方成。", "繩繩孫子更傑出，遠過鼻祖尤輪囷。", "蔚然翠羽漸成葆，稚者碧玉初抽簪。", "泥塗甫見露頭角，意氣已欲生風雲。", "繁枝會致鳳棲止，修幹能作龍飛騰。", "我來其下避新暑，洒若澗壑涵層冰。", "清高直亮異凡種，願言世與山長青。", "綠漪豈但爲目玩，於焉觀德知修身。", "吾宗叡聖所宜法，如圭如璧揚休聲。"]'),
('bd68a642-9aad-4d01-9f92-7c5678efff51','墳院新篁  其二','衛宗武','宋','宋诗','song-poetry','','[]','世更日月幾昃盈，依然有谷中窈冥。',160,'全唐诗/poet.song.218000.json','["世更日月幾昃盈，依然有谷中窈冥。", "脩筠夾道互經緯，宛如一機翠織成。", "非繇培植得攬玩，何異不稼而有囷。", "籜龍个个出頭角，密者櫛比疎猶簪。", "嬋娟色媚已映月，團欒氣合行屯雲。", "雨餘尋丈忽聳拔，其上速若鳶肩騰。", "中邊別種相間簉，又類潤玉陪清冰。", "我將於此事著述，編摩自足供殺青。", "此君時對吐秀句，榆境亦不孤閒身。", "涼床滑簟午睡足，坐聽雅奏來風聲。"]'),
('57276565-b5a6-4e47-bc85-428c110fd1ed','夏秋積雨歲用大祲長言紀實','衛宗武','宋','宋诗','song-poetry','','[]','四月五月淫澇積，噬嚙丘垤吞原隰。',384,'全唐诗/poet.song.218000.json','["四月五月淫澇積，噬嚙丘垤吞原隰。", "匪惟爲沼蕩爲陂，萬頃秧雲泯無跡。", "攢鴉聯尾空飛翻，化鰲爲城難障塞。", "五湖三泖欲貫通，浪接重江勢洄潏。", "茅茨比屋何可存，穀麥千金不論直。", "懦夫全室葬魚腹，强者呼儔作蟊賊。", "閉糴成風牢莫回，勸分有令徒無益。", "間存壠畝護餘苗，曾不什一于千百。", "旱赤堅栗刈未齊，晚紅䆉稏苞欲實。", "饑農競喜新穀收，一飽充腸云可必。", "夫何八月天瓢傾，其來震蕩而飄忽。", "勢如陣馬奔不停，銀溜浪浪欲穿石。", "直疑羣龍翻九河，小山摇撼大山兀。", "須臾泛溢滿中庭，平地如淵深計尺。", "明朝清野變白波，浩浩湯湯彌甚昔。", "積陰爲冷不堪收，殆類鴻濛未開闢。", "又如歷代政昏蒙，熏如宇宙成幽墨。", "飈旋霧塞晝冥冥，常俾蒼生氣湮鬰。", "簷間點滴無時乾，猶幸滂沱間霂霢。", "登場惟苦禾耳生，棲畝尚有禾頭出。", "深虞衮衮傾盆來，已壞垂成俱滅沒。", "大家蓋藏悉已空，猶恐有司徵斂急。", "若使租無斗斛收，卒歲輸官何自給。", "貧家薪桂米逾珠，待哺嗸嗸併日食。"]'),
('1a5bc281-d546-4e9b-b080-254f8ec0ac50','立秋喜雨','衛宗武','宋','宋诗','song-poetry','','[]','炎炎老火燒太空，熏灼萬類勢欲鎔。',240,'全唐诗/poet.song.218000.json','["炎炎老火燒太空，熏灼萬類勢欲鎔。", "高田幅裂稼已腐，低壤釜沸禾生蟲。", "金蛇飛走天鼓震，須臾散滅茫無蹤。", "火輪烈烈揚熾焰，夜鏡炯炯摩青銅。", "老夫望歲甚田叟，恨無神術驅羣龍。", "平明披衣視雲氣，霧靄四合何冥濛。", "沾濡俄頃遂滂沛，奔騰浩瀚猶崩洪。", "雨珠雨玉何足貴，雨菽雨粟亦有窮。", "涓流膏潤入秉穗，穰穰九穀苞其中。", "良疇何啻萬萬頃，一稔囷櫛過崇墉。", "溢爲懽聲沸比屋，洗空愁嘆蘇三農。", "亦知誠感斯響答，古佛之一真圓通。", "嗟吾年來生計蕩，殆若枯葉隨飄風。", "甌窶汙邪不應禱，凍餓真與窮民同。", "繼今甘霔願時有，鼓腹擊壤歌年豐。"]'),
('7a2f0478-da6b-42c1-9379-c1a34b1bbf3f','用韻再作','衛宗武','宋','宋诗','song-poetry','','[]','一氣運行於虛空，有形孰不歸陶鎔。',240,'全唐诗/poet.song.218000.json','["一氣運行於虛空，有形孰不歸陶鎔。", "燠寒燥濕互爲用，功被草木并昆蟲。", "胡然陽亢乃作沴，豐隆屏翳俱潛蹤。", "炎炎赫赫勢太甚，烹煎萬有何殊銅。", "田疇龜坼河港斷，水車不運骨掛龍。", "俄驚片雲變反掌，宇宙未剖猶鴻濛。", "初如綫溜氣纔應，繼若瓴建聲何洪。", "豈徒神力能致此，意者高厚悲人窮。", "豐凶由數亦匪數，厥有造化行其中。", "年來五穀亦狼戾，曾孫之庾高於墉。", "祇今戶戶嘆赤立，富者恨不爲耕農。", "要知千人萬人心，心心默與天相通。", "熙熙田畯爭薦喜，烹葵剝棗追豳風。", "更看十月場圃築，黄雞白酒村村同。", "但祈田祖去螟螣，願如荆叟歌元豐。"]'),
('136ea35c-0818-42b3-9615-6b885ea5c30f','賡南塘桂吟','衛宗武','宋','宋诗','song-poetry','','[]','卉木摇落如齒牙，紅紫凈盡無浮花。',212,'全唐诗/poet.song.218000.json','["卉木摇落如齒牙，紅紫凈盡無浮花。", "秋芳俄從天上至，人世有香誰敢誇。", "纍纍金粟疊爲蕊，風韵別自成一家。", "葱葱綠玉不改色，歲寒氣節何以加。", "滋榮豈但壓衆植，纖巧直可凌春華。", "一枝纔折聞四表，芬敷發達其無涯。", "看花花好時亦好，到眼不覺忘聲嗟。", "君家喬木知幾載，世世封植今彌嘉。", "來章璀璨耀珠璧，行墨遒勁飛龍蛇。", "我營小圃富靈種，丹犀列樹尤豪奢。", "虛堂中夜忽生白，扶疎清影來窗紗。", "世間萬事等塵土，何苦閉縮如藏蝸。", "只今有酒爛醉廣寒下，但恨無鼓可作漁陽撾。"]'),
('9d916f1a-d40b-4b1c-9d21-75386328bdaa','壽南塘八月生朝','衛宗武','宋','宋诗','song-poetry','','[]','一年最好八月月，此月迥與尋常別。',288,'全唐诗/poet.song.218000.json','["一年最好八月月，此月迥與尋常別。", "君於厥月乃誕彌，天一之精所凝結。", "涵精毓秀宜不凡，神如秋水膚如雪。", "蜚英騰茂載宦途，所至光明而煒曄。", "一簾瑩徹照今古，妙凝夜氣冰霜潔。", "芬芳滿腹貯天香，吐出篇章更奇絕。", "所存者厚養者深，晚歲丰姿尤發越。", "不知何物敢相干，屢月光華似消歇。", "直疑蒼狗互掩蔽，恨無長軀可手抉。", "又類妖蟇初啗餠，恨無利劍可殲厥。", "一朝天爲掃妖邪，銀輪爛爛仍高揭。", "久嗟湮晦忽清明，儼若身居廣寒闕。", "相將誕節紀祥弧，連夕金波倍澄澈。", "誰云弦望有盈虧，須知本體原無缺。", "滿堂子女競稱觴，比似常年更懽悅。", "月中自有藥長生，不勞復問長生訣。", "從今夜夜長輝光，年年月月無磨折。", "刀圭無惜惠仝人，使我頹齡起疲苶。"]'),
('092dd794-8274-4c0d-8317-967355e92c92','和吟友月夜遇風雨不見薄蝕韻','衛宗武','宋','宋诗','song-poetry','','[]','麟經紀載浩歲月，天家妖祥互分別。',208,'全唐诗/poet.song.218000.json','["麟經紀載浩歲月，天家妖祥互分別。", "所書薄蝕三十六，獨於黑夜泯無說。", "豈以爲陽義所崇，可略者陰辭遂輟。", "曩年月蝕無風雨，風雨胡爲爲月設。", "三百六旬惟此宵，羞使望舒顔面缺。", "第怪飛廉逞怒號，擺撼廣寒枝欲折。", "海濤助勢捲地來，萬戶千門一時撤。", "天目臲卼秦望摇，奚問區區小丘垤。", "明朝揭日出虞淵，疑是天工手親挈。", "羣陰散駮世清夷，蛟螭那復爲妖孽。", "我欲作詩頌陽明，文思久枯筆屢掣。", "但願合璧常光明，年穀順成風雨節。", "中秋把酒對嫦娥，處處團圓天下悅。"]'),
('c0ef9258-fa95-41c5-95ae-0e35cbfdf4d4','喜晴','衛宗武','宋','宋诗','song-poetry','','[]','朅來古寺當初寒，垂垂凍風不肯乾。',176,'全唐诗/poet.song.218000.json','["朅來古寺當初寒，垂垂凍風不肯乾。", "出門泥滓跬步艱，蟄處無異虬蛇蟠。", "剪花呈瑞天破慳，鑄出八九銀巑岏。", "使居城市那得看，衒耀老眼真奇觀。", "霅然陽明忽開張，俄復飛溜聲潺潺。", "癡雲布濩封乾端，冥濛莫睹雙跳丸。", "噫氣夜號力撼山，平明推上赤玉盤。", "羣陰解駮宇宙寬，草木禽鳥俱懽顔。", "金烏行空振羽翰，揚輝散彩送我還。", "却憐殘蠟猶欠三，日不屢數歲欲殫。", "盈尺爲瑞俄頃間，天公變化應無難。"]'),
('f242a8c6-d213-4e91-badd-3919121a43fd','和催雪','衛宗武','宋','宋诗','song-poetry','','[]','我欲問天天穹窿，歲卜其有於歲終。',288,'全唐诗/poet.song.218000.json','["我欲問天天穹窿，歲卜其有於歲終。", "胡然玄律欲遒盡，燠乎一歲融而沖。", "凍膚未起玉樓粟，寒力尚怯珠槽紅。", "臘前三見瑞盈尺，九土斯農之望同。", "沍寒雖以雲布濩，合影尚欠宵通朧。", "梁園徒聚爲賦客，灞橋更誤能詩翁。", "倩誰剪下銀潢水，六花人代天施工。", "不必作威藉風伯，不必布勢勞豐隆。", "預占多稼滿周畝，首驗小麥連崆峒。", "嘗聞玉妃從者萬，要看羽衛來仙宮。", "未多劉子比西閬，抑陋衛人歌北風。", "撐腸吐出冰雪句，清輝交映彌寒空。", "列岑銀鑄增突兀，千林楮刻森玲瓏。", "瑶芝一望千萬頃，不辨田上田中中。", "憶昔臘霙點予鬚，至今皓首如飛蓬。", "自憐老朽難用世，祇堪把耒勤農功。", "行天須見度有馬，入地庶使潛無螽。", "年豐常願頌秋報，豈止擊壤歌三農。"]'),
('e4b72a02-a265-490a-921b-ebff025d95c8','和雪吟','衛宗武','宋','宋诗','song-poetry','','[]','庖無美炙惟野䔩，爨無積薪用勞軸。',240,'全唐诗/poet.song.218000.json','["庖無美炙惟野䔩，爨無積薪用勞軸。", "夜半烹酒和雪吞，賸喜吾廬銀作屋。", "須臾清氣散入脾，不覺吟肩樓聳玉。", "映書更宜剔魚蠹，擁被那肯作龜縮。", "飽看衮衮來玉塵，搥璧斷圭隨所觸。", "地凝瑞氣盈欲尺，水剪飛霙出猶六。", "化工纖巧妙無倫，春卉秋葩總成僕。", "最欣歲歲爲農祥，散作陽和徧雲谷。", "去年一白兆年豐，幸爲民力舒窮蹙。", "今年將見臘前三，欲爲民生洗荼毒。", "不思金帳飲羊羔，不思朱門厭酒肉。", "目前多幸苟全生，稍得伸眉猶勝哭。", "可憐赤子寒欲僵，生理不遺升斗蓄。", "憂時老杜徒詠嗟，破廬凍死寧令獨。", "閉門猶喜得高眠，絕勝魯公書食粥。"]'),
('5c14d4f0-0ba6-4ff6-92cc-9c31e8e9461c','和家則堂韻贈高教之北','衛宗武','宋','宋诗','song-poetry','','["\u897f\u6e56"]','別時欠折蘇堤柳，西方美人無恙否。',128,'全唐诗/poet.song.218000.json','["別時欠折蘇堤柳，西方美人無恙否。", "子卿齧雪十九年，何似生前一杯酒。", "麒麟胡可係而羈，要使爲祥在郊藪。", "當年誰擅西湖春，公閭遺臭千載後。", "但知金屋醉蛾眉，簸弄威權翻覆手。", "徒勞吉士遠有行，令人驕驕賦維莠。", "君今重整燕薊轅，老子跫然欣得偶。", "殷勤爲我問平安，司馬深衣想如舊。"]'),
('a7d8c0c2-ab9a-44e2-9773-c1fd6f0b1360','贈范道人','衛宗武','宋','宋诗','song-poetry','','[]','黄紙差符不肯留，飄然願逐雲水遊。',128,'全唐诗/poet.song.218000.json','["黄紙差符不肯留，飄然願逐雲水遊。", "紆朱拖紫不肯慕，甘著草衣披布素。", "金珠斗量佩鳴珂，所得懽華能幾何。", "形氣日隨情欲蠹，曾不百歲同臭腐。", "學仙豈必便成仙，人世且結清凈緣。", "弘景寧爲軒冕錮，子平未免婚嫁累。", "有田有廬誓弗歸，有子有女棄若遺。", "道成却往愾城郭，化作千年令威鶴。"]'),
('3660fa6d-3891-49a0-8cea-0039492e34a5','舟回自霅至黄橋風大作復反朱涇泊舟','衛宗武','宋','宋诗','song-poetry','','[]','芒鞋徧踏苕溪岡，昌翔歸棹穿滄浪。',160,'全唐诗/poet.song.218000.json','["芒鞋徧踏苕溪岡，昌翔歸棹穿滄浪。", "吾廬咫尺自可到，飛廉怒吼俄作狂。", "濤頭掀舞勢欲立，紛紛雨霰來何滂。", "河伯怙此賈其勇，杯水幾至傾倉皇。", "急呼轉柂依古剎，道場千載揚靈光。", "我今七十僅三到，更覺古檜蒼髯長。", "應爲船子笑寂寂，老無聞達徒奔忙。", "明朝風靜日欲杲，載欣衡宇升吾堂。", "波濤蓋有起平地，覆車未必非康莊。", "人生夷險與利鈍，惟有委順於旻蒼。"]'),
('0bc071d5-dfba-4588-9311-c90985f7f880','爲湖州趙村凈妙庵主僧賦','衛宗武','宋','宋诗','song-poetry','','[]','自披五戒如來佛，十年面壁坐天目。',224,'全唐诗/poet.song.218000.json','["自披五戒如來佛，十年面壁坐天目。", "歸來滿袖唯白雲，徒得聲名喧世俗。", "碧玉嶙峋煙霧堆，鑿開混沌架突兀。", "不鞭而來爭獻助，斬木指囷人不惜。", "僧寮佛屋俱落成，撐空只欠塗金碧。", "精廬不獨爲安身，海納諸方禪悅食。", "上人湛然一太虛，真覺端由真凈得。", "是心已證涅槃心，妙處豈容言語詰。", "故於題扁發其機，要使人人箇中覓。", "學徒釋侶有能然，從茲作祖而成佛。", "大展坐具闡道場，勝地名山須卓錫。", "法筵乃見龍象尊，天池且作鵾鵬息。", "書來謂逮菊花期，蓮社紳緌應畢集。", "遠師如肯致淵明，亦擬袖香躋丈室。"]'),
('652924a7-afd0-4c3a-b68c-cd5ceb9981d1','賦方寸春','衛宗武','宋','宋诗','song-poetry','','[]','小亭依綠水，花竹自幽奇。',48,'全唐诗/poet.song.218000.json','["小亭依綠水，花竹自幽奇。", "地止一方闊，春無方寸虧。", "粟中藏世界，芥子納須彌。", "萬象融心境，寧爲目睫欺。"]'),
('ce00e676-31b3-4cda-b6aa-9e5505f2265d','新陽前口占','衛宗武','宋','宋诗','song-poetry','','[]','初見草生池，俄驚草又衰。',48,'全唐诗/poet.song.218000.json','["初見草生池，俄驚草又衰。", "秋山縮鱗甲，寒渚燭鬚眉。", "花露先春信，林存傲歲枝。", "新陽已潜動，爲報衆芳知。"]'),
('432aa798-06c8-471a-8c77-68bc2def46b4','山中新霽','衛宗武','宋','宋诗','song-poetry','','[]','一雨喜還晴，曉山青復青。',48,'全唐诗/poet.song.218000.json','["一雨喜還晴，曉山青復青。", "喬松清老眼，啼鳥悅幽情。", "與客評詩卷，看僧誦佛經。", "更憐清絕處，泉瀉佩琚聲。"]'),
('50c91cee-42b7-492d-bd36-dc3841c43ff4','清明行役過淀湖至吳','衛宗武','宋','宋诗','song-poetry','','[]','涉泖正清明，淀湖波更平。',48,'全唐诗/poet.song.218000.json','["涉泖正清明，淀湖波更平。", "雉媒空古蹟，鶴唳動鄉情。", "楊柳家家插，桃花處處生。", "青山俄在望，咫尺見吳城。"]'),
('b688dd1a-d88d-4a0b-b9d5-3a353f0998c8','和野渡詠梅','衛宗武','宋','宋诗','song-poetry','','[]','傍宅林園巧，亭垂剪剪茅。',48,'全唐诗/poet.song.218000.json','["傍宅林園巧，亭垂剪剪茅。", "雪香藏冷艷，月影浸疎梢。", "桃李陪臺等，松筠道義交。", "巡簷頻索笑，應不厭推敲。"]'),
('bfff6bc0-5dcb-4c94-b035-ae421e764ee0','紫荆花','衛宗武','宋','宋诗','song-poetry','','[]','穠艷壓春葩，葩成葉始芽。',48,'全唐诗/poet.song.218000.json','["穠艷壓春葩，葩成葉始芽。", "未張青羽旆，先糝紫金砂。", "譜接三荆樹，名齊連萼花。", "移根向深谷，寂寞愛繁奢。"]'),
('65026304-0a58-4b6f-9d2e-949de02e09d9','春山','衛宗武','宋','宋诗','song-poetry','','[]','新晴散佳麗，列阜氣尤豪。',48,'全唐诗/poet.song.218000.json','["新晴散佳麗，列阜氣尤豪。", "膩草翻風沃，芳林映日高。", "殢情醲似酒，溢目湧如濤。", "衆史應難畫，吟將入彩毫。"]'),
('1846181c-6c14-455a-89c4-e5cf5281501f','出郊','衛宗武','宋','宋诗','song-poetry','','[]','幾度擬郊行，天公欠一晴。',48,'全唐诗/poet.song.218000.json','["幾度擬郊行，天公欠一晴。", "水寒魚絕影，林暝鳥藏聲。", "雲斂天容凈，雨餘山骨清。", "津橋小盤薄，梅有數枝橫。"]'),
('fa41d971-e26d-49f9-9a14-1c156e961ae3','訪山庵','衛宗武','宋','宋诗','song-poetry','','[]','彌月住山家，晴天物色奢。',48,'全唐诗/poet.song.218000.json','["彌月住山家，晴天物色奢。", "鶑遷對人語，蜂聚報僧衙。", "筍老欲成竹，蕙香開徧花。", "清吟無箇事，冉冉送春華。"]'),
('91a1937f-f7d8-49b9-9134-79b321f51f03','次韻幽居','衛宗武','宋','宋诗','song-poetry','','[]','柴荆長日閉，一徑窈而深。',48,'全唐诗/poet.song.218000.json','["柴荆長日閉，一徑窈而深。", "花竹四時趣，簡編千古心。", "戶庭無俗駕，風月入騷吟。", "種秫多爲酒，客來須共斟。"]'),
('292a1667-ef66-41cb-9494-a90d295f01d6','張石山遷居','衛宗武','宋','宋诗','song-poetry','','[]','於我已渠渠，遷喬喜得廬。',48,'全唐诗/poet.song.218000.json','["於我已渠渠，遷喬喜得廬。", "挈來三釜粟，更有一床書。", "疊石境不俗，得山名豈虛。", "從今來問字，門外列高車。"]'),
('533e42ca-a8ab-431c-afa1-86fb63b53857','過安吉縣梅溪二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','壯年知幾到，幽徑喜重尋。',48,'全唐诗/poet.song.218000.json','["壯年知幾到，幽徑喜重尋。", "異世桃源路，暮春梅子林。", "屏山森秀色，槃澗漱清音。", "迤邐窮幽渺，山行不厭深。"]'),
('0906d166-642e-42fc-ac80-85b7fd6865f9','過安吉縣梅溪二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','縱步歷前村，翛然幽趣深。',48,'全唐诗/poet.song.218000.json','["縱步歷前村，翛然幽趣深。", "鳴鴻歸別渚，倦鵲立寒林。", "煙樹遠橫带，雲甍高聳岑。", "隨風數聲笛，清絕似龍吟。"]'),
('3ae457ef-8c90-4cf0-96a8-467fe4a3bcd6','題城山頂庵','衛宗武','宋','宋诗','song-poetry','','[]','高廣與城埒，平夷似砥同。',48,'全唐诗/poet.song.218000.json','["高廣與城埒，平夷似砥同。", "舉頭瞻近日，敵面怯東風。", "千嶂履屐下，重湖几席中。", "吾鄉那有此，幾欲傲愚公。"]'),
('235202e7-30d9-4ead-9f56-4a10193a47ff','牡丹和韻二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','紅紫富輪囷，京花非浪名。',48,'全唐诗/poet.song.218000.json','["紅紫富輪囷，京花非浪名。", "相看仝國色，獨酌愧耆英。", "物好能移老，春歸更有情。", "桑榆陰未徙，尚擬續芳盟。"]'),
('b5089424-0c7d-453a-951f-893b9567a49b','牡丹和韻二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','似盤還似囷，尊號擅芳名。',48,'全唐诗/poet.song.218000.json','["似盤還似囷，尊號擅芳名。", "洛土分來種，景星流作英。", "紛敷爲絕色，向背若含情。", "別久喜相對，開尊話舊盟。"]'),
('64fe8923-1f0c-4649-9f2e-ca1fa0f24ab6','自桃嶺歷諸隴後返至唐村庵','衛宗武','宋','宋诗','song-poetry','','[]','扶杖穿桃嶺，山行歷幾村。',48,'全唐诗/poet.song.218000.json','["扶杖穿桃嶺，山行歷幾村。", "嶔崎窮絕巘，旋折反窮源。", "地迥猶仙隠，山多隔市喧。", "層巒互將送，不覺月黄昏。"]'),
('c3ad46c0-299f-40cf-bb7e-3bde74d4b879','登多景樓口占立成','衛宗武','宋','宋诗','song-poetry','','[]','新霽登多景，斯遊亦快哉。',48,'全唐诗/poet.song.218000.json','["新霽登多景，斯遊亦快哉。", "雙尖浮殿塔，千堞裹樓臺。", "瀲灩琉璃合，微茫圖畫開。", "江山仍似舊，投紱慨重來。"]'),
('f5a09589-cbb7-4486-bcb0-9ca19689a5ba','過墓鄰僧寺','衛宗武','宋','宋诗','song-poetry','','[]','一見說交情，僧醪爲客斟。',48,'全唐诗/poet.song.218000.json','["一見說交情，僧醪爲客斟。", "溪山銜落照，杉竹聚清陰。", "日對畫圖軸，風生琴筑音。", "意行行不足，逸興對高吟。"]'),
('cc54c4f9-9ca5-4f8c-887d-a74815905160','和文友催梅','衛宗武','宋','宋诗','song-poetry','','[]','日昴驗星躔，陽和梅占先。',48,'全唐诗/poet.song.218000.json','["日昴驗星躔，陽和梅占先。", "未教疑雪似，早已奪春妍。", "少緩芳蕤放，多令秀句傳。", "輸君探山意，日日醉花前。"]'),
('59cc5562-c2f2-43ec-b448-02dc78f39ef8','和南塘賦東軒春日即事','衛宗武','宋','宋诗','song-poetry','','[]','十分春過半，穉綠已侵花。',72,'全唐诗/poet.song.218000.json','["十分春過半，穉綠已侵花。", "又見拳抽蕨，相將舌吐茶。", "川原美如畫，卉木爛成霞。", "紅旆思行樂，黄紬憶放衙。", "榆年許憔悴，芳景自紛華。", "但有書爲圃，不妨涵聖涯。"]'),
('17f50304-a394-4e50-a818-54e19fad29da','山行道間','衛宗武','宋','宋诗','song-poetry','','[]','行春行不足，今日又明朝。',48,'全唐诗/poet.song.218000.json','["行春行不足，今日又明朝。", "平嶺上危嶺，長橋過短橋。", "殘紅明石澗，膩綠暗風條。", "最是宜人聽，遷鶑出谷嬌。"]'),
('800fcd91-3c97-4c37-af22-86bc0ec387be','聽鶑','衛宗武','宋','宋诗','song-poetry','','[]','羽族滿幽谷，綿蠻聲更多。',48,'全唐诗/poet.song.218000.json','["羽族滿幽谷，綿蠻聲更多。", "翠林深萬緒，金羽擲雙梭。", "破曉頻驚夢，叫雲如解歌。", "弓丸那可近，鳴躍在高柯。"]'),
('3feebddb-97f9-4279-a35f-71739134bf77','山行舟回','衛宗武','宋','宋诗','song-poetry','','[]','細雨弄晴暉，舟行度翠微。',48,'全唐诗/poet.song.218000.json','["細雨弄晴暉，舟行度翠微。", "牧童臨水立，野鶩避人飛。", "風力偏欺酒，山光欲染衣。", "晚來雙槳發，擬載碧雲歸。"]'),
('3c83ff2a-8f8c-4908-a803-6966556fe0c0','和青溪山行','衛宗武','宋','宋诗','song-poetry','','[]','北崦共幽尋，森森萬綠新。',48,'全唐诗/poet.song.218000.json','["北崦共幽尋，森森萬綠新。", "柳陰停雨棹，柏逕岸風巾。", "幸有寬閒野，堪娛老病身。", "祇憐人事異，滄海亦揚塵。"]'),
('1673e2e9-2843-4e9a-8af8-c19b6465ec33','至上基祖墳','衛宗武','宋','宋诗','song-poetry','','[]','小逕入山村，行行及墓門。',48,'全唐诗/poet.song.218000.json','["小逕入山村，行行及墓門。", "豐林俱易種，古木失常尊。", "重悵松楸地，多爲荆棘原。", "青青一抔土，馬鬣喜猶存。"]'),
('dce7a290-7e31-416d-b9cd-b3233eb2def6','木蘭花','衛宗武','宋','宋诗','song-poetry','','[]','頗費東君巧，晚春纔有芳。',48,'全唐诗/poet.song.218000.json','["頗費東君巧，晚春纔有芳。", "森森紫毫束，艷艷粉囊張。", "凡木難仝譜，猗蘭祇有香。", "花名傳樂府，雅調更悠揚。"]'),
('8d01db3a-3aa1-4522-91c1-54c7ea11c5ad','春晚郊行  其一','衛宗武','宋','宋诗','song-poetry','','[]','盎若陽和氣，融融滿太空。',48,'全唐诗/poet.song.218000.json','["盎若陽和氣，融融滿太空。", "水涵春嶼碧，林鏤夕陽紅。", "過盡桃花雨，吹來楊柳風。", "韶光晚尤媚，遊興浩難窮。"]'),
('4f1d04a8-ea39-4314-a83d-3645caca60dd','春晚郊行  其二','衛宗武','宋','宋诗','song-poetry','','[]','步屧出郊原，家家春滿門。',48,'全唐诗/poet.song.218000.json','["步屧出郊原，家家春滿門。", "斜陽芳草岸，流水落花村。", "露葉梅藏子，雲根竹長孫。", "東君老仍媚，猶有野芳存。"]'),
('630c65e5-26d3-4d1d-8929-c0002ecafc2c','春晚郊行  其三','衛宗武','宋','宋诗','song-poetry','','[]','東風吹不斷，芳草正萋萋。',48,'全唐诗/poet.song.218000.json','["東風吹不斷，芳草正萋萋。", "暗綠藏禽語，殘紅襯馬蹄。", "莎汀連葦岸，麥隴間蔬畦。", "往歲行春路，推敲認舊題。"]'),
('3f73f3b7-e9fd-4bbb-bb85-d64e916f73e0','暮春','衛宗武','宋','宋诗','song-poetry','','[]','跨馬尋春去，未容春便歸。',48,'全唐诗/poet.song.218000.json','["跨馬尋春去，未容春便歸。", "山浮天際色，雲弄水中暉。", "綠長千林暗，紅無一片飛。", "茅茨籬落外，惟有菜花肥。"]'),
('ba52523a-0433-484e-9a52-e7477a40695c','晚春  其一','衛宗武','宋','宋诗','song-poetry','','[]','轉眼韶華老，絮飄萍滿塘。',48,'全唐诗/poet.song.218000.json','["轉眼韶華老，絮飄萍滿塘。", "啼鶑求友急，乳燕護雛忙。", "春晚犁鉏閙，雨餘桑柘香。", "清和猶好在，未忍廢奚囊。"]'),
('474779aa-6248-42c7-9539-682956074fab','晚春  其二','衛宗武','宋','宋诗','song-poetry','','[]','飛花迷柳岸，小葉貼荷塘。',48,'全唐诗/poet.song.218000.json','["飛花迷柳岸，小葉貼荷塘。", "冉冉年增老，匆匆春去忙。", "候禽喧巧哢，野卉逗餘香。", "盡日敲吟字，詩慳類括囊。"]'),
('5330be86-296c-47cb-a317-25c0fe606964','和張石山惜春韻  其一','衛宗武','宋','宋诗','song-poetry','','[]','天涯芳草路，幾度擬幽尋。',48,'全唐诗/poet.song.218000.json','["天涯芳草路，幾度擬幽尋。", "懷古空陳迹，傷春徒苦心。", "花殘猶宿蝶，柳暗已藏禽。", "天地年來別，一春常是陰。"]'),
('04b32988-81f6-474d-98ad-5c75cfc54cb4','和張石山惜春韻  其二','衛宗武','宋','宋诗','song-poetry','','[]','滿眼物華媚，芳辰與意違。',48,'全唐诗/poet.song.218000.json','["滿眼物華媚，芳辰與意違。", "愁多何樂少，昨是豈今非。", "轉蕙光風老，流花過雨肥。", "春來傳好事，空又送春歸。"]'),
('ed60f1e5-f8a1-4434-a5ad-51ba12aaf604','宣妙寺即事','衛宗武','宋','宋诗','song-poetry','','[]','寺小經年久，地偏人到稀。',48,'全唐诗/poet.song.218000.json','["寺小經年久，地偏人到稀。", "山光含野色，泉脉出林霏。", "老樹藏金粟，繁枝長綠衣。", "門前千歲柏，長日映清暉。"]'),
('54c4f270-485d-419b-a589-5b8bcdf76510','霅隴歸別庵僧','衛宗武','宋','宋诗','song-poetry','','[]','彌月分僧榻，翛然與世違。',48,'全唐诗/poet.song.218000.json','["彌月分僧榻，翛然與世違。", "何妨隨地隠，恨不載山歸。", "跡與風帆遠，秋隨春絮飛。", "何當泉石畔，歲歲得相依。"]'),
('5ef55d8d-59eb-4f17-9db5-90067e3027ce','自霅還登舟','衛宗武','宋','宋诗','song-poetry','','[]','日日上巑岏，吟邊飽看山。',48,'全唐诗/poet.song.218000.json','["日日上巑岏，吟邊飽看山。", "筍輿穿嶺徧，桂楫汎溪還。", "芳草垂楊際，行雲流水間。", "往來身不繫，未羨白鷗閒。"]'),
('6e70438a-9036-4040-abe7-0de91b168f21','僧庵','衛宗武','宋','宋诗','song-poetry','','[]','結屋倚巖隈，日高晨露晞。',48,'全唐诗/poet.song.218000.json','["結屋倚巖隈，日高晨露晞。", "開門放山入，隠几看雲歸。", "野老披白袷，樵夫穿翠微。", "僧居無箇事，盡日客來稀。"]'),
('4ee48eee-1907-4f1a-81a5-fbf643554745','自霅和石山','衛宗武','宋','宋诗','song-poetry','','[]','扁舟汎清霅，遊屐徧層戀。',48,'全唐诗/poet.song.218000.json','["扁舟汎清霅，遊屐徧層戀。", "幽討離家久，新吟借客看。", "槐陰風轉夏，梅子雨留寒。", "不謂浮雲跡，煩君上筆端。"]'),
('7b753458-54da-46cb-8206-68a5cbf52e20','歸舟','衛宗武','宋','宋诗','song-poetry','','[]','回艇臨塘路，撁夫欣路平。',48,'全唐诗/poet.song.218000.json','["回艇臨塘路，撁夫欣路平。", "歸鴻千里近，過鳥一身輕。", "溪派分頭去，山光戀眼明。", "松江水雲際，屈指不多程。"]'),
('40e0aa9b-497c-4c6e-83a7-95bd0bb53f6b','初夏登北山','衛宗武','宋','宋诗','song-poetry','','[]','推篷數峰出，野色弄新晴。',48,'全唐诗/poet.song.218000.json','["推篷數峰出，野色弄新晴。", "雷復陽初長，雪消山更青。", "嶺坳孤塔露，木杪片雲生。", "何日塵緣了，來尋猿鶴盟。"]'),
('400e7965-26c6-49cc-a60d-af973ca7595a','北山晚步','衛宗武','宋','宋诗','song-poetry','','[]','遠岫煙光合，天寒欲斂昏。',48,'全唐诗/poet.song.218000.json','["遠岫煙光合，天寒欲斂昏。", "栖鴉依古木，歸艇入前村。", "岸隔山藏寺，潮生水到門。", "川原渾似舊，竚立暗銷魂。"]'),
('601747f8-cd2a-4f84-b781-e786c3449a08','重九','衛宗武','宋','宋诗','song-poetry','','[]','榆景轉凄凉，逢秋更斷腸。',48,'全唐诗/poet.song.218000.json','["榆景轉凄凉，逢秋更斷腸。", "百年能幾日，多歲負重陽。", "杜釀慳浮白，陶籬半點黄。", "可嗟人事異，花不減寒香。"]'),
('e7b5af44-84f5-447b-b1b8-f5e8b1863e81','別陳玉峰','衛宗武','宋','宋诗','song-poetry','','[]','三載相親久，臨分思黯然。',48,'全唐诗/poet.song.218000.json','["三載相親久，臨分思黯然。", "不堪蘭佩遠，近在菊花前。", "欲買堯夫宅，難移杜曲田。", "臺山千萬疊，書有鴈能傳。"]'),
('ddb0ae2d-6a56-41ca-a027-d6c6df5b9a1f','野步','衛宗武','宋','宋诗','song-poetry','','[]','清景浩無際，天光接水光。',48,'全唐诗/poet.song.218000.json','["清景浩無際，天光接水光。", "晴雲侵別嶼，遠溆落殘陽。", "巖菊幽含馥，岸花嬌衒粧。", "田家競秋報，社鼓樂村坊。"]'),
('7dfe59e4-bcc8-4cbe-8f70-952af031a497','野塘晚步','衛宗武','宋','宋诗','song-poetry','','[]','數畝涵空碧，波光可染衣。',48,'全唐诗/poet.song.218000.json','["數畝涵空碧，波光可染衣。", "荷枯惟藕在，荻老作花飛。", "水浄遊鱗見，天寒過鴈稀。", "十分清絕處，秋月散明輝。"]'),
('8ba02671-3059-4b55-9a22-4c27d166f1f2','錢園小隠','衛宗武','宋','宋诗','song-poetry','','[]','林園依岸曲，小隠是誰家。',48,'全唐诗/poet.song.218000.json','["林園依岸曲，小隠是誰家。", "畫閣虛臨水，綠筠深護花。", "晴川流皓月，落景襯明霞。", "幻境無多地，幽情未易涯。"]'),
('8a280633-91dd-41de-bac8-de0854202219','下嶺','衛宗武','宋','宋诗','song-poetry','','[]','下嶺望前村，參差去路分。',48,'全唐诗/poet.song.218000.json','["下嶺望前村，參差去路分。", "數疇田接壠，一穗爨生雲。", "古樹藏山脅，幽泉潄石齦。", "巖居非不隠，士馬亦紛紛。"]'),
('4b459675-b702-44fc-a5a4-91d90cc64408','初秋夜雨','衛宗武','宋','宋诗','song-poetry','','[]','老火勢方張，欣逢律轉商。',48,'全唐诗/poet.song.218000.json','["老火勢方張，欣逢律轉商。", "打窗風送溼，襲袂夜生涼。", "灑若煩襟豁，悠然清夢長。", "流膏到原隰，黍稷徧含香。"]'),
('dba1df6a-0bc7-4f5a-adb2-96f86c384510','過荻塘','衛宗武','宋','宋诗','song-poetry','','[]','煙火人村盛，川途客旅稠。',48,'全唐诗/poet.song.218000.json','["煙火人村盛，川途客旅稠。", "荻塘三百里，禹甸幾千疇。", "綿絡廬相接，膏腴稼倍收。", "經從少至老，復此繫扁舟。"]'),
('2e8cf9b5-1db0-42ff-82b3-d6c9abec463d','月師西巖','衛宗武','宋','宋诗','song-poetry','','[]','靈山作巖骨，清氣滌炎洲。',48,'全唐诗/poet.song.218000.json','["靈山作巖骨，清氣滌炎洲。", "突兀插萬古，玲瓏涵九秋。", "排雲宿翳掃，賓日曉光浮。", "的的西來意，宜於此處求。"]'),
('75fd2279-41c8-4931-8eef-1abaced6154a','霅隴晚步','衛宗武','宋','宋诗','song-poetry','','[]','幽澗水縈迴，深林路杳微。',48,'全唐诗/poet.song.218000.json','["幽澗水縈迴，深林路杳微。", "僧居無客到，樵徑有人歸。", "歲晚松孤秀，天寒鳥倦飛。", "一塵渾不到，倚杖看斜暉。"]'),
('fd8e0951-392e-4ea9-bdec-4e92d0f178cf','重到霅隴  其一','衛宗武','宋','宋诗','song-poetry','','[]','重來知幾度，行屐徧松楸。',48,'全唐诗/poet.song.218000.json','["重來知幾度，行屐徧松楸。", "白日惟催老，黄花又送秋。", "山深林翳掃，墅豁稻雲收。", "盡說豐年樂，田家更覺愁。"]'),
('47eefd8d-6bcb-4d9c-bb86-054bf5342820','重到霅隴  其二','衛宗武','宋','宋诗','song-poetry','','[]','少壯記曾遊，茲來營首丘。',48,'全唐诗/poet.song.218000.json','["少壯記曾遊，茲來營首丘。", "青山不改色，白髮自多愁。", "寂寂千年晚，蕭蕭風雨秋。", "世緣何日了，一笑問盟鷗。"]'),
('abdc5165-761a-4195-8a23-febe9941f4a9','山行','衛宗武','宋','宋诗','song-poetry','','[]','晚芳開欲盡，落葉滿林楸。',48,'全唐诗/poet.song.218000.json','["晚芳開欲盡，落葉滿林楸。", "風色轉寒候，雨聲鳴暮秋。", "清遊殊有碍，歸興浩難收。", "何日逢開霽，天還解客愁。"]'),
('aa6aed9f-2b9e-4f11-ae3e-77b92ea2bd3c','晚眺  其一','衛宗武','宋','宋诗','song-poetry','','[]','一碧秋萬頃，了無雲翳侵。',48,'全唐诗/poet.song.218000.json','["一碧秋萬頃，了無雲翳侵。", "遠山醒病眼，澄水瑩塵襟。", "鴈落浮寒渚，烏棲認舊林。", "臨流小盤薄，飛鏡掛危岑。"]'),
('5c13c4df-e4e7-407e-98bf-58c8417bac6b','晚眺  其二','衛宗武','宋','宋诗','song-poetry','','[]','病眸猶遠眺，惟恨鬢霜侵。',48,'全唐诗/poet.song.218000.json','["病眸猶遠眺，惟恨鬢霜侵。", "稻色雲連畝，桂香風滿襟。", "野橋橫落照，晚磬出幽林。", "牧笛數聲外，明霞襯碧岑。"]'),
('67a7d00c-a4e0-4ea5-8d85-cf0c46ccc209','秋後郊行','衛宗武','宋','宋诗','song-poetry','','[]','水北水南村，縈回草徑深。',48,'全唐诗/poet.song.218000.json','["水北水南村，縈回草徑深。", "食蔬蟲篆葉，宿樹鳥盤林。", "岸斷分支港，雲開出遠岑。", "意行無箇事，斜日照孤吟。"]'),
('f6b68626-4ccf-40b6-9a5a-5b25819936e3','和詠雪二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','六出天施巧，時哉更可人。',48,'全唐诗/poet.song.218000.json','["六出天施巧，時哉更可人。", "後庚三日至，來復一陽新。", "破白祥開臘，剪紅工勝春。", "羊羔金帳飲，宜富不宜貧。"]'),
('57d80cad-69ab-411e-b0cf-3b8ccb8687bc','和詠雪二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','飛霙應冬候，志喜屬詩人。',48,'全唐诗/poet.song.218000.json','["飛霙應冬候，志喜屬詩人。", "遠岫千尖沒，寒林一色新。", "年豐呈上瑞，天巧占先春。", "比屋銀成屋，民貧豈療貧。"]'),
('da74f25e-cbfe-4ab6-aec9-02d85c99db03','喜晴','衛宗武','宋','宋诗','song-poetry','','[]','披霧出松關，行行破曉寒。',48,'全唐诗/poet.song.218000.json','["披霧出松關，行行破曉寒。", "崎嶇忽平坦，迤邐復巑岏。", "霜沐林光沃，山圍野色寬。", "朝曦開霽景，鳴鳥亦聲懽。"]'),
('b429a517-913f-49fd-86a9-0afda595af44','之霅','衛宗武','宋','宋诗','song-poetry','','[]','小艇經從處，村村盡掩扉。',48,'全唐诗/poet.song.218000.json','["小艇經從處，村村盡掩扉。", "山川今似舊，城郭是耶非。", "澤竭魚龍困，林空鳥雀稀。", "天寒歲年晚，蚤計盍知歸。"]'),
('067c58cb-26be-4aed-98b5-070556b6b939','津途風雨欲雪','衛宗武','宋','宋诗','song-poetry','','[]','宇宙忽凝合，一元如未分。',48,'全唐诗/poet.song.218000.json','["宇宙忽凝合，一元如未分。", "天慳花剪水，風潑墨成雲。", "饑鳥啄木理，戲鳬生浪紋。", "祁寒飛兩櫂，行役爲誰勤。"]'),
('3dafac29-f3d5-4447-be98-67c9f7073f75','和張菊存寄詩二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','江湖詩價滿，競說弟兄難。',48,'全唐诗/poet.song.218000.json','["江湖詩價滿，競說弟兄難。", "才壓曹劉短，氣凌郊島寒。", "騷壇新領袖，上國舊衣冠。", "未見詩先得，今人作古看。"]'),
('0000df07-05b3-4359-ae40-5e93f7e8d3e1','和張菊存寄詩二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','一紙飛雲端，驪珠得所難。',48,'全唐诗/poet.song.218000.json','["一紙飛雲端，驪珠得所難。", "句成春草夢，香带古梅寒。", "願見期傾蓋，遠游思整冠。", "乘流問陶逕，剩借菊吟看。"]'),
('54b4d6ba-30cc-4687-8995-1781dee9d443','過新豐村偶成','衛宗武','宋','宋诗','song-poetry','','[]','咫尺是江城，欲前猶未能。',48,'全唐诗/poet.song.218000.json','["咫尺是江城，欲前猶未能。", "舟行尋宿泊，村近問名稱。", "愁聚眉常斂，吟窮思屢凝。", "新豐舊遊地，過騎免憑陵。"]'),
('57e677d4-0cc3-4101-8b6e-38ec36a44254','唐村買杉爲槨南潯買杉爲棺戲作','衛宗武','宋','宋诗','song-poetry','','[]','一出四旬歸，身謀喜不遺。',48,'全唐诗/poet.song.218000.json','["一出四旬歸，身謀喜不遺。", "歌方想原壤，讖復合龜茲。", "厚薄惟求稱，死生難預知。", "桐棺三寸窆，亦足矯茶毗。"]'),
('2dce3c7f-0166-498a-8404-7700dc535339','過菁山秀王墓','衛宗武','宋','宋诗','song-poetry','','[]','對案毬獅衮，來岡陣馬驅。',48,'全唐诗/poet.song.218000.json','["對案毬獅衮，來岡陣馬驅。", "讖書曾昔驗，王氣慨今無。", "猶喜王侯冢，免遭詩禮儒。", "葱葱餘壤樹，柯葉尚紛敷。"]'),
('96ff2467-8c35-477b-a781-3911697aeb95','挽常蒲溪端明二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','蘭省冠時英，清華晚徧更。',48,'全唐诗/poet.song.218000.json','["蘭省冠時英，清華晚徧更。", "有年尤有德，全節復全名。", "世襲烏臺譽，身辭鵷閣榮。", "平生敭歷地，千古載廉聲。"]'),
('c0d5e731-70c8-4416-8502-e66c6b612e8d','挽常蒲溪端明二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','異邑阻登門，因風輒寄聲。',48,'全唐诗/poet.song.218000.json','["異邑阻登門，因風輒寄聲。", "方馳咫尺牘，已奠兩間楹。", "模倣楚人些，摩挲白傅銘。", "貞元朝士幾，三嘆重傷情。"]'),
('3c4a5979-6bad-4acb-b22b-284f4ffa9557','挽南塘朱檢閲二首  其一','衛宗武','宋','宋诗','song-poetry','','[]','傳笏自文昌，身名克顯揚。',48,'全唐诗/poet.song.218000.json','["傳笏自文昌，身名克顯揚。", "蜚聲騰宦路，接武近鴛行。", "廉尚冰霜潔，吟篇風露香。", "晚年陶靖節，松菊更凄凉。"]'),
('f2b6408e-1a52-4081-b9e1-43898a84b2b7','挽南塘朱檢閲二首  其二','衛宗武','宋','宋诗','song-poetry','','[]','蚤歲篤盟姻，交情晚更親。',48,'全唐诗/poet.song.218000.json','["蚤歲篤盟姻，交情晚更親。", "耆英亡老友，吟社欠同人。", "氣貌溫溫玉，襟懷盎盎春。", "北山期共隠，臨窆重傷神。"]'),
('5f1de3fd-7395-4b58-ba40-440f8a3ecae7','過秀城哭葉倅  其一','衛宗武','宋','宋诗','song-poetry','','[]','一見負吾願，人亡乃及門。',48,'全唐诗/poet.song.218000.json','["一見負吾願，人亡乃及門。", "溫乎容可即，儼若像如存。", "滿擬朋三壽，那知隔九原。", "瓣香傾老淚，竚立黯消魂。"]'),
('8115dba0-0609-41b6-9381-f81cd810e5a6','過秀城哭葉倅  其二','衛宗武','宋','宋诗','song-poetry','','[]','久矣致生芻，斯行夫豈徒。',48,'全唐诗/poet.song.218000.json','["久矣致生芻，斯行夫豈徒。", "不惟哀一老，亦欲識諸孤。", "魏笏期傳祖，韋經在業儒。", "子平仙去早，萬事付長吁。"]'),
('676ee250-d8de-4a65-8d29-9cdb7854f16b','挽儲華谷四首  其一','衛宗武','宋','宋诗','song-poetry','','[]','吾里文華士，平生湖海襟。',48,'全唐诗/poet.song.218000.json','["吾里文華士，平生湖海襟。", "四書窮洛學，五字逼唐吟。", "多識精能事，諸公競賞音。", "結交猶恨晚，十載獨知心。"]'),
('728d8803-a2c9-45b4-8828-bec9b69c8ef9','挽儲華谷四首  其二','衛宗武','宋','宋诗','song-poetry','','[]','處晦心常樂，安貧節愈堅。',48,'全唐诗/poet.song.218000.json','["處晦心常樂，安貧節愈堅。", "遺書訂無極，妙藴發先天。", "揚子惟存宅，龜蒙粗有田。", "阨窮身至泯，遺子獨青編。"]'),
('eb73e89e-e496-4aa9-a9e2-f311750084e9','挽儲華谷四首  其三','衛宗武','宋','宋诗','song-poetry','','[]','世慕長生術，君尤早用功。',48,'全唐诗/poet.song.218000.json','["世慕長生術，君尤早用功。", "談玄徒至老，養素竟成空。", "身已隨朝露，神應到閬風。", "清言那復接，頼有注參同。"]'),
('6bea0c64-3ab5-4e90-8508-a338393f8db2','挽儲華谷四首  其四','衛宗武','宋','宋诗','song-poetry','','[]','歸來纔一見，病已不能支。',48,'全唐诗/poet.song.218000.json','["歸來纔一見，病已不能支。", "擬作歲寒友，俄成夜壑悲。", "凄風吹老淚，落日照幽姿。", "賡唱無從再，酸心閲舊詩。"]'),
('d8ef3f9a-8f64-47fe-8f3d-12bf5a336cc7','挽悟悅師二章  其一','衛宗武','宋','宋诗','song-poetry','','[]','耆宿已凋零，如師亦曉星。',48,'全唐诗/poet.song.218000.json','["耆宿已凋零，如師亦曉星。", "宗門僧巨棟，梵宇世傳燈。", "身閲空花境，心潜多業經。", "悅禪方有悟，六秩弔頹齡。"]'),
('18c4a327-5f66-4971-9b19-6ca53761249e','挽悟悅師二章  其二','衛宗武','宋','宋诗','song-poetry','','[]','契合豈前因，交情淡愈真。',48,'全唐诗/poet.song.218000.json','["契合豈前因，交情淡愈真。", "開緘疑晉帖，賡句逼唐人。", "高著棋空局，清談案積塵。", "滿襟揮老淚，釋友更誰親。"]'),
('bdbd268c-955e-4d78-aeb9-e7821d87d4af','挽柳月澗','衛宗武','宋','宋诗','song-poetry','','[]','素履輩儒先，居鄉行不愆。',48,'全唐诗/poet.song.218000.json','["素履輩儒先，居鄉行不愆。", "五言唐句法，千古宋吟編。", "每恨貧難療，猶欣名可傳。", "此生何所有，老壽更希年。"]'),
('00370fdb-9d0b-4175-bd32-448565b21eed','挽葉倅二章  其一','衛宗武','宋','宋诗','song-poetry','','[]','八座家聲著，居官政不迷。',48,'全唐诗/poet.song.218000.json','["八座家聲著，居官政不迷。", "典刑鄉黨敬，節行古人稽。", "展驥空凡馬，解牛猶割雞。", "鴛行纔展武，勇退倦攀躋。"]'),
('f2cfbf84-c470-4425-bc7d-c097af33ea90','挽葉倅二章  其二','衛宗武','宋','宋诗','song-poetry','','[]','死別喜生反，心親恨迹賒。',48,'全唐诗/poet.song.218000.json','["死別喜生反，心親恨迹賒。", "交情金可斷，粹德玉無瑕。", "方擬來聞鶴，俄驚夢在蛇。", "歸藏重悲感，幸有子承家。"]'),
('5d2f10c7-c2a3-4eb5-afcc-4378510626e2','元日雪','衛宗武','宋','宋诗','song-poetry','','[]','曉來雲氣忽氤氳，上瑞俄驚到眼頻。',64,'全唐诗/poet.song.218000.json','["曉來雲氣忽氤氳，上瑞俄驚到眼頻。", "隔得一宵猶带臘，飛來萬點總成春。", "方傳六琯葭灰動，又報千林花事新。", "試向庭前披鶴氅，却嫌標致怯前人。"]'),
('a98161c5-3e61-41af-9626-76c25e1e0831','和野渡春雪','衛宗武','宋','宋诗','song-poetry','','[]','天教滕巽互驅馳，令下東皇莫敢違。',64,'全唐诗/poet.song.218000.json','["天教滕巽互驅馳，令下東皇莫敢違。", "雲擘碎綿迷眼界，山遮新黛抹腰圍。", "衆芳被虐難爭巧，二麥呈祥不用祈。", "片片吹將入簷幕，佳人錯認落梅飛。"]'),
('5c52bc98-7515-4241-91c1-9b8f20abf6fb','寄興  其一','衛宗武','宋','宋诗','song-poetry','','[]','希年逾五歎無聞，歲事從頭又一新。',64,'全唐诗/poet.song.218000.json','["希年逾五歎無聞，歲事從頭又一新。", "徒得襄陽齒耆舊，却慚莊子號陳人。", "垂垂榆景已侵耄，冉冉花辰不減春。", "日涉丘園今已矣，北山亦足了閒身。"]'),
('1b6c2639-1ddc-4ede-a06c-570bd116416a','寄興  其二','衛宗武','宋','宋诗','song-poetry','','[]','杜門世事不須聞，一任如棋局自新。',64,'全唐诗/poet.song.218000.json','["杜門世事不須聞，一任如棋局自新。", "多病不妨爲壽考，餘生更喜作閒人。", "居今野處黄冠日，記昔郊行紅旆春。", "須識世榮俱土苴，豈如有道善其身。"]'),
('52afe22e-cf69-4255-8b20-11b8c28610a7','春雨  其一','衛宗武','宋','宋诗','song-poetry','','[]','幾朝霢霂不破塊，通夕浪浪勢乃滂。',64,'全唐诗/poet.song.218000.json','["幾朝霢霂不破塊，通夕浪浪勢乃滂。", "竹下森然騂角露，桑間沃若繭絲香。", "田毛沾潤初含穗，土脉流膏欲布秧。", "多謝化工成歲事，從春節節爲人忙。"]'),
('e4314a14-f77a-4c67-ae96-729faef6bd74','春雨  其二','衛宗武','宋','宋诗','song-poetry','','[]','一自春來二月强，連宵甘霔澤斯滂。',64,'全唐诗/poet.song.218000.json','["一自春來二月强，連宵甘霔澤斯滂。", "潤留根蔕梅桃實，清及萌芽黍稷香。", "雀舌纖纖抽茗葉，羊羣戢戢長松秧。", "農桑從此無虛日，織婦耕夫處處忙。"]'),
('972a71b3-ccbf-4cb3-8f02-cc53d32faef3','春雨  其三','衛宗武','宋','宋诗','song-poetry','','[]','一自蒼精渙號揚，如酥小雨釀春忙。',64,'全唐诗/poet.song.218000.json','["一自蒼精渙號揚，如酥小雨釀春忙。", "霏霏透入根荄脈，點點染成桃杏粧。", "澤徧高深俱及物，氣融枯槁亦生香。", "老夫那復問芳訊，但願三時協雨暘。"]'),
('0b84404d-bda9-4ac3-90de-2e79b5155431','和玉峰春吟','衛宗武','宋','宋诗','song-poetry','','[]','年來愁似海波深，柏酒明朝試一斟。',64,'全唐诗/poet.song.218000.json','["年來愁似海波深，柏酒明朝試一斟。", "那復蘇堤追勝賞，不妨楚澤效狂吟。", "金旛曉賜夢何在，紅旆春行步莫尋。", "料得宮花仍似舊，應無墮珥與遺簪。"]'),
('651dc183-7218-465d-a264-8918f9342906','首春同枌友携樽過野渡訪梅即席  其一','衛宗武','宋','宋诗','song-poetry','','[]','枌朋載酒子雲居，何必孤山遠訪逋。',64,'全唐诗/poet.song.218000.json','["枌朋載酒子雲居，何必孤山遠訪逋。", "癯影參差濃復淡，古香傳送有還無。", "朋龜賸喜如雲集，汎螘何妨過日晡。", "索笑却嫌來較晚，一林芳意太紛敷。"]'),
('37e42ea4-a8d6-4b17-9c6c-909c2ee350c0','首春同枌友携樽過野渡訪梅即席  其二','衛宗武','宋','宋诗','song-poetry','','[]','訪梅尋友款幽居，俄見棲鴉已畢逋。',64,'全唐诗/poet.song.218000.json','["訪梅尋友款幽居，俄見棲鴉已畢逋。", "霽日幸同終日笑，春花有似此花無。", "銜杯林下嫌來晚，索句簷前祇恐晡。", "菲作不妨爲玉引，要看詞藻競芬敷。"]'),
('debaeca1-9187-4ccb-9866-9f695b2d85f7','初春次文友韻','衛宗武','宋','宋诗','song-poetry','','[]','原郊稚綠未成蒼，芽甲森森似蝟芒。',64,'全唐诗/poet.song.218000.json','["原郊稚綠未成蒼，芽甲森森似蝟芒。", "急景不堪烏兔躍，新年又見燕鶑忙。", "看看地列千機錦，冉冉風傳百和香。", "人事不如春事好，芳菲徒自滿河陽。"]'),
('dab33816-2ba5-4fb7-8e8a-d4c8c7ddd39b','賡野渡春集韻','衛宗武','宋','宋诗','song-poetry','','[]','紅紫春來獨擅場，銷魂人抱送春觴。',64,'全唐诗/poet.song.218000.json','["紅紫春來獨擅場，銷魂人抱送春觴。", "少嫌宴席聲歌短，晚覺書林氣味長。", "列座燕毛成二老，一番花事付諸郎。", "吾儕到此無他好，莫厭賡酬費錦腸。"]'),
('ed602570-e2ab-427c-8d54-cd727858ee10','月集呼聲妓不至野渡於觴末俾賦詩以紀初集','衛宗武','宋','宋诗','song-poetry','','[]','真率盟齊喜有初，崇觴載俎志交孚。',64,'全唐诗/poet.song.218000.json','["真率盟齊喜有初，崇觴載俎志交孚。", "共披白帢俱霑醉，獨惜紅裙不受呼。", "擬洛耆英宜有詠，班唐九老可成圖。", "從今勝集循環舉，歲歲毋令此意辜。"]'),
('ef07d0e5-3494-48ae-8064-4593ed5c74f7','清明前有遠役呈野渡','衛宗武','宋','宋诗','song-poetry','','[]','月集相期在後旬，料應主席不寒盟。',64,'全唐诗/poet.song.218000.json','["月集相期在後旬，料應主席不寒盟。", "方思北陸催行色，又爲東風問客程。", "鼓楫欲隨芳草去，傳杯須待綠陰成。", "姑蘇城外春光老，還許同舟載友生。"]'),
('9a2340f7-b2d4-4fb1-9c8b-5edbc4c99bb0','清明前呈文几','衛宗武','宋','宋诗','song-poetry','','[]','此月纔過禊事修，芳辰冉冉逝如流。',64,'全唐诗/poet.song.218000.json','["此月纔過禊事修，芳辰冉冉逝如流。", "牡丹開了寒應盡，燕子歸來春又休。", "衰鬢難將新綠染，顰眉豈爲落紅愁。", "勞生擾擾何時足，已擬拋家理釣舟。"]'),
('4adf4f40-5457-4101-b126-a99d41f325f3','清明前呈南塘','衛宗武','宋','宋诗','song-poetry','','[]','晚景凄凉事事休，與波上下任沉浮。',64,'全唐诗/poet.song.218000.json','["晚景凄凉事事休，與波上下任沉浮。", "花辰歲歲惟添老，榆火春春不改愁。", "幾曲畫屏新綠暗，一川流玉落紅稠。", "出門有碍家無累，水北山南負勝遊。"]'),
('0b42d2d6-7cbd-43e4-a044-4b57cd1de3a9','次華谷詠梅韻','衛宗武','宋','宋诗','song-poetry','','[]','宜煙宜雨更宜晴，竹底何妨枝带橫。',64,'全唐诗/poet.song.218000.json','["宜煙宜雨更宜晴，竹底何妨枝带橫。", "雅致恥隨春富貴，英姿不怕月分明。", "吟邊興動詩添韻，醉裏香傳夢亦清。", "一自孤山題品後，此花標格孰能名。"]'),
('c1b58089-5874-4774-b202-c11638f3fa4e','次韻詠梅','衛宗武','宋','宋诗','song-poetry','','[]','直疑姑射地行僊，綽約如臨几案前。',64,'全唐诗/poet.song.218000.json','["直疑姑射地行僊，綽約如臨几案前。", "和竹半欹能去俗，與蘭並列盍饒先。", "林間姿艷同霜潔，窗下精神待月傳。", "剩欲栽培爲老伴，相親日日在吟邊。"]'),
('2aa895b6-4b76-4426-8023-bbacedb73d9c','又和詠梅  其一','衛宗武','宋','宋诗','song-poetry','','[]','逸氣飄飄似欲僊，不論茅舍玉堂前。',64,'全唐诗/poet.song.218000.json','["逸氣飄飄似欲僊，不論茅舍玉堂前。", "衆芳無此風神秀，十友推爲行輩先。", "佳實尚堪爲世用，香名更喜有詩傳。", "蕭蕭白髮差同色，也欲拈花上鬢邊。"]'),
('2a4f7ebf-01d7-4d19-85aa-0dddbc8267ad','又和詠梅  其二','衛宗武','宋','宋诗','song-poetry','','[]','幾回渴想此癯仙，誰爲招邀倏在前。',64,'全唐诗/poet.song.218000.json','["幾回渴想此癯仙，誰爲招邀倏在前。", "明艷弗爲諸垢染，孤標獨出衆芳先。", "不矜顔色自奇絕，綽有馨香祇暗傳。", "空想名園千樹發，何時持酒向花邊。"]'),
('e052c9dc-556b-4f13-af75-57431d6a46f8','曉枕追記山梅','衛宗武','宋','宋诗','song-poetry','','[]','高眠紙帳思無塵，祇憶冰花入夢頻。',64,'全唐诗/poet.song.218000.json','["高眠紙帳思無塵，祇憶冰花入夢頻。", "斜倚溪山獨標致，明分霜月倍精神。", "瑞纔六出先呈臘，香壓羣芳不敢春。", "今古騷翁題不盡，孤山續筆屬何人。"]'),
('da78ded6-4896-4688-be88-a33993c7c2f7','蟠梅','衛宗武','宋','宋诗','song-poetry','','[]','妙製成春春未知，園工自出一家機。',64,'全唐诗/poet.song.218000.json','["妙製成春春未知，園工自出一家機。", "折旋夭矯龍蛇勢，繚繞繽紛蛾蝶圍。", "烟篆不生騰賸馥，月痕相倚衒清輝。", "西城纖巧仍如舊，祇慨梨雲昨夢非。"]'),
('a21a57f0-0878-4cd3-a88b-49e5fdefba69','詠野渡香片蟠梅','衛宗武','宋','宋诗','song-poetry','','[]','一瓣生香獨傲寒，此梅難並衆梅看。',64,'全唐诗/poet.song.218000.json','["一瓣生香獨傲寒，此梅難並衆梅看。", "明眸玉雪層層積，蛻骨蛟龍曲曲蟠。", "巧若天成經歲遠，移來地闊占春寬。", "老夫猶未識花面，覓句含毫作是觀。"]'),
('6e98082c-4c3d-4780-89bf-f3ca4bcaacd5','爲僧賦梅庭','衛宗武','宋','宋诗','song-poetry','','[]','奇絕生春五出花，僧居著此境尤嘉。',64,'全唐诗/poet.song.218000.json','["奇絕生春五出花，僧居著此境尤嘉。", "一方寒月浸清影，幾度春風生素華。", "何必江頭千樹暗，未如屋角數枝斜。", "繙經覓句無塵事，坐對尤宜雪煮茶。"]'),
('43d09e74-f9b1-4ce6-af10-76462773efb3','牡丹','衛宗武','宋','宋诗','song-poetry','','[]','淑景駸駸到牡丹，探芳日日倚楹欄。',64,'全唐诗/poet.song.218000.json','["淑景駸駸到牡丹，探芳日日倚楹欄。", "巧心吐出黄金縷，腴臉開成紫玉盤。", "春晚有花飛欲盡，山中此種得應難。", "便須收拾歸囊錦，更酌清尊仔細看。"]'),
('1b0907d1-675f-4271-bbfe-97e1bd1c0e4e','巨室遺牡丹有作  其一','衛宗武','宋','宋诗','song-poetry','','[]','幾年有負傾城艷，慚愧今朝對洛花。',64,'全唐诗/poet.song.218000.json','["幾年有負傾城艷，慚愧今朝對洛花。", "憶昔富文同勝集，慨今姚魏屬誰家。", "賞心不作園林想，過眼聊爲几席華。", "回首一年春又了，綠陰芳草接天涯。"]'),
('30e24a6b-d3e5-424b-a971-e836618c10b5','巨室遺牡丹有作  其二','衛宗武','宋','宋诗','song-poetry','','[]','殿春名譜壓羣葩，汲水金銅滿貯花。',64,'全唐诗/poet.song.218000.json','["殿春名譜壓羣葩，汲水金銅滿貯花。", "無地栽培娛老境，有風吹送到兒家。", "嬌容粉薄雨含沐，豐臉盃醺日絢華。", "花卒還榮人莫少，芳辰來往歲無涯。"]'),
('d88868eb-523b-44b2-90c1-13020769586f','春晚郊行','衛宗武','宋','宋诗','song-poetry','','[]','細草平蕪接渚沙，僧庵繫馬柏陰斜。',64,'全唐诗/poet.song.218000.json','["細草平蕪接渚沙，僧庵繫馬柏陰斜。", "青山幾曲遶流水，啼鳥數聲隨落花。", "芳景流連春富貴，晴林浮動日光華。", "獨憐人事多非舊，寂寞荒村點暮鴉。"]'),
('d51e2de3-7878-4f20-b7ea-980f9e42cfd3','喜晴  其一','衛宗武','宋','宋诗','song-poetry','','[]','梅雨成霖味已甘，淋漓更久恐難堪。',64,'全唐诗/poet.song.218000.json','["梅雨成霖味已甘，淋漓更久恐難堪。", "風雷幾晝起平陸，星斗一宵移下潭。", "萬畛針芒青曳曳，千山鱗羽綠毿毿。", "老夫晴雨不關念，心醉青編維日酣。"]'),
('8ae111e7-fbc5-47b9-bc5a-9f177aad914a','喜晴  其二','衛宗武','宋','宋诗','song-poetry','','[]','雨收宇宙喜清明，社舞村歌沸鼓鉦。',64,'全唐诗/poet.song.218000.json','["雨收宇宙喜清明，社舞村歌沸鼓鉦。", "竹下蛛絲粘葉穩，柳間蝶粉綴綿輕。", "班班遠岫髻鬟列，灧灧平川衣带橫。", "候轉清和景尤勝，翠林幽哢聽倉庚。"]'),
('ddbd8d18-314a-450b-8115-833f30ee0c8e','雨後堅山行之約','衛宗武','宋','宋诗','song-poetry','','[]','水泛新堤蘸柳條，郊行喜有可人招。',64,'全唐诗/poet.song.218000.json','["水泛新堤蘸柳條，郊行喜有可人招。", "不堪白髮三千丈，莫負青春九十朝。", "鷗鷺何妨爲伴侶，鵾鵬一任詫扶摇。", "山靈久擬騷人到，霽月光風不待邀。"]'),
('d888d3d3-9642-4dc5-8b6f-2c7e16b98135','和友人秋懷','衛宗武','宋','宋诗','song-poetry','','[]','林藪髮枯山斂眉，凜秋豈但楚臣悲。',64,'全唐诗/poet.song.218000.json','["林藪髮枯山斂眉，凜秋豈但楚臣悲。", "翩翩鶑燕知何往，獵獵鷹鸇正得時。", "殘雨曉添衣氣潤，新寒夜厭漏聲遲。", "悲風入調須頻奏，妙趣惟應心自知。"]'),
('3417b8ee-022e-4406-8cf5-2a969c258376','星節前戲成','衛宗武','宋','宋诗','song-poetry','','[]','依稀橋鵲布銀潢，又見天孫作婦忙。',64,'全唐诗/poet.song.218000.json','["依稀橋鵲布銀潢，又見天孫作婦忙。", "已向烟蘿深遁跡，不煩雲錦粲成章。", "追思高會飲傳燭，徒得清眠夢熟粱。", "却喜連朝天沛澤，應爲月姊釀秋芳。"]'),
('7ba1444d-7d7d-44fe-ac75-ce3440ec9621','和象翁七夕吟','衛宗武','宋','宋诗','song-poetry','','[]','暗度雙星見者希，那堪霧氣更霏霏。',64,'全唐诗/poet.song.218000.json','["暗度雙星見者希，那堪霧氣更霏霏。", "爲雲爲雨觀如夢，一歲一宵來即歸。", "玄鵲有靈勞翼負，素娥含恨減腰圍。", "綵樓誤却穿針女，玉宇銀潢欠發揮。"]'),
('7dac22e2-f6c9-4494-a1ef-846252317925','菊秋曉枕偶成','衛宗武','宋','宋诗','song-poetry','','[]','希年七十又加零，漸脫塵緣萬事輕。',64,'全唐诗/poet.song.218000.json','["希年七十又加零，漸脫塵緣萬事輕。", "冉冉壯心隨歲減，蕭蕭衰鬢與霜明。", "愁傾白墮嫌無量，老對黄花更有情。", "欲寫秋容到寥廓，却慚健筆欠縱橫。"]'),
('0880d047-1a09-4815-92e3-0b8ebac8d0fe','菊秋呈南塘','衛宗武','宋','宋诗','song-poetry','','[]','凄凉時序每興嗟，那復登高似孟嘉。',64,'全唐诗/poet.song.218000.json','["凄凉時序每興嗟，那復登高似孟嘉。", "尚喜烏紗粘皓髮，猶存青眼對黄花。", "百篇剩有詩堪索，九日愁無酒可賒。", "采采緬懷元亮節，不隨流俗競春華。"]'),
('f8afd73c-bac3-412a-bf3d-711383860970','赴野渡招賞桂  其一','衛宗武','宋','宋诗','song-poetry','','[]','幾年寥落負秋光，剩喜朋簪列耐堂。',64,'全唐诗/poet.song.218000.json','["幾年寥落負秋光，剩喜朋簪列耐堂。", "枌社重開真率集，桂華新薦廣寒香。", "故交今日嗟無幾，我輩晨星當自强。", "况有坐中名勝在，携尊何待菊花黄。"]'),
('bed6d551-5646-4b92-a8bb-a948ea90e0b1','赴野渡招賞桂  其二','衛宗武','宋','宋诗','song-poetry','','[]','插架金英噴月光，園中列樹更堂堂。',64,'全唐诗/poet.song.218000.json','["插架金英噴月光，園中列樹更堂堂。", "信從天上靈根出，染得古來詩句香。", "今度花遲前度發，三分秋占二分强。", "主人健筆供模寫，壓倒當年蘇與黄。"]'),
('ac3278a9-fbb2-4102-807f-baac97b6c7f0','和象翁雪  其一','衛宗武','宋','宋诗','song-poetry','','[]','欲把青空一色糊，集先維霰作花疎。',64,'全唐诗/poet.song.218000.json','["欲把青空一色糊，集先維霰作花疎。", "寸餘凝積常年有，尺許堅牢自昔無。", "粉陣成圍攢戲蝶，鹽車疑覆失前馿。", "新吟便是有聲畫，何必鵝溪寫作圖。"]'),
('c209f748-0872-44e3-ac64-b7de9e9f2ee0','和象翁雪  其二','衛宗武','宋','宋诗','song-poetry','','[]','剪水天爲農發祥，豈知寒卧欲成僵。',64,'全唐诗/poet.song.218000.json','["剪水天爲農發祥，豈知寒卧欲成僵。", "朱門快意酒肉會，墨客馳神詞翰場。", "梁苑集中呈賦手，灞橋行處吐詩香。", "羊羔茗飲評清濁，相去何殊千丈强。"]'),
('75595dc1-feda-4b01-a821-a9c106718dd8','和野渡甲申雪吟  其一','衛宗武','宋','宋诗','song-poetry','','[]','盈尺爲祥須應占，洪纖著物類形鹽。',64,'全唐诗/poet.song.218000.json','["盈尺爲祥須應占，洪纖著物類形鹽。", "幻成列阜鼉城湧，散作千林蝶陣粘。", "清友不妨添玉骨，蒼官俄怪變銀髯。", "祇憐歲歲催人老，染盡華顛亦可嫌。"]'),
('ba3734fb-ae57-403b-b04e-e8bde4fbf653','和野渡甲申雪吟  其二','衛宗武','宋','宋诗','song-poetry','','[]','三白先春花尺圍，玄冥喜不遜伊耆。',64,'全唐诗/poet.song.218000.json','["三白先春花尺圍，玄冥喜不遜伊耆。", "蓋深巖穴獸無迹，凍合林園鳥不飛。", "金帳從教資侈泰，銀城未必可憑依。", "卷懷經濟姑藏密，閉戶高眠未必非。"]'),
('e3d50b79-34a2-419b-aedd-d8558f818cac','即席賡喜雪韻','衛宗武','宋','宋诗','song-poetry','','[]','崇巒九疊破天慳，地遠塵囂隔幾關。',64,'全唐诗/poet.song.218000.json','["崇巒九疊破天慳，地遠塵囂隔幾關。", "方恨重雲封皓月，俄驚半夜老青山。", "莫嫌臘後欠三白，且喜春前露一斑。", "幾度冬來逢上瑞，更祈盈尺送舟還。"]'),
('fee93a90-6272-445e-88cf-1cd8c6986233','次韻雪積即消','衛宗武','宋','宋诗','song-poetry','','[]','馮夷剪水抑何慳，祇怕天工未許閒。',64,'全唐诗/poet.song.218000.json','["馮夷剪水抑何慳，祇怕天工未許閒。", "上瑞先春纔破白，屢豐卜歲已窺斑。", "可憐俄頃消成水，不怕明朝失却山。", "金帳羊羔非我事，汲清煮茗課奴蠻。"]'),
('3e9c425b-5d11-41eb-bac3-4946bae47cd8','和野渡雪消二律  其一','衛宗武','宋','宋诗','song-poetry','','[]','雪晴吟弄句仍佳，滿紙鮫珠屢拜嘉。',64,'全唐诗/poet.song.218000.json','["雪晴吟弄句仍佳，滿紙鮫珠屢拜嘉。", "刻玉林林空楮葉，沾泥處處失楊花。", "消成滴瀝原歸舊，潤入根荄生有涯。", "賸洗缾罌儲此水，待驅炎暑煮春茶。"]'),
('7600873e-352e-4ae8-af12-497d96db6757','和野渡雪消二律  其二','衛宗武','宋','宋诗','song-poetry','','[]','可親餘暇復奚爲，雪霽何妨剩賦詩。',64,'全唐诗/poet.song.218000.json','["可親餘暇復奚爲，雪霽何妨剩賦詩。", "應怪玉峰還翳薈，更憐銀屋變茅茨。", "結成冰筍方連夜，散作簷花特頃時。", "物物要知須返本，冰仍歸水更何疑。"]'),
('75afafb4-3b38-46cb-adf4-5fa2ce400740','寄賀陸翠庭遷居','衛宗武','宋','宋诗','song-poetry','','[]','翠庭欲到到非難，覿面須當聽麈談。',64,'全唐诗/poet.song.218000.json','["翠庭欲到到非難，覿面須當聽麈談。", "未必移家似東野，料應有宅過羅含。", "幽懷萬堞塵埃隔，勝概兩湖風月涵。", "唐宋詩人多姓陸，吟邊行遠可相參。"]'),
('3ab53282-33fb-4446-82f8-4a4dd34c1468','賀南塘得孫詩','衛宗武','宋','宋诗','song-poetry','','[]','咎消无妄福來宜，喜氣津津溢秀眉。',64,'全唐诗/poet.song.218000.json','["咎消无妄福來宜，喜氣津津溢秀眉。", "桂子昨方移別種，桐孫今見長新枝。", "金章魚佩須傳祖，玉果犀錢夢得兒。", "我欲去爲湯餠客，却慚未賦老坡詩。"]'),
('a0cc832c-fefe-4d8e-8fef-17257e8612c2','南塘歸自浙東','衛宗武','宋','宋诗','song-poetry','','[]','鼓枻歸來波浪平，碧天如水月分明。',64,'全唐诗/poet.song.218000.json','["鼓枻歸來波浪平，碧天如水月分明。", "幾番惡夢頻驚散，一片閒愁頓掃清。", "桂子高風生逸思，菊花老圃悅吟情。", "同盟約過淵明宅，載酒東籬莫厭傾。"]'),
('1fe18017-8048-4fa5-a899-418a3e3b7678','和南塘','衛宗武','宋','宋诗','song-poetry','','[]','歷徧崔嵬又涉川，菊秋還見早梅天。',64,'全唐诗/poet.song.218000.json','["歷徧崔嵬又涉川，菊秋還見早梅天。", "重來槁頂惟添老，屢對青山似有緣。", "携友擬爲深谷隠，有僧可問小乘禪。", "臨風却憶南塘老，便脫芒鞋棹去船。"]'),
('f6665b64-c2d2-4f3d-aa39-193abad8f8d3','和丹巖以青溪至有作','衛宗武','宋','宋诗','song-poetry','','[]','故人未到欠詩催，纔到九山雲爲開。',64,'全唐诗/poet.song.218000.json','["故人未到欠詩催，纔到九山雲爲開。", "野鶴正思尋老伴，盟鷗亦競喜朋來。", "免教北隴慙空帳，消得南山詠有臺。", "梅信已傳花信動，直須領客待春回。"]'),
('62ef5f73-8f66-4335-8218-927c917dca5c','霅隴回舟過湖城','衛宗武','宋','宋诗','song-poetry','','[]','起來雨氣掩朝陽，俄喜天開正色蒼。',64,'全唐诗/poet.song.218000.json','["起來雨氣掩朝陽，俄喜天開正色蒼。", "一道澄溪雲弄影，千峰霽景汎林光。", "微茫煙外頹城露，蓊鬰山巔古寺藏。", "踏遍層巒遊屐倦，歸船欵乃艣聲忙。"]'),
('9693c1e7-cf96-45c0-9a97-63f42b7ffe2a','重到霅隴新阡','衛宗武','宋','宋诗','song-poetry','','[]','摸金郎久徧郊原，冢域猶欣草木蕃。',64,'全唐诗/poet.song.218000.json','["摸金郎久徧郊原，冢域猶欣草木蕃。", "松已高年爲老友，竹添新譜長仍孫。", "四圍秀色山浮几，一曲清溪水到門。", "莫恨牛眠無瑞應，且欣老壽此身存。"]'),
('4777521d-dda1-46b0-918a-4c81bb156376','又題霅隴墳庵','衛宗武','宋','宋诗','song-poetry','','[]','斗大山庵歷幾春，茂林豐草綠初勻。',64,'全唐诗/poet.song.218000.json','["斗大山庵歷幾春，茂林豐草綠初勻。", "青山繚繞猶列戟，玉澗縈迴似曳紳。", "新竹羽成雛鳳尾，古松鱗長老龍身。", "吾年已邁嗟無用，表道瀧岡尚欠人。"]'),
('ed09325d-9fb6-4918-a7af-db1770d9f95d','南徐買舟將歸','衛宗武','宋','宋诗','song-poetry','','[]','風雨連朝思黯然，山迷宿靄水迷煙。',64,'全唐诗/poet.song.218000.json','["風雨連朝思黯然，山迷宿靄水迷煙。", "一年春事少閒日，半月客程逢漏天。", "喜涉鯨波返江國，便思鶴唳買河船。", "修途往復成何事，姑了餘生未了緣。"]'),
('d746cf41-e55d-4428-a3d2-964da43a057c','舟行分途次野渡韻','衛宗武','宋','宋诗','song-poetry','','[]','同舟李郭喜相親，盡日賡酬夜至分。',64,'全唐诗/poet.song.218000.json','["同舟李郭喜相親，盡日賡酬夜至分。", "未信詩能窮我輩，不應天遽喪斯文。", "相違雖判城西路，有約同看嶺上雲。", "從此吟毫可停運，祇疑風月未饒君。"]'),
('7754095a-94d3-416f-bad5-ddf6ce4b72a3','舟泊姑蘇','衛宗武','宋','宋诗','song-poetry','','[]','夜泊垂楊古渡頭，片帆已喜到鄰州。',64,'全唐诗/poet.song.218000.json','["夜泊垂楊古渡頭，片帆已喜到鄰州。", "經從城郭驚前夢，寂寞川途異舊遊。", "近事能知惟語燕，餘生何有付盟鷗。", "可堪人與春俱老，落絮飛花點點愁。"]'),
('aa73d001-cc75-4bbe-aa58-7cfed90a43eb','舟近吳興郡見山','衛宗武','宋','宋诗','song-poetry','','[]','一舸夷猶白浪間，擡頭俄喜對青山。',64,'全唐诗/poet.song.218000.json','["一舸夷猶白浪間，擡頭俄喜對青山。", "平生每見便刮目，今日重來不改顔。", "城郭衣冠應寂寂，川原草木尚斑斑。", "餘齡未艾須時到，健筆猶能記往還。"]'),
('def019b9-f532-4db3-a501-e402229f43e9','爲謝氏賦流芳','衛宗武','宋','宋诗','song-poetry','','[]','斯文一脈可傳家，囊帛籯金不足誇。',64,'全唐诗/poet.song.218000.json','["斯文一脈可傳家，囊帛籯金不足誇。", "須信詩書涵潤澤，自今庭戶發英華。", "謝蘭輝映方生玉，竇桂香含不斷花。", "不但種芳兼種德，百年之計此爲嘉。"]'),
('f9015ca3-10d8-4a61-9c76-65ead0cb4417','七十生朝製坡帽','衛宗武','宋','宋诗','song-poetry','','[]','喜至生朝疾有瘳，旋裁坡老帽蒙頭。',64,'全唐诗/poet.song.218000.json','["喜至生朝疾有瘳，旋裁坡老帽蒙頭。", "肖形雅稱氅披鶴，緩步何須杖策鳩。", "皓首今爲七十老，黄花更有幾番秋。", "明年準擬拋家宅，水北山南狎野鷗。"]'),
('d84fa0d8-e0ba-48fc-9db3-50ceb5e6df8e','借丹巖韻貽青溪','衛宗武','宋','宋诗','song-poetry','','[]','良朋有約著書催，未到愁雲撥不開。',64,'全唐诗/poet.song.218000.json','["良朋有約著書催，未到愁雲撥不開。", "丹穴孤雲宜間見，青溪隻鶴喜重來。", "有誰剖玉明荆璞，愧我無金築隗臺。", "鄭校子衿佻達久，擬延尼父鑄顔回。"]'),
('02753d98-77e2-44c0-9140-7bc5c7133d20','和丹巖述志  其一','衛宗武','宋','宋诗','song-poetry','','[]','蠹簡鑽研眼欲穿，讀書何似夏侯玄。',64,'全唐诗/poet.song.218000.json','["蠹簡鑽研眼欲穿，讀書何似夏侯玄。", "文傳可使紙增價，酒盡何妨尊屢眠。", "唾落成珠皆至寶，筆耕有粟勝良田。", "席珍儘足需時聘，經史何勞手更編。"]'),
('8a3f9237-bcec-4c8f-8f76-25b950f7da31','和丹巖述志  其二','衛宗武','宋','宋诗','song-poetry','','[]','室罄囊空氣不衰，朶頤寧肯舍靈龜。',64,'全唐诗/poet.song.218000.json','["室罄囊空氣不衰，朶頤寧肯舍靈龜。", "多金未羨陶朱富，淅玉姑爲杜老炊。", "暖客情難到貂鼠，惠人智不及蒲葵。", "春風可笑隨流俗，不長桃枝長棘枝。"]'),
('96b8a95a-77e2-43b4-b49c-6f134b761f89','和丹巖入屋韻','衛宗武','宋','宋诗','song-poetry','','[]','得廬莫恨太婆娑，繚以芳蘅葺以荷。',64,'全唐诗/poet.song.218000.json','["得廬莫恨太婆娑，繚以芳蘅葺以荷。", "徙舍借車家具少，架書充棟手編多。", "且甘窮巷飲瓢樂，須有文朋載酒過。", "他日不妨更爽塏，詩人寧遜庾并羅。"]'),
('bcefccb4-7764-49bb-8340-18f50f21071b','代餞行  其一','衛宗武','宋','宋诗','song-poetry','','[]','比來長掾宰如君，退食時惟儒士親。',64,'全唐诗/poet.song.218000.json','["比來長掾宰如君，退食時惟儒士親。", "編簡香中猶得味，簿書叢底不沾塵。", "乍交祇恨過從淺，每到須蒙問勞頻。", "多少清風留鶴國，不堪折柳向西津。"]'),
('5f40a617-3419-4861-af91-8d7d5fb6bae4','代餞行  其二','衛宗武','宋','宋诗','song-poetry','','[]','下車人已誦廉平，三載松江著令名。',64,'全唐诗/poet.song.218000.json','["下車人已誦廉平，三載松江著令名。", "敏則有功無滯事，惠而爲政及疲氓。", "班班可紀郡曹美，去去先馳臺掾聲。", "騰實蜚英聞北闕，佇看紫詔趣亨程。"]'),
('167a7dbd-b786-4439-a15d-cab20a52c8e0','和戚秋澗遺詩  其一','衛宗武','宋','宋诗','song-poetry','','[]','登金步玉信無緣，二十年來喜服田。',64,'全唐诗/poet.song.218000.json','["登金步玉信無緣，二十年來喜服田。", "肯羨鳴春爲候鳥，自甘飲露作寒蟬。", "嗜閒倦舉吟風筆，歎老貧無釣月船。", "但得有錢供客醉，絕勝名字掛凌煙。"]'),
('4e5b7a5e-c3ad-4629-872e-379aa1961cab','和戚秋澗遺詩  其二','衛宗武','宋','宋诗','song-poetry','','[]','欲廢推敲幾歲華，詩葩君至復萌芽。',64,'全唐诗/poet.song.218000.json','["欲廢推敲幾歲華，詩葩君至復萌芽。", "吟章既富舊成帙，生計無多新載家。", "胸著古今書拍塞，墨行真草字橫斜。", "年逾八十身方健，高把松喬壽未涯。"]'),
('f53712c0-9f67-4c7f-9e46-205a8a793d0d','偶成','衛宗武','宋','宋诗','song-poetry','','[]','平生夢不遇邯鄲，學道求仙興已闌。',64,'全唐诗/poet.song.218000.json','["平生夢不遇邯鄲，學道求仙興已闌。", "旋改詩編入新刻，重尋琴譜發清彈。", "不慚晚境爲寒峻，翻笑當年慕熱官。", "志業無成年及耄，那知身反誤儒冠。"]'),
('9be32811-d848-4f73-a72c-d51e3a85dd79','爲鄉人賦心田','衛宗武','宋','宋诗','song-poetry','','[]','方寸良疇人共有，能耕能斂幾人知。',64,'全唐诗/poet.song.218000.json','["方寸良疇人共有，能耕能斂幾人知。", "坦平非有山河界，存養何殊雨露滋。", "盍剖藩籬忘彼我，却明畦畛別公私。", "儘多陰隲於中種，播穫當爲百世菑。"]'),
('79a07660-4364-40fc-b6fa-e7c410811c92','宣妙寺偶成','衛宗武','宋','宋诗','song-poetry','','[]','孤寺蕭然寄碧岑，塵無半點到僧門。',64,'全唐诗/poet.song.218000.json','["孤寺蕭然寄碧岑，塵無半點到僧門。", "風傳鐘鼓萬家縣，山遶犁鋤十里村。", "一榻高眠慨今夕，八窗洞達納乾坤。", "此行梅月孤良覿，雨打寒林晚復昏。"]'),
('432feeff-3822-4f69-a319-c600261037ac','賦宣妙院古柏','衛宗武','宋','宋诗','song-poetry','','[]','飽經三百載風霜，幾見林間古木僵。',64,'全唐诗/poet.song.218000.json','["飽經三百載風霜，幾見林間古木僵。", "修骨蛻龍鱗甲長，繁柯擎鳳羽毛蒼。", "孤高獨與風雲會，葱蒨深藏雨露香。", "寄語山靈須愛護，殷勤重賦角弓章。"]'),
('650308bb-9ee0-4fd8-b6a7-e3f331ff0969','和南塘嘲謔','衛宗武','宋','宋诗','song-poetry','','[]','理存成壞與虧全，人事悲懽莫不然。',64,'全唐诗/poet.song.218000.json','["理存成壞與虧全，人事悲懽莫不然。", "梅帳道人新活計，柳枝歌妓舊因緣。", "斷絃謾說鸞膠續，剜肉難將獺髓填。", "更遣青裙並赤脚，獨將琴冊寄餘年。"]'),
('11b1de0d-6cff-418a-99bd-ac3ff80462da','過吳興城','衛宗武','宋','宋诗','song-poetry','','[]','兩溪浮玉浸晴空，萬井樓臺一葦通。',64,'全唐诗/poet.song.218000.json','["兩溪浮玉浸晴空，萬井樓臺一葦通。", "舟過恍如蓬島客，人行疑在廣寒宮。", "青山迎送猶佳友，綠鬢往來成老翁。", "遐想坡仙莘老輩，邇來那復有遺風。"]'),
('eebdac0b-56c5-4075-8937-81c73914034e','過安吉城','衛宗武','宋','宋诗','song-poetry','','[]','一年兩到吳興郡，夢想往時雲錦鄉。',64,'全唐诗/poet.song.218000.json','["一年兩到吳興郡，夢想往時雲錦鄉。", "敗堞頹垣尚圍遶，雕梁畫楝總凄凉。", "蕭蕭適際風寒候，黯黯全無山水光。", "日暮樓頭鳴鼓角，聲聲悲壯斷人腸。"]'),
('8350ecab-de2b-4301-b88b-8218a45ee660','過荻塘次韻','衛宗武','宋','宋诗','song-poetry','','[]','平林歷歷曉雲迷，津堠將迎客棹西。',64,'全唐诗/poet.song.218000.json','["平林歷歷曉雲迷，津堠將迎客棹西。", "千古興亡泰伯國，一川經緯狄公堤。", "雨添柳色成蛾綠，春剩花香散麝臍。", "去去苕城知不遠，摩挲老眼看山溪。"]'),
('9693a72e-ceb6-4378-9de0-a9b674222eb9','次韻答柯提幹','衛宗武','宋','宋诗','song-poetry','','[]','年來人物慨凋零，義重交盟嵩華輕。',64,'全唐诗/poet.song.218000.json','["年來人物慨凋零，義重交盟嵩華輕。", "一葦匪遥秋水隔，兩章相映夜光明。", "乾坤何日可還古，風月於人無異情。", "姑把愁懷寄觴詠，出門一笑九山橫。"]'),
('352b12c8-fac2-4603-a957-80956804f808','和葉幹慶七秩詩','衛宗武','宋','宋诗','song-poetry','','[]','不圖聞達老何求，久矣甘爲農服疇。',64,'全唐诗/poet.song.218000.json','["不圖聞達老何求，久矣甘爲農服疇。", "晚歲但知書甲子，希年徒自富春秋。", "作朋何敢班耆父，招隠猶堪共釣遊。", "寄語紛紛朝市客，狐裘未必似羊裘。"]'),
('3264ce70-7dfa-4ed7-a838-f04c0439b786','和王總幹韻','衛宗武','宋','宋诗','song-poetry','','[]','碑銘細讀識前人，貽後無非舊典刑。',64,'全唐诗/poet.song.218000.json','["碑銘細讀識前人，貽後無非舊典刑。", "宦業傳家守清白，儒科繼祖播芳馨。", "縶駒共歎淹場藿，鳴鹿終當歌野芩。", "千古斯文應不泯，待將辭藻掞天庭。"]'),
('31abfd1d-229a-41f2-95ab-785ff84098c1','挽都務弟  其一','衛宗武','宋','宋诗','song-poetry','','[]','功名剩擬著先鞭，永訣於今十九年。',64,'全唐诗/poet.song.218000.json','["功名剩擬著先鞭，永訣於今十九年。", "地下那知多歲月，人間別是一乾坤。", "生前桂籍身如在，死後芸編子竝傳。", "己巳歸藏無欠事，獨憐埋玉重凄然。"]'),
('3f58b6bd-a6e1-4100-9d29-af7a6466ea99','挽都務弟  其二','衛宗武','宋','宋诗','song-poetry','','[]','襲舛承訛俗尚仝，爲謀所喜適吾從。',64,'全唐诗/poet.song.218000.json','["襲舛承訛俗尚仝，爲謀所喜適吾從。", "傷心幾載鴒原夢，灑淚今朝馬鬣封。", "梁棟材嗟空故木，珠璣香喜長新松。", "最忻壤樹首丘正，祖壠葱葱佳氣鍾。"]'),
('5e0f6230-41ae-4964-8a96-f8631472f53b','挽林梅癯','衛宗武','宋','宋诗','song-poetry','','[]','晚擢亞科躋憲掾，擬航選海竟無緣。',64,'全唐诗/poet.song.218000.json','["晚擢亞科躋憲掾，擬航選海竟無緣。", "苦吟方與甫俱瘦，疏影俄隨逋已仙。", "谷水吟編多手澤，廣陵琴趣得心傳。", "年幾八秩身何憾，老友凋零重愴然。"]'),
('ad4013c1-8796-4383-98e9-33d947553a6b','挽王總幹父知縣','衛宗武','宋','宋诗','song-poetry','','[]','蜀溪名閥世爲儒，祖擢巍科子亦如。',64,'全唐诗/poet.song.218000.json','["蜀溪名閥世爲儒，祖擢巍科子亦如。", "從仕爲民辭薦牘，移忠有後竟懸車。", "一生冰蘗節愈厲，兩度絃歌政可書。", "共擬瀧碑表親墓，詎知簪笏化犁鋤。"]'),
('8f5ded6b-b552-41cc-af6a-4a19cca2bb80','春日','衛宗武','宋','宋诗','song-poetry','','[]','化工溥至仁，生機運不停。',24,'全唐诗/poet.song.218000.json','["化工溥至仁，生機運不停。", "榮觀徧原野，宇宙一丹青。"]'),
('7a804cfa-018d-4bf6-a63a-1446a934f53a','望霽','衛宗武','宋','宋诗','song-poetry','','[]','陰陽互闔闢，宇宙幾洪荒。',24,'全唐诗/poet.song.218000.json','["陰陽互闔闢，宇宙幾洪荒。", "重明麗乎正，萬象生輝光。"]'),
('f480ad3c-4609-485e-8ed1-9d7ea7259936','覽古','衛宗武','宋','宋诗','song-poetry','','[]','治忽無常形，今古無常勢。',24,'全唐诗/poet.song.218000.json','["治忽無常形，今古無常勢。", "必有非常人，以制非常世。"]'),
('68282c8b-41ea-457f-91e9-bc45f3018de7','和黄山秋吟','衛宗武','宋','宋诗','song-poetry','','[]','有山靜而秀，有水清且漪。',24,'全唐诗/poet.song.218000.json','["有山靜而秀，有水清且漪。", "風霜空宿翳，草木含幽姿。"]'),
('47087dcc-0e18-46c8-8fc6-c1c063adc0e5','題畫軸卷後','衛宗武','宋','宋诗','song-poetry','','[]','林阜玉參差，寒烏千萬斯。',24,'全唐诗/poet.song.218000.json','["林阜玉參差，寒烏千萬斯。", "直疑飛繞處，錯認月明枝。"]'),
('bdafd588-4fc1-4771-bb15-a6713b93fa9b','蜘蛛','衛宗武','宋','宋诗','song-poetry','','[]','經緯智何多，網張猶設羅。',24,'全唐诗/poet.song.218000.json','["經緯智何多，網張猶設羅。", "但知爲物穽，更有物誰何。"]'),
('9e55d6df-ffdb-411c-acea-eca4c070bbf8','蜂','衛宗武','宋','宋诗','song-poetry','','[]','爲巢倒懸樹，竅竅自成房。',24,'全唐诗/poet.song.218000.json','["爲巢倒懸樹，竅竅自成房。", "螫人雖有毒，終爲人所傷。"]'),
('13cee594-a989-4b3d-bdf9-c3d1e86fac99','蠅虎','衛宗武','宋','宋诗','song-poetry','','[]','狀有類蛛蝥，見物常勇投。',24,'全唐诗/poet.song.218000.json','["狀有類蛛蝥，見物常勇投。", "奮身如虎猛，所得亦蠅頭。"]'),
('2ae62425-b854-48b7-b445-5785f68a831b','詠蠅','衛宗武','宋','宋诗','song-poetry','','[]','營營止于棘，或赤而或黑。',24,'全唐诗/poet.song.218000.json','["營營止于棘，或赤而或黑。", "皓皓染成汙，姦魂併佞魄。"]'),
('6226a4ab-0189-4a2e-a3ed-15dd1297c51e','螢','衛宗武','宋','宋诗','song-poetry','','[]','本從腐草生，聚爲寒士燈。',24,'全唐诗/poet.song.218000.json','["本從腐草生，聚爲寒士燈。", "一朝書課效，功寧不汝矜。"]'),
('d0add6d9-6423-40af-8673-375d5d515e6b','絕交','衛宗武','宋','宋诗','song-poetry','','[]','北山有鳴鴞，不潔而嗤鳳。',24,'全唐诗/poet.song.218000.json','["北山有鳴鴞，不潔而嗤鳳。", "宜下絕交書，塤箎非伯仲。"]'),
('4f0c5dce-cc87-437b-a6b8-e667297be2e9','次韻賦蠟梅  其一','衛宗武','宋','宋诗','song-poetry','','[]','將到窮冬寂寞鄉，誰知花事未渠央。',32,'全唐诗/poet.song.218000.json','["將到窮冬寂寞鄉，誰知花事未渠央。", "最憐剪蠟翻新樣，却笑燒鉛作素粧。"]'),
('e768d606-fd42-462d-8a3a-df6385a5b16f','次韻賦蠟梅  其二','衛宗武','宋','宋诗','song-poetry','','[]','能向早梅前獨秀，何妨秋卉後纔香。',32,'全唐诗/poet.song.218000.json','["能向早梅前獨秀，何妨秋卉後纔香。", "祇嫌一種開何晚，直待東風爲發揚。"]'),
('85f94f37-43d2-42c1-90f3-072d4d703c02','和詠梅  其一','衛宗武','宋','宋诗','song-poetry','','[]','獨占東風第一籌，孤芳不與衆芳侔。',32,'全唐诗/poet.song.218000.json','["獨占東風第一籌，孤芳不與衆芳侔。", "飄零猶待調金鼎，未逐凡花浪蕊休。"]'),
('241a79ed-166d-47b7-9eac-3cd2ab9eed9f','和詠梅  其二','衛宗武','宋','宋诗','song-poetry','','[]','點檢春工首到梅，枝枝羞澀未全開。',32,'全唐诗/poet.song.218000.json','["點檢春工首到梅，枝枝羞澀未全開。", "試看詩句相料理，換得清香入夢來。"]'),
('f85611ba-cc3a-4a2d-bb7d-8753d3b025d3','和詠梅  其三','衛宗武','宋','宋诗','song-poetry','','[]','年前疎秀明於雪，年後芬敷蓊若雲。',32,'全唐诗/poet.song.218000.json','["年前疎秀明於雪，年後芬敷蓊若雲。", "有色有香尤耐久，十分春事占三分。"]'),
('ac0dd204-8d78-434b-8171-e4a60523f62a','春日','衛宗武','宋','宋诗','song-poetry','','[]','天公要與物爲春，人事紛紛藹若雲。',32,'全唐诗/poet.song.218000.json','["天公要與物爲春，人事紛紛藹若雲。", "錦繡山川誰管領，祇應魚鳥得平分。"]'),
('3a03d9d8-2b2e-4796-8837-3df5f44b6c07','和海棠韻','衛宗武','宋','宋诗','song-poetry','','[]','鬢霧鬟雲襯臉紅，嫣然一笑倚春風。',32,'全唐诗/poet.song.218000.json','["鬢霧鬟雲襯臉紅，嫣然一笑倚春風。", "直疑傾國傾城魄，聚入此花顔色中。"]'),
('606f1593-92fa-4b44-93d5-360c7580969b','爲慈上人賦雲溪  其一','衛宗武','宋','宋诗','song-poetry','','[]','油然出岫擘晴綿，點綴青空水接天。',32,'全唐诗/poet.song.218000.json','["油然出岫擘晴綿，點綴青空水接天。", "心跡兩閒無俗累，靜觀飛躍樂魚鳶。"]'),
('8c0d9859-0ba1-4e1b-8437-0a4617f682ce','爲慈上人賦雲溪  其二','衛宗武','宋','宋诗','song-poetry','','[]','白衣蒼狗任從渠，不礙波涵一太虛。',32,'全唐诗/poet.song.218000.json','["白衣蒼狗任從渠，不礙波涵一太虛。", "雅契高僧方寸地，卷舒流止自如如。"]'),
('1142e439-32f7-4284-beb9-ab0c48d18024','和象翁絕句  其一','衛宗武','宋','宋诗','song-poetry','','[]','春花色色俱成夢，夏實纍纍結滿枝。',32,'全唐诗/poet.song.218000.json','["春花色色俱成夢，夏實纍纍結滿枝。", "獨有葵榴媚清晝，薰風時度五絃詩。"]'),
('10fcb84c-0668-462d-b5be-54397684e79e','和象翁絕句  其二','衛宗武','宋','宋诗','song-poetry','','[]','恰好軒窗傍竹開，絕勝舞榭與歌臺。',32,'全唐诗/poet.song.218000.json','["恰好軒窗傍竹開，絕勝舞榭與歌臺。", "樅樅甲刃丈夫立，彈壓炎威不敢來。"]'),
('93be692a-9c35-4372-a79d-5a1f77e5ed1c','和象翁絕句  其三','衛宗武','宋','宋诗','song-poetry','','[]','舟行必水陸行車，此地無桑只種麻。',32,'全唐诗/poet.song.218000.json','["舟行必水陸行車，此地無桑只種麻。", "安得野蠶生活萬，化成絲繭徧家家。"]'),
('6bd2362c-f6e8-45ce-b8e0-f1896f426656','和象翁絕句  其四','衛宗武','宋','宋诗','song-poetry','','[]','浮生一夢寄南柯，烏兔雙馳迅若梭。',32,'全唐诗/poet.song.218000.json','["浮生一夢寄南柯，烏兔雙馳迅若梭。", "世事如棋知幾變，捄時無著奈時何。"]'),
('e58e08b1-0605-466e-80ca-274c7c9ece14','和丹巖  其一','衛宗武','宋','宋诗','song-poetry','','[]','芳事從今鼎鼎來，看看花片撲樓臺。',32,'全唐诗/poet.song.218000.json','["芳事從今鼎鼎來，看看花片撲樓臺。", "一和既盎寒如掃，錦繡香中圖畫開。"]'),
('1e75c534-76a0-4c93-914c-2309aa42b9bb','和丹巖  其二','衛宗武','宋','宋诗','song-poetry','','[]','玉女裁花撒碎瓊，寒威凜凜壓山屏。',32,'全唐诗/poet.song.218000.json','["玉女裁花撒碎瓊，寒威凜凜壓山屏。", "消殘猶自衒天巧，點綴裙腰一半青。"]'),
('daaf419b-aa8c-4c15-8826-6e506fa8a01a','和丹巖  其三','衛宗武','宋','宋诗','song-poetry','','[]','絳帷深密障嚴霜，衿佩芬芳聚一堂。',32,'全唐诗/poet.song.218000.json','["絳帷深密障嚴霜，衿佩芬芳聚一堂。", "竹外琅琅聽春誦，咿唔聲裏带詩香。"]'),
('64908a83-91e9-4b50-90ed-2ce2c78e93de','和丹巖  其四','衛宗武','宋','宋诗','song-poetry','','[]','一片花飛未減春，方來赬紫蓋如雲。',32,'全唐诗/poet.song.218000.json','["一片花飛未減春，方來赬紫蓋如雲。", "新晴賸擬扶鳩杖，試探芳辰有幾分。"]'),
('649f2db9-be6e-4666-b562-aa8c8a0a99ee','和丹巖  其五','衛宗武','宋','宋诗','song-poetry','','[]','餘寒威壓皚浮瓊，粉黛羣空欠肉屏。',32,'全唐诗/poet.song.218000.json','["餘寒威壓皚浮瓊，粉黛羣空欠肉屏。", "欲著春衫憶纖手，不勞陸展染青青。"]'),
