('58aa9c43-bddf-4eb8-a606-579ae26b57b1','閲道書  其一','衛宗武','宋','宋诗','song-poetry','','[]','穆穆皇皇九五居，舍儒爲政豈良圖。',32,'全唐诗/poet.song.218000.json','["穆穆皇皇九五居，舍儒爲政豈良圖。", "不思濟世思超世，佞佛求僊總是愚。"]'),
('ac79e592-1d30-4e7a-9fc6-6e21fa3395d5','閲道書  其二','衛宗武','宋','宋诗','song-poetry','','[]','抱璞含和道俗同，寥寥萬代想皇風。',32,'全唐诗/poet.song.218000.json','["抱璞含和道俗同，寥寥萬代想皇風。", "後來賢智知多少，未似當年牧馬童。"]'),
('268b5949-6520-4c6a-ac82-b09ef1b78f28','出城山墓域行至趙村','衛宗武','宋','宋诗','song-poetry','','[]','纔出城山路，雲收霽景呈。',48,'全唐诗/poet.song.218000.json','["纔出城山路，雲收霽景呈。", "乾端頓軒豁，山色更晶明。", "遠近煙村露，微茫野水橫。", "平頭今七十，此地幾經行。"]'),
('94e35e0f-cad1-496e-867a-d5b1af5b97a6','至霅白莞澤步入唐村','衛宗武','宋','宋诗','song-poetry','','[]','舍舟而從陸，邐迤步巑岏。',132,'全唐诗/poet.song.218000.json','["舍舟而從陸，邐迤步巑岏。", "綠畦平野寬，青嶂四面還。", "春容千萬狀，平挹跬步間。", "行行二十里，窈窕入我山。", "故山迎故人，禽鳥俱懽顔。", "清泉響琚珮，列峰擁髻鬟。", "回視塵囂廛，相去隔幾關。", "幽谷多白雲，可與相對閒。", "不妨自吟哦，但恐好句慳。", "更須窮勝事，尚喜兩脚頑。", "皇皇欲何之，並遊當忘還。"]'),
('46cd3d46-8756-4b6b-b7d8-6332af03608c','耕漁處','衛宗武','宋','宋诗','song-poetry','','[]','清漣萬頃渟爲湖，湛湛一鏡涵太虛。',210,'全唐诗/poet.song.218000.json','["清漣萬頃渟爲湖，湛湛一鏡涵太虛。", "其旁鱗次田莓莓，四望沃若皆膏腴。", "蔬畦麥隴間碧樹，洲蘋岸蓼連平蕪。", "水村落照晚鍾寺，中有一山成畫圖。", "鄭谷無此寬閒野，嚴瀨無此浩渺區。", "更於何所堪下釣，更於何所堪荷鋤。", "誰與卜築於此居，峨然其冠孔氏徒。", "時哉不偶堪遯世，垂緡把耒以自娛。", "興來風月入吟嘯，錯落吐出鮫盤珠。", "人惟內省有足樂，眇視外物芻狗如。", "膏粱於此且不願，況爲鱣鮪而施罛。", "則知之子命名者，是特寄意耕與漁。", "豈亦伯成子高之在野，莊周濠上之觀魚。"]'),
('47725a65-0632-4827-a73b-656fa8666f3e','雁來紅','孫吳會','宋','宋诗','song-poetry','','[]','眩碧成朱被眼瞞，分明是葉作花看。',32,'全唐诗/poet.song.218000.json','["眩碧成朱被眼瞞，分明是葉作花看。", "道人本不知香色，只與窗前草一般。"]'),
('62f7bea7-4853-403c-b98e-2023d7282854','句','孫吳會','宋','宋诗','song-poetry','','[]','遊人只解遊晴晝，風雨朝昏盡屬君。',16,'全唐诗/poet.song.218000.json','["遊人只解遊晴晝，風雨朝昏盡屬君。"]'),
('2ecfcf22-eb64-42fc-b81b-ef0b02a0d3ca','秋晚懷友','程洙','宋','宋诗','song-poetry','','[]','長亭一樽酒，猶記別時斟。',48,'全唐诗/poet.song.218000.json','["長亭一樽酒，猶記別時斟。", "碧草思前夢，黄花見此心。", "關河秋北望，天地日西沈。", "遥想山中桂，何人月下吟。"]'),
('1a5d0e3d-9b5d-444f-9a06-6b1050c267fe','雨晴','程洙','宋','宋诗','song-poetry','','[]','溪雨生流水，山晴出白雲。',48,'全唐诗/poet.song.218000.json','["溪雨生流水，山晴出白雲。", "花來風逐逐，泥遣燕紛紛。", "客路猶千里，春光已十分。", "歸從都下者，相遇說新聞。"]'),
('e1f9f287-fd6a-4b60-a971-c0995558ff50','奉送丞相訥齋程先生二首  其一','程洙','宋','宋诗','song-poetry','','[]','先生富貴本無心，冰節從來照士林。',64,'全唐诗/poet.song.218000.json','["先生富貴本無心，冰節從來照士林。", "三載調元名愈重，七章告老意何深。", "九重屢挽音形玉，一念難回歸散金。", "此是吾邦真偉事，清風萬古孰追尋。"]'),
('66e35745-d049-4c6f-868f-d5252db96873','奉送丞相訥齋程先生二首  其二','程洙','宋','宋诗','song-poetry','','[]','公相胸中藴識幾，中和不假佩弦韋。',64,'全唐诗/poet.song.218000.json','["公相胸中藴識幾，中和不假佩弦韋。", "人心未免自强弱，公論何嘗無是非。", "歲到寒時知勁節，事當難處見圓機。", "便須再出扶宗社，未許從容戀翠微。"]'),
('d92bc6ea-8211-4341-b211-92c255eeea7a','玉山道上','鄧有功','宋','宋诗','song-poetry','','[]','玉谿谿上雨聲乾，日暮東風客衲寒。',32,'全唐诗/poet.song.218000.json','["玉谿谿上雨聲乾，日暮東風客衲寒。", "數樹梅花吹作雪，行人猶自倚闌干。"]'),
('4bbd83a0-97f3-4dc2-9ca6-662338ba1b50','客信豐寄劉起潛  其一','鄧有功','宋','宋诗','song-poetry','','[]','怪得寒燈昨夜花，五更歸夢倏還家。',32,'全唐诗/poet.song.218000.json','["怪得寒燈昨夜花，五更歸夢倏還家。", "多情兒女傷離別，爭挽征衫問鬢華。"]'),
('b9e826ca-7401-44de-b852-1f703f37fc2f','客信豐寄劉起潛  其二','鄧有功','宋','宋诗','song-poetry','','[]','魚苗客子去成羣，野笑狂歌慢慢行。',32,'全唐诗/poet.song.218000.json','["魚苗客子去成羣，野笑狂歌慢慢行。", "三十里頭齊頓住，聞官早過吉州城。"]'),
('8d65e3f2-6f32-43f6-b092-f7cdf60f371d','客信豐寄劉起潛  其三','鄧有功','宋','宋诗','song-poetry','','[]','錦衣戍卒豎霜矛，彈壓鹽丁過嶺頭。',32,'全唐诗/poet.song.218000.json','["錦衣戍卒豎霜矛，彈壓鹽丁過嶺頭。", "三月聞韶堪歎息，南中還是一年憂。"]'),
('2c307a95-ef98-4752-abaa-d0549ef1a90b','客信豐寄劉起潛  其四','鄧有功','宋','宋诗','song-poetry','','[]','嶺南咫尺莫如虔，和暖嚴寒別有天。',32,'全唐诗/poet.song.218000.json','["嶺南咫尺莫如虔，和暖嚴寒別有天。", "一夜詩魂清到骨，曉霜封却釣魚船。"]'),
('560855ff-2cce-41cd-9c1d-08fd01de0e67','賀劉掞赴召史館校勘','鄧有功','宋','宋诗','song-poetry','','[]','秋堂風露聲唔咿，青燈一點昏兩眵。',224,'全唐诗/poet.song.218000.json','["秋堂風露聲唔咿，青燈一點昏兩眵。", "蟫魚蠹紙老白日，未識心宇包黄羲。", "麟膠飲盡霜兔泣，儷花鬭葉紛奇姿。", "少年輕裘舌秦衍，睥睨六印京塵緇。", "平生眼底厭糠秕，自對春風樂沂水。", "搜奇抉怪問子雲，載酒歸來成獨醉。", "金刀喜有南鄰翁，曾吹藜焰丹霞峰。", "白雲滿榻呼不起，斜日倚仗酣秋空。", "紫皇一夕下綸旨，細祓丹鉛勘文字。", "會將一語贊陽秋，高入九天卑九地。", "聖明勛業琬琰儲，不獨焜燿冰銜書。", "兩朝蒐輯摩日月，往往呼喝羞庭衢。", "廬陵健筆人莫贖，南豐瓣香竟誰續。", "西江浩浩流古今，莫遣白頭愧青竹。"]'),
('8acc1348-8270-4a7a-926b-e7d3b0af698f','送曾子華遊贛','鄧有功','宋','宋诗','song-poetry','','[]','丈夫達有遇，出令走千里。',168,'全唐诗/poet.song.218000.json','["丈夫達有遇，出令走千里。", "焚香玩太空，宴坐塵不起。", "云胡子曾子，不自樂沂水。", "風烟挾兩袖，足跟尚芒履。", "持被直承明，三省良未巳。", "觀君氣如虹，接淅亦可美。", "昔年子長游，落筆妙信史。", "三蘇出岷峨，文章仰歐子。", "此行崆峒嶺，萬事寧足侈。", "鬰孤有奇觀，佳句公摩洗。", "予生事斗室，出若畏瀾蠡。", "長安歌狹邪，神鼎鑄螭鬽。", "窮通匪同途，動靜實一理。", "時止復時行，願與參此義。"]'),
('6e0d2807-5577-436d-abce-76028ed3725d','遣興  其一','吳汝弌','宋','宋诗','song-poetry','','[]','弱齡性淡泊，鄭圃吾其師。',96,'全唐诗/poet.song.218000.json','["弱齡性淡泊，鄭圃吾其師。", "及茲拙生事，窮窘常經時。", "無方可紆急，何以宣中懷。", "柴門蔽殘席，咏書倦徘徊。", "呼兒促觴至，目翫天雲飛。", "山鳥送新響，日遲花露滋。", "頹然醉簷下，不省何如時。", "雖非富貴樂，富貴乃所乖。"]'),
('7b111940-74ad-4786-8a5b-b51ef90bdb90','遣興  其二','吳汝弌','宋','宋诗','song-poetry','','[]','疎松碎明月，密竹篩清風。',72,'全唐诗/poet.song.218000.json','["疎松碎明月，密竹篩清風。", "親交昔與別，若謂行相從。", "延企邈不及，音容隨想生。", "諒彼亦耿耿，飛爽留空形。", "援琴不能寐，意乃多於聲。", "晤言豈無偶，眷眷詎可忘。"]'),
('3fde318c-bcaa-4858-bdff-366367b29b2e','遣興  其三','吳汝弌','宋','宋诗','song-poetry','','[]','編蓬諧夙心，尊古豈文義。',84,'全唐诗/poet.song.218000.json','["編蓬諧夙心，尊古豈文義。", "所得靡有言，應酬聊爾耳。", "室中無萊婦，童弱偶成四。", "團欒寧無思，達此天亦蛻。", "客來問長鬚，新醅可篘未。", "行行陟高岡，一顧俯煙水。", "客去不肯留，吾歸且休矣。"]'),
('8b27ab63-0850-4e22-b6b0-bc8990bc2662','歲終呈一齋  其一','吳汝弌','宋','宋诗','song-poetry','','[]','磊砢千丈松，清陰蔭林丘。',48,'全唐诗/poet.song.218000.json','["磊砢千丈松，清陰蔭林丘。", "豈無棟梁用，匠伯不見收。", "匠伯恐未良，棟梁終有求。", "天風叶偃蓋，五雲常爲浮。"]'),
('b79f2959-8dca-4f3a-8c63-3ac58179d155','歲終呈一齋  其二','吳汝弌','宋','宋诗','song-poetry','','[]','學道非學世，韜精養中和。',48,'全唐诗/poet.song.218000.json','["學道非學世，韜精養中和。", "紆朱各自貴，誰肯聆商歌。", "皦皦大聖心，脗然空自多。", "著書後子雲，千載應不磨。"]'),
('9991f3bb-1f91-41b4-ab89-e4b41ff6ff0c','酬玉汝  其一','吳汝弌','宋','宋诗','song-poetry','','[]','磔攘畢春氣，長嬴換新綠。',48,'全唐诗/poet.song.218000.json','["磔攘畢春氣，長嬴換新綠。", "爽風吹凉光，紉餌釣山淥。", "鯈魚噀水香，菰蒲削藍玉。", "老景結清和，心花委濠濮。"]'),
('3b0cdca3-e5b6-4cb7-a321-53582ce09786','酬玉汝  其二','吳汝弌','宋','宋诗','song-poetry','','[]','日暮雲倒飛，苦雨濕茅屋。',48,'全唐诗/poet.song.218000.json','["日暮雲倒飛，苦雨濕茅屋。", "奇哉五碎金，青草眠黄犢。", "天行貴葆真，心骨迥凡俗。", "一尺黄菊花，秋風播芳馥。"]'),
('dee36c3d-626a-4e2e-9f9c-97d7613b3cfe','遊石仙分韻得觀字','吳汝弌','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','閑攏兩袖秋，步入沖寂觀。',288,'全唐诗/poet.song.218000.json','["閑攏兩袖秋，步入沖寂觀。", "古樹老雲中，仙居毀巖半。", "是時零雨高，葉脫凄風亂。", "怪禽走何忙，澀水流不漫。", "那知張郎仙，譎幻敢懸斷。", "雷書貯紅崖，愚下浪傳贊。", "符碑儻長靈，鬼物豈歌喚。", "尚云劍埋山，安得急推斷。", "冷翁亦張徒，精氣不知散。", "死坐豫樟空，鑿竅競窺看。", "何不葬山原，不然棄江沜。", "烏鳶與螻蟻，豈食吾一貫。", "獨流天地間，萬古亙光燦。", "神仙固渺茫，此事良可惋。", "忍哉偷兒狂，更擣泥腹爛。", "我來擬少休，亭壓不敢玩。", "黄冠四三人，拙野只欲竄。", "延坐無好言，令我住凉館。", "飯餘且縱觀，逸興薄霄漢。", "琴鳴著高彈，弈勝出奇算。", "歗咏壺隠樓，撫事發長嘆。", "大書同人名，聊欲記遊翫。", "陰霾淰輕寒，日色倏昏晏。", "倩人買村醪，煮芋疊肴桉。"]'),
('3459ea49-62f5-4366-9557-e0040572244b','朅來  其一','吳汝弌','宋','宋诗','song-poetry','','[]','嶺上朅來觀白雲，翔鸞奮鶴浮天英。',64,'全唐诗/poet.song.218000.json','["嶺上朅來觀白雲，翔鸞奮鶴浮天英。", "斜開錦繡春樹滿，溶溶半露遥山青。", "忽然變現成蒼狗，萬里長風霍無有。", "海龍塞氣不敢吹，日照虛空無老時。"]'),
('ca14642e-2c83-48c6-8d39-65df5e917d31','朅來  其二','吳汝弌','宋','宋诗','song-poetry','','[]','嶺上朅來弄明月，千里銀光寒不缺。',64,'全唐诗/poet.song.218000.json','["嶺上朅來弄明月，千里銀光寒不缺。", "蝦𢋙魍魎走死盡，直數秋毫上金闕。", "心如此月月如心，嗒然獨據無絃琴。", "騰騰轉空白日晝，詩带流星過南斗。"]'),
('4ea569cb-2ca1-4db8-b001-49f60631a60a','讀柴桑集','余觀復','宋','宋诗','song-poetry','','[]','游心太古初，得句萬物表。',72,'全唐诗/poet.song.218000.json','["游心太古初，得句萬物表。", "平生一罇酒，寂寞三逕小。", "有琴不張絃，正以知音少。", "伊予挹殘芳，道心炯相照。", "北窗清夢長，山間自啼鳥。", "吾欲問先生，天闊白雲杳。"]'),
('1784a6ff-afe2-4d2f-a49d-179f3596c8b4','咏懷','余觀復','宋','宋诗','song-poetry','','[]','山容洗眼青，江光照肌白。',156,'全唐诗/poet.song.218000.json','["山容洗眼青，江光照肌白。", "翻枝鵲查查，抱葉蟬嘖嘖。", "蒹葭摇風聲，梧桐淡秋色。", "草木了無能，陰陽互相激。", "人於大化中，真成逆旅客。", "藏舟夜半移，不假賁育力。", "塵網罩八紘，貪夫受羅織。", "蹇予丘壑姿，一室頗安適。", "荒尋縱奇懷，清詭吊塵迹。", "風摇泛海槎，雨澀登山屐。", "世遠事荒唐，天高興寥閴。", "渺渺孤征鴻，一舉振六翮。", "此意人莫知，獨嘯巖扉寂。"]'),
('460c5629-eb24-47f6-9972-be890071682c','寄伯成  其一','余觀復','宋','宋诗','song-poetry','','[]','昔別青梅酸，今來黄葉墮。',72,'全唐诗/poet.song.218000.json','["昔別青梅酸，今來黄葉墮。", "葉墮却歸根，窗隙見駒過。", "大巧亦自然，小智空瑣瑣。", "一言取封侯，千金賈奇禍。", "達人知倚伏，去就無不可。", "天公亦可爲，妙用正在我。"]'),
('169e4228-bae4-48a2-8527-53b694bafa13','寄伯成  其二','余觀復','宋','宋诗','song-poetry','','[]','風雅不可復，亦乃世代然。',48,'全唐诗/poet.song.218000.json','["風雅不可復，亦乃世代然。", "君看黄初語，已減河梁篇。", "神思透溟涬，至寶辭雕鎸。", "黨欲剩著語，不如寂無言。"]'),
('517dd5de-00f6-4f7c-9a12-5e9f9646faac','梅花引','余觀復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','耨銀雲，鋤璧月，栽得寒花寄愁絕。',252,'全唐诗/poet.song.218000.json','["耨銀雲，鋤璧月，栽得寒花寄愁絕。", "陽和一點來天根，春滿江南誰漏泄。", "珊瑚作樹玉爲膚，沉水熏香檀吐屑。", "野橋橫，寒澗潔，斜梢舞破屋角烟，老樹壓殘牆角雪。", "風流不肯王謝儔，孤高尚笑夷齊劣。", "蕭然與俗最無緣，此話難明向誰說。", "絕愛西湖君，暗香浮動月黄昏。", "亦愛東坡老，竹外一枝斜更好。", "二仙去矣花寂寥，著語壓花花不倒。", "誰能淡筆傳其真，誰能楚語招其魂。", "參橫月落興未了，三叫花神聞不聞。", "花影摇摇情默默，冷透吟脾醒醉魄。", "問渠桃李豈知春，西抹東塗受春役。", "自然香，無色色。", "譙樓角動霜初飛，蕭寺鐘鳴天欲白。", "披衣遶遍樹頭行，判斷人間風月國。"]'),
('c5318894-58b1-4422-89c8-614a94152094','梅花','余觀復','宋','宋诗','song-poetry','','[]','羣卉皆輿隸，孤標真聖賢。',48,'全唐诗/poet.song.218000.json','["羣卉皆輿隸，孤標真聖賢。", "乾坤清不徹，風月興無邊。", "生意春常在，貞心晚更堅。", "騷經雖不載，已入二南篇。"]'),
('20923c96-61dd-43be-8354-14eda4123abf','山居即事','余觀復','宋','宋诗','song-poetry','','[]','密竹環茆舍，應無俗士過。',48,'全唐诗/poet.song.218000.json','["密竹環茆舍，應無俗士過。", "睡濃嫌日出，坐久厭塵多。", "鬭雀翻危葉，饑鵝唼短莎。", "世涂真九曲，奔走欲如何。"]'),
('46d10e18-ca23-437b-aa1f-4ff40d8c7400','梅花','余觀復','宋','宋诗','song-poetry','','[]','自是孤芳集大成，紅紅白白漫爭名。',64,'全唐诗/poet.song.218000.json','["自是孤芳集大成，紅紅白白漫爭名。", "天邊差有雪堪亞，世上更無花敢清。", "筆到花光空幻相，句如和靖藹遺聲。", "一枝勾引窗前月，冷淡相看太古情。"]'),
('b9114433-d433-4711-ab3a-e18aebce1d4e','次韻春日','余觀復','宋','宋诗','song-poetry','','[]','日淡風輕養物華，老天將此付詩家。',64,'全唐诗/poet.song.218000.json','["日淡風輕養物華，老天將此付詩家。", "人情巧似營巢燕，春意忙於赴壑蛇。", "寂寞蘭亭空有感，凄凉金谷竟誰誇。", "絕憐狂甚樊川杜，枉殺吟情豆蔻花。"]'),
('b207c5a4-6d98-4f72-a8d1-2bd79bd15767','次韻','余觀復','宋','宋诗','song-poetry','','[]','榴簇殷紅竹迸青，風驚簷玉一時鳴。',32,'全唐诗/poet.song.218000.json','["榴簇殷紅竹迸青，風驚簷玉一時鳴。", "晚來幽趣無人解，流水聲中看月行。"]'),
('c6f26278-c66f-4728-892d-6eb0b40748a2','步遶','余觀復','宋','宋诗','song-poetry','','[]','步遶蒼苔自詠詩，吟情惟有澗泉知。',32,'全唐诗/poet.song.218000.json','["步遶蒼苔自詠詩，吟情惟有澗泉知。", "山猿忽地來偷果，攀斷庭前烏桕枝。"]'),
('26c661b5-515b-4195-986f-8048f383d1f3','木犀','余觀復','宋','宋诗','song-poetry','','[]','盤盤老桂樹，金屑黄𩰀鬆。',96,'全唐诗/poet.song.218000.json','["盤盤老桂樹，金屑黄𩰀鬆。", "孕此無盡香，襲襲乘西風。", "幽人爲延佇，古意滋無窮。", "王孫招不來，西郊草蒙茸。", "欲以遺遠者，道阻嗟難從。", "□□不忍替，攬之寄房櫳。", "夢魂怳而清，夜午超鴻濛。", "常恐芳氣歇，我恨何時終。"]'),
('ccbcbf38-4c45-4515-8d6b-0ce3874e74a3','堯任舜禹行','釋文珦','宋','宋诗','song-poetry','','[]','堯任舜禹，聖化日熙。',240,'全唐诗/poet.song.218000.json','["堯任舜禹，聖化日熙。", "二臣至德，惟堯克知。", "明良胥會，徵庸弗疑。", "佐命垂統，股肱綱維。", "行堯之道，蚤夜孳孳。", "上齊七政，大錄萬幾。", "與人爲善，念茲在茲。", "舉相去凶，咨牧授時。", "執德於心，其化若馳。", "洪水滔天，浩浩無涯。", "下民昏墊，荒度爲宜。", "乃乘四載，奠決刊隨。", "櫛風沐雨，手胼足胝。", "四海會同，九澤具陂。", "誕敷文德，帝命是祗。", "翔泳咸若，鳳皇來儀。", "堯嘉厥功，翕受敷施。", "同聲相應，百僚師師。", "是知官人，安危之基。", "用賢則安，用佞則危。", "惟彼陶唐，百工允釐。", "後世有述，先天弗違。", "能賞能禪，纘承伏犧。", "爲民之極，黄收純衣。"]'),
('c0799290-92dd-4bea-8e4d-e242d2609c1d','天地無窮行','釋文珦','宋','宋诗','song-poetry','','[]','天地無窮，人處于中。',160,'全唐诗/poet.song.218000.json','["天地無窮，人處于中。", "三才既兆，庶類皆通。", "至聖立極，萬方所宗。", "如星拱北，如水朝東。", "垂衣而治，天下爲公。", "孝慈道廣，是謂大同。", "自茲而降，謀用是崇。", "兵由此起，彊弱相攻。", "上下分亂，莫知適從。", "匪茲禮義，曷能靖共。", "順之者吉，逆之者凶。", "不能率此，斯曰顓蒙。", "窮通得喪，實維降衷。", "巧愚不與，係於遭逢。", "毋肆小智，以菑厥功。", "安時處順，於焉考終。"]'),
('5d3f5fee-84c7-4bcd-a17d-d3d432626736','天道夷簡行','釋文珦','宋','宋诗','song-poetry','','[]','天道夷簡，蕩蕩巍巍。',200,'全唐诗/poet.song.218000.json','["天道夷簡，蕩蕩巍巍。", "人心不然，大行險巇。", "轉眼翻覆，誠不易知。", "忠或見疎，信或見疑。", "離間致入，寧復顧思。", "昔者繾綣，終焉棄遺。", "聖如周公，王猶不知。", "孝若申生，姬能死之。", "在彼盛時，尚有爾爲。", "况乎季世，顛倒是非。", "讒人飽祿，志士苦饑。", "俯仰今古，其誰不悲。", "命懸于天，逆之爲嗤。", "沖靜無患，進取必危。", "守道安危，其殆庶幾。", "禍福之兆，可以理推。", "夷齊去周，西山採薇。", "黄綺避秦，商巖茹芝。", "景行先哲，良足爲規。", "規而罔念，雖悔何追。"]'),
('b14fd6a9-7b47-44fd-b165-cee19a3e6107','天道雖遠行','釋文珦','宋','宋诗','song-poetry','','[]','天道雖遠，人心匪殊。',160,'全唐诗/poet.song.218000.json','["天道雖遠，人心匪殊。", "內直不欺，與天爲徒。", "對越無媿，陟降恒俱。", "祝史陳言，曾非矯誣。", "桑林之禱，金縢之書。", "至誠感通，如皷應桴。", "神人以和，大信以孚。", "不勉不思，自止于符。", "天有常道，人無異塗。", "志斯一矣，天其遠諸。", "大道既漓，人心日渝。", "背天從欲，覆族亡軀。", "作善降祥，爲惡速辜。", "聖言孔彰，是訓是謨。", "一念之差，千里而迂。", "惟當自修，以反厥初。"]'),
('8617a6be-dc4b-4b67-9f58-ab088b3f0146','別日何易行','釋文珦','宋','宋诗','song-poetry','','[]','別日何易，會日何難。',120,'全唐诗/poet.song.218000.json','["別日何易，會日何難。", "道路修阻，山川鬰盤。", "寤寐懷思，涕泣汍瀾。", "思君不已，損我容顔。", "時歌舊章，期以自寬。", "歌終太息，反開憂端。", "孤鴻嘹唳，過彼雲間。", "欲托遺音，遐征不還。", "出戶徘徊，風露淒寒。", "明月皎皎，星斗闌干。", "羅帷飄揚，顧影難安。", "耿耿長夜，摧此心肝。"]'),
('c5dd4d20-d2bb-41cf-b14e-fab9ccb0dd0d','北遊朔城行','釋文珦','宋','宋诗','song-poetry','','[]','北遊朔城，險阻艱難。',100,'全唐诗/poet.song.218000.json','["北遊朔城，險阻艱難。", "荒溪遐曠，穹谷紆盤。", "白日晦景，陰雲洞寒。", "凝冰不冶，積雪寧乾。", "凍草色死，北風聲酸。", "林嘯猛虎，路多胡犴。", "愁腸分裂，趼足蹣跚。", "風餐不飽，露宿難安。", "別離之苦，維昔所歎。", "懷哉征人，曷云來還。"]'),
('3bd8c3f9-e8ea-4f53-8d06-9860250dec62','山中放歌','釋文珦','宋','宋诗','song-poetry','','[]','春草離離，秋蘭猗猗，足紉吾衣。',135,'全唐诗/poet.song.218000.json','["春草離離，秋蘭猗猗，足紉吾衣。", "南山有芝，西山有薇，足樂吾饑。", "誰信誰疑，誰是誰非，足亡吾機。", "或瘞或焚，或暴或沉，足爲吾歸。", "生浮死休，已而已而，出山何爲。", "歌闋聲消，隠几而息，夢爲飛雲。", "遨遊八極，我爲雲邪，雲爲我邪。", "無待無得，窅然皆喪，自適夫道。", "吾心之適，富兮貴兮，吾不與易。"]'),
('5cf30fb6-bd13-4100-88a2-5b1afe9f8260','靈鳥篇','釋文珦','宋','宋诗','song-poetry','','[]','嘗聞有靈鳥，其名爲鳳凰。',144,'全唐诗/poet.song.218000.json','["嘗聞有靈鳥，其名爲鳳凰。", "九苞信嘉瑞，五色成文章。", "其宿必丹穴，其鳴在朝陽。", "有德斯出現，德衰還伏藏。", "始至於少皡，再巢於陶唐。", "舜恩被動植，聞韶復翺翔。", "閔其出非時，見歌於楚狂。", "仲尼歎不至，是亦爲世傷。", "蕩蕩二千齡，孰能致斯祥。", "當今邁三五，君明臣且良。", "其或一來儀，足以慰萬方。", "鳳兮儻不來，吾淚徒滂滂。"]'),
('bfc6d892-cab4-4a1a-8aaa-4345a050224e','羌笛','釋文珦','宋','宋诗','song-poetry','','[]','美竹生窮崖，西人翦爲笛。',96,'全唐诗/poet.song.218000.json','["美竹生窮崖，西人翦爲笛。", "制度誠簡易，不假金玉飾。", "五音既繁會，八音亦交出。", "鳳鳴何雝雝，龍吟尤歷歷。", "貪者聽之廉，愁者聽之懌。", "悍者聽之和，勞者聽之佚。", "遺調感人多，今人孰能識。", "空復想桓伊，三弄楚天碧。"]'),
('bebb67b5-9ebc-4386-b0f4-75b4be67fa4b','悠悠萬里行','釋文珦','宋','宋诗','song-poetry','','[]','悠悠萬里行，河畔草青青。',192,'全唐诗/poet.song.218000.json','["悠悠萬里行，河畔草青青。", "青草有衰歇，遠行無期程。", "秦既滅六國，驅民築長城。", "長城三千里，將以限胡兵。", "城邊沙水寒，飲馬馬悲鳴。", "築夫困久役，誰無鄉土情。", "父母念孝養，室家歎孤嬛。", "萬一死於築，白骨空支撐。", "膏血脂草莽，魂魄亦飄零。", "苦哉築城人，舉杵無樂聲。", "仁守國自固，不仁禍斯宏。", "祖龍不知此，縱暴勞蒼生。", "高明鬼瞰室，天道常惡盈。", "長城徒高高，不救秦祚傾。", "豈若唐虞君，垂衣燕泰寧。", "至德亙萬古，巍巍不可名。"]'),
('3f08c0ef-c9c9-4b1b-8423-91d1ad072d11','征婦怨','釋文珦','宋','宋诗','song-poetry','','[]','寧爲路傍草，莫作戰士妻。',132,'全唐诗/poet.song.218000.json','["寧爲路傍草，莫作戰士妻。", "初嫁席未溫，夫今戍遼西。", "憶與夫別時，山川正飛雪。", "腰間弓箭重，冰凍馬蹄裂。", "夫君在萬里，如何可相求。", "瞻彼日月光，使妾心悠悠。", "悠悠復悠悠，想思曷云已。", "夜夜勞夢魂，遥遥渡遼水。", "軍中有紀律，君當慎終始。", "勿以念室家，無心事戎壘。", "自昔忠義人，從軍皆效死。"]'),
('3fb30a00-889b-44cb-bfe6-fce33f30e9f3','杜宇朝夕啼客舍檐樹間','釋文珦','宋','宋诗','song-poetry','','[]','杜宇蜀帝魂，啼時吻流血。',48,'全唐诗/poet.song.218000.json','["杜宇蜀帝魂，啼時吻流血。", "知有思歸人，日夜啼不絕。", "吾歸渺無期，汝啼豈易說。", "故宮春草深，高堂滿簪雪。"]'),
('8c9be3a7-1d6d-497a-83ae-9fedc8a58859','讀史有感','釋文珦','宋','宋诗','song-poetry','','[]','明良但間作，瑣瑣常相因。',96,'全唐诗/poet.song.218000.json','["明良但間作，瑣瑣常相因。", "讒諛既得志，聖哲多罹屯。", "大化造萬物，差品難具陳。", "薰蕕不同器，仁暴當異倫。", "使之混而處，枘鑿安能親。", "西伯居羑里，仲尼傷獲麟。", "遂使黄綺徒，商山終避秦。", "潄泉茹紫芝，揮手謝世人。"]'),
('b9e57d4d-2355-4355-a6cc-d9f339c70b91','戒奢','釋文珦','宋','宋诗','song-poetry','','[]','羲農至舜禹，所尚惟樸素。',96,'全唐诗/poet.song.218000.json','["羲農至舜禹，所尚惟樸素。", "迨及三代衰，君臣皆不度。", "其源既已開，展轉若塗附。", "秦漢距陳隋，相沿少知悟。", "傷財而害民，多不能永祚。", "乃知縱奢淫，天人所同惡。", "金玉不可衣，錦綉不可茹。", "所貴在農桑，工巧皆民蠹。"]'),
('abb0c8d3-44ec-40e9-83bb-e9f86a1d1c68','秋胡詩','釋文珦','宋','宋诗','song-poetry','','[]','潔婦與秋胡，以禮成配匹。',144,'全唐诗/poet.song.218000.json','["潔婦與秋胡，以禮成配匹。", "畢結方五朝，秋胡事行役。", "道塗既云遠，年運亦易徂。", "日月迭相代，五回見榮枯。", "秋胡仕侯邦，音塵久疎絕。", "誓言奉姑嫜，秋霜擬貞潔。", "春日行採桑，援柯向前林。", "秋胡倏來歸，相逢贈黄金。", "重義不受金，采采實筐篚。", "歸來見夫婿，乃是贈金子。", "苦辭讓其諐，投身入淵死。", "豈是不愛身，示心如此水。"]'),
('061d3530-05ce-45a5-9f85-9a4412ea21ea','浮萍寄水行','釋文珦','宋','宋诗','song-poetry','','[]','浮萍寄諸水，漂流本無根。',192,'全唐诗/poet.song.218000.json','["浮萍寄諸水，漂流本無根。", "倚水以爲命，然後生意蕃。", "女子方在室，怙恃父母恩。", "及其既結髮，託身向他門。", "室家以禮合，偕老古所敦。", "畢力閨中事，未嘗憚其煩。", "夙興而夜寐，黽勉無後言。", "德音罔違越，生育皆充完。", "夫壻輕薄兒，翻覆何無端。", "青天起雲雷，無風作濤瀾。", "中情一朝異，棄舊淫新婚。", "宴爾如兄弟，視我同讎怨。", "非唯不見答，暴怒難具論。", "妃耦道遂喪，安能久自存。", "祇憐妾薄命，仰天每長歎。", "願還念昔者，無爲卒相諼。"]'),
('809b833e-82ee-4dbd-99d4-2650105be605','靜夜不寐行','釋文珦','宋','宋诗','song-poetry','','[]','靜夜不遑寐，秋氣殊清清。',120,'全唐诗/poet.song.218000.json','["靜夜不遑寐，秋氣殊清清。", "霜露塗庭蕪，隕葉摧枝莖。", "西風更蕭騷，萬竅皆同聲。", "蜻蛚亦含悲，嘖嘖牀下鳴。", "出門一以視，青天綴繁星。", "三五正縱橫，北斗方斜傾。", "飛鴻朔方來，迢迢困遐征。", "中路失儔侶，隻影何煢煢。", "感物懷遠人，徘徊以屏營。", "心折不能言，默默徒憤盈。"]'),
('47edfd19-0a2c-46a8-9add-02ed63c30d0c','贈道士褚雪巘','釋文珦','宋','宋诗','song-poetry','','[]','褚君樂嘉遯，門徑多青蕪。',96,'全唐诗/poet.song.218000.json','["褚君樂嘉遯，門徑多青蕪。", "心同水月皎，身與山雲俱。", "古壁懸篆籀，不愛燒藥鑪。", "南華註已畢，終然得玄珠。", "高風度寥廓，逸韻淩江湖。", "策杖時過我，以我機事無。", "中情了無取，斯爲真隠徒。", "知已換凡骨，何時上清都。"]'),
('355242d6-c3ce-4150-9eb1-973afc519fae','賡趙別駕天寧古檜韻','釋文珦','宋','宋诗','song-poetry','','[]','檜龍奮頭角，百獸毋敢獰。',144,'全唐诗/poet.song.218000.json','["檜龍奮頭角，百獸毋敢獰。", "居然護祇園，老鬽魂魄驚。", "本根既深固，樛枝任縱橫。", "秋城風雨癡，或躍常夜鳴。", "夜鳴不自已，江頭雲霧生。", "乘雲何所之，變化朝帝京。", "歸來氣尚豪，撼動老禪兄。", "空庭儼相對，健骨殊淒清。", "中林萬古松，或可爲同盟。", "蒲柳先秋凋，襟期信難并。", "異質誠正直，扶持乃神明。", "更看霜雪繁，黛色挺孤擎。"]'),
('133a7043-8443-44a4-9aac-ec0dd4e85869','江頭雨霽','釋文珦','宋','宋诗','song-poetry','','[]','雨收江路涼，徐行吊孤影。',48,'全唐诗/poet.song.218000.json','["雨收江路涼，徐行吊孤影。", "遠岫夕陽明，平洲霽華靜。", "渡頭人盡歸，佳趣在漁艇。", "漁翁不自知，醉卧風吹醒。"]'),
('737c643b-2f52-415d-9d63-df229abdcfa9','鏡中放歌','釋文珦','宋','宋诗','song-poetry','','[]','日日行鏡中，身與白鷗同。',48,'全唐诗/poet.song.218000.json','["日日行鏡中，身與白鷗同。", "閒蹤無滯留，清興何始終。", "紅蕖耀晨妝，綠蒲媚新叢。", "長歌對漁父，滄浪有遺風。"]'),
('58db7e03-859e-455e-b82d-87ba961199ca','野外即事','釋文珦','宋','宋诗','song-poetry','','[]','春暮倉庚鳴，農家語堪聽。',60,'全唐诗/poet.song.218000.json','["春暮倉庚鳴，農家語堪聽。", "雨暘不違時，麥高桑葉青。", "烹豚酌清酒，廟中謝神靈。", "田蠶杯珓好，歡聲動林坰。", "祭罷各分散，羣鳥啄餘腥。"]'),
('5d02e1fe-866e-484c-b03a-99b706fed1d5','結交','釋文珦','宋','宋诗','song-poetry','','[]','結交盡閒交，日欲共幽討。',48,'全唐诗/poet.song.218000.json','["結交盡閒交，日欲共幽討。", "道人失前期，使我縈懷抱。", "清猿往相催，同來須及早。", "良恐秋風高，吹我杞菊老。"]'),
('1f3a799a-0fa6-439d-96fb-4101d2c3479a','遠別曲','釋文珦','宋','宋诗','song-poetry','','[]','問君何所之，執手立前墀。',48,'全唐诗/poet.song.218000.json','["問君何所之，執手立前墀。", "可堪爲遠別，都不道回期。", "簷間蠨蛸蟲，似知妾心悲。", "纏綿結離恨，千絲仍萬絲。"]'),
('901da1b7-7cab-42c7-842b-765afbb83d80','投宿山家','釋文珦','宋','宋诗','song-poetry','','[]','山家忘四時，力作倦還息。',120,'全唐诗/poet.song.218000.json','["山家忘四時，力作倦還息。", "鴉鳴知欲曙，雞栖念當夕。", "兩男皆長成，盡解供賦役。", "季女方及笄，亦復能紡績。", "老翁獨無事，醉飽岸巾幘。", "喜客到柴扉，掃室具枕席。", "棗栗非外求，園蔬更堪摘。", "殷勤話生理，頗覺計自得。", "我生獨何爲，轉徙常寄食。", "語殘燈欲死，草際蟲嘖嘖。"]'),
('e8d550e9-2b52-47ac-ba65-ddafb1bcae6e','廢塚','釋文珦','宋','宋诗','song-poetry','','[]','荒草沒頹垣，知是何人墓。',48,'全唐诗/poet.song.218000.json','["荒草沒頹垣，知是何人墓。", "高頂上牛羊，空間住狐兔。", "行旅爲傷神，子孫在何處。", "飋飋起悲風，蕭騷白楊樹。"]'),
('8e5ccc7f-f514-4440-b897-e0e3211e3fcf','鄞江送友','釋文珦','宋','宋诗','song-poetry','','[]','西風日夜起，江上楓葉赤。',60,'全唐诗/poet.song.218000.json','["西風日夜起，江上楓葉赤。", "可憐未歸人，復送行遠客。", "相見鬢毛改，轉覺世路迫。", "他日慰相思，豈必在書尺。", "薄俗能移人，出處當自力。"]'),
('0c35a72a-d464-4a5e-9f6f-2509ddad7375','喜晴  其一','釋文珦','宋','宋诗','song-poetry','','[]','郊行雨初歇，野徑泥猶滑。',48,'全唐诗/poet.song.218000.json','["郊行雨初歇，野徑泥猶滑。", "斜日照殘雲，雲邊飛鳥沒。", "別浦有行舟，乘流櫂歌發。", "對景未能去，沙頭待新月。"]'),
('fae4a0cb-8fd5-4450-a644-5b87ccf15146','喜晴  其二','釋文珦','宋','宋诗','song-poetry','','[]','經旬雨不斷，今日喜新霽。',60,'全唐诗/poet.song.218000.json','["經旬雨不斷，今日喜新霽。", "杖策東臯行，桑柘陰翳翳。", "蠶老欲登箔，菜麥亦可刈。", "田園足生理，外此盡誤計。", "父老誠見客，吾駕從茲稅。"]'),
('4dbe7c0f-43fd-453d-8bcc-5354a91e1a82','客夜','釋文珦','宋','宋诗','song-poetry','','[]','客館何寥寥，明月竟窗戶。',48,'全唐诗/poet.song.218000.json','["客館何寥寥，明月竟窗戶。", "青天懸列星，零露霑宿莽。", "懷感不遑寐，起坐聽漏皷。", "聽罷復重聽，聽徹三四五。"]'),
('868b80c3-b9f3-475f-894f-1e18959d1afd','觀海','釋文珦','宋','宋诗','song-poetry','','[]','粵自兩儀分，溟波長諸水。',132,'全唐诗/poet.song.218000.json','["粵自兩儀分，溟波長諸水。", "涵渟昭體量，沆瀁無涯涘。", "一目但浺瀜，百川競輸委。", "東聞號扶桑，西或稱濛汜。", "浴日揚明輝，浮天忘表裏。", "神靈奠厥居，鱗介安攸止。", "蜃氣成樓臺，珠光耀坁沚。", "漁商所依憑，利用何窮已。", "鼓楫通九夷，乘風超萬里。", "初唯見平相，漸得悟深理。", "儻可覓蓬萊，當從赤松子。"]'),
('fdf8b8dd-a877-4252-996c-6f3669eb5523','永嘉迪古巖作亭梅竹間東閣爲摘少陵天寒翠袖薄日暮倚修竹句扁曰寒倚書來索詩寄題四韻','釋文珦','宋','宋诗','song-poetry','','[]','凜凜冰玉質，亭亭雪霜姿。',48,'全唐诗/poet.song.219000.json','["凜凜冰玉質，亭亭雪霜姿。", "共此歲寒操，不與東風期。", "羣芳性苦殊，道人心自知。", "悠然澹相對，千載有遐思。"]'),
('97d97ea4-06a9-43f7-901f-60afb417b784','蠶麥辭','釋文珦','宋','宋诗','song-poetry','','[]','山人日無事，行行自娛嬉。',96,'全唐诗/poet.song.219000.json','["山人日無事，行行自娛嬉。", "竹西數家村，喜聞翁媼辭。", "蠶以禦我寒，麥以充我饑。", "二者嘗致禱，羣神將我貽。", "繭必大如甕，繭繭皆成絲。", "麥必生兩岐，粒粒皆可炊。", "儻得遂所願，報謝無敢遲。", "此意頗淳古，當見於周詩。"]'),
('7dfcad88-d23d-4e3f-ba8c-875e5149a716','夢覺辭','釋文珦','宋','宋诗','song-poetry','','[]','霜月何皎皎，寒風更淒淒。',96,'全唐诗/poet.song.219000.json','["霜月何皎皎，寒風更淒淒。", "氣候感微蟲，終夜常悲啼。", "遊子當此時，能不念故棲。", "念久結爲夢，遠過橫塘西。", "此夢亦良勞，屢涉山谷溪。", "宛然見親友，笑語相招携。", "覺來仍在旅，鄉遠人乖暌。", "浮生等如夢，短長不須稽。"]'),
('1fe3f31a-fc2c-415d-9900-c3734fd78216','晚宿山寺','釋文珦','宋','宋诗','song-poetry','','[]','日晚投山寺，蕭然異人境。',48,'全唐诗/poet.song.219000.json','["日晚投山寺，蕭然異人境。", "石房雲氣深，苔階雨聲冷。", "心清不成寐，篝燈對孤影。", "清猿亦可人，長嘯西南頂。"]'),
('dc171b72-ca2d-45bf-bb22-7fa8fd66a840','題東皋','釋文珦','宋','宋诗','song-poetry','','[]','東臯縱遐目，生意良自多。',48,'全唐诗/poet.song.219000.json','["東臯縱遐目，生意良自多。", "魚躍喜冰釋，鳥語乘春和。", "芳蘭馥餘荄，名花眩喬柯。", "倦客獨無依，奈此庶物何。"]'),
('9f80eccc-2698-4c8a-af35-85039de8aade','披雲亭','釋文珦','宋','宋诗','song-poetry','','[]','我愛山中人，冥心住幽寂。',48,'全唐诗/poet.song.219000.json','["我愛山中人，冥心住幽寂。", "危亭上絕巘，不染世人跡。", "群峰合空翠，疑若天宇窄。", "午夜獨長嘯，雲開山月白。"]'),
('d5e74c71-d93a-48e0-8d40-280a4fbc4818','題聽松亭','釋文珦','宋','宋诗','song-poetry','','[]','別駕公事閒，翦棘開三徑。',48,'全唐诗/poet.song.219000.json','["別駕公事閒，翦棘開三徑。", "天風引長松，蕭蕭滿清聽。", "坐石琴意真，憑欄醉魂醒。", "亦使山中人，悠然動歸興。"]'),
('8873924a-b8ce-40cd-b0f4-407a2c0fbc89','題靈泉寺更幽軒','釋文珦','宋','宋诗','song-poetry','','[]','寒泉發靈竇，翠靄生重岡。',48,'全唐诗/poet.song.219000.json','["寒泉發靈竇，翠靄生重岡。", "偶因山鳥鳴，得此林僧房。", "高槐肅夜氣，短牖熙晨光。", "空門了無事，歲月靜中忘。"]'),
('0b1977d2-4dcc-40b9-851e-d7d7feaafb78','爲清渭濱賦集清軒詩','釋文珦','宋','宋诗','song-poetry','','[]','造化既橐籥，坱圠斯無窮。',96,'全唐诗/poet.song.219000.json','["造化既橐籥，坱圠斯無窮。", "下達于幽陰，上徹于穹窿。", "物各限己私，是以無全功。", "高人作軒宇，與彼造化通。", "洋水皆心深，一碧涵虛空。", "洗盡世間塵，萬象皆沖融。", "乾坤清淑氣，大集於其中。", "爲語登軒人，快覩開昏蒙。"]'),
('a099726f-7c6f-426e-8588-0c680415648a','郊外春日','釋文珦','宋','宋诗','song-poetry','','[]','垂楊裊東風，桐花醉鳴鳩。',24,'全唐诗/poet.song.219000.json','["垂楊裊東風，桐花醉鳴鳩。", "地僻無行人，方塘水交流。"]'),
('089905bd-af44-4f24-ab72-83add70bf9ab','春夜夢遊溪上如世傳桃源與梵僧仙子遇具蟠桃丹液靈芝胡麻於雲窗霧閣間請賦古詩頗有思致覺而恍然猶能記憶五句云灘峻舟行遲亂峰青虬蟠一瀑素霓吼靈桃粲丹朱仙飯雜芝糗遂追述夢事足成一十七韻','釋文珦','宋','宋诗','song-poetry','','[]','隨意作清遊，唯與筇竹偶。',204,'全唐诗/poet.song.219000.json','["隨意作清遊，唯與筇竹偶。", "徘徊望原田，宛轉赴林藪。", "隔溪更幽奇，欲往興彌厚。", "漁人自知心，涉我不待叩。", "爛爛桃花明，粼粼白沙走。", "灘峻舟行遲，輟棹入崖口。", "亂峰青虬蟠，一瀑素霓吼。", "微徑上青冥，高木掛星斗。", "梵宇金碧開，萬象發蒙蔀。", "老僧雪眉長，妙語滌心垢。", "乘雲者何人，笙鶴自先後。", "邀余過殊庭，酌以流霞酒。", "靈桃粲丹朱，仙飯雜芝糗。", "白鹿守天壇，彩煙生藥臼。", "謂言保其真，物我盡芻狗。", "窗外鐵鐘鳴，驚覺復何有。", "乃知百年間，夢境匪長久。"]'),
('62f3b21a-1acc-456e-aadb-8c06970bd109','夢中作','釋文珦','宋','宋诗','song-poetry','','[]','棄置何足憂，貧賤元非病。',48,'全唐诗/poet.song.219000.json','["棄置何足憂，貧賤元非病。", "山邊水邊行，頗適幽人情。", "柴門絕輪鞅，蒼苔滿修徑。", "忽聽漁者歌，還動江湖興。"]'),
('7dd16b19-6f53-4d62-8b93-54b96be69b97','記夢','釋文珦','宋','宋诗','song-poetry','','[]','神清發幽夢，夢到仙人峰。',120,'全唐诗/poet.song.219000.json','["神清發幽夢，夢到仙人峰。", "老仙啟玄門，問我來何從。", "仙髮映山綠，仙顔眩日紅。", "高低種玉田，異植方茸茸。", "里閭見翁媼，亦復非塵容。", "雞犬聲相聞，略與桃源同。", "雲中飛仙人，縹緲如游龍。", "遄征不可即，得非是喬松。", "白雲既變滅，仙軿亦無蹤。", "夢覺兩何有，聞打西林鐘。"]'),
('abb1ddaa-1884-4840-8a52-ce119c5096ce','過嚴灘登子陵釣臺','釋文珦','宋','宋诗','song-poetry','','[]','幽人山水心，獨向新安去。',48,'全唐诗/poet.song.219000.json','["幽人山水心，獨向新安去。", "應爲一絲風，元非釣名具。", "浪高灘七里，片石還如故。", "回首問雲臺，荒煙渺無處。"]'),
('dcac726f-e0b9-4b89-b28c-2ed784a02729','旅感','釋文珦','宋','宋诗','song-poetry','','[]','苦無住山資，千里遠爲客。',48,'全唐诗/poet.song.219000.json','["苦無住山資，千里遠爲客。", "兄弟會面難，雙親鬢毛白。", "故園書不來，愁緒日夜積。", "滿庭枯草根，忽復化新碧。"]'),
('49e38258-1fc4-4335-8c80-d62307ed4ab6','大水後作','釋文珦','宋','宋诗','song-poetry','','[]','田家望西成，彌月雨霖霔。',120,'全唐诗/poet.song.219000.json','["田家望西成，彌月雨霖霔。", "流潦迷川澤，秔稻盡漂淤。", "牛犬奔崇丘，雞亦栖高樹。", "室廬畢沈沒，野老無歸處。", "大家還急租，官中未蠲賦。", "妻子多轉徙，天高不可籲。", "但願吾皇知，聖恩加咻噢。", "下詔發倉廩，賑卹散紅腐。", "不唯赤子活，亦使根本固。", "八表皆歸仁，萬歲永終譽。"]'),
('76fdc5da-4146-423f-9e02-4a78a736ea25','秋懷','釋文珦','宋','宋诗','song-poetry','','[]','霜風吹槁梧，索索生秋聲。',48,'全唐诗/poet.song.219000.json','["霜風吹槁梧，索索生秋聲。", "梁燕已無跡，哀鴻復南征。", "遊子當此時，轉覺難爲情。", "庭闈隔千里，日夜白髮生。"]'),
('36b0261d-b53a-40bf-b2ca-dc49dac4f89d','倣古思邊','釋文珦','宋','宋诗','song-poetry','','[]','去年與君別，綠樹聞啼鴂。',36,'全唐诗/poet.song.219000.json','["去年與君別，綠樹聞啼鴂。", "今年當此時，憶君君未歸。", "音書難寄遠，珠淚濕羅衣。"]'),
('98beaa1e-0553-43c7-a8a3-726b4fa7c310','秋光','釋文珦','宋','宋诗','song-poetry','','[]','秋光已過半，風氣日淒緊。',48,'全唐诗/poet.song.219000.json','["秋光已過半，風氣日淒緊。", "鴻鴈復來賓，燕鶑無留影。", "遊子於此時，感物念鄉井。", "縱使夢能歸，歸塗難歷省。"]'),
('84460ad9-96c1-413b-ba34-fba59527109d','送歸篇','釋文珦','宋','宋诗','song-poetry','','[]','秋老木葉乾，露冷蟲聲死。',48,'全唐诗/poet.song.219000.json','["秋老木葉乾，露冷蟲聲死。", "征人未授衣，鄉心日千里。", "揮手睇雲帆，頃刻限煙水。", "他時慰相思，遠寄書一紙。"]'),
('7337cff7-f811-45f4-8692-fceb42499fc7','還山','釋文珦','宋','宋诗','song-poetry','','[]','吾性本閒曠，素不喜城郭。',180,'全唐诗/poet.song.219000.json','["吾性本閒曠，素不喜城郭。", "而况賓主間，禮數相束縛。", "悵望西南山，佳氣日參錯。", "逸興不可羈，飄飄出籠鶴。", "翩然曳杖還，專意在一壑。", "時方孟夏初，衆花已零落。", "櫧林晚雪香，麥隴殘雲薄。", "谷深絕遊塵，苗田叫姑惡。", "幽人舊相知，一見心喜躍。", "謂言舊山畬，今猶可耕鑿。", "日夕共登臨，靡憚筋力弱。", "於焉得天真，畢志甘澹泊。", "初非傲軒冕，終又畏矰繳。", "置身聲利場，何如且行樂。", "纍纍北原上，萬古同寂寞。"]'),
('962a7d27-afa6-44cd-a7f3-6e94a1c2af2d','仙佛辭','釋文珦','宋','宋诗','song-poetry','','[]','仙以靜爲道，佛以空爲宗。',96,'全唐诗/poet.song.219000.json','["仙以靜爲道，佛以空爲宗。", "羣動本皆靜，萬有體恒空。", "服食迷靜趣，仙道不可從。", "宴息昧空性，佛理無由通。", "或曰空靜殊，斯言吾不庸。", "空靜即仙佛，得於此心中。", "心乃佛仙質，仙佛心之容。", "三法妙而一，脗焉歸大同。"]'),
('0cf75af6-08e0-4c63-9bde-219fcdad2897','深居','釋文珦','宋','宋诗','song-poetry','','[]','深居謝交遊，積葉任埋徑。',120,'全唐诗/poet.song.219000.json','["深居謝交遊，積葉任埋徑。", "澹然忘所營，爲是疎懶性。", "已達身本虛，寧憂室垂罄。", "時於泉石間，信意成短詠。", "于以寫吾情，漁樵或相命。", "一皆用其真，魯魚事參訂。", "猶不拘四聲，豈復疑八病。", "難入時人耳，獨許山鬼聽。", "生來妄想絕，禪心本清浄。", "斷不重出山，此志寔先定。"]'),
('3829eb77-07a8-4971-8021-e3a062bcca10','戍婦詞','釋文珦','宋','宋诗','song-poetry','','[]','女蘿施松柏，終始相因依。',72,'全唐诗/poet.song.219000.json','["女蘿施松柏，終始相因依。", "結髮爲婚姻，偕老相與期。", "夫今戍邊城，賤妾無由隨。", "行行日已遠，何時定當歸。", "但願崇勳業，上報明主知。", "諒君守恒節，妾心終不移。"]'),
('12946bfd-e188-4a6c-896d-2f5881bc424f','短歌行','釋文珦','宋','宋诗','song-poetry','','[]','憶昨遊中林，鳥鳴蘭蕙芳。',96,'全唐诗/poet.song.219000.json','["憶昨遊中林，鳥鳴蘭蕙芳。", "重來豈云久，草木倏已黄。", "乙鳥始辭去，羣鴻復南翔。", "天道有代謝，人生安得常。", "促促不我留，譬如石火光。", "紅顔日以瘁，玄髮日以霜。", "載念泉下人，寧不增悲傷。", "聆我短歌行，歌短意則長。"]'),
('26e9a51e-7c13-45a0-a70b-7833aac4dbde','竹下曉吟','釋文珦','宋','宋诗','song-poetry','','[]','竹下坐清曉，露氣沾裳衣。',48,'全唐诗/poet.song.219000.json','["竹下坐清曉，露氣沾裳衣。", "樓鐘發清響，山月耿餘輝。", "心靜息欲無，渺與萬物違。", "莊周苦未達，夢作蝴蝶飛。"]'),
('9ca104c3-6c66-4b04-8a37-f3660765ac5a','先雲洲訪予於萬玉歸而寄詩因用其韻','釋文珦','宋','宋诗','song-poetry','','[]','曉行竺山心，草露濡衣襟。',132,'全唐诗/poet.song.219000.json','["曉行竺山心，草露濡衣襟。", "稽留雖在眼，謝客難重尋。", "靈木逾千齡，斤斧日見侵。", "侵伐殊未已，使我老氣瘖。", "雅樂寖不作，滿耳侏離淫。", "野性羞雷同，自爲梁父吟。", "疵賤苦無力，安能變夷音。", "畏塗不可行，林下甘陸沈。", "世道已如此，懷抱那易禁。", "獨愛古桂林，歲晚猶森森。", "此桂亦未保，慨歎良又深。"]'),
('898a7bf2-8c33-4944-8fe1-f19cc5408e07','靈雨','釋文珦','宋','宋诗','song-poetry','','[]','靈雨應時至，四野生新泉。',48,'全唐诗/poet.song.219000.json','["靈雨應時至，四野生新泉。", "眢井久廢汲，湛湛成深淵。", "老農喜欲舞，田苗綠如煙。", "桔槔掛屋梁，坦腹清晝眠。"]'),
('4dcc3b81-098d-45a8-83fb-40442f36984e','雨後','釋文珦','宋','宋诗','song-poetry','','[]','夜雨萬雷集，漲水三尺深。',48,'全唐诗/poet.song.219000.json','["夜雨萬雷集，漲水三尺深。", "游鱗得其所，波間自浮沉。", "科斗千點墨，鯉鯽數寸金。", "偶會濠梁意，道人本無心。"]'),
('6caa1c1b-2438-4e42-b682-aab833d923a3','古意  其一','釋文珦','宋','宋诗','song-poetry','','[]','難與時流道，憂心常悄悄。',48,'全唐诗/poet.song.219000.json','["難與時流道，憂心常悄悄。", "古道貴平易，今人尚機巧。", "好古而居今，每飯不能飽。", "來往無嫌猜，唯知愛沙鳥。"]'),
('f8df2693-cba5-4318-9a80-b81a510b8a54','古意  其二','釋文珦','宋','宋诗','song-poetry','','[]','逝水尚東流，白日易西沒。',72,'全唐诗/poet.song.219000.json','["逝水尚東流，白日易西沒。", "悠悠天地間，二物何飄忽。", "促迫於生人，綠鬢成華髮。", "昧者不自知，終朝常汩汩。", "利欲沈厥身，其本已先蹷。", "孰若繕真性，以自固靈骨。"]'),
('1d26738d-dd7f-4829-8b23-b182298946db','古意  其三','釋文珦','宋','宋诗','song-poetry','','[]','老梅何偃蹇，雪時方始花。',72,'全唐诗/poet.song.219000.json','["老梅何偃蹇，雪時方始花。", "自守歲寒性，不肯隨春華。", "隠人適然見，移植溪水涯。", "瘦影無陽艷，清香絕淫邪。", "閒靜如隠人，隠人心所嘉。", "樵牧無見侵，以貽隠人嗟。"]'),
('ab6b8990-57a1-4b22-b70c-bae764444d64','古意  其四','釋文珦','宋','宋诗','song-poetry','','[]','自昔真仙道，恬淡而無爲。',96,'全唐诗/poet.song.219000.json','["自昔真仙道，恬淡而無爲。", "以之固靈根，遠寄或可期。", "秦皇與漢武，縱欲不知疲。", "既已長中國，復欲威四夷。", "其性忍而愎，舉非仙者資。", "天監常昭晰，詎容肆謾欺。", "不自省其衷，妄冀苟得之。", "所願竟無成，徒爲後人嗤。"]'),
('e4be2b76-d2a9-4360-91cb-1e11cd03a65c','天樂歌','釋文珦','宋','宋诗','song-poetry','','[]','鳥樂在深林，魚樂在深淵。',96,'全唐诗/poet.song.219000.json','["鳥樂在深林，魚樂在深淵。", "人樂在深居，不深常致患。", "吾居今已深，柴門草樹間。", "油然自成樂，其樂難具言。", "問吾樂伊何，一皆得之天。", "至樂任天與，不知然而然。", "朝樂暮亦樂，此樂真具全。", "吾歌天樂歌，聽者慎勿喧。"]'),
('5d726a80-5cb7-4a4e-9282-3a46e112cb08','夏雨應禱','釋文珦','宋','宋诗','song-poetry','','[]','當夏而閔雨，百神靡不宗。',168,'全唐诗/poet.song.219000.json','["當夏而閔雨，百神靡不宗。", "精誠既上達，所願神輒從。", "觸石忽生雲，初亦無多濃。", "東風借其力，斯須滿諸峰。", "稍久彌六虛，油油復溶溶。", "炎歊化清涼，密布難知重。", "雷電發靈響，潭湫起飛龍。", "甘霔岡不周，非止千里封。", "槁苗浡然興，連疇遂芃芃。", "焚香拜天賜，歡聲徧羣農。", "當書大有年，賦食皆足供。", "公私有餘羨，露積如崇墉。", "誓言爲酒醴，報祀於秋冬。", "降福宜孔皆，萬國稱時雍。"]'),
('cf00ff59-2b19-449f-922f-1b4827786583','感時','釋文珦','宋','宋诗','song-poetry','','[]','厚地産桑穀，爲民衣食資。',120,'全唐诗/poet.song.219000.json','["厚地産桑穀，爲民衣食資。", "井田取什一，公私兩俱宜。", "今者異古昔，苛征常倍蓰。", "倍蓰猶未厭，泛索仍無時。", "官因字民設，胡爲反害之。", "盡以應上求，民病莫能支。", "織者恒苦寒，耕者恒苦饑。", "空村絕雞犬，敗屋多流離。", "白叟與我言，其言乃如斯。", "老夫爲悲吟，聞者當致思。"]'),
('d16bc80a-486b-40e0-ad4e-8b1dc2275e8a','迂拙','釋文珦','宋','宋诗','song-poetry','','[]','迂拙不任用，於焉老雲耕。',120,'全唐诗/poet.song.219000.json','["迂拙不任用，於焉老雲耕。", "曾非尚高亢，聊復辭送迎。", "孤蹤類山鹿，幽意存柴荆。", "春薇擷初茁，秋菊餐落英。", "倦來唯宴默，興到或遊行。", "明目煙霞色，清聽風泉聲。", "萬象畢昭明，四體常安平。", "縱誕殊有適，利祿非所榮。", "外物遺天地，真心齊死生。", "但願絕知聞，怡我閒曠情。"]'),
('c2e4e502-95dc-41d9-a0cc-c2702f765d31','拙叟','釋文珦','宋','宋诗','song-poetry','','[]','拙叟百念無，眎身同木石。',96,'全唐诗/poet.song.219000.json','["拙叟百念無，眎身同木石。", "有客問生涯，笑指松與柏。", "客言人之生，當有資生策。", "縱曰遺聲利，其能去衣食。", "松柏本無情，於子知何益。", "吾言子姑去，吾倦將偃息。", "反關據槁梧，隤然竟終夕。", "覺來寂無有，雞叫東方白。"]'),
('0a16f9f0-ffb2-4082-a6d5-4c31c5d3390c','題醉翁圖','釋文珦','宋','宋诗','song-poetry','','[]','所畫者誰子，將非高陽兒。',108,'全唐诗/poet.song.219000.json','["所畫者誰子，將非高陽兒。", "滿腹常貯酒，何異於鴟夷。", "陶陶以自樂，禮法不可縻。", "釀酒用老瓦，漉酒脫接䍦。", "寧復問升斗，豈嘗辨醇醨。", "終日但兀兀，一巵掌中持。", "頗謂有妙理，非人所能知。", "飲罷忘百慮，袒跣行斜暉。", "大笑沈湘人，獨醒亦奚爲。"]'),
('132a6f78-cf6e-451e-8b8c-8b81d67939e8','山棲','釋文珦','宋','宋诗','song-poetry','','[]','十載棲山楹，影不入州縣。',120,'全唐诗/poet.song.219000.json','["十載棲山楹，影不入州縣。", "地偏交易絕，心閒體逾健。", "脫粟無宿儲，壞衣多斷綫。", "人皆爲吾憂，吾樂未嘗變。", "上下巖壑間，幽賞不知倦。", "一一全天真，斷斷非飾緣。", "西峰煉金客，邂逅時相見。", "談笑輒忘形，殊亦諧素願。", "古者賢達人，道或在貧賤。", "往躅良可循，維以謹繾綣。"]'),
('023d77c1-a69b-4733-b8d4-70000cc07dcb','閑居  其一','釋文珦','宋','宋诗','song-poetry','','[]','四體本虛空，萬物猶土苴。',48,'全唐诗/poet.song.219000.json','["四體本虛空，萬物猶土苴。", "以此存內照，頗覺非外假。", "存亡楚人弓，得失塞翁馬。", "但使吾道存，正欲知者寡。"]'),
('9a052308-54fe-44bd-8a23-501b1d248bf7','閑居  其二','釋文珦','宋','宋诗','song-poetry','','[]','蕭然謝塵境，日夕心悠哉。',48,'全唐诗/poet.song.219000.json','["蕭然謝塵境，日夕心悠哉。", "厨空無鼠雀，徑僻多莓苔。", "麻衣足自蔽，柴門詎曾開。", "坐聽風葉鳴，疑有幽人來。"]'),
('6b48a08e-5336-4493-9b55-2726ad2514d1','閑居  其三','釋文珦','宋','宋诗','song-poetry','','[]','閒人了無營，偃卧常至午。',48,'全唐诗/poet.song.219000.json','["閒人了無營，偃卧常至午。", "暖日到床前，落葉滿籬戶。", "或時散幽步，東岡復西塢。", "誓此畢餘齡，青山不相負。"]'),
('a5d87b60-fedd-4934-83f9-7a4f4ce50ddc','閑居  其四','釋文珦','宋','宋诗','song-poetry','','[]','雖貧常晏如，兀兀坐山舍。',48,'全唐诗/poet.song.219000.json','["雖貧常晏如，兀兀坐山舍。", "案有麻衣易，門無俗士駕。", "虞人不從招，尼父亦待賈。", "狗苟復蠅營，此事吾不暇。"]'),
('728f29a5-c8f2-48ad-8ae0-e9af7414f7b7','言交','釋文珦','宋','宋诗','song-poetry','','[]','結交貴同心，心同難間疏。',48,'全唐诗/poet.song.219000.json','["結交貴同心，心同難間疏。", "嘗聞膠漆固，亦曰金蘭如。", "君子要其終，小人變厥初。", "宜當作管鮑，慎勿爲耳餘。"]'),
('38424b69-48f8-4a34-8220-9c539f831135','又言交','釋文珦','宋','宋诗','song-poetry','','[]','道交淡如水，世交甘如醴。',60,'全唐诗/poet.song.219000.json','["道交淡如水，世交甘如醴。", "結交當以真，審交當以理。", "道交似無情，曾不異生死。", "世稱刎頸交，未必能終始。", "君不見昔者，陳餘與張耳。"]'),
('b52557a8-83aa-4c91-b1d9-363d05023284','野性','釋文珦','宋','宋诗','song-poetry','','[]','野性樂疎曠，從來厭風塵。',84,'全唐诗/poet.song.219000.json','["野性樂疎曠，從來厭風塵。", "孤寒無所資，屈身隨衆人。", "貴遊棄疵賤，不能强相親。", "蹉跎三十年，客路常清貧。", "晚來歸山林，麋鹿爲我鄰。", "萬事不掛意，一一皆天真。", "同流乃知此，難與俗子陳。"]'),
('fe52715c-c83a-4420-85da-94eabebb5223','白日苦短行','釋文珦','宋','宋诗','song-poetry','','[]','白日常苦短，無方使遲延。',144,'全唐诗/poet.song.219000.json','["白日常苦短，無方使遲延。", "始見出暘谷，忽已沈虞淵。", "迫促於生人，無一能永年。", "豐質成槁項，鬒髮變華顛。", "雞鳴逐聲利，夜分未遑眠。", "奄化同草木，沒沒歸重泉。", "或復自超放，導引求神仙。", "喬松在何許，亦若茫昧然。", "必當實根祗，塵物皆棄捐。", "德性貴純正，文華在昭宣。", "道與天地準，萬古唯聖賢。", "景行不可忘，抒情爲此篇。"]'),
('6ac62a6b-76af-4a76-a23b-9061bf23a674','有適','釋文珦','宋','宋诗','song-poetry','','[]','破屋無兄弟，拙者所棲息。',180,'全唐诗/poet.song.219000.json','["破屋無兄弟，拙者所棲息。", "衡門未嘗啟，聲利詎能迫。", "資身不求備，百事遂省力。", "糞埽皆可衣，草木皆可食。", "春來有餘暇，手種豆一席。", "秋深葉黄隕，霜莢漸開拆。", "收歸籬落間，早晚自剝擊。", "藏之於瓶罌，粒粒堪愛惜。", "窮冬火鑪頭，時喚山猿喫。", "猿去吾亦眠，巖房愈幽寂。", "口誦寒山詩，頭枕麻衣易。", "于以陶性情，終然遠憂責。", "頗謂貧非病，更覺損勝益。", "與其稱楩柟，未若作樗櫟。", "傍人莫相問，老子方有適。"]'),
('a9152bf3-9e29-43bb-9a8f-1ade155097f7','秋興','釋文珦','宋','宋诗','song-poetry','','[]','秋雲滿茅屋，秋風響楓林。',60,'全唐诗/poet.song.219000.json','["秋雲滿茅屋，秋風響楓林。", "杖藜步幽徑，落葉數寸深。", "悠然拾葉歸，寫我閒中吟。", "坐客興亦閒，彈入青瑶琴。", "曲終各無語，山水遺清音。"]'),
('fb8c98b6-553f-4a7e-b568-4eeee0c19e4e','喜雪','釋文珦','宋','宋诗','song-poetry','','[]','北風吹同雲，慘澹日已夕。',144,'全唐诗/poet.song.219000.json','["北風吹同雲，慘澹日已夕。", "枕上聞霰零，須臾映窗白。", "曉來籬戶間，平地忽過尺。", "羣峰靜繚繞，彌望無寸碧。", "棲鳥噤不鳴，空山斷行跡。", "古木摧危梢，荒崖失奇石。", "瑞色徧天壤，膏潤歸宿麥。", "螟蟊深入地，沴氣亦消釋。", "豐年信可占，豈復憂民食。", "野老不知寒，歡聲動阡陌。", "聊作喜雪歌，仰謝天鈞力。", "歌長遣誰和，寫寄西峰客。"]'),
('7353dd38-8aa1-426e-8904-b33c8d3b32df','感春','釋文珦','宋','宋诗','song-poetry','','[]','忽聞春欲去，園林謾遊矚。',120,'全唐诗/poet.song.219000.json','["忽聞春欲去，園林謾遊矚。", "輕風散餘紅，細雨滋繁綠。", "綠繁似歡榮，紅散猶僇辱。", "因悟人間世，萬事易翻覆。", "賤或登青雲，貴或成赤族。", "禍福無定端，往往相倚伏。", "那知今日歌，不是明朝哭。", "書以爲世鑒，得志毋縱欲。", "兢兢如履冰，坎坎念伐輻。", "苟能閑此理，堪追聖賢躅。"]'),
('583c7587-8e8c-4b38-adc7-e99edd6a6d1c','曉步十韻示山友','釋文珦','宋','宋诗','song-poetry','','[]','隠居絕他營，曉步緣澗壑。',120,'全唐诗/poet.song.219000.json','["隠居絕他營，曉步緣澗壑。", "水深魚影閒，林密鳥聲樂。", "晴空極清明，孤雲何住著。", "原窮得危磴，路轉見橫彴。", "嘯響空谷傳，吟情古靈覺。", "所遇皆隠淪，論心遺厚薄。", "在山無小草，忘世勝大藥。", "餘生豈須計，此興諒非錯。", "其適在閒曠，何用嫌落魄。", "書此以告君，狂言君勿噱。"]'),
('2a38907f-9c28-4a27-9b1b-d143195e0769','夜思','釋文珦','宋','宋诗','song-poetry','','[]','靜坐四無鄰，看山待明月。',48,'全唐诗/poet.song.219000.json','["靜坐四無鄰，看山待明月。", "池邊暑氣盡，竹上涼颸發。", "伏翼打窗飛，孤螢隨草沒。", "予心適有會，還就幽人說。"]'),
('99b50e5f-7093-41ce-8aa3-4a2ca67e9ab6','事君盡忠行','釋文珦','宋','宋诗','song-poetry','','[]','爲子當盡孝，事君當盡忠。',144,'全唐诗/poet.song.219000.json','["爲子當盡孝，事君當盡忠。", "凡人不知此，斯與犬豕同。", "臣子固貞亮，君父或顓蒙。", "乃知守忠孝，亦繫於遭逢。", "比干忠以戮，申生孝而終。", "忠戮得稱仁，孝終宜曰恭。", "古今每如此，片言安可窮。", "炳然垂竹帛，于以開盲聾。", "所遭雖若彼，力行誠在躬。", "於焉二本立，足爲百行宗。", "忠孝苟純至，聞望當昭融。", "此理亙萬世，來者能無從。"]'),
('fefaeace-8783-4134-9915-f7402566b2af','嵬嵬山石行','釋文珦','宋','宋诗','song-poetry','','[]','山石何嵬嵬，孤松何薿薿。',120,'全唐诗/poet.song.219000.json','["山石何嵬嵬，孤松何薿薿。", "其大踰百圍，其高過千尺。", "廣厦需梁棟，求之若匪克。", "梓人一以視，斤斧見促迫。", "牛夫競牽輓，輸入王侯宅。", "觀者如堵牆，靡不重嘉惜。", "鏤刻以爲工，丹青以爲飾。", "巍然在雲霄，七貴所棲息。", "梁棟豈不美，殘生良可哀。", "寧作南山松，毋爲廣厦材。"]'),
('f619dd13-8a5a-4df1-80c5-adeae9a2441f','四序','釋文珦','宋','宋诗','song-poetry','','[]','四序迭遷變，春光獨豐茂。',96,'全唐诗/poet.song.219000.json','["四序迭遷變，春光獨豐茂。", "生意徧羣物，動植不違候。", "噰噰塞鴻歸，喔喔野雉雊。", "軟草鋪作茵，芳葩粲成綉。", "唯有靜者徒，抱道終莫售。", "直躬在林藪，朝夕飯藜糗。", "與時既乖舛，輿臺或加詬。", "俛仰天地間，此理終莫究。"]'),
('88edc55c-8cf9-4e7a-b142-73677cc375e5','狂吟','釋文珦','宋','宋诗','song-poetry','','[]','槿籬三四掩，荒竹百十箇。',48,'全唐诗/poet.song.219000.json','["槿籬三四掩，荒竹百十箇。", "無人扣柴扉，偏稱潜夫卧。", "夢作野雲飛，覺來松日墮。", "隨分有狂吟，吟長不須和。"]'),
('e0d6f50a-9c0d-423c-9bcc-0d6fb255ad3c','自紀','釋文珦','宋','宋诗','song-poetry','','[]','生無機巧姿，所貴唯實踐。',96,'全唐诗/poet.song.219000.json','["生無機巧姿，所貴唯實踐。", "探玄髮盡霜，窮勝足重趼。", "渡水識歸源，看雲悟舒卷。", "寧教身不遭，頗謂首難俛。", "餘年辭畏途，滅迹向絕巘。", "形骸未全枯，囂煩幸俱遣。", "中心本難誣，萬事不欲辯。", "手把楞伽經，交趺對鑪篆。"]'),
('751ec072-e4dd-4510-8279-da0df34a0830','秋興','釋文珦','宋','宋诗','song-poetry','','[]','昔人苦悲秋，我獨愛秋色。',144,'全唐诗/poet.song.219000.json','["昔人苦悲秋，我獨愛秋色。", "無雲天萬里，遠嶠出寒碧。", "楓林葉如丹，溪水清見石。", "飽雨豆莢肥，經霜栗包拆。", "連疇稻正黄，冒野蕎亦白。", "籬菊忽盈把，山萸又堪摘。", "日月如過鳥，良辰敢虛擲。", "青猿頗會意，爲我具短策。", "西風吹破帽，野興在故屐。", "不憚登涉勞，遠訪巢居客。", "此客更可人，分我漁樵席。", "人生貴適意，何必累形役。"]'),
('74fb4730-93d7-48c1-9529-c0675e1416ff','早睡','釋文珦','宋','宋诗','song-poetry','','[]','天寒常早睡，不待日光斂。',48,'全唐诗/poet.song.219000.json','["天寒常早睡，不待日光斂。", "恐礙山猿入，柴門未嘗掩。", "落葉打窗鳴，枕間疑雨點。", "起視西峰頭，月殘星閃閃。"]'),
('ea5aa325-2530-480a-bd9c-531a0d503a32','居山樂','釋文珦','宋','宋诗','song-poetry','','[]','居山樂無涯，三徑富松菊。',48,'全唐诗/poet.song.219000.json','["居山樂無涯，三徑富松菊。", "山體靜吾心，山光悅吾目。", "春來山蕨肥，秋後山田熟。", "未必王侯家，有吾清浄福。"]'),
('ba86bdbd-3b65-488e-b4ca-4f0c7ee4d4fc','暑夜步月','釋文珦','宋','宋诗','song-poetry','','[]','畏暑不復眠，空階踏涼月。',48,'全唐诗/poet.song.219000.json','["畏暑不復眠，空階踏涼月。", "冰輪了無翳，明可數毛髮。", "夜久肝肺清，如嚥太古雪。", "擬換飛仙人，乘鸞上寥泬。"]'),
('058e8efe-5b9d-4a61-a2ea-62703a67a0cb','贈梅','釋文珦','宋','宋诗','song-poetry','','[]','見說春方還，春猶未相識。',72,'全唐诗/poet.song.219000.json','["見說春方還，春猶未相識。", "山童指梅花，言是春消息。", "梅花亦含笑，道我是知音。", "遮莫隨桃李，貪榮變此心。", "相看出此語，愛爾良獨深。", "聽之儻不疑，足以爲規箴。"]'),
('c86c9804-742c-4312-b24f-f18d2e483506','夜興','釋文珦','宋','宋诗','song-poetry','','[]','萬緣不相涉，默坐調四肢。',96,'全唐诗/poet.song.219000.json','["萬緣不相涉，默坐調四肢。", "天理靜中見，物情閒處知。", "長風掃重陰，皎月生東籬。", "寒蟲唧唧鳴，亦各知天時。", "悠然發清興，朗誦淵明詩。", "人生百年間，汲汲奚所爲。", "賢愚雖有殊，同爲來者悲。", "爲語高世流，有酒當自持。"]'),
('db71f341-69a2-499d-b88f-7cd51bc565e7','散人詠','釋文珦','宋','宋诗','song-poetry','','[]','金散免鎔冶，木散逃斧斤。',48,'全唐诗/poet.song.219000.json','["金散免鎔冶，木散逃斧斤。", "人散外榮辱，所以爲散人。", "世皆賤吾散，此散吾自珍。", "偃蹇不任用，庶足全其身。"]'),
('8849f6a5-2661-45ed-9a55-c17e65960504','初夏同趙東閣西里諸公山行聞鶑分韻得隔字','釋文珦','宋','宋诗','song-poetry','','[]','今日天氣清，聊試登山屐。',48,'全唐诗/poet.song.219000.json','["今日天氣清，聊試登山屐。", "共看雲外峰，分坐澗邊石。", "絕境不逢人，啼鶑似留客。", "一聲無處尋，還被青林隔。"]'),
('05a57161-7288-4fb4-b310-f9b8b4b40a71','秋夜感懷','釋文珦','宋','宋诗','song-poetry','','[]','秋山夜無人，蟲在草根泣。',144,'全唐诗/poet.song.219000.json','["秋山夜無人，蟲在草根泣。", "明月照高林，虛窗風露入。", "生年四十餘，萬事未有立。", "東西岐路間，終歲常汲汲。", "雙親死經年，宅兆久完葺。", "兄弟亦貧窶，於此不暇給。", "回首思故園，愁雲滿原隰。", "交朋閲千百，存者已無十。", "顧我枯槁姿，奈此短景急。", "終宵不成寐，起坐千慮集。", "至人乃忘情，效慕安可及。", "唯作無生觀，去此衣袖濕。"]'),
('a208c239-d1db-4bd7-9595-0744af69c7f5','烏棲曲','釋文珦','宋','宋诗','song-poetry','','[]','白露生庭蕪，明月照栖烏。',48,'全唐诗/poet.song.219000.json','["白露生庭蕪，明月照栖烏。", "栖烏啼不已，閨人中夜起。", "起視西北方，翩翩鴈南翔。", "幽燕戍未返，云胡不悽傷。"]'),
('31c18fd3-4d06-4be0-b9ab-616d9c13dddf','食薺','釋文珦','宋','宋诗','song-poetry','','[]','生無食肉資，飯蔬幽壑底。',48,'全唐诗/poet.song.219000.json','["生無食肉資，飯蔬幽壑底。", "朝采南澗芹，莫擷東籬薺。", "此中有真味，豈必鱠魴鱧。", "何曾萬金饌，惡謚不可洗。"]'),
('32346d7c-fce0-42b4-bfca-5caef64a9d53','感興','釋文珦','宋','宋诗','song-poetry','','[]','一身素貧窶，四海長爲客。',120,'全唐诗/poet.song.219000.json','["一身素貧窶，四海長爲客。", "客塗不可窮，老去少筋力。", "賤者人多棄，風霜變顔色。", "歸來旅亭下，倚杖三歎息。", "隻字不堪煮，萬卷亦徒積。", "未如田舍翁，耕桑了衣食。", "身世蟻旋磨，日月駒過隙。", "百年竟何爲，鬢髮空皓白。", "乾坤渺難馮，倦羽復奚適。", "一枝願深栖，庶以避彈射。"]'),
('06f4af91-bf15-4e03-8465-c126b49cca3e','途中感興','釋文珦','宋','宋诗','song-poetry','','[]','悠悠涉長途，西日照禾黍。',96,'全唐诗/poet.song.219000.json','["悠悠涉長途，西日照禾黍。", "回首睇關山，故鄉在何許。", "秋風吹櫟林，憂思莫能禁。", "同懷不可見，日暮空沈吟。", "方矜美少年，倏忽傷醜老。", "百年能幾何，况復不長保。", "存者日已少，逝者日已多。", "榮華亦難恃，薤露有遺歌。"]'),
('19894c77-0d59-433d-8699-2f1e60c79845','金竹峰','釋文珦','宋','宋诗','song-poetry','','[]','雙檜高亭亭，遥見百里外。',48,'全唐诗/poet.song.219000.json','["雙檜高亭亭，遥見百里外。", "恍疑香烟幢，亦若羽葆蓋。", "秀色何其多，貞心固常在。", "化龍想非難，坐待風雨會。"]'),
('438534a1-b05d-48f7-9eb8-2dc0534e5fb9','歲暮旅思','釋文珦','宋','宋诗','song-poetry','','[]','岐路不可極，歲月亦易遒。',60,'全唐诗/poet.song.219000.json','["岐路不可極，歲月亦易遒。", "朔風振寒威，行子無衾裯。", "厥生良可哀，半世空悠悠。", "知音盡淪沒，明月難暗投。", "親朋復遐阻，日夕生離憂。"]'),
('30addf25-24be-43dd-b484-4d35a6454220','世路','釋文珦','宋','宋诗','song-poetry','','[]','世路饒風波，生平有終極。',60,'全唐诗/poet.song.219000.json','["世路饒風波，生平有終極。", "東西苦漂蕩，鬢髮非舊色。", "倦鳥懷安栖，老馬思故櫪。", "萬類雖不齊，彼此各有適。", "富貴亦偶然，何須置胸臆。"]'),
('f241a6cb-411b-4f9f-96ae-752c91007e97','遊興  其一','釋文珦','宋','宋诗','song-poetry','','[]','端居念局促，聊復起行遊。',96,'全唐诗/poet.song.219000.json','["端居念局促，聊復起行遊。", "褰裳涉淺瀨，隨雲陟高丘。", "時當孟夏月，嘉木清且稠。", "衆鳥相和鳴，關關無時休。", "頗覺愜幽抱，遂爾忘百憂。", "解衣坐磐石，濯足臨長流。", "心空了無取，身閒方自由。", "寄言養生客，於此同歸休。"]'),
('b1956c75-56c5-421d-b06e-86d08f4daf03','遊興  其二','釋文珦','宋','宋诗','song-poetry','','[]','閒人無所管，扶藜散幽步。',120,'全唐诗/poet.song.219000.json','["閒人無所管，扶藜散幽步。", "古路絕遊塵，霜林葉自雨。", "坐石聽流泉，頗得空寂趣。", "雲外巢居子，邂逅兩相遇。", "語久各忘還，見月出深樹。", "彼此無滯情，忽散同烟霧。", "歸來夜已深，山衣浥清露。", "隤然竟終夕，不復脫芒屨。", "鐵鐘驚夢回，斗轉東方曙。", "重欲見巢居，雲深無覓處。"]'),
('09fcab22-6629-4b05-bb5d-4ac724b8e668','遊興  其三','釋文珦','宋','宋诗','song-poetry','','[]','不暖亦不寒，氣候正清淑。',72,'全唐诗/poet.song.219000.json','["不暖亦不寒，氣候正清淑。", "岸柳盡垂絲，園筍已成竹。", "山禽屢催喚，拄杖情又熟。", "出門信吾步，豈復計遲速。", "渡水或穿雲，山陰又溪曲。", "悠然得真趣，此外非所欲。"]'),
('894be803-6477-4247-a03a-01617243bfc4','昨日出城南行','釋文珦','宋','宋诗','song-poetry','','[]','昨日出城南，戰陣如雲屯。',264,'全唐诗/poet.song.219000.json','["昨日出城南，戰陣如雲屯。", "兵刃欲相接，殺氣方騰掀。", "黄塵塞天地，日月爲之昏。", "壯士仗忠義，不忘喪其元。", "奮然爲前驅，誓報明主恩。", "卒伍皆賈勇，翕合無異言。", "唯欲紓禍難，豈辭屬櫜鞬。", "元戎既啟行，旌旆交繽繙。", "謂當奏凱還，受爵效屏藩。", "衆寡力不侔，傍復乏外援。", "戰久俄敗衂，靡聞鉦皷喧。", "軍中紀律嚴，致死無敢奔。", "全師同陷沒，千萬無一存。", "肢體膏草莽，血流成川源。", "國雖加恤典，莫能返其魂。", "白骨蔽四野，鬼哭多煩冤。", "懷哉唐虞君，大德罔虧騫。", "垂衣成至治，萬國皆晏然。", "齊威雖霸主，亦頼仲父賢。", "九合不以兵，仲尼所稱傳。", "兵乃不祥器，聖賢嘗戒旃。", "人苟服其仁，斯亦何用焉。"]'),
('106c720b-c59e-4b22-abed-5ce863126981','不屈','釋文珦','宋','宋诗','song-poetry','','[]','屈身必受制，屈志必違仁。',48,'全唐诗/poet.song.219000.json','["屈身必受制，屈志必違仁。", "受制己則辱，違仁道則屯。", "身志兩不辱，度幾德之純。", "以此率其性，乾坤一閑人。"]'),
('6166f39c-4e82-49e1-8aff-b26f328f8b09','閒身  其一','釋文珦','宋','宋诗','song-poetry','','[]','閒身孰能鞿，蕭散隨所欲。',48,'全唐诗/poet.song.219000.json','["閒身孰能鞿，蕭散隨所欲。", "涼風入芒屨，緩步秋塘曲。", "清波淡無涯，于以滌心目。", "魚鳥亦忘情，何如在濠濮。"]'),
('c867477a-1b34-40a8-bdc3-c78ff084e450','閒身  其二','釋文珦','宋','宋诗','song-poetry','','[]','閑身出塵表，世鞅詎能絕。',48,'全唐诗/poet.song.219000.json','["閑身出塵表，世鞅詎能絕。", "真若寒崖松，凌傲幾霜雪。", "枝葉任生枯，唯自老根節。", "更有無心雲，油然足怡悅。"]'),
('426d73c8-d619-445b-9ae7-7510afef0c4a','釣者吟','釋文珦','宋','宋诗','song-poetry','','[]','吾謂釣者徒，今古不同流。',84,'全唐诗/poet.song.219000.json','["吾謂釣者徒，今古不同流。", "今釣曲爲餌，古釣直不鈎。", "直釣不在得，所得過於求。", "曲釣志在得，所得良可羞。", "乃知今古釣，不可相爲謀。", "好古不好今，頗若能自修。", "試問羊裘人，亦合子意不。"]'),
('d56b7443-892d-4f6a-ac2d-75722776454b','西村老叟','釋文珦','宋','宋诗','song-poetry','','[]','西村逢老叟，事事皆天真。',84,'全唐诗/poet.song.219000.json','["西村逢老叟，事事皆天真。", "髮白不記歲，鳥鳴知是春。", "耕桑了衣食，兒女俱和循。", "日暮野中歸，荷鋤仍带薪。", "見人但恭敬，塵滿頭上巾。", "未嘗識都邑，豈聞有君臣。", "我疑百世下，猶有羲皇民。"]'),
('09a1da85-e9d4-4649-ad17-1793fb6c8f9d','梅花','釋文珦','宋','宋诗','song-poetry','','[]','梅如姑射仙，桃李終難竝。',60,'全唐诗/poet.song.219000.json','["梅如姑射仙，桃李終難竝。", "雪底暗傳香，泉邊孤照影。", "清聲聞麗譙，至味入鐘鼎。", "愛者雖繁多，知名獨和靖。", "隠顯不同功，因之發深省。"]'),
('61449b67-cc01-4a30-870a-e566bc493487','遊仙  其一','釋文珦','宋','宋诗','song-poetry','','[]','吾嫌人世隘，忻同古仙伍。',48,'全唐诗/poet.song.219000.json','["吾嫌人世隘，忻同古仙伍。", "寂爾契沖虛，與之相爾汝。", "晨多遊玉清，夕每憇園圃。", "身已外乾坤，飄飄自遐舉。"]'),
('2e88e2c0-e983-4f00-a60a-d12e9a11b9a8','遊仙  其二','釋文珦','宋','宋诗','song-poetry','','[]','結交真仙徒，翛然凌太清。',48,'全唐诗/poet.song.219000.json','["結交真仙徒，翛然凌太清。", "體與虛無合，心同日月明。", "逍遥龍鳳駕，縹緲雲霓旌。", "豈知區中人，狗苟復蠅營。"]'),
('2bea2025-1865-4c7b-b061-e560b73392a4','遊仙  其三','釋文珦','宋','宋诗','song-poetry','','[]','喧囂非所事，靈府自怡神。',48,'全唐诗/poet.song.219000.json','["喧囂非所事，靈府自怡神。", "食每吸丹景，飲常漱玄津。", "洞覽周八極，內照唯一真。", "體妙含至精，希微難具陳。"]'),
('fb329508-97eb-4ced-accc-d022f220f802','遊仙  其四','釋文珦','宋','宋诗','song-poetry','','[]','高升洞陽界，論道太常前。',48,'全唐诗/poet.song.219000.json','["高升洞陽界，論道太常前。", "與彼羣仙游，一夕千萬年。", "眼中屢曾見，滄海爲桑田。", "時同宴玉醴，廣樂聽鈞天。"]'),
('772dc277-76eb-4770-b09c-e63e62cd4e80','遊仙  其五','釋文珦','宋','宋诗','song-poetry','','[]','超然塵垢外，元化實希夷。',48,'全唐诗/poet.song.219000.json','["超然塵垢外，元化實希夷。", "吾生有道骨，中心常慕之。", "感通影響然，高真不遐遺。", "導我歸帝鄉，雲軿共委蛇。"]'),
('0766b441-9c9b-4374-b1c4-0d1b349baa16','遊仙  其六','釋文珦','宋','宋诗','song-poetry','','[]','青峰萬仞高，雲路多盤紆。',132,'全唐诗/poet.song.219000.json','["青峰萬仞高，雲路多盤紆。", "松柏冬不凋，懸溜成石膚。", "上有逍遥天，元心與道俱。", "長揖謝塵凡，放情常晏如。", "唯服玉石脂，千年貌不枯。", "命我登仙壇，壇名號玄都。", "天風起西極，日月生東隅。", "神仙遞升降，鸞鶴相號呼。", "拍肩友洪崖，揮手招麻姑。", "流目極昭曠，使我隘九區。", "山中有至樂，功名焉足圖。"]'),
('d932e004-87d0-4f7e-b04c-064e1bd5a7c0','平旦','釋文珦','宋','宋诗','song-poetry','','[]','平旦氣偏清，境界復深窔。',48,'全唐诗/poet.song.219000.json','["平旦氣偏清，境界復深窔。", "初日上東溟，高峰最先照。", "會意發長吟，何似蘇門嘯。", "不必諧宮商，自是山中調。"]'),
('6c883749-c3b9-49cf-97c2-ca243bd6596f','清遊','釋文珦','宋','宋诗','song-poetry','','[]','清遊興難窮，倦就苔磯坐。',48,'全唐诗/poet.song.219000.json','["清遊興難窮，倦就苔磯坐。", "爲愛松風涼，不知寒日墮。", "鹿下飲溪流，猨來摘山果。", "我本貴無聞，何用人知我。"]'),
('bff6a2e4-648a-4952-98d9-fad406bb0909','桐溪','釋文珦','宋','宋诗','song-poetry','','[]','修梧散瑶碧，溪水涵清漪。',48,'全唐诗/poet.song.219000.json','["修梧散瑶碧，溪水涵清漪。", "凡翼毋飲棲，鳳鳥當來儀。", "山人以自鳴，俗士安能知。", "陵谷可變遷，此志當勿移。"]'),
('9c0aa3e8-f598-458a-895f-a091143bd3a7','旅懷','釋文珦','宋','宋诗','song-poetry','','[]','北風吹荒林，蕭騷起寒聲。',58,'全唐诗/poet.song.219000.json','["北風吹荒林，蕭騷起寒聲。", "客子耳中聞，展轉傷離情。", "親朋不在眼，他鄉但{女孕+日}{女孕+日}。", "狐死亦首丘，奈此終身行。"]'),
('473d5fbf-fe13-442d-8b5b-c70129594943','琴泉','釋文珦','宋','宋诗','song-poetry','','[]','子期不可作，伯牙終絕絃。',48,'全唐诗/poet.song.219000.json','["子期不可作，伯牙終絕絃。", "泠泠太古音，在此幽澗泉。", "泉流如碧玉，老僧聽不足。", "後夜月明時，還向泉邊宿。"]'),
('fabbfc70-ca6f-492a-b7cb-6b109b4e36a1','逝水','釋文珦','宋','宋诗','song-poetry','','[]','逝水向東流，前後浪相續。',168,'全唐诗/poet.song.219000.json','["逝水向東流，前後浪相續。", "尼父達機兆，川上歎不足。", "人生天地間，百年誠短促。", "菁華草頭露，光景風中燭。", "兩鬢成枯蓬，蕭蕭不再綠。", "那知今日歡，不是明朝哭。", "所仰唯聖賢，亦復歸鬼錄。", "而況頑冥者，厥身沈利欲。", "隨流不知返，終世常僕僕。", "大化一朝盡，腐滅同草木。", "豈若黄綺徒，居然在空谷。", "于焉自逍遥，其人美如玉。", "吾生千載餘，猶知慕遐躅。", "寤寐斯不忘，耿耿在心目。"]'),
('69fea86c-1bc0-4a9b-9508-c107fd6456a4','水西','釋文珦','宋','宋诗','song-poetry','','[]','水西多好山，山光足娛人。',96,'全唐诗/poet.song.219000.json','["水西多好山，山光足娛人。", "一重復一掩，比比如魚鱗。", "居來三十年，仙佛皆其鄰。", "魚鳥不忘情，朝暮長相親。", "遯世乃吾性，非因來避秦。", "曾不事緣飾，庶事全天真。", "早嘗知夢幻，視身若無身。", "無生以爲樂，此樂難具陳。"]'),
('6304899c-4b0e-48d4-a01d-771f6c944564','生年','釋文珦','宋','宋诗','song-poetry','','[]','生年已六十，所歷更萬端。',72,'全唐诗/poet.song.219000.json','["生年已六十，所歷更萬端。", "富貴等浮雲，變滅不足觀。", "身如冬嶺松，獨立守歲寒。", "心如古井水，到底無波瀾。", "吾道即古道，處今良獨難。", "是非不易辯，長歎復長歎。"]'),
('ee1f9b97-1a0f-4891-8ba5-b081378bc50b','曉林日融葉霜滴瀝如涕泣','釋文珦','宋','宋诗','song-poetry','','[]','槁葉殊可憐，寒風吹女急。',48,'全唐诗/poet.song.219000.json','["槁葉殊可憐，寒風吹女急。", "天復雨嚴霜，恐女難自立。", "零落歸草莽，晚悟嗟何及。", "朝陽達機兆，爲女增泫泣。"]'),
('fbe41f0b-670d-46ee-84e1-a70ef33004a4','屏迹','釋文珦','宋','宋诗','song-poetry','','[]','江湖厭風波，巖壑事幽屏。',72,'全唐诗/poet.song.219000.json','["江湖厭風波，巖壑事幽屏。", "柴門絕往還，自閲朝昏景。", "日出烟霧消，鳥散松竹靜。", "須臾日西頹，餘暉在高嶺。", "短生亦如寄，舉世孰能省。", "願學遠公儔，終然謝塵境。"]'),
('0a34f144-8aaf-42b2-8aca-072f6d6f0f4a','夢覺吟','釋文珦','宋','宋诗','song-poetry','','[]','百年如大夢，夢裏幾紛馳。',48,'全唐诗/poet.song.219000.json','["百年如大夢，夢裏幾紛馳。", "覺後識爲夢，夢時曾未知。", "吾生今已覺，不記夢中時。", "在夢人無限，昏昏信可悲。"]'),
('5f2e63e3-cb34-4724-bd6c-f99bef0570b5','吾心','釋文珦','宋','宋诗','song-poetry','','[]','吾心靜而貞，是乃出天稟。',96,'全唐诗/poet.song.219000.json','["吾心靜而貞，是乃出天稟。", "驅之入塵樊，違性豈不甚。", "所對非同流，欲語口還噤。", "世塗機穽多，動足常懔懔。", "今來返中林，夜卧始安枕。", "山薇既可餐，清泉又堪飲。", "布衣極相宜，亦不羨文錦。", "斯謀良已臧，餘生不須諗。"]'),
('1499d2bc-5c75-4cf0-9e5b-d580c0eb6584','枯樹謠','釋文珦','宋','宋诗','song-poetry','','[]','高木引修藤，藤束樹身死。',72,'全唐诗/poet.song.219000.json','["高木引修藤，藤束樹身死。", "慎莫進小人，終當負君子。", "君子思報德，小人易忘恩。", "所與苟非類，反爲禍之元。", "誠能遠小人，終身乃無患。", "世莫輕斯言，亦足以爲諫。"]'),
('0a48f1d8-e8c3-49c1-adc5-f938708d41ad','道狹踟躕行','釋文珦','宋','宋诗','song-poetry','','[]','道狹難並車，相逢苦踟躕。',156,'全唐诗/poet.song.219000.json','["道狹難並車，相逢苦踟躕。", "踟躕將何念，所念在康衢。", "康衢平如砥，八達無斜迂。", "君子之所履，所履常虛邪。", "折旋應規矩，永矢無越踰。", "有時亦壅底，久之還廓如。", "狹道殊徑捷，小人所爭趨。", "夙夜不遑止，草露多沾濡。", "勢利迭相傾，旋踵成遷渝。", "迷眩不知返，逝將致淪胥。", "康衢吾所遵，狹道吾所吁。", "遄車返山林，守一以自娛。", "大道既凋喪，安能復區區。"]'),
('eadd18f3-cc11-4cf4-be74-33444efe50e1','南山松柏章','釋文珦','宋','宋诗','song-poetry','','[]','松柏何夭矯，南山何崚嶒。',72,'全唐诗/poet.song.219000.json','["松柏何夭矯，南山何崚嶒。", "松柏有常性，南山不騫崩。", "南山人所仰，松柏人所承。", "尋常部婁間，瑣瑣唯薪蒸。", "彼無高志徒，眡此宜自懲。", "堅守歲寒操，亦當慎攸憑。"]'),
('90a54d9b-ee5a-4350-8925-2643ae9c2854','青松篇','釋文珦','宋','宋诗','song-poetry','','[]','西山有孤松，亭亭高百尺。',96,'全唐诗/poet.song.219000.json','["西山有孤松，亭亭高百尺。", "冰雪屢凌厲，難變青青色。", "東園盛桃李，摇艷矜春容。", "少皞布秋律，掃地無遺蹤。", "青松固真心，桃李乏堅操。", "君子與小人，自古不同調。", "寧忍學桃李，誓言作青松。", "偃蹇終不屈，傲睨秦皇封。"]'),
('25091ef5-a83e-431a-bb50-3d43af27d481','箴放心','釋文珦','宋','宋诗','song-poetry','','[]','養形而放心，譬若樹抱蝎。',48,'全唐诗/poet.song.219000.json','["養形而放心，譬若樹抱蝎。", "表似內已虛，識者爲憯怛。", "形瘁或當腴，心蠹不可活。", "先民有格言，勿使本先撥。"]'),
('a3d8f349-4d00-4e24-8bcf-e630120c0ac7','天竺中夜','釋文珦','宋','宋诗','song-poetry','','[]','白露變氣候，促織階下鳴。',72,'全唐诗/poet.song.219000.json','["白露變氣候，促織階下鳴。", "切切鳴不已，倦客心自驚。", "中夜攬衣起，星疎松月明。", "念彼同懷人，迢迢隔山城。", "此身無羽翼，不得東南征。", "聊作相思吟，寄此千里情。"]'),
('3ef1abba-0081-42a8-91ab-767d8b8d41e9','養疾','釋文珦','宋','宋诗','song-poetry','','[]','介特無門徒，室亦如垂罄。',60,'全唐诗/poet.song.219000.json','["介特無門徒，室亦如垂罄。", "隤然類枯株，聊以養衰病。", "朝來啟籬戶，落葉滿苔徑。", "流光遽如斯，脆質安能競。", "虛籟起高林，助我發長詠。"]'),
('09b4367f-fb39-4cc0-9be8-33afeebf7646','馮深居長余二十三歲趙東閣長余二十二歲周汶陽長余一十七歲皆折行輩與余交淳祐辛丑同訪余於竺山有會宿詩距咸淳乙丑已二十五年矣痛先覺之凋零感吾生之既老因成十韻以寄死生之情','釋文珦','宋','宋诗','song-poetry','','[]','三老皆達人，虛受無蔕芥。',120,'全唐诗/poet.song.219000.json','["三老皆達人，虛受無蔕芥。", "筆陣絕縱橫，詞源極澎湃。", "丁時身屢蹇，志道心不懈。", "放浪事物表，若曰宇宙隘。", "求我於空間，豈識有機械。", "留詩在幽窗，足以鎮山怪。", "神靈謹守藏，光豔無減殺。", "今朝一長吟，頓使老疾差。", "三老不可作，吾心亦遄邁。", "中心曷能忘，長吟復長喟。"]'),
('c8e13a4f-8c28-4d80-abce-cf5192fd989e','晨興','釋文珦','宋','宋诗','song-poetry','','[]','晨興啟蓬戶，當面來清風。',48,'全唐诗/poet.song.219000.json','["晨興啟蓬戶，當面來清風。", "初日麗喬林，光影尤玲瓏。", "悠然與心會，物物皆沖融。", "得喪豈吾事，此道足自終。"]'),
('2621bd28-b697-4ae5-995d-3ea4692831df','山蔬','釋文珦','宋','宋诗','song-poetry','','[]','山蔬有真味，肉食者不知。',120,'全唐诗/poet.song.219000.json','["山蔬有真味，肉食者不知。", "老我於空林，自愛園中葵。", "種蒔舉有法，采擷初無時。", "置之折脚鐺，燎以枯松枝。", "芼之以薑桂，是乃性所宜。", "嗜此已成癖，自覺甘如飴。", "既足果吾腹，何用五鼎爲。", "衆欲不干慮，出處常委蛇。", "笑傲泉石間，萬象皆吾詩。", "我已自忘我，人知我爲誰。"]'),
('3612aff1-2a6c-4b88-96e6-3f8386ba147e','百年  其一','釋文珦','宋','宋诗','song-poetry','','[]','百年如大夢，夢中誰到老。',48,'全唐诗/poet.song.219000.json','["百年如大夢，夢中誰到老。", "貧賤固可憐，富貴亦何好。", "舉世盡蚩蚩，醒寤苦不早。", "自古知幾人，獨在商山皓。"]'),
('71d4ff0f-86b3-4e1f-8941-fadddee7e226','百年  其二','釋文珦','宋','宋诗','song-poetry','','[]','百年亦何爲，終歲常壈坎。',48,'全唐诗/poet.song.219000.json','["百年亦何爲，終歲常壈坎。", "玄裘不掩脛，素髮自垂頷。", "吾親歸夜臺，益重霜露感。", "仰視天一方，星河同慘澹。"]'),
('4494b539-619e-47ac-9d43-6e8ee739b273','雲際獨坐','釋文珦','宋','宋诗','song-poetry','','[]','雲際坐磐石，悠悠兩無心。',48,'全唐诗/poet.song.219000.json','["雲際坐磐石，悠悠兩無心。", "波靜白鷗下，山寒黄葉深。", "幽人住何處，午磬來清音。", "日暮不能去，羣峰生夕陰。"]'),
('cf82e3e7-fbec-4123-be41-e86623a8652a','山人居澗上號澗居因澗作池名鑑止爲賦是詩','釋文珦','宋','宋诗','song-poetry','','[]','幽人臨澗居，爲愛澗中水。',72,'全唐诗/poet.song.219000.json','["幽人臨澗居，爲愛澗中水。", "泠泠出雲竇，决决漱石齒。", "流行本無意，遇坎還自止。", "坎深遂成池，寒光映窗几。", "于以鑑禪心，清浄絕塵滓。", "唯供種白蓮，不洗聞堯耳。"]'),
('f2f2b743-0d0d-4d25-9e30-2fc9fd0097f7','苦益菜','釋文珦','宋','宋诗','song-poetry','','[]','苦菜吾所嗜，意與食蘗同。',96,'全唐诗/poet.song.219000.json','["苦菜吾所嗜，意與食蘗同。", "古者以益名，頗足昭其衷。", "秋花更清妍，綽約冰雪容。", "恍疑姑射仙，或如采芝翁。", "菊以彭澤顯，蓮以濂溪崇。", "此獨無知音，沒身蕭艾中。", "人生天壤間，用舍爲窮通。", "草木豈不然，一皆係其逢。"]'),
('0e2b381f-ae99-4c11-9f45-19ea8aabd9f3','哭李雪林','釋文珦','宋','宋诗','song-poetry','','[]','昔者聞盧殷，頗爲世所推。',120,'全唐诗/poet.song.219000.json','["昔者聞盧殷，頗爲世所推。", "讀書過萬卷，盡以資於詩。", "復聞孟東野，氣清而色夷。", "平生嗜章句，有甚於渴饑。", "二士舉無子，所學竟不施。", "昌黎爲買棺，又作銘墓辭。", "相去五百年，雪林酷似之。", "春谷古人徒，生死相維持。", "亦爲立佳城，著文樹穹碑。", "林兮信不忘，千載修名垂。"]'),
('f472d8d1-50ba-45a7-911c-ca79a5b926fc','梅友','釋文珦','宋','宋诗','song-poetry','','[]','梅有歲寒姿，桃李非其偶。',72,'全唐诗/poet.song.219000.json','["梅有歲寒姿，桃李非其偶。", "冰雪見凌厲，斯固梅之守。", "伊人清且妍，是曰梅之友。", "臭味得所同，不在金蘭後。", "溪烟隴月間，幽期未嘗負。", "中路勿棄捐，友道貴長久。"]'),
('c019bf94-3457-48e6-a8e2-a5a2d587bef1','吾年  其一','釋文珦','宋','宋诗','song-poetry','','[]','吾年未七十，頗覺漸昏耄。',60,'全唐诗/poet.song.219000.json','["吾年未七十，頗覺漸昏耄。", "舊事盡遺忘，獨餘山水好。", "天寒附葉火，塵埃滿烏帽。", "客至欲逢迎，無奈筋力耗。", "君當恕衰翁，遮莫謂予傲。"]'),
('3d56241a-2088-4f54-8332-6690e659387c','吾年  其二','釋文珦','宋','宋诗','song-poetry','','[]','吾年易逾邁，感慨難具陳。',144,'全唐诗/poet.song.219000.json','["吾年易逾邁，感慨難具陳。", "齒髮半缺禿，肌膚多不仁。", "屏迹於空山，幾與木石鄰。", "憶昔少年時，秉志將求伸。", "所交四方士，一一非常人。", "論文窮道要，日夕長相親。", "逝者若流水，存者猶參辰。", "輾轉空懷思，欲見終無因。", "新知棄玼賤，坐卧唯一身。", "餘生諒非久，當爲灰與塵。", "存亡固可念，亦復徒傷神。", "於焉息吾慮，靜然全天真。"]'),
('f69cea83-7b1a-4c6d-953d-d5214ec04bf8','秋晚懷浙東故人','釋文珦','宋','宋诗','song-poetry','','[]','遊人未歸來，芳草又還歇。',48,'全唐诗/poet.song.219000.json','["遊人未歸來，芳草又還歇。", "悵望江東雲，久負山中月。", "扁舟在何處，一水不可越。", "相思千里間，日暮飛鳥沒。"]'),
('e616848d-8cb8-4af8-9f98-e22c2b279a8e','紀事','釋文珦','宋','宋诗','song-poetry','','[]','庸賈狗鼠輩，齷齪無足觀。',288,'全唐诗/poet.song.219000.json','["庸賈狗鼠輩，齷齪無足觀。", "少小爲博徒，狹斜恣遊般。", "憑附椒房寵，濫吹於王官。", "匿罪而言功，虛聲尚欺謾。", "以之致鼎貴，真如沐猴冠。", "擅命十五年，肆毒侔蠑蚖。", "仁脈爲之絕，善類爲之殫。", "納侮於北鄰，徵盟日囂讙。", "兵戈滿四海，天步極艱難。", "鄂漢距江淮，列郡多創殘。", "人命若菅蒯，聞之心膽寒。", "王家急軍食，耕者不得餐。", "罪大已難逭，猶思揜其奸。", "駕言督諸軍，翺翔向江干。", "小器不自量，妄冀於曹瞞。", "潛欲移帝室，微辭啟其端。", "賢哉夏金吾，直氣生忠肝。", "立欲碎其首，無奈師旅單。", "姦謀既已洩，跼蹐方自歎。", "畏誅竟宵遁，鴞鵩鎩羽翰。", "逆賊幸屏迹，宗社得再安。", "勤王畢雲會，聖慮行小寬。", "祖宗德澤深，國體宜無瘢。", "指日恢中原，以盡萬國歡。"]'),
('aa76a137-1ae4-4698-b990-0abfe3e66086','爲先雲洲賦塵外地','釋文珦','宋','宋诗','song-poetry','','[]','狂賈何人斯，曾莫犬豕若。',240,'全唐诗/poet.song.219000.json','["狂賈何人斯，曾莫犬豕若。", "包藏竊國機，直爾棄天爵。", "逆罪浮草莽，盜術逾跖蹻。", "殛死於荒陬，厲肉不中臛。", "竄賊亦云晚，帝脈以微弱。", "倉扁皆拱手，神聖難救藥。", "興亡誰召之，禮樂至銷鑠。", "兵戈滿天地，騰沸猶鼎鑊。", "億萬蒼生命，枕藉委溝壑。", "寰中蕩無章，吾徒曷棲託。", "頼有塵外地，猶堪遂飛躍。", "泉石盡清奇，烟霞地參錯。", "有客賦歸來，楸枰見高著。", "真是離聲名，非唯解纓絡。", "山心極閒曠，雲蹤忘住著。", "長歌松月高，晏坐林花落。", "游衍狎漁樵，追隨任猿鶴。", "他年四方志，此日三生約。", "終逃小草譏，嘉遯自成樂。", "於焉以求志，爲記良不惡。"]'),
('3fc42d48-5901-4832-a077-248322c7ce63','過賈似道葛嶺舊居','釋文珦','宋','宋诗','song-poetry','','[]','順逆人獸心，成敗翻覆手。',120,'全唐诗/poet.song.219000.json','["順逆人獸心，成敗翻覆手。", "鬼神不相容，子孫豈能守。", "昔者過此門，歌鐘會羣醜。", "今者過此門，闐然已豐蔀。", "羞死滿院花，顰殘數株柳。", "空室走鼪鼯，荒池長蝌蚪。", "轉眼即淒涼，况復百年後。", "積釁多自戕，盛德斯可久。", "富貴如浮埃，於身竟何有。", "爲謝高明人，非義慎勿取。"]'),
('2d8a1ef2-2601-4dea-bac7-7526c9b33ab0','惟初','釋文珦','宋','宋诗','song-poetry','','[]','惟初結髮時，志氣凌蒼昊。',96,'全唐诗/poet.song.219000.json','["惟初結髮時，志氣凌蒼昊。", "飄然去園廬，名山縱幽討。", "流光暗相催，於今已衰老。", "滿眼皆少年，誰堪寫懷抱。", "潛蹤寂寞濱，蕭颯同霜草。", "謂可安餘齡，異俗驚我倒。", "頗解空王宗，懷之以爲寶。", "世故等浮塵，棄置勿復道。"]'),
('a354b2a9-63f3-418e-a62c-383f75d1e2b4','世情','釋文珦','宋','宋诗','song-poetry','','[]','世情多反覆，衰榮難預卜。',72,'全唐诗/poet.song.219000.json','["世情多反覆，衰榮難預卜。", "本是昔時笑，翻成今日哭。", "故鄉無舊業，客身同草木。", "紛紛輕薄兒，誰能顧幽獨。", "雖無祿資身，喜有山在目。", "得失何足論，長歌倚修竹。"]'),
('d83ca0d9-4a33-4d8f-96f5-1ae44d449efe','貧賤詩','釋文珦','宋','宋诗','song-poetry','','[]','貧賤交親絕，形影自相弔。',48,'全唐诗/poet.song.219000.json','["貧賤交親絕，形影自相弔。", "清泉白石間，朝夕事吟嘯。", "甑墮何足言，灰死不須溺。", "達人乃知此，寧免俗士誚。"]'),
('9e2d50ce-6d0b-4dd4-b7a6-b016a7dc26f5','酬李漫翁暑中見寄韻','釋文珦','宋','宋诗','song-poetry','','[]','羲娥不停轂，催暑到茅屋。',48,'全唐诗/poet.song.219000.json','["羲娥不停轂，催暑到茅屋。", "萍蓬無地頭，桑梓念天目。", "古吟寓深情，時事堪痛哭。", "餘生竟何歸，行已變陵谷。"]'),
('e477af27-f829-45e0-a8a2-7e173517ae43','篔房暑中寄詩依韻酬答','釋文珦','宋','宋诗','song-poetry','','[]','谿翁若冰雪，明浄不受涅。',48,'全唐诗/poet.song.219000.json','["谿翁若冰雪，明浄不受涅。", "經歲斷知聞，使我心菀結。", "佳句來清風，足以灑炎熱。", "山中有奇事，遲向秋深說。"]'),
('fddd768a-dd62-443d-9e22-62a7a82b36af','依韻酬葛秋巖陶體四首  其一','釋文珦','宋','宋诗','song-poetry','','[]','山林自多趣，况此晴和時。',48,'全唐诗/poet.song.219000.json','["山林自多趣，况此晴和時。", "我友賁然來，相娛以琴詩。", "倉庚遺好音，薰風發清吹。", "悠然與心會，安能遽忘茲。"]'),
('d3063041-a35d-4fd8-90de-d3205d3bfa54','依韻酬葛秋巖陶體四首  其二','釋文珦','宋','宋诗','song-poetry','','[]','大化無端倪，至道絕馮仗。',48,'全唐诗/poet.song.219000.json','["大化無端倪，至道絕馮仗。", "委身於一靜，足以去羣妄。", "死生亦寄耳，遐齡豈吾望。", "伯倫稱達人，胡爲未忘葬。"]'),
('8d9977ac-65c0-4905-a311-2b01ff34a23c','依韻酬葛秋巖陶體四首  其三','釋文珦','宋','宋诗','song-poetry','','[]','吾生一無營，終日衡門下。',48,'全唐诗/poet.song.219000.json','["吾生一無營，終日衡門下。", "棲遲已成樂，豈羨臺與榭。", "相彼常汲汲，而我獨多暇。", "時聽蜾祝兒，於以知物化。"]'),
('4d0cd216-cd76-404f-aef5-a3a5e20044aa','依韻酬葛秋巖陶體四首  其四','釋文珦','宋','宋诗','song-poetry','','[]','東原風正和，西山氣尤爽。',48,'全唐诗/poet.song.219000.json','["東原風正和，西山氣尤爽。", "坐我於其中，此心日以廣。", "腰間豈須重，眼下何必兩。", "顔原陋巷居，歌有金石響。"]'),
('461baee3-1543-4db5-9327-30628a6646d7','效陶四首用葛秋巖韻  其一','釋文珦','宋','宋诗','song-poetry','','[]','坐石滋南風，幽抱和且衎。',48,'全唐诗/poet.song.219000.json','["坐石滋南風，幽抱和且衎。", "志唯在山水，身不關治亂。", "終曲遂忘言，舉目送飛翰。", "所得皆天真，初不加習翫。"]'),
('d89d0497-9089-4d7f-afe3-90eac069ea85','效陶四首用葛秋巖韻  其二','釋文珦','宋','宋诗','song-poetry','','[]','山深自無暑，五月草樹寒。',48,'全唐诗/poet.song.219000.json','["山深自無暑，五月草樹寒。", "頗有遯世樂，得之亦非難。", "巖翁我同流，邂逅成清歡。", "回首功名人，瑣瑣不足觀。"]'),
('aba5c522-d060-4333-b3af-bcd2b6b04ce8','效陶四首用葛秋巖韻  其三','釋文珦','宋','宋诗','song-poetry','','[]','眼前幾富貴，變滅同浮烟。',48,'全唐诗/poet.song.219000.json','["眼前幾富貴，變滅同浮烟。", "舉非吾所欽，眷然思古先。", "窮達無二道，彭殤可齊年。", "中心既昭徹，萬象皆澄鮮。"]'),
('b6c9fe45-be65-4a21-b5a7-faa84e926cf8','效陶四首用葛秋巖韻  其四','釋文珦','宋','宋诗','song-poetry','','[]','我居本山林，茅茨蔭嘉樹。',48,'全唐诗/poet.song.219000.json','["我居本山林，茅茨蔭嘉樹。", "骯髒塵網間，歸心自西騖。", "吾駕今已返，終然守貞素。", "每思夜氣清，起坐天未曙。"]'),
('cd84f247-88dc-480c-8e42-a0148fe27e22','野翁','釋文珦','宋','宋诗','song-poetry','','[]','野翁百不爲，白髮老巖澗。',48,'全唐诗/poet.song.219000.json','["野翁百不爲，白髮老巖澗。", "寧肯慕膏粱，且復飽藜莧。", "故交非不多，盡作風葉散。", "餘生雖獨存，反觀亦如幻。"]'),
('76dc861d-41cf-47f3-a2e8-bbfd66e961c8','山居答客問','釋文珦','宋','宋诗','song-poetry','','[]','富貴有何好，祇以勞其形。',120,'全唐诗/poet.song.219000.json','["富貴有何好，祇以勞其形。", "吾居在山林，四體常安寧。", "寒緝沼中荷，饑斸松下苓。", "蒼苔沒幽徑，白雲度疎櫺。", "明月石上看，清風枕間聽。", "滅惑生智焰，破塵出空經。", "真如寐而寤，亦若醉而醒。", "此外非吾事，眡之等浮萍。", "誓不出籬戶，期以終頹齡。", "君如不吾信，重當問山靈。"]'),
('0ed53c08-00d1-4737-afc7-c26731dce18e','遣興','釋文珦','宋','宋诗','song-poetry','','[]','吾方慕孤貞，俗苦尚馮附。',72,'全唐诗/poet.song.219000.json','["吾方慕孤貞，俗苦尚馮附。", "一身天地間，瓠落如大瓠。", "短寄無百年，倏忽已遲暮。", "平生清浄禪，猶嫌被詩污。", "洗除豈誠難，心空滅萬慮。", "更當尋亮公，竟入西山去。"]'),
('9d8a75bc-3ace-4b59-bc18-71eebdba8153','寓形','釋文珦','宋','宋诗','song-poetry','','[]','寓形宇宙間，治身猶治木。',72,'全唐诗/poet.song.219000.json','["寓形宇宙間，治身猶治木。", "要在直而方，毋使圓且曲。", "直方固違衆，吾心以爲是。", "圓曲雖適時，吾心以爲恥。", "人由圓曲富，吾用直方貧。", "吾心雖不移，予以書諸紳。"]'),
('5a651dab-e84e-4a33-a413-89b96a7969ad','黄葉','釋文珦','宋','宋诗','song-poetry','','[]','吾心愛黄葉，不翅於南金。',48,'全唐诗/poet.song.219000.json','["吾心愛黄葉，不翅於南金。", "九月秋風高，柴門積來深。", "一一自掇拾，書我白頭吟。", "吟成意誰與，拄頰對遥岑。"]'),
('3f53e976-2a1c-4c2b-a5cd-8ca5e55ceefc','寄友分得客字','釋文珦','宋','宋诗','song-poetry','','[]','夜來有清夢，夢見山陰客。',48,'全唐诗/poet.song.219000.json','["夜來有清夢，夢見山陰客。", "宛然過蘭亭，分吟坐苔石。", "曉聞在湖寺，揮麈論經席。", "會面安可期，相思春草碧。"]'),
('7c0a9029-3d72-4b2e-b861-ce38c2ed1ea1','吾生','釋文珦','宋','宋诗','song-poetry','','[]','吾生少壯時，窮力在經教。',48,'全唐诗/poet.song.219000.json','["吾生少壯時，窮力在經教。", "一心融萬境，頗亦能致效。", "老來更脫略，山水隨所樂。", "今成信手棋，勝負不復校。"]'),
('6e1bddc6-eae8-4d85-8dfc-d1b044d45be5','人生幾何行  其一','釋文珦','宋','宋诗','song-poetry','','[]','人生能幾何，百年三萬日。',72,'全唐诗/poet.song.219000.json','["人生能幾何，百年三萬日。", "一半睡中消，餘壽或難必。", "鐘鼎與軒裳，總是牢籠物。", "貪夫所甘心，宛轉無由出。", "富貴者常勞，貧賤者常逸。", "所以箕山人，不爲唐堯屈。"]'),
('df2fd5fa-6644-4c78-a87c-3730c6cac7f2','人生幾何行  其二','釋文珦','宋','宋诗','song-poetry','','[]','人生百年間，何殊旅亭客。',48,'全唐诗/poet.song.219000.json','["人生百年間，何殊旅亭客。", "少壯不可留，漸覺衰老迫。", "縱使功業成，誰能免形役。", "長歌歸去來，山中煮白石。"]'),
('c4c092fc-f55f-4547-8d3b-b4d4ea292909','冬日山中遣興','釋文珦','宋','宋诗','song-poetry','','[]','始見迎秋氣，又復換玄律。',120,'全唐诗/poet.song.219000.json','["始見迎秋氣，又復換玄律。", "寒山何蕭蕭，飄風何弗弗。", "雙丸遞隠見，百齡信超忽。", "慨念同遊人，大半成異物。", "吾年亦云衰，逾六已望七。", "不唯齒髮變，舊聞盡遺失。", "死生無定據，萬事難固必。", "且以永今朝，奚須計明日。", "息影入山林，曾不厭深密。", "賢哉龐德公，萬世稱隠逸。"]'),
('33c3d4a4-d9e4-49ac-bf83-a18ecb66817b','重阜崔嵬行','釋文珦','宋','宋诗','song-poetry','','[]','重阜何崔嵬，遥瞻北邙路。',156,'全唐诗/poet.song.219000.json','["重阜何崔嵬，遥瞻北邙路。", "曠野無人居，高低盡丘墓。", "不知古與新，落落似棋布。", "下有荒草叢，上有白楊樹。", "樹頂嘯鴟鳶，草根穴狐兔。", "嗟哉昔爲人，妻子相愛慕。", "豈知易殂落，到此長別處。", "天地雖好生，安能蹔留駐。", "夜臺杳冥冥，千載竟不曙。", "託身同草木，坐受螻蟻蠹。", "衣冠變成塵，精靈自相語。", "親戚不重過，他人豈能顧。", "聽我蒿里歌，年命如朝露。"]'),
('5979c65a-64aa-46a1-a41d-b038521abb2d','與雲耕重會復別','釋文珦','宋','宋诗','song-poetry','','[]','久別思見面，重逢反成悲。',84,'全唐诗/poet.song.219000.json','["久別思見面，重逢反成悲。", "相持問年紀，各在桑榆時。", "道途筋力殘，玄髮成素絲。", "時命苟不遭，有才亦奚爲。", "榮華既非願，但願亡寒饑。", "眼前且相慰，老別難再期。", "此語亦良苦，君心還自知。"]'),
('89a7b462-8310-4b73-adbe-00074e782466','別山中友','釋文珦','宋','宋诗','song-poetry','','[]','人生貴適意，窮達奚足論。',48,'全唐诗/poet.song.219000.json','["人生貴適意，窮達奚足論。", "此意君能知，方喜吾道存。", "于心既莫逆，彼此俱忘言。", "胡爲又當別，誰能不消魂。"]'),
('2939c274-1af7-4724-a79e-99ed43ac095f','閉戶','釋文珦','宋','宋诗','song-poetry','','[]','閉戶日無事，山光滿盈几。',48,'全唐诗/poet.song.219000.json','["閉戶日無事，山光滿盈几。", "飯餘曲肱睡，一覺頗酣美。", "心平不作夢，境寂如止水。", "山童爲煎茶，茶熟我當起。"]'),
('fc91dde4-ff80-454a-b937-f6d7e993f360','夜歸  其一','釋文珦','宋','宋诗','song-poetry','','[]','天氣殊清和，山中多勝踐。',48,'全唐诗/poet.song.219000.json','["天氣殊清和，山中多勝踐。", "沿流采香芹，穿雲得芳荈。", "幽懷日以舒，囂塵自茲遣。", "乘月返茅茨，倦足不復洗。"]'),
('ed306db1-9421-4347-912a-a7491ea65056','夜歸  其二','釋文珦','宋','宋诗','song-poetry','','[]','生唯浄命食，持鉢向人境。',48,'全唐诗/poet.song.219000.json','["生唯浄命食，持鉢向人境。", "莫夜歸茅廬，月出山愈靜。", "處處聞泉聲，行行踏松影。", "洗足便安禪，雲深石床冷。"]'),
('29c13766-adb3-4deb-949c-b4750cdf67e7','煎茶','釋文珦','宋','宋诗','song-poetry','','[]','吾生嗜苦茗，春山恣攀緣。',120,'全唐诗/poet.song.219000.json','["吾生嗜苦茗，春山恣攀緣。", "采采不盈掬，浥露殊芳鮮。", "慮溷仙草性，崖間取靈泉。", "石鼎乃所宜，灌濯手自煎。", "擇火亦云至，不令有微烟。", "初沸碧雲聚，再沸雪浪翻。", "一碗復一碗，盡啜袪憂煩。", "良恐失正味，緘默久不言。", "須臾齒頰甘，兩腋風颯然。", "飄飄欲遐舉，未下盧玉川。"]'),
('c3e7c5a7-7b33-4900-a4bd-451c83613d6b','芝田老師索余作松石因書此詩','釋文珦','宋','宋诗','song-poetry','','[]','學畫同學書，藝精人已老。',48,'全唐诗/poet.song.219000.json','["學畫同學書，藝精人已老。", "三年始向學，一紙未能好。", "墨淡石不蒼，筆枯松亦槁。", "芝翁索此圖，遺笑應絕倒。"]'),
('b8ccbf44-4ea6-4102-9e3c-8186ec604f19','樗散','釋文珦','宋','宋诗','song-poetry','','[]','樗散不任用，居然老空林。',48,'全唐诗/poet.song.219000.json','["樗散不任用，居然老空林。", "柴門絕車馬，徑草三尺深。", "靜對西山雲，頗覺諧素心。", "此外非所知，誰言有華簪。"]'),
('aff8d0f5-d0ff-4b59-b153-958e12eb38d5','藤杖','釋文珦','宋','宋诗','song-poetry','','[]','楖𣗖古藤杖，偃蹇如虬龍。',72,'全唐诗/poet.song.219000.json','["楖𣗖古藤杖，偃蹇如虬龍。", "伊昔訪隠人，得之天柱峰。", "眡爾如良朋，出處常相從。", "渡水逾萬折，穿雲或千重。", "忽於風雨時，狡獪誇靈蹤。", "使我失馮倚，瓠落無所容。"]'),
('145de0ab-2843-469c-b643-2d50db6b181b','爲顧美山賦五字田','釋文珦','宋','宋诗','song-poetry','','[]','寶此五字田，不羨千畝耤。',48,'全唐诗/poet.song.219000.json','["寶此五字田，不羨千畝耤。", "冥搜爲播種，發言皆黍稷。", "梅山老吟農，良已著深績。", "終然乃有秋，不負平生力。"]'),
('eb1b2c91-67e5-42bc-abff-582bf402804a','湯婆','釋文珦','宋','宋诗','song-poetry','','[]','野翁有湯婆，愛逾美淑姬。',96,'全唐诗/poet.song.219000.json','["野翁有湯婆，愛逾美淑姬。", "眡之若彭亨，虛中而無爲。", "冬日則飲湯，身唯一衲隨。", "曾不涴脂粉，簡潔良易資。", "終宵暖吾足，貞靜無邪思。", "德音之所同，可作偕老期。", "誓不中道絕，若彼氓蚩蚩。", "作詩以遺婆，婆聽當勿疑。"]'),
('bc3ed4e2-2009-49f9-acf6-550b0e3326ee','讀郭文舉傳','釋文珦','宋','宋诗','song-poetry','','[]','衆人務苟合，達士羞雷同。',36,'全唐诗/poet.song.219000.json','["衆人務苟合，達士羞雷同。", "不可相爲謀，真成馬牛風。", "我愛郭文舉，乾坤一冥鴻。"]'),
('7fbb2c39-e16f-49c5-8483-d7c57357bcec','送僧東歸','釋文珦','宋','宋诗','song-poetry','','[]','今朝送君處，草色如許新。',72,'全唐诗/poet.song.219000.json','["今朝送君處，草色如許新。", "後會既難定，別愁那易陳。", "分手限吳越，烟波渺無津。", "雲山更重疊，歸與何峰鄰。", "憑人問消息，或恐非其真。", "不如早重來，勿使山猿嗔。"]'),
('3153c32d-a9b8-4933-bb36-eb8669db45be','祭坦仲履','釋文珦','宋','宋诗','song-poetry','','[]','仲履真吾徒，敏慧出流輩。',120,'全唐诗/poet.song.219000.json','["仲履真吾徒，敏慧出流輩。", "比玉無纖瑕，方珠絕微纇。", "子心如秋月，皎皎長不昧。", "子身如閒雲，出處極自在。", "相從逾十年，不見時俗態。", "愛子靜而文，喜子和而耐。", "語子以玄微，一一能領會。", "今子隔重泉，使我增感慨。", "酌彼清澗泉，爲子供一酹。", "魂氣誠有知，歆監儼如對。"]'),
('ee4d9281-f47f-4abf-831b-ae6baccb4e1f','同友行山逢隠僧語','釋文珦','宋','宋诗','song-poetry','','[]','我本忘世人，有志在巖穴。',144,'全唐诗/poet.song.219000.json','["我本忘世人，有志在巖穴。", "欣逢會心友，提携步林樾。", "雲中野僧居，樹梢清磬發。", "不憚登陟勞，遂得造石窟。", "門前羃蘿蔦，座後翳松栝。", "結草爲三衣，降龍在一鉢。", "問我從何來，執手道契闊。", "食我青精飯，語我頗諄切。", "教我去衆巧，使我守一拙。", "我誠服其言，畢志不敢越。", "他年定依止，相與定晚節。", "萬事盡棄捐，飲澗茹薇蕨。"]'),
('c2bb84c4-9b46-424b-b8b2-fc73ad113d69','寄教西岑','釋文珦','宋','宋诗','song-poetry','','[]','西岑我同流，常惜會面疏。',120,'全唐诗/poet.song.219000.json','["西岑我同流，常惜會面疏。", "秋深來舊京，一嘗造君廬。", "感君故情深，館我於恬虛。", "十日更倡酬，閒蹤頗虛邪。", "人事那好乖，扁舟賦歸與。", "茫茫烟水隔，無使堪寄書。", "萬玉森篔簹，孤峰麗芙蕖。", "掛夢於其間，栩栩復蘧蘧。", "以我常思君，知君亦思予。", "何時重携手，使此菀結舒。"]'),
('ea304388-d316-4815-a026-8ea4ec19bcc0','炙背','釋文珦','宋','宋诗','song-poetry','','[]','老身不能寒，心唯愛冬日。',60,'全唐诗/poet.song.219000.json','["老身不能寒，心唯愛冬日。", "炙背蓬門下，暖氣浹肌骨。", "自謂人間世，此樂居第一。", "雖曰狐貉溫，功莫與之匹。", "山居人不到，獨坐快捫虱。"]'),
('c2e0e12e-f864-4e1b-ab1b-7b2b421c752c','贈同志','釋文珦','宋','宋诗','song-poetry','','[]','我本無生儔，涉有乖素願。',120,'全唐诗/poet.song.219000.json','["我本無生儔，涉有乖素願。", "百年直寄耳，倏忽如過電。", "猶記學語時，老色遽滿面。", "富貴非所希，吾道在貧賤。", "往事絕尋思，殘生喜彊健。", "忘機有白鷗，消日頼黄卷。", "今辰扶杖出，窮探不知倦。", "與子偶相逢，抵掌說嘉遯。", "同歌紫芝曲，共飽青精飯。", "世人不相知，心通亦何悶。"]'),
('6f96ea14-868c-4f9d-b724-fd1717dfa49c','寄贈王子靜','釋文珦','宋','宋诗','song-poetry','','[]','子靜野鹿性，蕭散逃縶鞿。',96,'全唐诗/poet.song.219000.json','["子靜野鹿性，蕭散逃縶鞿。", "倚詩以爲田，曾弗憂年饑。", "詩腸有餘積，詩貌無多肥。", "朝吟暮亦吟，吐屑常霏霏。", "糟粕三百篇，自能發天機。", "兩脚走黄土，頗若知音稀。", "多時不相逢，念爾魂夢飛。", "何當抱詩來，共食山中薇。"]'),
('1876fdd6-213d-4d19-9519-4ff988afbbc0','贈隠僧','釋文珦','宋','宋诗','song-poetry','','[]','高僧謝人世，誅茅亂峰曲。',48,'全唐诗/poet.song.219000.json','["高僧謝人世，誅茅亂峰曲。", "三衣不著蠶，一飯長分鹿。", "露滴秋逕松，烟蒙曉窗竹。", "真隠澹無營，怡然心自足。"]'),
('32a38409-7357-4839-9d47-73a370823922','問李篔房疾','釋文珦','宋','宋诗','song-poetry','','[]','篔翁非時流，溫然古君子。',120,'全唐诗/poet.song.219000.json','["篔翁非時流，溫然古君子。", "我雖異教人，臭味略相似。", "四月不見翁，相望隔煙水。", "石壇忽來前，言翁乖攝理。", "真體本無病，請說病原委。", "乃知爲蒼生，常欲致平治。", "神明所扶持，厥疾自衰已。", "秋日定拏舟，賀翁勿藥喜。", "既爲蒼生病，須爲蒼生起。", "比壽於廣成，與宋相終始。"]'),
('0262d26b-0c4a-4d8d-8530-1841d31db272','重會馨桂山','釋文珦','宋','宋诗','song-poetry','','[]','桂山吾友于，壯歲即相親。',144,'全唐诗/poet.song.219000.json','["桂山吾友于，壯歲即相親。", "跌宕去鞿縶，出語必驚人。", "倏爾罹世難，東西各全身。", "十年不相逢，有若參與辰。", "偶乘霅舟來，見翁西澗濱。", "相對恍如夢，彼此白髮新。", "抵掌話疇昔，故情一何真。", "遺我白雪章，字字無埃塵。", "長歌山水中，鏗鈜驚鬼神。", "胡爲又當別，繾綣難具陳。", "風前一回首，寒波渺無津。", "他時定相思，題詩附雙鱗。"]'),
('5d66ecfd-5c80-4eb7-af87-0058d4ec2e2a','日夕佳','釋文珦','宋','宋诗','song-poetry','','[]','城市多溷濁，溪山宜避喧。',48,'全唐诗/poet.song.219000.json','["城市多溷濁，溪山宜避喧。", "山色日在門，變態從朝昏。", "悠然得之心，真樂方自存。", "此心誠不渝，軒冕何足論。"]'),
('ee2ed9f8-b992-4060-aa19-d546ce65688f','放浪詩','釋文珦','宋','宋诗','song-poetry','','[]','放浪遊名山，山水悅人意。',96,'全唐诗/poet.song.219000.json','["放浪遊名山，山水悅人意。", "窮日不知疲，行行轉幽邃。", "空籟如風聲，奇峰似雲氣。", "濯足就寒流，憇錫投古寺。", "長廊遇真僧，妙語發清秘。", "道我多隠情，喜我無衆僞。", "願言從此始，萬事盡捐棄。", "相從了餘生，共踐真實地。"]'),
('e3996425-cdb9-4fdf-a13f-d79c23b34dcb','屏居','釋文珦','宋','宋诗','song-poetry','','[]','屏居泉石間，所樂在閒縱。',48,'全唐诗/poet.song.219000.json','["屏居泉石間，所樂在閒縱。", "山田與山果，皆吾手自種。", "禾穗已垂穎，栗包初拆縫。", "一飽既可期，肯復作詩用。"]'),
('c16c40de-b1ed-4ed1-bbde-0d322885f5de','過野人居','釋文珦','宋','宋诗','song-poetry','','[]','閒人無外事，飯餘聊散策。',120,'全唐诗/poet.song.219000.json','["閒人無外事，飯餘聊散策。", "路逢一老翁，疑是避秦客。", "招携過別墅，茅茨翳桑麥。", "唯聞雞犬聲，了無車馬跡。", "自言入山來，居然長兒息。", "身將雲木親，志與風塵隔。", "屋邊種桃李，無言花自拆。", "原上耦耕人，將非是沮溺。", "遺世乃全真，何爲牽物役。", "從此數相尋，幽期竟難易。"]'),
('f3a714bd-1b2d-4530-989e-858874e8e756','酬清苕恭仲溫見寄舊詩追誌於此','釋文珦','宋','宋诗','song-poetry','','[]','吾生苦疎拙，不解謀此身。',108,'全唐诗/poet.song.219000.json','["吾生苦疎拙，不解謀此身。", "輾轉常寄食，短褐如懸鶉。", "徒御捨之去，往往嫌我貧。", "達交亦良多，安能强相親。", "唯有湖濱山，於我如故人。", "日夕與之對，澹然忘主賓。", "仲溫我同流，道我此意真。", "新詩遠相寄，可以書諸紳。", "何時到清苕，相携采白蘋。"]'),
('badb62a4-3f4f-4315-9a83-3937fd06a83a','送僧','釋文珦','宋','宋诗','song-poetry','','[]','雲作達人性，東西無定居。',48,'全唐诗/poet.song.219000.json','["雲作達人性，東西無定居。", "重逢在京闕，忽憶歸園廬。", "水宿傍江市，山行見樵車。", "後期難重尋，握手空躊躇。"]'),
('5d1d7e0c-4e2d-4a21-85bd-f024cfb23d0d','吾身  其一','釋文珦','宋','宋诗','song-poetry','','[]','東西南北人，寂寞住巖澗。',48,'全唐诗/poet.song.219000.json','["東西南北人，寂寞住巖澗。", "年衰鬢凝霜，客久衣絕襻。", "何須念粱肉，且復飽藜莧。", "猶患有吾身，身死即無患。"]'),
('16f97d39-5009-4364-8c4b-470010b5325d','吾身  其二','釋文珦','宋','宋诗','song-poetry','','[]','趨時非好步，步步青山歸。',48,'全唐诗/poet.song.219000.json','["趨時非好步，步步青山歸。", "眼界絕塵垢，耳根遺是非。", "充腸草木實，被體雲霞衣。", "吾貧豈當念，吾願已無違。"]'),
('2c1b6398-218b-425d-a350-e836570d0ebb','林卧','釋文珦','宋','宋诗','song-poetry','','[]','林卧歲月久，閒襟頗孤清。',120,'全唐诗/poet.song.219000.json','["林卧歲月久，閒襟頗孤清。", "靜中觀庶類，因之感予情。", "木伐以其材，膏煎以其明。", "獸檻以狡彯，禽籠以音聲。", "人苟矜智慮，自械傷神形。", "縱使功業崇，或受鼎鑊烹。", "今古無不然，念之殊可驚。", "世用常致患，時棄乃全生。", "所以箕潁客，翛然竟遺名。", "吾幸拙而愚，冀可終餘齡。"]'),
('8701986e-923c-4b34-9521-4e26c8c5ce7d','曉坐','釋文珦','宋','宋诗','song-poetry','','[]','夢破不成寐，茅齋坐清曉。',72,'全唐诗/poet.song.219000.json','["夢破不成寐，茅齋坐清曉。", "他山已擊鐘，獨樹初啼鳥。", "四體既調柔，衆境亦深窈。", "素書未終軸，朝光射林杪。", "任性無外求，一靜萬緣了。", "何事塵中人，百年徒擾擾。"]'),
('ecd87d81-8a31-4e64-9843-afe5d6a841da','冬日山居','釋文珦','宋','宋诗','song-poetry','','[]','出門無所求，藜杖常掛壁。',48,'全唐诗/poet.song.219000.json','["出門無所求，藜杖常掛壁。", "睡起日將午，耳目有清適。", "冰池坼寒光，雪簷響清滴。", "道人期不來，獨看麻衣易。"]'),
('64045118-b212-40b4-9efc-a29858aba0de','山居','釋文珦','宋','宋诗','song-poetry','','[]','自爲山居人，夢寐亦安佚。',48,'全唐诗/poet.song.219000.json','["自爲山居人，夢寐亦安佚。", "頗謂龜六藏，全勝兔三窟。", "性中唯一真，身外無餘物。", "形謝即示已，誰能問埋骨。"]'),
('7555aad4-a8d9-4bbc-8ad3-e359fe8bffb8','釣雪老漁','釋文珦','宋','宋诗','song-poetry','','[]','彼漁者何人，莫是滄浪叟。',48,'全唐诗/poet.song.219000.json','["彼漁者何人，莫是滄浪叟。", "萬頃自清心，千山同白首。", "忘世但垂綸，得魚唯換酒。", "醉後任扁舟，流到湘川口。"]'),
('c0ff6fcd-1956-4caa-8e1a-17df7af43bb0','贈別','釋文珦','宋','宋诗','song-poetry','','[]','古道久淪喪，世塗堪痛哭。',96,'全唐诗/poet.song.219000.json','["古道久淪喪，世塗堪痛哭。", "鸞鳳盡收聲，豺虎方擇肉。", "君從東方來，求我山北谷。", "君容一何臞，我髮日已禿。", "衰殘兩如此，寧不感心目。", "又還別我去，後期難重卜。", "握手臨路岐，贈言以爲祝。", "一祝宜强飯，二祝宜避俗。"]'),
('dc154aae-e62b-4f96-ba9f-6f48891bed2f','秋日有懷故人','釋文珦','宋','宋诗','song-poetry','','[]','山人出山去，山鳥長相憶。',48,'全唐诗/poet.song.219000.json','["山人出山去，山鳥長相憶。", "歲月能幾何，諸峯復秋色。", "孤雲在何處，烟水望不極。", "怊悵多遠情，飛鴻杳無跡。"]'),
('ca25adee-4d02-4242-b41d-e690774aeb52','屏居','釋文珦','宋','宋诗','song-poetry','','[]','吾生本疎庸，不作塵間夢。',96,'全唐诗/poet.song.219000.json','["吾生本疎庸，不作塵間夢。", "屏居萬山中，野性頗自縱。", "消摇鷹脫鞲，蕭散馬釋鞚。", "天寒放麋入，春燠聞鳥哢。", "斸藥時荷鉏，灌圃晨抱甕。", "薇生富採擷，橘熟斷包貢。", "喬松已巢鶴，瘦竹待鳴鳳。", "回首視世人，真若螘一鬨。"]'),
('76549b1b-847d-43b8-a76b-812ce7a847fb','尋幽宿隠者居','釋文珦','宋','宋诗','song-poetry','','[]','先生巢許流，遠志在箕潁。',120,'全唐诗/poet.song.219000.json','["先生巢許流，遠志在箕潁。", "由來天機深，遂使塵事屏。", "雲霾山徑長，草沒柴門靜。", "相逢冬日暮，共語寒夜永。", "照暝然枯松，漱泉𣂏暗井。", "虎嘯谷風生，猿啼霜月冷。", "潺湲瀑泉聲，寒亂高杉影。", "藐焉豁塵襟，頗若異人境。", "明朝還別君，尋幽過他嶺。", "他日擬重來，同采春山茗。"]'),
('db864139-c22a-4076-9177-53a263328626','齒脫','釋文珦','宋','宋诗','song-poetry','','[]','老齒皆脫落，十中無二三。',48,'全唐诗/poet.song.219000.json','["老齒皆脫落，十中無二三。", "存者一動摇，咀嚼寧復堪。", "荼薺均一咽，盡略苦與甘。", "世味非道腴，正爾不欲耽。"]'),
('9a999d75-16ff-4e0b-9faf-45332ea5e120','老景','釋文珦','宋','宋诗','song-poetry','','[]','日月如飛梭，爲我織老景。',48,'全唐诗/poet.song.219000.json','["日月如飛梭，爲我織老景。", "蒼艾浸成色，素絲颯垂領。", "短長任所裁，厚薄焉足省。", "善賈亦徒施，終然付泡影。"]'),
('217a32e8-3203-4e90-8efb-836627416671','天目山僧隠居','釋文珦','宋','宋诗','song-poetry','','[]','卜居就窮崖，几席凈如氾。',48,'全唐诗/poet.song.219000.json','["卜居就窮崖，几席凈如氾。", "三池更幽絕，澄澈皆可鑑。", "深處有蟠蛟，遊子不敢瞰。", "獨向月明時，臨流學清梵。"]'),
('21f460f7-d95f-4e66-9d02-9d0819fce71b','滅迹','釋文珦','宋','宋诗','song-poetry','','[]','滅迹巖岫間，居然養真素。',48,'全唐诗/poet.song.219000.json','["滅迹巖岫間，居然養真素。", "夕餐籬菊英，朝飲木蘭露。", "玄衢諒堪涉，時榮焉足慕。", "萬古功名人，纍纍但丘墓。"]'),
('ceea8c27-ff1b-4f58-a0bd-3790143a534b','衰病','釋文珦','宋','宋诗','song-poetry','','[]','衰病苦無悰，偃仰以終日。',48,'全唐诗/poet.song.219000.json','["衰病苦無悰，偃仰以終日。", "少間步東園，愈使我心怵。", "名芳掃跡空，野草爭頭出。", "無力事耘耛，長吁返蓬室。"]'),
('990b5af3-584b-4509-a2b2-7976642d214b','桂感','釋文珦','宋','宋诗','song-poetry','','[]','桂非桃李儔，露冷花始拆。',48,'全唐诗/poet.song.219000.json','["桂非桃李儔，露冷花始拆。", "馨香枝可取，欲以寄嘉客。", "道遠莫能致，徘徊終日夕。", "別情因物感，千里未嘗隔。"]'),
('f58b6544-5ed1-45f8-af20-18ef079e82d6','四皓','釋文珦','宋','宋诗','song-poetry','','[]','皓首四老人，獨見何明徹。',60,'全唐诗/poet.song.219000.json','["皓首四老人，獨見何明徹。", "耻爲暴秦汙，商山永歸潔。", "暫出正前星，遄回卧松雪。", "終令漢天子，不敢亂適孽。", "舒卷盡天機，非徒上名節。"]'),
('201e8f78-4ce0-4ec3-9060-769adabc514f','石室','釋文珦','宋','宋诗','song-poetry','','[]','石室靜而深，青山迭相映。',48,'全唐诗/poet.song.219000.json','["石室靜而深，青山迭相映。", "且無籠檻羈，頗適猿鳥性。", "外物俱棄捐，內塵亦清凈。", "人莫來扣門，驚回老僧定。"]'),
('aa17333f-ea51-402a-b672-a6bb8e20e31e','深居  其一','釋文珦','宋','宋诗','song-poetry','','[]','深居在空閑，頗適靜者性。',48,'全唐诗/poet.song.219000.json','["深居在空閑，頗適靜者性。", "門外無遊塵，落葉滿荒徑。", "陽光下西垂，東嶺有餘映。", "焚香讀楞伽，唯許山鬼聽。"]'),
('babc7ed5-04cc-4974-8d92-8d3afe91dab6','深居  其二','釋文珦','宋','宋诗','song-poetry','','[]','榮華不入夢，於焉謝憂責。',48,'全唐诗/poet.song.219000.json','["榮華不入夢，於焉謝憂責。", "深居三十年，禽猿盡相識。", "白日久知心，孤雲本無迹。", "丈室常寂然，焚香自終夕。"]'),
('b1b9da2c-bb5d-4db6-8275-9c2b09656f50','哭立虛舟','釋文珦','宋','宋诗','song-poetry','','[]','虛舟我良友，生平快冥搜。',144,'全唐诗/poet.song.219000.json','["虛舟我良友，生平快冥搜。", "放迹江湖間，自與造物遊。", "憶昔仗短筇，訪我竺峰頭。", "貽我選體詩，得法於曹劉。", "因之與定盟，有若膠漆投。", "出處雖小殊，夢寐常相求。", "是乃以神交，真如持遠儔。", "有力負舟去，迅速不少留。", "易寘於涼池，亦善爲舟謀。", "我獨念故情，涕淚如泉流。", "些舟以此詩，舟亦能聽不。", "舟或不吾聽，吾淚終難收。"]'),
('a1d00c5b-ee92-467e-9ee5-075d91cce3f6','今日','釋文珦','宋','宋诗','song-poetry','','[]','今日天氣佳，悠然動清興。',48,'全唐诗/poet.song.219000.json','["今日天氣佳，悠然動清興。", "桑間葚初熟，時復鳴戴勝。", "同遊盡蕭散，野徑亦幽夐。", "仰面看青天，長嘯山谷應。"]'),
('fb8ddf2e-f35c-44d6-919e-ec9a0986f21c','閒靜詞','釋文珦','宋','宋诗','song-poetry','','[]','自從住山來，未嘗離於山。',48,'全唐诗/poet.song.219000.json','["自從住山來，未嘗離於山。", "予愛山之靜，山亦多予閒。", "閒靜兩相得，悠然真意存。", "白雲乃知此，難與躁者言。"]'),
('334cca1c-c088-4ab7-b573-92c14026705c','裒集詩藁','釋文珦','宋','宋诗','song-poetry','','[]','吾學本經論，由之契無爲。',96,'全唐诗/poet.song.219000.json','["吾學本經論，由之契無爲。", "書生習未忘，有時或吟詩。", "興到即有言，長短信所施。", "盡忘工與拙，往往不修辭。", "唯覺意頗真，亦復無邪思。", "事物皆寓爾，又豈存肝脾。", "老來欲消閒，裒集還自嗤。", "聊以識吾過，吾道不在茲。"]'),
('c2f7c461-0d8e-49ea-944d-fbad9260a0a1','月夜聽琴歌','釋文珦','宋','宋诗','song-poetry','','[]','石床定起夜方中，爲豁幽興開房櫳。',192,'全唐诗/poet.song.219000.json','["石床定起夜方中，爲豁幽興開房櫳。", "吳天潔凈無雲蹤，萬里一色磨青銅。", "明月皎皎行虛空，穿松透竹光玲瓏。", "猛虎忽嘯茅屋東，林樹葉葉皆生風。", "壯哉宿客清溪翁，對月與我調絲桐。", "不拘商羽徵角宮，五音迭奏意無窮。", "希聲一一關天聰，天神下假山鬼從。", "玄鶴抃舞節奏同，延頸舒翼多儀容。", "嘗聞雅樂與政通，乃知此語非顓蒙。", "更漏欲徹曲未終，西鄰忽打五鼓鐘。", "溪翁憶著溪頭蓬，抱琴歸去還怱怱。", "願翁重來勿棄儂，儂欲共爾論心胸。"]'),
('d68ffd32-25d0-43e8-bc3c-b34be736c48b','母子吟','釋文珦','宋','宋诗','song-poetry','','[]','遊子行遠方，慈母在高堂。',59,'全唐诗/poet.song.219000.json','["遊子行遠方，慈母在高堂。", "砌有忘憂草，對之還斷腸。", "母心乃如斯，子心其可忘。", "子心苟如母，足以感蒼蒼。", "君不見漢蔡邕，晉王祥。"]'),
('93f000f2-53de-4f8b-b221-c7726197654e','江山縣旅夜','釋文珦','宋','宋诗','song-poetry','','[]','江郎峰頭雲漠漠，江郎廟前風雨作。',80,'全唐诗/poet.song.219000.json','["江郎峰頭雲漠漠，江郎廟前風雨作。", "路傍古寺不可棲，破屋殘僧情味惡。", "重尋野店度前林，夜寒無奈春衣薄。", "慚媿主人能會意，地鑪爇火深相慰。", "何似山中夢覺時，紙被蒙頭聽松吹。"]'),
('602ac44f-c069-45b1-b366-f00062a51621','烏夜啼','釋文珦','宋','宋诗','song-poetry','','[]','東家屋樹與雲齊，夜夜有烏來上棲。',64,'全唐诗/poet.song.219000.json','["東家屋樹與雲齊，夜夜有烏來上棲。", "明月照樹栖烏啼，愁殺窗中戰士妻。", "官家遣夫戍遼西，三年不歸守空閨。", "烏啼不止婦增泣，淚痕如雨衣裳濕。"]'),
('d97dd7ff-53d5-4af0-99bf-872f4b382cde','有美一人行','釋文珦','宋','宋诗','song-poetry','','[]','有美一人閑且都，天然自與常人殊。',160,'全唐诗/poet.song.219000.json','["有美一人閑且都，天然自與常人殊。", "奔逸絕塵遺步趨，宛在大海之東隅。", "珠宮貝闕非凡居，鮫綃被體雲霞裾。", "朝乘一鶴暮雙鳬，往來圓嶠仍方壺。", "所交皆古真仙徒，赤松羨門及麻姑。", "共論妙道得道樞，天地萬物指馬如。", "人間歲月良易徂，別來眼暗齒髮疎。", "山可泐兮海可枯，相思之念無時無。", "示好亦有明月珠，藏之懷袖不敢沽。", "屢欲致之乏飛魚，側身東望空躊躇。"]'),
('ad5d4883-9d14-4875-8e9c-1496080d6d62','過苕溪','釋文珦','宋','宋诗','song-poetry','','[]','苕溪發源自天目，一谿東之漾寒淥。',64,'全唐诗/poet.song.219000.json','["苕溪發源自天目，一谿東之漾寒淥。", "岸山續續相照映，原田每每資滲漉。", "祗看後浪催前浪，當悟新人換舊人。", "來往舟航謾如識，到頭若箇曾知津。"]'),
('96916235-d9f0-4b72-84b3-95e84f074f7c','苕霅歌','釋文珦','宋','宋诗','song-poetry','','["\u592a\u6e56"]','昔聞兩溪水色異，苕清霅渾猶渭涇。',118,'全唐诗/poet.song.219000.json','["昔聞兩溪水色異，苕清霅渾猶渭涇。", "又聞發源自天目，懸高墜峻如建瓴。", "日夜滾滾流不止，盡過白蘋紅蓼汀。", "流入太湖不復辨，挹之但聞魚鼈腥。", "堪笑人生亦如此，百年汲汲勞其形。", "到頭富貴亦何用，一卧泉下無由醒。", "爭似漁翁扁舟獨往最脫灑，七十二峰相對長青青。"]'),
('99032763-7313-46ed-b37e-d84da44d9bfb','春日吟','釋文珦','宋','宋诗','song-poetry','','[]','春山青，春水綠，野鳥啼春聲續續。',52,'全唐诗/poet.song.219000.json','["春山青，春水綠，野鳥啼春聲續續。", "提壺勸我飲，杜鵑勸我歸。", "吾歸不待勸，吾貧無酒資。", "之二蟲，不吾知，徒爾爲。"]'),
('0e9c65c6-3d47-42b6-a4ae-72763b5ab258','芙蓉花歌','釋文珦','宋','宋诗','song-poetry','','[]','東鄰檻外芙蓉花，初開粲粲如朝霞。',96,'全唐诗/poet.song.219000.json','["東鄰檻外芙蓉花，初開粲粲如朝霞。", "今朝花謝枝空在，繞樹千回只嘆嗟。", "花謝明年還復開，紅顔已去終難回。", "人生不及花枝耐，况有流光白髮催。", "遊子對花心盡醉，老翁見之如夢寐。", "解把浮生比夢中，肯計榮華與憔悴。"]'),
('1e05db9e-1df9-4512-846f-caeff6f7592d','晚秋遊興','釋文珦','宋','宋诗','song-poetry','','[]','餘英山中楓葉赤，龜溪溪上蘋花白。',112,'全唐诗/poet.song.219000.json','["餘英山中楓葉赤，龜溪溪上蘋花白。", "野翁杖屨往來頻，爲愛溪山好秋色。", "白叟虬髯眼深碧，邂逅相歡坐苔石。", "語終長嘯歸青壁，恐是雲深避秦客。", "斯人再見雖難期，忘機亦有漁樵席。", "藉草班荆相爾汝，無主無賓心自適。", "沙鷗飛度夕陽間，烟外遥聞一聲笛。"]'),
('dce1c566-000e-470c-afa4-d0c7a325d8da','趙白雲宗丞以詩送惠柳下謁浙西憲使包宏齋命余同賦','釋文珦','宋','宋诗','song-poetry','','[]','宏齋伊洛宗，白雲風雅主。',103,'全唐诗/poet.song.219000.json','["宏齋伊洛宗，白雲風雅主。", "二公在斯世，光艷燭寰宇。", "白雲歸帝鄉，宏齋庇寒士。", "出處雖小殊，憐才酷相似。", "吟詩貧到骨，白雲古知音。", "吹送宏齋前，雄詞重南金。", "乘流春浩蕩，變化那可測。", "君不見北溟有魚會風雲，一舉自然生羽翼。"]'),
('442edf8a-8d24-49d0-80d6-97586538374b','周草窗命題異人爪搯仙境圖','釋文珦','宋','宋诗','song-poetry','','[]','幽齋衆客多清娛，弁翁開卷示此圖。',196,'全唐诗/poet.song.219000.json','["幽齋衆客多清娛，弁翁開卷示此圖。", "細畫纖纖比毛髮，老眼眴轉眡若無。", "須臾神定乃能辨，蓬山圓嶠連方壺。", "山川盤紆體勢遠，樓觀縹緲棼桴鋪。", "霓旌羽蓋蔽空日，雲軿鶴馭交天衢。", "瓌麗綺錯千萬狀，一一盡與人間殊。", "弁翁指陳更詳悉，言是澄江惠氏所寶之舊物。", "昔有道人方外來，暮夜延之入其室。", "蕭然獨卧無燈明，時聞爪甲鏗有聲。", "明發道人不知處，但見桶底搯畫成。", "吾知道人非小巧，物物之中存幻眇。", "更于爪畫兩俱忘，當與道人同一笑。"]'),
('52af2f26-7f59-4ae1-ac9b-ab63272a31ea','周草窗吟藁號蠟屐爲賦古語','釋文珦','宋','宋诗','song-poetry','','[]','嘗聞阮孚心好屐，對客蠟之手不釋。',112,'全唐诗/poet.song.219000.json','["嘗聞阮孚心好屐，對客蠟之手不釋。", "閒暢非唯時所推，千載嘉名猶著白。", "弁山山陽有吟翁，嗜詩亦與嗜屐同。", "盡將書傳資詩用，字字句句加磨礱。", "萬象一時供掇拾，大翫於詞成鉅集。", "還將蠟屐以自名，吾知清尚人難及。", "尚喜江湖有此翁，此詩此屐當無窮。"]'),
('31274d1f-076f-4ea0-8c0e-812ea3e3635e','風雨','釋文珦','宋','宋诗','song-poetry','','[]','晚來江上天不分，老蛟吐氣成江雲。',128,'全唐诗/poet.song.219000.json','["晚來江上天不分，老蛟吐氣成江雲。", "夜半大風飄屋瓦，頃刻簷間雨如瀉。", "柴門緊閉不敢開，漸聞水聲到床下。", "開門處處聞啼號，盡說浪頭三尺高。", "室廬漂蕩無處所，妻孥大半隨波濤。", "江市一時爲沮洳，急打行包入山去。", "通衢沆漭不可行，歷盡西山豺虎路。", "但願自今風雨調，無復破塊與鳴條。"]'),
('43139853-b04d-4957-8602-7d5b8e2eedf6','公無渡河','釋文珦','宋','宋诗','song-poetry','','[]','河源來自崑崙西，滔天沃日無津涯，擢夫漁子不敢窺。',56,'全唐诗/poet.song.219000.json','["河源來自崑崙西，滔天沃日無津涯，擢夫漁子不敢窺。", "公欲徑渡公誠癡，癡公溺死如何爲。", "竟委骨肉於蛟螭，徒使萬古箜篌悲。"]'),
('25e5210c-268d-43e4-85c6-2760442e0f3c','古松歌','釋文珦','宋','宋诗','song-poetry','','[]','山中草木知何數，獨愛菴西古松樹。',80,'全唐诗/poet.song.219000.json','["山中草木知何數，獨愛菴西古松樹。", "千歲老鶴巢其巔，根有茯苓心不蠹。", "秋來是物皆摇落，此君勁色還如故。", "嘗間無用乃全生，却恐身爲材所誤。", "最好無過是樗散，一生不入良工眼。"]'),
('d1806a8e-949f-441c-aca7-e96c773f9400','神樹詞','釋文珦','宋','宋诗','song-poetry','','[]','村西大樹高入雲，樹根作屋祠爲神。',112,'全唐诗/poet.song.219000.json','["村西大樹高入雲，樹根作屋祠爲神。", "村農四時常祭賽，但願長幼無災屯。", "更乞風雨皆調適，官不追呼無盜賊。", "六畜蕃滋百穀成，報神之賜何終極。", "問農當年未生樹，此樹之神何所附。", "它時此樹朽而仆，樹神又向何方去。", "農笑吾言吾笑農，濁涇清渭終難同。"]'),
('4027f653-1560-487d-9336-a57130c4aae6','爲李少監賦秋崖歌','釋文珦','宋','宋诗','song-poetry','','[]','四時之氣秋最清，千崖風骨方崢嶸。',96,'全唐诗/poet.song.219000.json','["四時之氣秋最清，千崖風骨方崢嶸。", "石黛碧玉迭照映，喬松老柏森縱橫。", "上有白雲可爲佩，下有寒泉堪濯纓。", "樵夫仰視不敢上，鸞鶴日夜長和鳴。", "若有人兮似冰雪，以斯崖兮擬高潔。", "飲玄津兮餐玉屑，御清風兮朝帝闕。"]'),
('0b83a74f-2044-44d7-a213-aa594b990fec','秋浦老漁','釋文珦','宋','宋诗','song-poetry','','[]','秋浦老漁人不識，清溪數灣船一隻。',80,'全唐诗/poet.song.219000.json','["秋浦老漁人不識，清溪數灣船一隻。", "釣竿垂垂釣絲直，眼光過似谿光碧。", "得魚歸來不自喫，開籠分與白鷳食。", "却來獨坐磯頭石，對著斜陽誦周易。", "恐是渭濱姜子牙，安得文王與同車。"]'),
('b0c284d3-d33a-48cb-a5f1-d307998ae80b','蠶婦歎','釋文珦','宋','宋诗','song-poetry','','[]','吳儂三月春盡時，蠶已三眠蠶正饑。',96,'全唐诗/poet.song.219000.json','["吳儂三月春盡時，蠶已三眠蠶正饑。", "家貧無錢買桑餧，奈何饑蠶不生絲。", "婦姑携籃自相語，誰知我儂心裏苦。", "姑年二十無嫁衣，官中催稅聲如虎。", "無衣衣姑猶可緩，無絹納官當破産。", "鄰家破産已流離，頹垣廢井行人悲。"]'),
('5e6e3d7d-dd24-40e4-86f6-e878056f48aa','鳴鴈行','釋文珦','宋','宋诗','song-poetry','','[]','鳴鴈𡄸𡄸來自北，一一銜蘆度深磧。',80,'全唐诗/poet.song.219000.json','["鳴鴈𡄸𡄸來自北，一一銜蘆度深磧。", "空受嚴霜捐羽毛，不爲征人寄消息。", "散落湘吳無定所，或寄平川或洲渚。", "相喚相呼不亂羣，非比寒鴉無次序。", "弋者多懷害爾心，栖宿須尋烟水深。"]'),
('964d6394-928e-4975-bce3-1b5553dff7ff','北風行','釋文珦','宋','宋诗','song-poetry','','[]','北風凜凜生祁寒，陰雲萬里何𩆓𩆓，羣木盡槁叶盡丹。',136,'全唐诗/poet.song.219000.json','["北風凜凜生祁寒，陰雲萬里何𩆓𩆓，羣木盡槁叶盡丹。", "日月迅駃猶飛湍，人間光景亦易殫。", "離家不如在家安，胡爲夫君乃遊般。", "自古共嗟行路難，摧輪折軸良可嘆。", "客中憂緒常萬端，何當對面同歌歡。", "願得此身生羽翰，與君相逐同鴛鸞。", "有懷未遂寧容寬，耿耿不寐遥夜闌。", "孤鴻求匹聲嘶酸，使我感物摧心肝。"]'),
('ae2d77ad-ace0-4d35-bb1d-945e1bbc9d7e','聽野老所言','釋文珦','宋','宋诗','song-poetry','','[]','衰翁卧病山之阿，東村沈老來相過。',224,'全唐诗/poet.song.219000.json','["衰翁卧病山之阿，東村沈老來相過。", "首言年饑苦無備，次說時政多煩苛。", "其間數事盡切己，具有本末非差訛。", "農家累世服畎畝，此外寧復知其他。", "世道愈變俗愈薄，天意亦復相折磨。", "舉貸養蠶不收繭，盡瘁耕耨田無禾。", "千瘡百孔正難補，前月里正來催科。", "家貧乏錢辦酒食，賣却養命雙種鵝。", "昨朝縣吏又追喚，真如鳥雀遭網羅。", "兒女啼號顧弗及，心如亂絲頭緒多。", "西鄰寡婦更可念，譬彼壞木無枝柯。", "饑寒交煎絕生意，母子牽挽沈於河。", "句句皆從痛腸出，語罷涕泣俱滂沱。", "民之多艱有如此，於乎彼蒼其奈何。"]'),
('dad5f28b-7108-4cac-a87b-8498f0105a5b','寒風','釋文珦','宋','宋诗','song-poetry','','[]','寒風蕭蕭吹我衣，迎晨入山采蕨薇。',96,'全唐诗/poet.song.219000.json','["寒風蕭蕭吹我衣，迎晨入山采蕨薇。", "魍魎窺人猛虎嘯，草間多露猶未晞。", "歷盡窮崖與陰谷，終朝采之不盈匊。", "憂心殷殷日將暮，手持空筐返茅屋。", "賊臣惡子厭輕肥，志士幽人常苦饑。", "古來萬代共如此，樂天知命復何悲。"]'),
('f5e7e16a-3847-4bea-8618-4cae216064af','讀韓非子','釋文珦','宋','宋诗','song-poetry','','[]','非本韓國諸公子，胡乃人形心蝮虺。',128,'全唐诗/poet.song.219000.json','["非本韓國諸公子，胡乃人形心蝮虺。", "身既入秦而媚秦，肆無忌憚浮商李。", "狂言著書三十篇，讀者能無汙脣齒。", "且言仁義不足用，唯有嚴刑堪致治。", "斯言豈足稱人言，反悖經常滅天理。", "助秦爲虐猶庶幾，名教不容良可耻。", "昔者韓虔嘗篡晉，遠遡其源固應爾。", "吾欲火書而人人，周孔之道不如是。"]'),
('e987e223-a896-4271-9ef5-006016510803','旱雨','釋文珦','宋','宋诗','song-poetry','','[]','賊臣弄權罔明主，億萬蒼生受辛苦。',80,'全唐诗/poet.song.219000.json','["賊臣弄權罔明主，億萬蒼生受辛苦。", "大家巨室盡逃亡，賸積黄金向郿鄔。", "弘羊未烹旱如許，弘羊將烹天乃雨。", "吾言此雨是雨穀，點點活人勝珠玉。", "聖恩新放限田租，從此農家飽飦粥。"]'),
('e69d4218-c292-454d-8a5b-9c5639d81aa3','夏暑正隆望秋得雨因賦長句','釋文珦','宋','宋诗','song-poetry','','[]','夏日烈烈揚暉光，陽氣入土土力强。',128,'全唐诗/poet.song.219000.json','["夏日烈烈揚暉光，陽氣入土土力强。", "望秋三日雨滂滂，庶物浡然俱阜昌。", "雨暘時若異咎恒，秔稻薿薿如人長。", "西風朝夕吹新涼，風來已作酒飯香。", "老農再拜謝穹蒼，此去足以供烝嘗。", "只今吏卒多豺狼，唯恐肆威加奪攘。", "一粒不得入我腸，父子悲啼茹糟糠。", "願將此意達君王，毋官貪冒官循良。"]'),
('121bdab7-ea83-483a-92ba-b90e9f375c8c','走馬引','釋文珦','宋','宋诗','song-poetry','','[]','走馬官奴金縷衣，食人膏血如瓠肥。',64,'全唐诗/poet.song.219000.json','["走馬官奴金縷衣，食人膏血如瓠肥。", "田夫力耕猶餓死，爾曹醉飽忘年饑。", "天視生民同一子，胡爲不平乃如此。", "人衆勝天且勿驚，天若定時天自平。"]'),
('93201c8d-adf5-4d74-b557-c9aca6e6d45d','答仇山村見寄','釋文珦','宋','宋诗','song-poetry','','[]','十年不見山村人，瑶華忽到英溪濱。',96,'全唐诗/poet.song.219000.json','["十年不見山村人，瑶華忽到英溪濱。", "見詩猶如見君面，讀詩隻字必三嚥。", "當今滿眼非吾曹，與君例亦同此遭。", "風雅之音幸未變，託之足以舒鬰陶。", "頗謂仇仙若鸞鳳，造次而鳴亦驚衆。", "丹穴方堪養羽儀，他年會作明時用。"]'),
('2e05895c-3e4f-46ac-97f2-c21a17fd26c4','爲脩樗作歌','釋文珦','宋','宋诗','song-poetry','','[]','我愛巖間古樗櫟，蔽日參雲過千尺。',128,'全唐诗/poet.song.219000.json','["我愛巖間古樗櫟，蔽日參雲過千尺。", "樵蘇來往作陰凉，不爲風霜變顔色。", "匠氏入林持斧斤，材無大小皆選掄。", "豫章楩楠豈復有，獨以無用全其身。", "山僧因得養生理，故以巖樗自爲比。", "只把樛枝庇本根，肯誇美幹招殘毀。", "幽人志士當勿疑，聽我朗誦巖樗詩。", "縱爲梁棟或易撓，巖下清風無盡時。"]'),
('4885ea5a-3c47-413f-b939-2c66a1c42d4f','爲山僧作松石歌','釋文珦','宋','宋诗','song-poetry','','[]','一片石，一株松。',65,'全唐诗/poet.song.219000.json','["一片石，一株松。", "石如虎距松如龍，風雲變化多靈蹤。", "有僧託此憇寂寞，心與境會無塵容。", "記得當年採秀於天台萬八千丈之深峰，石橋西畔曾相逢。"]'),
('e517686b-f16a-461f-863b-05597b9fcd4e','溪翁','釋文珦','宋','宋诗','song-poetry','','[]','青山映溪三十里，水中白石何齒齒。',72,'全唐诗/poet.song.219000.json','["青山映溪三十里，水中白石何齒齒。", "是非不入溪翁耳，生涯祇在清溪裏。", "終日磯頭坐碧藟，釣絲入潭魚唯唯。", "得魚滿籠渾家喜。", "溪光似鏡山如黛，不是溪翁不知愛。"]'),
('d6b8e1e2-fac1-42cf-94b3-3737374b87b4','西城行','釋文珦','宋','宋诗','song-poetry','','[]','閒蹤無滯留，有興即行樂。',96,'全唐诗/poet.song.219000.json','["閒蹤無滯留，有興即行樂。", "崎嶇歷重丘，窈窕窮遠壑。", "遂步西城道，脩墉带高閎。", "門前設梐枑，喧喧歌吹聲。", "老人咨嗟語予故，園林曾是前人墓。", "予謂老人置勿論，自古廢興何定據。", "今人歡樂寧長保，後人還爲傷懷抱。"]'),
('81de716e-20cf-4325-a9b7-046ece43c8c7','靈泉篇','釋文珦','宋','宋诗','song-poetry','','[]','高僧誦經經出泉，泉靈不許蛟龍眠。',64,'全唐诗/poet.song.219000.json','["高僧誦經經出泉，泉靈不許蛟龍眠。", "湛湛長開古明鏡，泠泠暗瀉朱絲絃。", "曾說煮茶甘入齒，爲是心源功德水。", "淵然千古無是非，遮莫放人來洗耳。"]'),
('4bb21125-8866-409a-8744-ac609220d196','題履道兄古松圖','釋文珦','宋','宋诗','song-poetry','','[]','屏間何人畫四松，高標半在烟雲中。',182,'全唐诗/poet.song.219000.json','["屏間何人畫四松，高標半在烟雲中。", "人來盡作真松看，槎枒古怪勢不同。", "一株連蜷如老龍，曾見於康廬窈窱之深峰。", "兩株橫斜蒼黛色，曾見於鴈蕩高寒之絕壁。", "最西一株更奇特，老來昏耄記不得。", "想得當初落筆時，名山洞府徧尋思。", "細將覽勝探幽興，暗寫凌霜傲雪姿。", "古來畫者雖無數，少有人能得真趣。", "畢宏韋偃骨已寒，今日此圖堪獨步。", "主人勸我爲作歌，才薄無奈此圖何。", "疾書一百六十字，勿笑迫促無委佗。"]'),
('40ffbb44-0a18-473b-905d-b3851115962a','秋月山中放歌','釋文珦','宋','宋诗','song-poetry','','[]','秋氣清，秋葉鳴，四山風骨方崢嶸。',78,'全唐诗/poet.song.219000.json','["秋氣清，秋葉鳴，四山風骨方崢嶸。", "有時支頤靜對，有時緩步遊行。", "朝昏之景無盡藏，一皆遺我無人爭。", "中林橡栗又可拾，老夫快活不可名。", "乃作歌，歌此情，雲中木客時來賡。"]'),
('55e79290-3beb-4d44-9a66-7e1e11c2365c','山房假寐夢有一客抱琴奏曲而去既覺詩以記之','釋文珦','宋','宋诗','song-poetry','','[]','山房夜坐無衆喧，隠几而卧方澹然。',112,'全唐诗/poet.song.219000.json','["山房夜坐無衆喧，隠几而卧方澹然。", "忽夢有人來我前，從容爲我揮五絃。", "琴聲一一皆清圓，如聽廣樂於鈞天。", "曲終倏爾升雲軿，亦有笙鶴相後先。", "未知重會在何年，臨風別恨空綿綿。", "覺來竟亦何有焉，唯聞漏鼓聲咽咽。", "因識死生同寤寐，榮枯得失皆無意。"]'),
('4a9b23ac-8379-4355-b271-d47221f0d37e','關山月','釋文珦','宋','宋诗','song-poetry','','[]','月從東海出，冷照玉門關。',72,'全唐诗/poet.song.219000.json','["月從東海出，冷照玉門關。", "征人家萬里，夢向月中還。", "金閨亦有夢，却行玉關道。", "道路不相知，思深各衰老。", "胡笳亂吹哀怨多，奈此關山明月何。", "終宵迸淚如金波。"]'),
('6be83996-e3b1-4eb7-8e5f-99895cbf439e','月下吟','釋文珦','宋','宋诗','song-poetry','','[]','炎宵喜見月，對月還傷神。',80,'全唐诗/poet.song.219000.json','["炎宵喜見月，對月還傷神。", "視彼清涼月，感吾夢幻身。", "月色鎮長在，身將化爲塵。", "月照今人盡，還照後來人。", "今人後人自歸土，此月光輝彌萬古。", "了知身幻不堅牢，富貴功名何足取。"]'),
('aa391ed7-b021-4628-bf84-76d8b9984842','寧退耕巖維石隆湖隠皆嘗有德於余圖報未能而俱下世感念存亡哭以十韻','釋文珦','宋','宋诗','song-poetry','','[]','吾生素無寵祿願，自向空林灰百念。',160,'全唐诗/poet.song.219000.json','["吾生素無寵祿願，自向空林灰百念。", "但存心地如砥平，不道人間有崖塹。", "皇天幸能念無辜，脫我險難歸夷塗。", "天定勝人乃其證，紛紛譖舌胡爲乎。", "四方交朋盈什百，反眼如同不相識。", "豈唯袖手不能援，多若蒼蠅變白黑。", "獨有空門三老人，或未識面非交親。", "奮身爲余直其枉，惻隠如此宜稱仁。", "思欲報之苦無力，但有此心匪石席。", "今日同爲異世人，俛仰存亡三太息。"]'),
('0f6471e6-12e0-4898-a07a-a8cd776a1d01','余行江湖餘五十載備知交態唯熏自聞始終不變因作歌見意焉','釋文珦','宋','宋诗','song-poetry','','[]','小人必樹黨，勢利相因依。',139,'全唐诗/poet.song.219000.json','["小人必樹黨，勢利相因依。", "勢成乃翕合，勢去還暌離。", "君子貴獨立，中心存不欺。", "榮華羞附麗，衰謝罔棄遺。", "君子與小人，於此常見之。", "君子誠可宗，小人足堪嗤。", "君不見媚春野卉億萬數，花欄映發如有期。", "一朝霜風肆凌厲，傍睨不復相扶持。", "澗底喬松過百尺，干霄直上無附枝。", "黛色不爲時所變，澹然自有歲寒姿。"]'),
('9c5f3467-81ac-4d49-9172-8a0925398276','卧雲歌','釋文珦','宋','宋诗','song-poetry','','[]','潛山道人性疎懶，地覆天翻渾不管。',96,'全唐诗/poet.song.219000.json','["潛山道人性疎懶，地覆天翻渾不管。", "草座麻衣居絕巘，一間茅屋雲常滿。", "頗愛雲縱亦蕭散，於焉誓與雲爲伴。", "終日卧雲忘早晚，夢回日照雲床暖。", "彼此無心體舒緩，所以相從加繾綣。", "他年我死雲獨存，雲應惋惜吾生短。"]'),
('2e42fcfa-287c-43a9-a1e5-ec6bd7f907f2','少年走馬行','釋文珦','宋','宋诗','song-poetry','','[]','少年走馬去如飛，大笑吾衰行走遲。',80,'全唐诗/poet.song.219000.json','["少年走馬去如飛，大笑吾衰行走遲。", "吾同君健應無日，君似吾衰定有時。", "烏兔交馳猶急傳，能令海水桑田變。", "物之大者尚難常，何况百年如迅電。", "要知此語非相誣，更當持以問麻姑。"]'),
('4a188ddf-71ad-45be-a002-f6fd4ebba7de','書仇遠吟卷後','釋文珦','宋','宋诗','song-poetry','','[]','昔在英谿識仇遠，豈意別來陵谷變。',96,'全唐诗/poet.song.219000.json','["昔在英谿識仇遠，豈意別來陵谷變。", "死生契闊不相知，一十四年如過電。", "蓮花峰下得重逢，老色駸駸驚上面。", "袖出新吟數百篇，非特清新更奇健。", "我道風流似謫仙，定知當上金鑾殿。", "愛才未必無明皇，薦聞亦有賀知章。"]'),
('560ac7cb-98c2-43c6-bfdc-ad5ddd75128f','次教西岑見貽韻','釋文珦','宋','宋诗','song-poetry','','[]','宴山山裏白頭翁，室空亦復無山童。',64,'全唐诗/poet.song.219000.json','["宴山山裏白頭翁，室空亦復無山童。", "往來山月幾圓缺，入山未聾今已聾。", "柴門反關不容叫，翁欲養蒙仍養浩。", "莫嫌翁苦戀山中，良恐出山爲小草。"]'),
('17903942-5fd2-47e3-9359-4442f3a1ac45','懷天目西尖隠者','釋文珦','宋','宋诗','song-poetry','','[]','西尖高插白雲裏，下視行人細如蟻。',32,'全唐诗/poet.song.219000.json','["西尖高插白雲裏，下視行人細如蟻。", "客至山翁禪不起，天風吹落青松子。"]'),
('dc59ba84-ca15-4371-bc4d-4734c00028da','送僧歸廬山','釋文珦','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','上人家在廬山陰，木皮作衣雲作心。',64,'全唐诗/poet.song.219000.json','["上人家在廬山陰，木皮作衣雲作心。", "獨携鐵錫來參尋，禪中悟得唐人吟。", "秋高忽憶歸山住，舊結茅茨連古樹。", "他年我欲尋君去，祇恐雲深不知處。"]'),
('584156b4-901b-4b9c-bbe1-bf7f8bd1339c','送僧','釋文珦','宋','宋诗','song-poetry','','[]','寒蟲感秋氣，非爲遊子吟。',56,'全唐诗/poet.song.219000.json','["寒蟲感秋氣，非爲遊子吟。", "遊子寂寞聞，自然動歸心。", "歸到南巖秋欲晚，山栗正肥山稼滿。", "山中獨坐看雲時，還憶湖邊舊吟伴。"]'),
('fc5ea00b-852d-48cf-a1e4-450a442596b5','遣興','釋文珦','宋','宋诗','song-poetry','','[]','七十七歲潛山翁，見聞已盡如盲聾。',64,'全唐诗/poet.song.219000.json','["七十七歲潛山翁，見聞已盡如盲聾。", "祇在山邊水邊住，了得人空我亦空。", "鐵心石腸安晚節，未輸金口而木舌。", "此真難與時人說，明知獨有高空月。"]'),
('efb38aab-d24f-4edc-9ede-ecef5f66fcad','送林弓寮歸閩省覲竹谿中書往赴安谿縣新任  其一','釋文珦','宋','宋诗','song-poetry','','[]','當展經綸志，初爲撫字官。',48,'全唐诗/poet.song.219000.json','["當展經綸志，初爲撫字官。", "五絃能自愛，百里幾民安。", "此去還家便，知非行路難。", "蒍于歌一曲，先合盡親歡。"]'),
('08202e33-3825-4aa4-a455-6013c6bcc16f','送林弓寮歸閩省覲竹谿中書往赴安谿縣新任  其二','釋文珦','宋','宋诗','song-poetry','','[]','別我重雲裏，揚舲積雨餘。',48,'全唐诗/poet.song.219000.json','["別我重雲裏，揚舲積雨餘。", "預愁千里道，難寄一緘書。", "蹔爾還谿館，重來任石渠。", "明朝謾凝睇，舟已過桐廬。"]'),
('23c18e0f-8d9e-407f-8e2b-e83b5a0fe062','初三夜月','釋文珦','宋','宋诗','song-poetry','','[]','新月似蛾眉，娟娟止片時。',48,'全唐诗/poet.song.219000.json','["新月似蛾眉，娟娟止片時。", "輝光雖有缺，輪廓未曾虧。", "三五還應滿，尋常那得知。", "人生亦如此，窮達信難期。"]'),
('9f4d5e39-3ed1-43a7-911e-a909ff5ad34a','懷隠者','釋文珦','宋','宋诗','song-poetry','','[]','逸步脫譏讒，高蹤不混凡。',48,'全唐诗/poet.song.219000.json','["逸步脫譏讒，高蹤不混凡。", "獨甘巢絕谷，人似說遊巖。", "自製幽人筆，妻裁隠士衫。", "世交空見憶，無處寄書函。"]'),
('d30b2525-5b54-484b-996d-289940aaccaa','送趙一嚴守永嘉','釋文珦','宋','宋诗','song-poetry','','[]','九重思共理，符竹付更生。',48,'全唐诗/poet.song.219000.json','["九重思共理，符竹付更生。", "卿月輝麟譜，文星次鹿城。", "精微敷易教，信厚播詩聲。", "好使中川水，長流不盡清。"]'),
('9f77388f-6d14-4e50-9d3e-42ff547b50f4','送兵部兄出守高安','釋文珦','宋','宋诗','song-poetry','','[]','君是甲科人，文章已立身。',48,'全唐诗/poet.song.219000.json','["君是甲科人，文章已立身。", "遠邦迎父母，天闕動星辰。", "行愛三冬日，到爲千里春。", "如將致吾后，先要惜斯民。"]'),
('7751aef0-4cb2-4b22-9b3b-376afd1df3cc','雲門六寺即唐靈澈師舊隠','釋文珦','宋','宋诗','song-poetry','','[]','吟徧唐人句，玄蹤不易攀。',48,'全唐诗/poet.song.219000.json','["吟徧唐人句，玄蹤不易攀。", "一溪清到郭，諸寺各依山。", "暮雨松花老，秋風藥井間。", "唯應千歲後，華表鶴飛還。"]'),
('0e16db05-1345-48b9-8f83-93bd0fec596d','題暇亭','釋文珦','宋','宋诗','song-poetry','','[]','人與山同靜，亭安紫翠間。',48,'全唐诗/poet.song.219000.json','["人與山同靜，亭安紫翠間。", "無時臨鏡水，終日見南山。", "子敬心猶雜，淵明意自閒。", "坐來輕世事，薄暮鳥飛還。"]'),
('9712e667-06ec-42bb-9b1e-a1d134c75ede','日鑄山中阻雪','釋文珦','宋','宋诗','song-poetry','','[]','來訪幽人宿，春風未變和。',48,'全唐诗/poet.song.219000.json','["來訪幽人宿，春風未變和。", "水聲依澗遠，雪意向山多。", "坡竹摧新粉，庭杉失舊柯。", "山童曉相報，鹿跡夜曾過。"]'),
('0ae439b0-e278-4848-830d-2bc635582bbc','客居阻雪','釋文珦','宋','宋诗','song-poetry','','[]','客居還歲暮，風雪掩柴扉。',48,'全唐诗/poet.song.219000.json','["客居還歲暮，風雪掩柴扉。", "人向行中老，鄉從夢裏歸。", "繁聲交澗竹，餘冷入山衣。", "消遣憑詩句，猶慚未入微。"]'),
('720bb2d2-cfb0-4dad-a9f1-6c9fe9d7e40b','新昌南巖','釋文珦','宋','宋诗','song-poetry','','[]','大禹未疏鑿，此山爲海門。',48,'全唐诗/poet.song.219000.json','["大禹未疏鑿，此山爲海門。", "試從樵逕上，猶有釣車存。", "佛屋棲靈竇，仙墳蔭遠村。", "巖頭一滴水，居者不知源。"]'),
('0ada0d3b-3b33-4076-8c4c-96ee897a0541','宿山庵','釋文珦','宋','宋诗','song-poetry','','[]','絕頂一庵孤，悠悠清夜徂。',48,'全唐诗/poet.song.219000.json','["絕頂一庵孤，悠悠清夜徂。", "野僧寒出定，山鬼暗相呼。", "泉落池應滿，雲深樹欲無。", "何年捐萬事，來此共跏趺。"]'),
('03b14405-7928-4f11-a169-fb5d0712483d','野祠','釋文珦','宋','宋诗','song-poetry','','[]','翁媼已相催，喧喧鼓笛來。',48,'全唐诗/poet.song.219000.json','["翁媼已相催，喧喧鼓笛來。", "荒祠三面水，老樹一身苔。", "休咎馮巫語，凶豐信珓杯。", "神前釃酒罷，風散紙錢灰。"]'),
('a16cf8e8-9231-4e21-aeb3-4e9ab34cd0da','和人晚秋客思','釋文珦','宋','宋诗','song-poetry','','[]','雙轂苦難留，江城又晚秋。',48,'全唐诗/poet.song.219000.json','["雙轂苦難留，江城又晚秋。", "故鄉難寄訊，倦客獨登樓。", "衰草重重恨，征鴻字字愁。", "漁翁却蕭散，吹笛過前洲。"]'),
('a3918f14-f42f-4d4d-a877-c2a8c38608af','節物','釋文珦','宋','宋诗','song-poetry','','[]','節物苦驚人，那堪遠客身。',48,'全唐诗/poet.song.219000.json','["節物苦驚人，那堪遠客身。", "梅心輕送臘，柳意轉隨春。", "叢薄啼新鳥，深泉動蟄鱗。", "獨憐歸夢短，不得面慈親。"]'),
('15e00807-dc2d-4ab2-9528-88ac1f75c289','姚江舟中夢故人勸歸','釋文珦','宋','宋诗','song-poetry','','[]','一舸寒江上，蕭蕭兩鬢華。',48,'全唐诗/poet.song.219000.json','["一舸寒江上，蕭蕭兩鬢華。", "不唯傷道路，終恐委泥沙。", "宿雨添山靄，秋風起浪花。", "故人應念我，夢裏勸還家。"]'),
('4130386b-98c8-4cc3-acde-a407f69b666d','鄞中他山堰','釋文珦','宋','宋诗','song-poetry','','[]','碧浸他山古，梅梁昔化龍。',48,'全唐诗/poet.song.219000.json','["碧浸他山古，梅梁昔化龍。", "江溪一堰隔，禾黍四郊重。", "絕唱思幽客，歡聲徧野農。", "長官功不朽，遺廟合歌鐘。"]'),
('5aa2a46d-310a-4969-9b83-d0a5e49e2922','漁父','釋文珦','宋','宋诗','song-poetry','','[]','在處變名姓，往來長嘯歌。',48,'全唐诗/poet.song.219000.json','["在處變名姓，往來長嘯歌。", "一身無賦役，幾口共烟波。", "江月垂綸下，汀雲宿棹和。", "却應嫌渭叟，老去脫寒蓑。"]'),
('da0bc6c9-a28f-4322-9b8d-e2de3b0e4985','忠文洪相公挽辭  其一','釋文珦','宋','宋诗','song-poetry','','[]','間氣鍾河岳，深衷悟冕旒。',48,'全唐诗/poet.song.219000.json','["間氣鍾河岳，深衷悟冕旒。", "雄文驚萬古，勁節凜高秋。", "清廟絃何絕，明堂柱不留。", "我生蒙許與，灑淚莫能休。"]'),
('7ec4ed95-7e86-49e3-aeaf-2f4e4f26f394','忠文洪相公挽辭  其二','釋文珦','宋','宋诗','song-poetry','','[]','盛德歸冥寞，斯文轉寂寥。',48,'全唐诗/poet.song.219000.json','["盛德歸冥寞，斯文轉寂寥。", "聲名昭信史，功業在清朝。", "遺表祈天切，忠魂入地遥。", "九重思亮直，應作楚辭招。"]'),
('1c0d5a37-3b99-4eab-92c1-50aec250c109','水亭舒眺','釋文珦','宋','宋诗','song-poetry','','[]','秋風水上亭，獨坐望郊坰。',48,'全唐诗/poet.song.219000.json','["秋風水上亭，獨坐望郊坰。", "佛寺山偏好，漁家地亦腥。", "桑枯因抱蝎，草腐自生螢。", "踏月歸林下，柴扉尚未扃。"]'),
('e1ed06bc-fc43-45b2-9f97-374ebcc0d578','鄞中桃花渡即事','釋文珦','宋','宋诗','song-poetry','','[]','城北桃花渡，樓居半海商。',48,'全唐诗/poet.song.219000.json','["城北桃花渡，樓居半海商。", "官河通遠浦，津樹雜高檣。", "旭日江烟暖，東風水草香。", "爲看風土異，客子又懷鄉。"]'),
('c3482833-d4e0-421b-bd55-8e048b7904e8','自鄞江東泛舟至黄山橋度嶺遊白雲寺','釋文珦','宋','宋诗','song-poetry','','[]','望望白雲居，崔嵬在碧虛。',48,'全唐诗/poet.song.219000.json','["望望白雲居，崔嵬在碧虛。", "水窮方度嶺，石峻不容車。", "舊愛松蘿頂，重來筍蕨餘。", "却憐清絕景，無地著吟廬。"]'),
('651edea2-bbed-4f16-93a6-7018b30da3e0','建溪青玉峽雲際寺','釋文珦','宋','宋诗','song-poetry','','[]','飛瀑掛晴霓，山門對小溪。',48,'全唐诗/poet.song.219000.json','["飛瀑掛晴霓，山門對小溪。", "曉行青玉峽，時聽白猿啼。", "野竹樊蕉徑，脩桐間茗畦。", "儻容分席地，便此卜幽棲。"]'),
('eba10a91-dfad-414c-a571-d8cece2b2ae3','石橋瀑布','釋文珦','宋','宋诗','song-poetry','','[]','瀑布依真境，何曾與世同。',48,'全唐诗/poet.song.219000.json','["瀑布依真境，何曾與世同。", "灑空輕作霧，濺石亂生風。", "絕壁驚飛鳥，危梁卧斷虹。", "人言龍窟宅，祇在此潭中。"]'),
('e8e01ad0-b81c-4a4d-8d55-93ed1fc45d03','九仙山中瀑','釋文珦','宋','宋诗','song-poetry','','[]','一水從天下，源深不可知。',48,'全唐诗/poet.song.219000.json','["一水從天下，源深不可知。", "千尋垂縞練，餘沫散珠璣。", "響激雷霆合，風生草木欹。", "老僧來灌頂，濺濕薜蘿衣。"]'),
('443d5085-73c1-4d39-b955-0e89bc9bd746','雙溪寺','釋文珦','宋','宋诗','song-poetry','','[]','複嶺又重岡，塵緣此地忘。',48,'全唐诗/poet.song.219000.json','["複嶺又重岡，塵緣此地忘。", "五峰朝寺古，雙澗出雲長。", "深靜宜棲隠，高寒易雪霜。", "擬登華頂去，幽徑旋鋤荒。"]'),
('1fac0df7-7071-49bc-a371-827fa81cf2f1','煙霞石屋諸寺','釋文珦','宋','宋诗','song-poetry','','[]','緣山一徑微，竹樹隠禪扉。',48,'全唐诗/poet.song.219000.json','["緣山一徑微，竹樹隠禪扉。", "雲絕去來性，僧無生滅機。", "風簷鐵自語，陰洞石能飛。", "終擬携缾錫，他年向此歸。"]'),
('2793f061-8325-423c-9317-768ad94960bd','溪寺書懷','釋文珦','宋','宋诗','song-poetry','','[]','野寺依溪曲，長橋接柳堤。',48,'全唐诗/poet.song.219000.json','["野寺依溪曲，長橋接柳堤。", "俗人忙不入，孤客自安棲。", "嬾散今成性，煙雲盡入題。", "鄰居有農父，時與話耕犁。"]'),
('41eab392-11db-49e3-8ec6-4dc5eba857b5','宿閩中溪寺','釋文珦','宋','宋诗','song-poetry','','[]','獨宿閩溪寺，中宵夢自驚。',48,'全唐诗/poet.song.219000.json','["獨宿閩溪寺，中宵夢自驚。", "月斜移樹影，風急轉灘聲。", "起對清秋色，難爲遠客情。", "雲山千萬疊，何處是神京。"]'),
('cf99ea61-3976-46f6-b4da-3ef2ea4f50be','送友人住海寺','釋文珦','宋','宋诗','song-poetry','','[]','海上蓮花國，初從太守招。',48,'全唐诗/poet.song.219000.json','["海上蓮花國，初從太守招。", "衣傳方石偈，舟泊丈亭潮。", "漁子應焚簄，鮫人擬獻綃。", "他時思舊社，無奈寄書遥。"]'),
('7972efb2-cf88-4fb8-a08a-4e1ffa4fe8e8','山寺  其一','釋文珦','宋','宋诗','song-poetry','','[]','古寺氛埃表，幽程屈曲通。',48,'全唐诗/poet.song.219000.json','["古寺氛埃表，幽程屈曲通。", "高峰常似雨，陰壑易生風。", "架棧爲平地，寒鐘出半空。", "他年依老宿，掛錫此山中。"]'),
('615b2ed1-cccb-4c34-b403-c6972a77dea0','山寺  其二','釋文珦','宋','宋诗','song-poetry','','[]','出城行半日，始得到招提。',48,'全唐诗/poet.song.219000.json','["出城行半日，始得到招提。", "山氣隨時變，州形入望低。", "地靈多産藥，村遠不聞雞。", "詰旦還離此，尋幽過別谿。"]'),
('f2da1399-956c-4b43-9733-82d641fba89c','閩中歲暮懷吳中','釋文珦','宋','宋诗','song-poetry','','[]','冉冉年光盡，悽悽客思驚。',48,'全唐诗/poet.song.219000.json','["冉冉年光盡，悽悽客思驚。", "疎狂輕萬事，行役負平生。", "海月移松影，山風壯瀑聲。", "寒宵頻作夢，曾不離吳城。"]'),
('a71e60de-9e89-4042-9228-767c45bc37f2','懷安養  其一','釋文珦','宋','宋诗','song-poetry','','[]','凈土雖周徧，標方必在西。',48,'全唐诗/poet.song.219000.json','["凈土雖周徧，標方必在西。", "一心無彼此，九品自高低。", "久別情無奈，重歸路不迷。", "依憑法藏願，名字欲先題。"]'),
('7f1e697c-be45-4c09-b6fa-8481b5ee98d9','懷安養  其二','釋文珦','宋','宋诗','song-poetry','','[]','惟吾與西佛，天性本相關。',48,'全唐诗/poet.song.219000.json','["惟吾與西佛，天性本相關。", "怊悵迷方久，浮沉苦海間。", "三心終不退，上輩必容攀。", "慈念應尤切，提携早共還。"]'),
('121d77b4-38e6-4f23-8a8e-dc44ac45d1a8','懷安養  其三','釋文珦','宋','宋诗','song-poetry','','[]','容易拋鄉國，漂流幾歲年。',48,'全唐诗/poet.song.219000.json','["容易拋鄉國，漂流幾歲年。", "癡兒竟何事，慈父必興憐。", "客泪東風裏，歸心落日邊。", "如今定當返，業已具西船。"]'),
('bea9a907-b6a7-4322-b4bc-2fb139a158b6','懷安養  其四','釋文珦','宋','宋诗','song-poetry','','[]','西方清泰國，元自是吾家。',48,'全唐诗/poet.song.219000.json','["西方清泰國，元自是吾家。", "寶樹千般樂，金池四色花。", "同遊諸伴侶，一別幾年華。", "有意重歸去，途程本不賒。"]'),
('c41498b7-5f40-4150-b58d-b3e619ba79eb','春日懷人','釋文珦','宋','宋诗','song-poetry','','[]','林嶺春雲滿，陂湖春水多。',48,'全唐诗/poet.song.219000.json','["林嶺春雲滿，陂湖春水多。", "舊鄉書不到，久客意如何。", "老去長牢落，悲來一嘯歌。", "故人今在否，相憶夢青蘿。"]'),
('64177b60-5edb-49f9-9de2-72c396c6f897','贈隠人','釋文珦','宋','宋诗','song-poetry','','[]','換却青雲志，高眠舊隠廬。',48,'全唐诗/poet.song.219000.json','["換却青雲志，高眠舊隠廬。", "閒門誰踐草，隙地自栽蔬。", "交道貧尤密，吟情老不疎。", "囊中何所有，一卷養生書。"]'),
('5af3c2d6-153a-46d1-a10f-e25f11ee2f78','七里灘別友','釋文珦','宋','宋诗','song-poetry','','[]','斷壁青松古，空江翠靄多。',48,'全唐诗/poet.song.219000.json','["斷壁青松古，空江翠靄多。", "行人幾迴老，漁父祇高歌。", "縱有重逢約，其如此別何。", "明朝重回首，惆悵隔烟波。"]'),
('509f6c62-985c-400c-93ee-6007d01ae283','湖亭別友','釋文珦','宋','宋诗','song-poetry','','[]','與君俱是客，重別意如何。',48,'全唐诗/poet.song.219000.json','["與君俱是客，重別意如何。", "斜日孤帆去，寒江風浪多。", "遠懷隨鴈影，新詠雜漁歌。", "知此遨遊地，何時復共過。"]'),
('366dc60f-9cac-4f7a-92fa-426aa6a334f9','江上與故人暫會復別','釋文珦','宋','宋诗','song-poetry','','[]','交朋似君少，澹泊自真宗。',48,'全唐诗/poet.song.219000.json','["交朋似君少，澹泊自真宗。", "不記何年別，翻驚此地逢。", "烟波涵暮景，霜露改秋容。", "又說天台去，天台千萬峰。"]'),
('102301f0-ba25-4b4e-a14a-1c1b02bd89e7','池上別友人','釋文珦','宋','宋诗','song-poetry','','[]','今朝携手處，高榭俯風漪。',48,'全唐诗/poet.song.219000.json','["今朝携手處，高榭俯風漪。", "正爾俱衰暮，寧堪又別離。", "柳長深映馬，荷弱未勝龜。", "它日遥相憶，還應話此時。"]'),
('6bd1eba4-8118-444f-b6fe-3d07da318a35','贈王門老賓客','釋文珦','宋','宋诗','song-poetry','','[]','薄俗謾紛紛，焉知贋與真。',48,'全唐诗/poet.song.219000.json','["薄俗謾紛紛，焉知贋與真。", "空餘千里馬，難覓九方歅。", "古道何當復，時風未易陳。", "王門舊賓客，懷舊重悲辛。"]'),
('1e4ddee9-e33a-459e-9361-a55c2a0a3b4a','孤客','釋文珦','宋','宋诗','song-poetry','','[]','衆人皆汲汲，孤客自俞俞。',48,'全唐诗/poet.song.219000.json','["衆人皆汲汲，孤客自俞俞。", "方外居來久，囊中物盡無。", "行將筇作伴，講以石爲徒。", "若問何宗旨，饑來飯一盂。"]'),
('842e797b-552b-4a26-a679-51e2a1424d46','除狹','釋文珦','宋','宋诗','song-poetry','','[]','世狹難紆轡，全生託散財。',48,'全唐诗/poet.song.219000.json','["世狹難紆轡，全生託散財。", "紛華因地遣，懷抱向山開。", "野祭鴉爭聚，貧居燕亦來。", "不知江上笛，何事有餘哀。"]'),
('49263a30-d3fe-473f-94e2-242883b6bd51','題顔晞仲歸隠','釋文珦','宋','宋诗','song-poetry','','[]','飄然携杖錫，歸隠故山中。',48,'全唐诗/poet.song.219000.json','["飄然携杖錫，歸隠故山中。", "鳥道雲泉遠，猿聲烟樹重。", "清閑銷不盡，塵累坐來空。", "早晚須相覓，知居若箇峰。"]'),
('4f0edf34-dc71-4d34-99e8-a079d32f0157','行石林蒼莽間頗多幽致有思歸隠','釋文珦','宋','宋诗','song-poetry','','[]','離城纔一舍，已得近樵漁。',48,'全唐诗/poet.song.219000.json','["離城纔一舍，已得近樵漁。", "秀石雲松路，荒籬水竹居。", "陽坡收早粟，燒地長新蔬。", "便好爲茲隠，吾生不願餘。"]'),
('23581206-6c50-4da8-8c92-1f3c00f9c123','看月','釋文珦','宋','宋诗','song-poetry','','[]','靜室焚香罷，間吟倚石欄。',48,'全唐诗/poet.song.219000.json','["靜室焚香罷，間吟倚石欄。", "忽從青玉峽，湧出白銀盤。", "列宿消芒盡，清暉照膽寒。", "終宵不成寐，二十四回看。"]'),
('bae67656-8312-44b2-80dc-53fafab08b41','尋北山友不值','釋文珦','宋','宋诗','song-poetry','','[]','山南山北住，來往共煙霞。',48,'全唐诗/poet.song.219000.json','["山南山北住，來往共煙霞。", "午徑行松葉，秋籬問菊花。", "叩門人不見，歸路日西斜。", "應是孤雲性，難教只在家。"]'),
('a0af49d2-95ad-4799-ba09-043934a2cd6f','旱雨','釋文珦','宋','宋诗','song-poetry','','[]','驟雨幡然下，風雷駕疾威。',48,'全唐诗/poet.song.219000.json','["驟雨幡然下，風雷駕疾威。", "烏兼巢穴墮，龍挾水雲飛。", "物象回生意，神功解旱圍。", "田間喜相語，點點勝珠璣。"]'),
('04bfec54-3d69-4c79-a9b7-cb1d443880e4','三術','釋文珦','宋','宋诗','song-poetry','','[]','利祿與名稱，拘囚豈易勝。',48,'全唐诗/poet.song.219000.json','["利祿與名稱，拘囚豈易勝。", "由來立仗馬，有媿脫鞲鷹。", "達者知求解，貪夫反自矜。", "吾方用三術，止觀足堪憑。"]'),
('f9a02de5-f3f5-495b-b8fe-af54fc497634','山夜','釋文珦','宋','宋诗','song-poetry','','[]','山氣夜沉沉，泉流石澗陰。',48,'全唐诗/poet.song.219000.json','["山氣夜沉沉，泉流石澗陰。", "虛廊羣動息，寒殿一燈深。", "潔白孤蟾影，清澄野客心。", "興來歌古調，風動古松林。"]'),
('7ccaa553-7d60-49d6-b1c1-402420f863f2','閒樂','釋文珦','宋','宋诗','song-poetry','','[]','祇以閒爲樂，寧論是與非。',48,'全唐诗/poet.song.219000.json','["祇以閒爲樂，寧論是與非。", "安身唯草座，終歲掩柴扉。", "水蓏收菱芡，山糧采蕨薇。", "幾回清夢去，還共白雲飛。"]'),
('302f0f03-d658-49d6-8dd9-c2867a1eb23b','題規無範雲深室','釋文珦','宋','宋诗','song-poetry','','[]','物外清虛境，由來遠衆紛。',48,'全唐诗/poet.song.219000.json','["物外清虛境，由來遠衆紛。", "靈蹤幾年說，梵放或時聞。", "似有似無路，漫山漫谷雲。", "自難容俗駕，曾不待移文。"]'),
('174b5504-a506-4387-8f21-034822e83a26','飛來峰猿','釋文珦','宋','宋诗','song-poetry','','[]','恐山還欲去，着爾慰山靈。',48,'全唐诗/poet.song.219000.json','["恐山還欲去，着爾慰山靈。", "掛處頻分影，吟時不見形。", "鷲峰愁外遠，巴峽夢中青。", "月下三聲苦，幽人却要聽。"]'),
('a27909df-3c21-4712-a56a-e9299505d98e','禁體詠雪','釋文珦','宋','宋诗','song-poetry','','[]','應臈雨連朝，豐年瑞已饒。',48,'全唐诗/poet.song.219000.json','["應臈雨連朝，豐年瑞已饒。", "亂聲還蔌蔌，猛勢尚瀌瀌。", "嶺嶠松增秀，原田麥長臕。", "窮閻休怨冷，見睍自應消。"]'),
('9a1bdf2a-bd13-48b2-ac46-6f08b30fb435','禁體詠雪時方用兵故其末及之','釋文珦','宋','宋诗','song-poetry','','[]','擁衲坐深更，頻聞蔌蔌聲。',48,'全唐诗/poet.song.219000.json','["擁衲坐深更，頻聞蔌蔌聲。", "祇疑爲落葉，不道是飛霙。", "曉壓松頭重，寒鋪砌面平。", "幸成豐歲兆，何事却徵兵。"]'),
('e55c4f9d-808a-4b63-b8df-4417aa6848f2','地遠  其一','釋文珦','宋','宋诗','song-poetry','','[]','地遠無人迹，心閒見物情。',48,'全唐诗/poet.song.219000.json','["地遠無人迹，心閒見物情。", "洞中飛石燕，崖頂住山精。", "僊木開花異，靈泉吐溜清。", "幽棲已成趣，不復問浮名。"]'),
('d4acbc46-aefa-4897-bf74-fa0f0f2d10e2','地遠  其二','釋文珦','宋','宋诗','song-poetry','','[]','地遠隔凡塵，因而此隠淪。',48,'全唐诗/poet.song.219000.json','["地遠隔凡塵，因而此隠淪。", "閒知雲意度，清愛水精神。", "蔬食聊充腹，麻衣足蔽身。", "休嫌吾懶拙，懶拙廼吾真。"]'),
('289a43b9-0ad6-431b-ae2c-b7928cce2140','送遠','釋文珦','宋','宋诗','song-poetry','','[]','離情不可說，握手更躊躇。',48,'全唐诗/poet.song.219000.json','["離情不可說，握手更躊躇。", "爲客三秋盡，還家千里餘。", "山程楓葉赤，水驛柳條疎。", "日夕空林下，何人伴索居。"]'),
('90137969-a02e-46ab-8111-3070f0f3419c','吾性','釋文珦','宋','宋诗','song-poetry','','[]','吾性本疎狂，難教住帝鄉。',48,'全唐诗/poet.song.219000.json','["吾性本疎狂，難教住帝鄉。", "看心忘世界，濯足愛滄浪。", "往事皆如夢，浮生底用忙。", "到頭華衮服，不及芰荷裳。"]'),
('d60a5732-c9d5-445d-8319-7a00ac3d05ea','愛性','釋文珦','宋','宋诗','song-poetry','','[]','愛性畏讙呶，雲深一徑茅。',48,'全唐诗/poet.song.219000.json','["愛性畏讙呶，雲深一徑茅。", "了無徒屬累，唯結鹿麋交。", "灌木由來古，修篁亦漸苞。", "終然聲利表，頗若類由巢。"]'),
('e5ca0ad1-d464-47ab-9ba2-64cebbe92755','嬾性','釋文珦','宋','宋诗','song-poetry','','[]','嬾性難趨世，深棲自養蒙。',48,'全唐诗/poet.song.219000.json','["嬾性難趨世，深棲自養蒙。", "得閒真可樂，未死已知空。", "陰壑長留雪，喬林易有風。", "見聞今又絕，眼暗耳全聾。"]'),
('8f3b81df-4912-4850-abbb-fe4283f9036d','野性','釋文珦','宋','宋诗','song-poetry','','[]','野性難諧俗，空林自葺茅。',48,'全唐诗/poet.song.219000.json','["野性難諧俗，空林自葺茅。", "且教同木石，不是慕夷巢。", "竹樹長陰合，風泉夜響交。", "山中無小草，那許世人嘲。"]'),
('7ae77ee3-9c7d-4778-be36-952f1d824dd8','詠苕霅','釋文珦','宋','宋诗','song-poetry','','[]','苕霅水烟鄉，溪風六月涼。',48,'全唐诗/poet.song.219000.json','["苕霅水烟鄉，溪風六月涼。", "家家有船步，日日聽魚桹。", "柳樹垂陰密，蘋花入夢香。", "山入心亦愛，時到詠滄浪。"]'),
('74fb0954-4094-490f-b3f9-136333929a07','訪山家','釋文珦','宋','宋诗','song-poetry','','[]','山翁居處僻，野屋蓋茅新。',48,'全唐诗/poet.song.219000.json','["山翁居處僻，野屋蓋茅新。", "自得烟霞趣，應無車馬塵。", "怪禽啼似鬼，古木變爲人。", "不是忘緣者，誰能與子親。"]'),
('14c70fe3-d243-47ee-9c14-243c3d009fc7','送王逸人','釋文珦','宋','宋诗','song-poetry','','[]','閒身如野鶴，天地一虛巢。',48,'全唐诗/poet.song.219000.json','["閒身如野鶴，天地一虛巢。", "山水琴中趣，松筠世外交。", "懷親逢遠信，開卦卜歸爻。", "更說雲門好，相期共結茅。"]'),
('1f5bc14d-39c3-42be-b16a-541907a1feae','送立上人偕沈東皋謁吳退菴','釋文珦','宋','宋诗','song-poetry','','[]','闔閭城裏去，瘦沈是同舟。',48,'全唐诗/poet.song.219000.json','["闔閭城裏去，瘦沈是同舟。", "不用悲遊鹿，唯須問狎鷗。", "夕陽空茂苑，殘雪徧長洲。", "太守相逢日，言詩定點頭。"]'),
('ed25e9dc-20a7-4d64-a096-0b08083fd257','送王商公遊永嘉兼呈東甽曹侍郎荆山劉學士','釋文珦','宋','宋诗','song-poetry','','[]','覓句東嘉去，春風草又薰。',48,'全唐诗/poet.song.219000.json','["覓句東嘉去，春風草又薰。", "一千餘里路，四十九盤雲。", "幸有江山助，休爲旅泊分。", "曹劉諸老在，爲我致殷勤。"]'),
('fe5bc4d5-3fd6-49a8-812c-0efeff985ac7','旅中秋晚','釋文珦','宋','宋诗','song-poetry','','[]','秋露洗晴空，秋光處處同。',48,'全唐诗/poet.song.219000.json','["秋露洗晴空，秋光處處同。", "楓霞明野樹，蘆雪覆沙叢。", "旅況悲寒蛩，歸心寄斷鴻。", "幾時隨牧豎，吹笛亂山中。"]'),
('c61118aa-c69a-4f77-8922-205f2118d343','桐廬縣','釋文珦','宋','宋诗','song-poetry','','[]','瀟灑桐廬縣，名聞漢代餘。',48,'全唐诗/poet.song.219000.json','["瀟灑桐廬縣，名聞漢代餘。", "民風尚耕釣，土物富薪蔬。", "江水連衢港，雲山带越墟。", "終期置茅屋，鄰近釣臺居。"]'),
('34354666-f180-4531-8596-9a625ae19afc','華亭縣','釋文珦','宋','宋诗','song-poetry','','[]','地占三吳勝，名因二陸雄。',48,'全唐诗/poet.song.219000.json','["地占三吳勝，名因二陸雄。", "海村宵見日，江市晝多風。", "商賈通倭舶，樓臺半佛宮。", "歸來千歲鶴，應恨故巢空。"]'),
('e6b24e20-e934-4c34-9b89-fd217d4dde4d','臨安縣','釋文珦','宋','宋诗','song-poetry','','[]','霸業歸王室，空城但黍苗。',48,'全唐诗/poet.song.219000.json','["霸業歸王室，空城但黍苗。", "溪隨山勢轉，路入市聲遥。", "故俗多征歛，遺民尚寂寥。", "傷心到今古，祠樹亦蕭蕭。"]'),
('b045bb6d-baa8-4a46-90f7-ef64c99da239','秋聲','釋文珦','宋','宋诗','song-poetry','','[]','商飆何厲疾，羣籟盡囂囂。',48,'全唐诗/poet.song.219000.json','["商飆何厲疾，羣籟盡囂囂。", "迴穴生崖谷，淜滂度泬寥。", "恍疑沙漠戰，誤聽浙江潮。", "遮莫頻相聒，羈魂易得消。"]'),
('fd7f3100-126d-404c-acdd-b3209e4f3cea','江上留滯有作','釋文珦','宋','宋诗','song-poetry','','[]','寂寥誰與共，華髮卧滄洲。',48,'全唐诗/poet.song.219000.json','["寂寥誰與共，華髮卧滄洲。", "月照空堂夕，蛩吟壞壁秋。", "故人稀問訊，遠客易生愁。", "安得如沙鳥，煙波任去留。"]'),
('8cf84e96-c494-428f-bf01-00b9fa86121c','秋江獨泛','釋文珦','宋','宋诗','song-poetry','','[]','秋波無際遠，短艇遡寒江。',48,'全唐诗/poet.song.219000.json','["秋波無際遠，短艇遡寒江。", "風景由來異，鄉心未易降。", "晚烟生驛樹，空翠撲船窗。", "賦得滄浪曲，長謠不便腔。"]'),
('856fcc58-0eb0-4aad-838f-3b79d18cb041','水鄉聞鴈','釋文珦','宋','宋诗','song-poetry','','[]','短景又還暮，羈愁那易禁。',48,'全唐诗/poet.song.219000.json','["短景又還暮，羈愁那易禁。", "半生無著莫，萬事任浮沉。", "衲敝蘆花冷，爐存葑火深。", "雲間斷行鴈，時復動哀吟。"]'),
('f36ae088-961f-48d4-bc7c-4c9fe66b8db4','孤雁','釋文珦','宋','宋诗','song-poetry','','[]','孤雁如貞婦，餘生不再雙。',48,'全唐诗/poet.song.219000.json','["孤雁如貞婦，餘生不再雙。", "避寒辭北塞，隨日到南邦。", "倦翼堪憐影，哀音自滿腔。", "空閨人聽得，離思轉難降。"]'),
('23328aa4-f1e8-4438-86dd-8ddff6d0d597','秋感','釋文珦','宋','宋诗','song-poetry','','[]','客中難度日，池上獨徘徊。',48,'全唐诗/poet.song.219000.json','["客中難度日，池上獨徘徊。", "露冷芙蕖死，天高鴻雁來。", "枯莖寧再潤，羣叫易成哀。", "對此能無感，吾親在夜臺。"]'),
('8166da11-70c2-4008-a52e-50261cf17f22','歸夢','釋文珦','宋','宋诗','song-poetry','','[]','幾歲遠辭家，勞生詎有涯。',48,'全唐诗/poet.song.219000.json','["幾歲遠辭家，勞生詎有涯。", "客居終不穩，詩鬢獨先華。", "掃葉江風厲，侵床山月斜。", "念歸歸未得，清夢入煙霞。"]'),
('059101c5-bbec-4c4c-93f8-16becf3d6a0a','記夢','釋文珦','宋','宋诗','song-poetry','','[]','吟是大乘禪，禪深夢亦僊。',48,'全唐诗/poet.song.219000.json','["吟是大乘禪，禪深夢亦僊。", "放身行碧落，古樂聽鈞天。", "骨換言方異，心空意始圓。", "手挼黄菊蕊，寫放瀑厓邊。"]'),
('d835345d-2176-4726-bb6b-f38abd301198','春夜夢中得觀與心爲度身將世作仇一聯既覺而足成四韻寄修觀者','釋文珦','宋','宋诗','song-poetry','','[]','高人持遠流，凈行在林丘。',48,'全唐诗/poet.song.219000.json','["高人持遠流，凈行在林丘。", "觀與心爲度，身將世作仇。", "不曾過午食，常滿六時修。", "苦海人求度，師應駕法舟。"]'),
('30e7be0e-8a78-4581-be09-2db6f9297292','清苕','釋文珦','宋','宋诗','song-poetry','','[]','清曉泛苕濱，長歌撥櫂頻。',48,'全唐诗/poet.song.219000.json','["清曉泛苕濱，長歌撥櫂頻。", "山川開霽景，草木暢餘春。", "野老知閒趣，沙鷗似故人。", "絕勝拈麈尾，駕說弊精神。"]'),
('41850103-d9ff-4be1-afb1-3af07253a8a3','題竹房','釋文珦','宋','宋诗','song-poetry','','[]','野水連苔徑，山雲掩竹房。',48,'全唐诗/poet.song.219000.json','["野水連苔徑，山雲掩竹房。", "人閑清晝永，鳥語綠陰凉。", "斷刻排籤古，新茶入焙香。", "眼前清事足，不道在殊方。"]'),
('34d2882d-51dd-4b3a-8cb5-d602fb236225','宿靈鷲瀾師房','釋文珦','宋','宋诗','song-poetry','','[]','清泉繞砌流，境界極深幽。',48,'全唐诗/poet.song.219000.json','["清泉繞砌流，境界極深幽。", "有客暫投宿，羨君長此留。", "詩成雲滿磵，人靜月當樓。", "忽聽清猨嘯，南山山樹秋。"]'),
('6e2e9e9e-833f-41fa-916c-163cd4ece179','幽程','釋文珦','宋','宋诗','song-poetry','','[]','幽程寧憚遠，野外意無窮。',48,'全唐诗/poet.song.219000.json','["幽程寧憚遠，野外意無窮。", "山疊高低古，川流宛轉通。", "采芝隨羽客，拾橡共狙公。", "爛熳遊三日，塵勞頓覺空。"]'),
('3306cdaa-45ed-4569-be0a-06e5281aca70','隨寓','釋文珦','宋','宋诗','song-poetry','','[]','我忘方就隠，鳥倦自知還。',48,'全唐诗/poet.song.219000.json','["我忘方就隠，鳥倦自知還。", "隨寓皆爲道，何人有此閒。", "微茫春水渡，平遠夕陽山。", "盡入清吟景，誰言勝事慳。"]'),
('77047712-ddef-4080-9eb3-92f404dd9289','寄淮頭家兄','釋文珦','宋','宋诗','song-poetry','','[]','君向淮堧去，相思夢不安。',48,'全唐诗/poet.song.219000.json','["君向淮堧去，相思夢不安。", "兵戈猶未定，道路自應難。", "曠野人煙少，荒城鬼燐寒。", "故園松菊在，何必戀微官。"]'),
('45c8d7d9-7691-4f19-b0e1-2829c231fc09','秋夜憶兄','釋文珦','宋','宋诗','song-poetry','','[]','石房清睡熟，猶擁黑貂裘。',48,'全唐诗/poet.song.219000.json','["石房清睡熟，猶擁黑貂裘。", "鄉遠難爲夢，山深易得秋。", "脊令空在詠，蟋蟀暗生愁。", "何日潜溪岸，吟詩共倚樓。"]'),
('49eb202d-7f12-4260-b50a-e79421a10b58','哭何甥','釋文珦','宋','宋诗','song-poetry','','[]','秀穎出儒林，吾甥所得深。',48,'全唐诗/poet.song.219000.json','["秀穎出儒林，吾甥所得深。", "良材竟難用，造物果何心。", "身後無遺育，生前惜寸陰。", "臨棺一悲咤，萬籟亦同音。"]'),
('673a93c7-3338-4714-ab7c-8326d1c73d0e','邊思','釋文珦','宋','宋诗','song-poetry','','[]','少年爲遠戍，兩鬢已䰄䰄。',48,'全唐诗/poet.song.219000.json','["少年爲遠戍，兩鬢已䰄䰄。", "百戰功誰賞，空閨信不來。", "鄉關成夢境，邊月是愁媒。", "聽徹胡笳曲，寒聲轉更哀。"]'),
('65c66a72-36da-43f1-8903-809e802a8ac3','春江夜泛','釋文珦','宋','宋诗','song-poetry','','[]','江月照揚舲，乘風過萬汀。',48,'全唐诗/poet.song.219000.json','["江月照揚舲，乘風過萬汀。", "素光流遠漢，高浪濕寒星。", "客恨消長笛，閒身渺一蘋。", "到京天未曙，隠隠越山青。"]'),
('0d4abf23-6530-45bc-bf84-02d9b66827ae','反舌','釋文珦','宋','宋诗','song-poetry','','[]','毛羽誠無取，禽中號善鳴。',48,'全唐诗/poet.song.219000.json','["毛羽誠無取，禽中號善鳴。", "能將一片舌，巧作百般聲。", "元是因風氣，曾非出性情。", "君看五月後，瘖默媿流鶑。"]'),
('8f254308-305a-4efe-aa8e-ff0d06339c05','馮深居宰會稽','釋文珦','宋','宋诗','song-poetry','','[]','詔辟稽山縣，清風在一琴。',48,'全唐诗/poet.song.219000.json','["詔辟稽山縣，清風在一琴。", "那知致君術，不是字民心。", "官舍桐陰合，圜扉草色深。", "退衙人吏散，應共野僧吟。"]'),
('090e7149-b693-4d91-8814-66839901ebe4','送趙寒泉重宰南中邑','釋文珦','宋','宋诗','song-poetry','','[]','字民無異術，薄斂與寬刑。',48,'全唐诗/poet.song.219000.json','["字民無異術，薄斂與寬刑。", "宓子琴猶在，蒍于歌重聽。", "瘴雲消晝黑，毒草變春青。", "萬里南中路，秋風幾驛亭。"]'),
('9603f184-9333-4fd2-882d-7f4c7b1f2832','錢塘晚渡','釋文珦','宋','宋诗','song-poetry','','[]','殘日下重城，寒潮起暮聲。',48,'全唐诗/poet.song.219000.json','["殘日下重城，寒潮起暮聲。", "岸遥江樹小，天闊野雲平。", "一水分吳越，孤舟寄死生。", "如何未歸者，猶此計鄉程。"]'),
('842c4c50-9a4b-40bc-9329-2d399fc65011','泛富春江','釋文珦','宋','宋诗','song-poetry','','[]','夢寐羊裘客，清遊樂此邦。',48,'全唐诗/poet.song.219000.json','["夢寐羊裘客，清遊樂此邦。", "一篙殘臘雨，千古富春江。", "岸轉青螺合，烟明白鳥雙。", "洗除名利跡，灘瀨日舂撞。"]'),
('be394d10-fb1e-49b3-879e-95b1485d6d69','釣臺','釋文珦','宋','宋诗','song-poetry','','[]','世祖龍飛日，玄纁起故人。',48,'全唐诗/poet.song.219000.json','["世祖龍飛日，玄纁起故人。", "榮名既無取，閒足固應伸。", "釣石關乾象，江流入富春。", "高風千古在，來者自迷津。"]'),
('9031ab36-9948-41ff-9c18-809b26185d32','懷寄南陵尉沈道正','釋文珦','宋','宋诗','song-poetry','','[]','南陵初作尉，應亦似南昌。',48,'全唐诗/poet.song.219000.json','["南陵初作尉，應亦似南昌。", "名在神仙籍，才優翰墨場。", "盜聞無欲止，吏化不欺良。", "交舊如君少，懷思未易忘。"]'),
('007f05ce-335c-4279-ba6a-41ec70d4434a','寄潛齋王尚書','釋文珦','宋','宋诗','song-poetry','','[]','自解朝纓去，西山有的傳。',48,'全唐诗/poet.song.219000.json','["自解朝纓去，西山有的傳。", "此心如白水，把酒問青天。", "直道難諧俗，閒身勝得仙。", "山林鐘鼎味，併在小梅邊。"]'),
('7e238ea7-657b-4abf-b3b3-1b02f068000f','客中會友','釋文珦','宋','宋诗','song-poetry','','[]','客塗方浩蕩，歲物正蕭條。',48,'全唐诗/poet.song.219000.json','["客塗方浩蕩，歲物正蕭條。", "相見江城暮，俱傷鬢髮凋。", "陰雲將變雪，寒水不成潮。", "明日還爲別，離愁未易消。"]'),
('282626d7-54d4-4e9a-8c00-cab7f310f0dc','重遊天台華頂峰  其一','釋文珦','宋','宋诗','song-poetry','','[]','梯空上華頂，老脚尚能堪。',48,'全唐诗/poet.song.219000.json','["梯空上華頂，老脚尚能堪。", "照膽泉源異，薰人藥氣酣。", "危巔窺巨浸，晴日破重嵐。", "記得前回到，幽人未結庵。"]'),
('279d5051-7041-4eac-b0db-53eb8778e2db','重遊天台華頂峰  其二','釋文珦','宋','宋诗','song-poetry','','[]','天台三萬丈，華頂入穹蒼。',48,'全唐诗/poet.song.219000.json','["天台三萬丈，華頂入穹蒼。", "片石群魔懾，千年古寺荒。", "樹枯頳菌出，僧老白眉長。", "極目滄溟際，烟波更渺茫。"]'),
('2a3cc079-e993-410c-9690-c5243ec83112','野興','釋文珦','宋','宋诗','song-poetry','','[]','野人乘野興，短策勝華軒。',48,'全唐诗/poet.song.219000.json','["野人乘野興，短策勝華軒。", "緩步有幽趣，長歌非俗言。", "烟霞僊佛境，鼓笛鬼神村。", "遯世今成樂，浮華豈足論。"]'),
('b7acbf99-7fa3-4e90-9964-371a6484a968','天台野興','釋文珦','宋','宋诗','song-poetry','','[]','短策堪扶老，飄飄野興濃。',48,'全唐诗/poet.song.219000.json','["短策堪扶老，飄飄野興濃。", "山行不知遠，真侶或相逢。", "積溜穿幽石，長蘿上古松。", "今宵隨處宿，難定在何峰。"]'),
('c16d3cd7-ffa7-4c5f-9c26-7892cad98e28','示山友','釋文珦','宋','宋诗','song-poetry','','[]','地僻斷知聞，相過知有君。',48,'全唐诗/poet.song.219000.json','["地僻斷知聞，相過知有君。", "晴溪堪數石，晚岫暗通雲。", "果熟猨無數，松高鶴不羣。", "深居豈無事，終勝世紛紛。"]'),
('9802ea32-543a-4a27-8963-61221e70f762','鴈蕩大龍湫','釋文珦','宋','宋诗','song-poetry','','[]','深蹊入薜蘿，一瀑瀉巖阿。',48,'全唐诗/poet.song.219000.json','["深蹊入薜蘿，一瀑瀉巖阿。", "曾閲西天志，言居諾詎羅。", "斜飛疑是雨，清激自成渦。", "下有蒼龍窟，樵人不敢過。"]'),
('6d4f77aa-3055-437b-a940-c092855ded0a','采菖蒲','釋文珦','宋','宋诗','song-poetry','','[]','鴈蕩高寒處，穿雲採得來。',48,'全唐诗/poet.song.219000.json','["鴈蕩高寒處，穿雲採得來。", "豈能同野草，容易有花開。", "瘦節偏宜石，纖叢不受埃。", "幽人知爾性，曉澗汲泉杯。"]'),
('a3a7fb92-e8ab-431f-868b-955e9d60a9f3','客袂','釋文珦','宋','宋诗','song-poetry','','[]','客袂只翩翩，家林何處邊。',48,'全唐诗/poet.song.219000.json','["客袂只翩翩，家林何處邊。", "天寒愁遠道，木落感衰年。", "慘澹漁村日，凄涼鴈渚烟。", "秋來更多疾，空有夢歸田。"]'),
('a50e0312-207b-4520-ba6c-bfc0502bc981','贈山中琴友','釋文珦','宋','宋诗','song-poetry','','[]','雲影晝沉沉，雲邊草徑深。',48,'全唐诗/poet.song.219000.json','["雲影晝沉沉，雲邊草徑深。", "樹爲幽鳥宅，山是隠人心。", "靜室無他物，清風寄一琴。", "調高唯自識，不問有知音。"]'),
('fa16745d-5b55-4591-abcd-74e3d8bd3ca3','山中僧','釋文珦','宋','宋诗','song-poetry','','[]','日落西水浄，雲歸北崦昏。',48,'全唐诗/poet.song.219000.json','["日落西水浄，雲歸北崦昏。", "老僧方在定，童子不譍門。", "伏虎知慈力，靈禽演法言。", "檻前泉數斛，清澈是心源。"]'),
('6396ea07-9da3-4463-a55e-2c85130223e7','旅夜  其一','釋文珦','宋','宋诗','song-poetry','','[]','秋宵似歲長，旅館更荒涼。',48,'全唐诗/poet.song.219000.json','["秋宵似歲長，旅館更荒涼。", "燈暗鼠出穴，天寒蟲近床。", "羈栖彌歲月，老大易悲傷。", "幸有茅廬在，何爲別故鄉。"]'),
('50d3c2ae-778f-4974-b6cb-ebd26ae88f28','旅夜  其二','釋文珦','宋','宋诗','song-poetry','','[]','離人厭夜長，獨起坐空床。',48,'全唐诗/poet.song.219000.json','["離人厭夜長，獨起坐空床。", "苦雨遲家信，秋雲隔舊鄉。", "燭殘重作焰，桂濕不生香。", "倘得歸期遂，閒居在上方。"]'),
('d71f3720-d650-43c4-bcbc-94fedb62b2ae','宿海上正覺寺','釋文珦','宋','宋诗','song-poetry','','[]','霜滿啼猿石，風迴落鴈洲。',48,'全唐诗/poet.song.219000.json','["霜滿啼猿石，風迴落鴈洲。", "半生爲遠客，此夕欠同流。", "白月無窮意，滄波不盡秋。", "倚闌吟未足，長嘯上峰頭。"]'),
('cc72f843-5fba-4cd4-9715-ea2d977fc875','過逸人居','釋文珦','宋','宋诗','song-poetry','','[]','尚此高閑久，空林舊徑存。',48,'全唐诗/poet.song.219000.json','["尚此高閑久，空林舊徑存。", "掩關防俗駕，登閣俯鄰園。", "植竹驚初笋，移花過別根。", "幽懷在自得，勿易與人言。"]'),
('2f8d805c-a36f-449f-bc0e-9f8cad47fbbf','爲林隠君賦石田','釋文珦','宋','宋诗','song-poetry','','[]','石田所無用，君獨愛斯名。',48,'全唐诗/poet.song.219000.json','["石田所無用，君獨愛斯名。", "應爲詩書種，免教人世爭。", "秋風還自穫，春雨不須耕。", "除是長沮輩，能知高隠情。"]'),
('1055bd23-aae1-4842-b496-a2bb744cfc9e','胡逸人幽居','釋文珦','宋','宋诗','song-poetry','','[]','幽居清絕甚，四面盡滄波。',48,'全唐诗/poet.song.219000.json','["幽居清絕甚，四面盡滄波。", "柳步春船集，花源晚吹和。", "宦情垂釣薄，吟思捲簾多。", "便有書來辟，其如愛此何。"]'),
('d2fc8388-9b99-4edc-8148-a30f9797ef24','澤國幽居夏日雜題  其一','釋文珦','宋','宋诗','song-poetry','','[]','澤國無袢暑，幽居趣自長。',48,'全唐诗/poet.song.219000.json','["澤國無袢暑，幽居趣自長。", "花開殊旦暮，稻熟間青黄。", "急雨分塍下，微風度水涼。", "斷除車馬跡，日日聽魚桹。"]'),
('1c5fde92-f2cd-4d1f-9aa5-e15d79d66954','澤國幽居夏日雜題  其二','釋文珦','宋','宋诗','song-poetry','','[]','爲得近樵漁，來尋此地居。',48,'全唐诗/poet.song.219000.json','["爲得近樵漁，來尋此地居。", "省交長閉戶，耽靜欲焚書。", "自愛心清淡，人嫌禮貌疎。", "徑荒從草沒，衰懶不能除。"]'),
('59dae565-a6f8-407c-9cd0-b1aea6a0a2a8','遠遊','釋文珦','宋','宋诗','song-poetry','','[]','林憩無完室，舟行避惡灘。',48,'全唐诗/poet.song.219000.json','["林憩無完室，舟行避惡灘。", "異鄉爲客久，浮俗定交難。", "草引春愁長，霜侵曉夢殘。", "忽聞城角動，歸思若爲安。"]'),
('224dde0f-9688-470a-a02a-2c8a08fe5567','客中春日','釋文珦','宋','宋诗','song-poetry','','[]','客處空林下，貧唯七尺單。',48,'全唐诗/poet.song.219000.json','["客處空林下，貧唯七尺單。", "重陰迷曉色，細雨作春寒。", "鄉信憑誰寄，離情强自寬。", "一詩吟未穩，倚遍石池欄。"]'),
('124edceb-fa61-42c4-9b2b-f1687c044f1e','春日','釋文珦','宋','宋诗','song-poetry','','[]','春泉青似淀，春嶂碧于螺。',48,'全唐诗/poet.song.219000.json','["春泉青似淀，春嶂碧于螺。", "遠近隨吾意，芒鞋幽興多。", "人生行樂爾，富貴復如何。", "難與時人道，風前獨放歌。"]'),
('0dbff11b-a5eb-4faa-b2aa-22a2a5bd9b30','麥秋遊興','釋文珦','宋','宋诗','song-poetry','','[]','心喜麥秋晴，貪遊舉步輕。',48,'全唐诗/poet.song.219000.json','["心喜麥秋晴，貪遊舉步輕。", "泬寥無點翳，山水有餘清。", "怕入紅欄隊，來尋白社盟。", "應門童子熟，認得老夫聲。"]'),
('7962c08e-ff24-4ed7-923d-1f20f53683b3','宋氏林園','釋文珦','宋','宋诗','song-poetry','','[]','徑穿荒草入，門向斷河開。',48,'全唐诗/poet.song.219000.json','["徑穿荒草入，門向斷河開。", "不是君居此，應無人到來。", "種花逢雨活，接樹待春回。", "冷笑求名者，衣間有俗埃。"]'),
('bf7d80f1-d8f6-46f9-b2ea-c074ee47692f','集奉川道中','釋文珦','宋','宋诗','song-poetry','','[]','一路盤雲遠，連朝策瘦筇。',48,'全唐诗/poet.song.219000.json','["一路盤雲遠，連朝策瘦筇。", "神祠依古木，佛屋占奇峰。", "立石分田界，疏泉作澗舂。", "因思似鄉土，歸意忽然濃。"]'),
('c8a1e4e4-11e5-44f6-b95b-2a93e11c6815','雨夜','釋文珦','宋','宋诗','song-poetry','','[]','身同水上萍，老去尚飄零。',48,'全唐诗/poet.song.219000.json','["身同水上萍，老去尚飄零。", "遠客人誰到，空床夢獨醒。", "閃雲雙電紫，晦雨一燈青。", "慷慨長歌發，歌聲入杳冥。"]'),
('f5f3030c-c50d-493c-8b08-682d3fa5b677','登太白絕頂龍池望遠','釋文珦','宋','宋诗','song-poetry','','[]','蒼莽勢連空，躋攀徑絕蹤。',48,'全唐诗/poet.song.219000.json','["蒼莽勢連空，躋攀徑絕蹤。", "亂峰排似戟，片石響於鐘。", "鳥語春雲密，龍歸暮雨重。", "下觀羣岫小，始覺此爲宗。"]'),
('9537c285-28b9-41ca-b6a2-a43f9b6fe9b0','湖寺上方通玄峰頂','釋文珦','宋','宋诗','song-poetry','','[]','峰頂非人世，青山滿目多。',48,'全唐诗/poet.song.219000.json','["峰頂非人世，青山滿目多。", "塔層侵樹影，鐘響度湖波。", "心外元無境，詩成亦是魔。", "禪翁清浄耳，渾不聽笙歌。"]'),
('f3ec83fb-d70c-4432-a133-43a69a6d0f7b','客遊','釋文珦','宋','宋诗','song-poetry','','[]','客遊忘歲月，長是自調心。',48,'全唐诗/poet.song.219000.json','["客遊忘歲月，長是自調心。", "野水偏多浪，浮雲易作陰。", "途窮何用哭，興到即須吟。", "吟到忘言境，方諧正始音。"]'),
('555fafd5-d27c-4247-a0ff-f453c4403fae','旅况','釋文珦','宋','宋诗','song-poetry','','[]','日暮投村館，悽然逆旅情。',48,'全唐诗/poet.song.219000.json','["日暮投村館，悽然逆旅情。", "地荒頻有盜，城遠不聞更。", "度歲無多日，思鄉是幾程。", "聽雞還束被，霜月伴晨征。"]'),
('59a9f7e8-e56f-4b4e-9260-6751d10b25ff','柘溪道中','釋文珦','宋','宋诗','song-poetry','','[]','荒烟迷小市，細雨隔遥津。',48,'全唐诗/poet.song.219000.json','["荒烟迷小市，細雨隔遥津。", "麥浪農疇晚，桐花客路春。", "幾番時序換，兩鬢雪霜新。", "唯有溪邊鷺，相看似故人。"]'),
('9b348805-5839-4622-a690-6180dcc76c6b','山中古墓','釋文珦','宋','宋诗','song-poetry','','[]','白石蒼苔路，荒涼古墓門。',48,'全唐诗/poet.song.219000.json','["白石蒼苔路，荒涼古墓門。", "看來百歲後，曾有幾人存。", "故物餘翁仲，今誰是子孫。", "狐狸穿敗穴，殘魄不能言。"]'),
('b2ec362f-8af0-4e3c-90c2-10203e81fdb9','懷歸西國','釋文珦','宋','宋诗','song-poetry','','[]','此世爲何世，吾身亦幻身。',48,'全唐诗/poet.song.219000.json','["此世爲何世，吾身亦幻身。", "固應常邈邈，其可效頻頻。", "餞日懷鄉國，聞鶑憶故人。", "得歸方始樂，久客厭風塵。"]'),
('87a3578e-410a-4e63-bbcb-a90be2f24903','老大','釋文珦','宋','宋诗','song-poetry','','[]','老大偏多感，那堪客路中。',48,'全唐诗/poet.song.219000.json','["老大偏多感，那堪客路中。", "凄涼經月病，安忍半生窮。", "衰草凝霜白，高楓借日紅。", "今朝方暫起，先問菊花叢。"]'),
('97fffa23-a19d-4b6c-98c7-6c1aeec0ba8e','散人','釋文珦','宋','宋诗','song-poetry','','[]','乾坤有散人，事事不關身。',48,'全唐诗/poet.song.219000.json','["乾坤有散人，事事不關身。", "斂念息諸妄，到頭唯一真。", "忘榮寧慮辱，無富豈嫌貧。", "雖道青山好，猶知是外塵。"]'),
('3255b38e-b863-4e85-82f9-4c002fb19cd3','探幽','釋文珦','宋','宋诗','song-poetry','','[]','秋色令人愛，青藜助遠探。',48,'全唐诗/poet.song.219000.json','["秋色令人愛，青藜助遠探。", "柿楓丹互映，天水碧相涵。", "絕景沙鷗占，幽程野老諳。", "謂予雲外去，更有古龍潭。"]'),
('ae7bfc56-d520-4d3e-ac12-45db8d21b767','立春日','釋文珦','宋','宋诗','song-poetry','','[]','上國又逢春，衣裳化客塵。',48,'全唐诗/poet.song.219000.json','["上國又逢春，衣裳化客塵。", "園廬空入夢，歲月但依人。", "生意歸羣物，窮愁老一身。", "喜餘鷗鷺伴，猶不怪吾真。"]'),
('ae24aac7-fefe-47e5-a908-77bf933c1998','臘月立明年春','釋文珦','宋','宋诗','song-poetry','','[]','閏歲兩番春，流光故逼人。',48,'全唐诗/poet.song.219000.json','["閏歲兩番春，流光故逼人。", "月筩將謝丑，斗柄倏旋寅。", "玉作梅容潤，金歸柳眼新。", "物情雖萬變，曾莫變吾真。"]'),
('971e2786-adc9-49b2-8883-45760ada7c89','吳中靈巖寺','釋文珦','宋','宋诗','song-poetry','','[]','離宮今作寺，往事日荒蕪。',48,'全唐诗/poet.song.219000.json','["離宮今作寺，往事日荒蕪。", "越女承恩寵，吳王失霸圖。", "屧廊斜带嶺，香徑直通湖。", "莫上琴臺望，風烟滿舊都。"]'),
('25c4cd14-ee9f-4134-b0f7-794edb0f2106','廢宅','釋文珦','宋','宋诗','song-poetry','','[]','昔年誇富貴，磨滅等流塵。',48,'全唐诗/poet.song.219000.json','["昔年誇富貴，磨滅等流塵。", "應是重歸燕，難尋舊主人。", "徑莎空泣露，門柳不成春。", "唯有同遊客，經過感慨頻。"]'),
('30fbfd22-1925-4919-9438-3c694ded82dc','天目山逸人居','釋文珦','宋','宋诗','song-poetry','','[]','隠處元無路，烟霞素所期。',48,'全唐诗/poet.song.219000.json','["隠處元無路，烟霞素所期。", "不逢樵子說，那有世人知。", "樹老回春晚，山高見日遲。", "欲爲重到約，恐爾又深移。"]'),
('d9daa865-a670-45d4-9aed-3ef7429fc250','西風','釋文珦','宋','宋诗','song-poetry','','[]','西風落葉間，孤客有餘閒。',48,'全唐诗/poet.song.219000.json','["西風落葉間，孤客有餘閒。", "寒水皆歸壑，秋雲不離山。", "鶻翻枯草去，鴉带夕陽還。", "幽趣何人共，柴門祇自關。"]'),
('1608340a-bb4c-4273-a345-08134fe97dfd','歸興','釋文珦','宋','宋诗','song-poetry','','[]','歸興比春濃，迢遥發鏡中。',48,'全唐诗/poet.song.219000.json','["歸興比春濃，迢遥發鏡中。", "船頭指西日，帆腹飽春風。", "岸柳眉舒黛，源桃臉露紅。", "到家天已暝，童穉候衰翁。"]'),
('7ff68663-6eb3-491a-a0ba-2bc01a3cd492','墜壁嶺','釋文珦','宋','宋诗','song-poetry','','[]','石徑隨山轉，迢迢十里餘。',48,'全唐诗/poet.song.219000.json','["石徑隨山轉，迢迢十里餘。", "險曾稱地壁，高合號天衢。", "老樹因風折，新畬趁雨鋤。", "層巔人不到，異鳥自相呼。"]'),
('49a03d38-08f9-40bd-9d0b-fc559d955f2a','歸棲竺嶺將啟午供野鶴必鳴寺僧常以此爲候','釋文珦','宋','宋诗','song-poetry','','[]','古寺千峰表，雲泉處處佳。',48,'全唐诗/poet.song.219000.json','["古寺千峰表，雲泉處處佳。", "山靈嫌俗駕，野鶴喚僧齋。", "靜默通玄理，幽深愜隠懷。", "閒門何用掃，秋葉任平階。"]'),
('c0133dc6-3eff-4170-9b21-d6eaec5b3082','陟三十六渡溪唐塢嶺','釋文珦','宋','宋诗','song-poetry','','[]','三十六渡溪，溪邊絕去蹊。',48,'全唐诗/poet.song.219000.json','["三十六渡溪，溪邊絕去蹊。", "亂山如疊浪，一嶺類登梯。", "風緊妖蛇出，烟昏異鳥啼。", "蜀僧言劍閣，與此亦相齊。"]'),
('1bd17a9a-5a8c-4731-a09f-927943ad1ccf','山巔水涯','釋文珦','宋','宋诗','song-poetry','','[]','布襪與青鞋，山巔復水涯。',48,'全唐诗/poet.song.219000.json','["布襪與青鞋，山巔復水涯。", "閒爲真富貴，吟是好情懷。", "既可全吾樂，何慙與世乖。", "自隨無畚插，忘死亦忘骸。"]'),
('82ead987-6c7f-43a3-ab1b-1dd37e7fa03d','殘夜清坐','釋文珦','宋','宋诗','song-poetry','','[]','壺更猶未徹，起坐看螢流。',48,'全唐诗/poet.song.219000.json','["壺更猶未徹，起坐看螢流。", "夜氣清如水，禪心淡似秋。", "月沉西嶺樹，鐘動上方樓。", "可有昏冥者，知吾所得優。"]'),
('fdb0bf00-7458-4100-975e-6c00f259f551','龍井','釋文珦','宋','宋诗','song-poetry','','[]','崖井涵虛碧，心塵望即空。',48,'全唐诗/poet.song.219000.json','["崖井涵虛碧，心塵望即空。", "遥通滄海脈，近出白雲峰。", "旱夕翻爲雨，饑年屢變豐。", "小魚纔似葉，誰識是真龍。"]'),
('51e41778-414f-4a86-a952-e933cbf016fa','五洩龍井','釋文珦','宋','宋诗','song-poetry','','[]','五井蜿蜒宅，幽深父老言。',48,'全唐诗/poet.song.219000.json','["五井蜿蜒宅，幽深父老言。", "傍溪唯見瀑，度嶺始知源。", "夾谷斜暉隠，空林夕電翻。", "屢聞當旱歲，噀雨出松門。"]'),
('d66c5d3a-10ca-4fc0-8820-3cddcb4bf352','雷峰','釋文珦','宋','宋诗','song-poetry','','[]','不定似飛蓬，還來宿此峰。',48,'全唐诗/poet.song.219000.json','["不定似飛蓬，還來宿此峰。", "霜欺孤客枕，風亂四山鐘。", "好夢如冰薄，歸心與酒濃。", "舊房誰占住，門有最長松。"]'),
('da5cfc44-821c-447d-8546-5336d7f27ae2','歲旱','釋文珦','宋','宋诗','song-poetry','','[]','經歲雨不作，溪源皆絕流。',48,'全唐诗/poet.song.219000.json','["經歲雨不作，溪源皆絕流。", "旱妖長似夏，蟲響謾占秋。", "滿目傷黎庶，焦心在冕旒。", "天河盍傾瀉，併洗甲兵憂。"]'),
('8bab1339-23b5-4d38-ae9c-87252c00de0b','行飛來冷泉水石間','釋文珦','宋','宋诗','song-poetry','','[]','鷲嶺清無盡，池亭趣亦佳。',48,'全唐诗/poet.song.219000.json','["鷲嶺清無盡，池亭趣亦佳。", "泉衝沙觜出，石壓樹身斜。", "居者應遺世，遊人欲忘家。", "蓮華峰更好，惜被白雲遮。"]'),
('5f371f32-914f-4cda-8faa-0fdb8dcce5c7','秋野即事','釋文珦','宋','宋诗','song-poetry','','[]','深原草徑斜，烟際兩三家。',48,'全唐诗/poet.song.219000.json','["深原草徑斜，烟際兩三家。", "老屋門無鑰，清溪底見沙。", "斷蟬嘶敗柳，孤蝶戀寒花。", "歷省曾遊處，分明似若耶。"]'),
('e7ce52a3-4ff9-4961-92f9-8181cfcbb016','安分','釋文珦','宋','宋诗','song-poetry','','[]','鷃鵬雖有異，小大各逍遥。',48,'全唐诗/poet.song.219000.json','["鷃鵬雖有異，小大各逍遥。", "靜處安吾分，塵緣坐見消。", "烟霞開古色，松柏尚高標。", "更愛無生侶，時來伴寂寥。"]'),
('03faf1af-1f60-4311-813e-21097d53eb3f','甲子歲初夏連雨作寒','釋文珦','宋','宋诗','song-poetry','','[]','雨脚何當斷，風頭不肯收。',48,'全唐诗/poet.song.219000.json','["雨脚何當斷，風頭不肯收。", "中宵還集霰，四月尚重裘。", "客有塗泥嘆，民懷畎畝憂。", "是誰同燮理，對此合包羞。"]'),
('1e07e8ff-96a3-4d3e-b6d4-3065a71a9da7','苦雨','釋文珦','宋','宋诗','song-poetry','','[]','秋雨連三月，愁吟野水濆。',48,'全唐诗/poet.song.219000.json','["秋雨連三月，愁吟野水濆。", "漸看禾黍沒，難使渭涇分。", "山澤纔通氣，天霄便作雲。", "民憂昏墊苦，苦語不堪聞。"]'),
('b727bbf7-57b0-4e2a-8984-49ffea885820','秋色','釋文珦','宋','宋诗','song-poetry','','[]','西郊金氣盛，庶物減華滋。',48,'全唐诗/poet.song.219000.json','["西郊金氣盛，庶物減華滋。", "蘀蘀丹楓雨，茫茫白草衰。", "炎曦何慘淡，氣曀若委遲。", "對此凄涼景，能無宋玉悲。"]'),
('0193a644-948f-4565-88b3-42f9948d6980','送楊菊屋','釋文珦','宋','宋诗','song-poetry','','[]','菊屋何爲者，耽吟嘔肺肝。',48,'全唐诗/poet.song.219000.json','["菊屋何爲者，耽吟嘔肺肝。", "短衣空自詠，長鋏向誰彈。", "不計爲儒誤，唯言得句難。", "幾人憐此別，把酒不成歡。"]'),
('dfdfe021-df8e-4c7c-a638-fa52c73d6085','送友','釋文珦','宋','宋诗','song-poetry','','[]','山臨東郭暮，路轉北原斜。',48,'全唐诗/poet.song.219000.json','["山臨東郭暮，路轉北原斜。", "此地輕爲別，孤蓬不戀家。", "客程何地盡，離思滿天涯。", "明日重陽至，同誰對菊花。"]'),
('1f4ce952-d413-4de6-af60-b3948ce0cab5','送人','釋文珦','宋','宋诗','song-poetry','','[]','送子西風裏，令予起別愁。',48,'全唐诗/poet.song.219000.json','["送子西風裏，令予起別愁。", "何時通遠信，逾月在孤舟。", "野果經霜實，潮田带露收。", "明朝於此地，獨自倚高樓。"]');
